_MODULES["ui.hex"] = function()
-- Hexagon shape builder. Draws a flat-top regular hexagon as a stack of
-- horizontal rows whose width matches the hex's geometry at that y. Rows are
-- ~2px tall and each overlaps its neighbor by 1px to hide the seam, so the
-- diagonal edges still read smooth while halving the GuiObject count vs the old
-- 1-row-per-pixel build (the hub draws ~3 hexes per feature row, so it adds up).
--
-- Geometry for a flat-top hex inscribed in w x h:
--   * widest at the vertical middle (width = w)
--   * narrowest at the top and bottom edges (width = w/2)
--   * width(y) = w - |y - h/2| * w/h
-- For a regular hexagon, pass h = w * sqrt(3)/2 (~= 0.866w). Stretched
-- proportions still draw cleanly but are no longer "regular."

local hex = {}

function hex.build(parent, w, h, color, zIndex, texture)
    -- texture (optional): { image, src, transparency, tint }. When given, each
    -- row becomes an ImageLabel showing its horizontal band of `image` (assumed
    -- `src` px square) over the base `color`, so the picture fills the hex
    -- silhouette -- used to give the "P" button the same carbon look as panels.
    -- ~2px per row (was ~1px). rowH+1 sizing below keeps a 1px overlap so the
    -- coarser stepping doesn't open gaps on the diagonal edges.
    local rows = math.max(8, math.ceil(h / 2))
    local rowH = h / rows
    local src  = texture and (texture.src or 128) or nil

    local host = Instance.new("Frame")
    host.Size = UDim2.fromOffset(w, h)
    host.BackgroundTransparency = 1
    host.ZIndex = zIndex or 1
    host.Parent = parent

    for i = 0, rows - 1 do
        local yCenter = (i + 0.5) * rowH
        local distFromMid = math.abs(yCenter - h / 2)
        local rowW = w - distFromMid * w / h
        if rowW < 1 then rowW = 1 end

        local row
        if texture then
            -- Sample the sub-rect of the image that lines up with this row so
            -- the whole picture is reconstructed inside the hex outline.
            local left = w / 2 - rowW / 2
            row = Instance.new("ImageLabel")
            row.BackgroundColor3 = color           -- base tints through the texture
            row.Image = texture.image
            row.ScaleType = Enum.ScaleType.Stretch
            row.ImageRectOffset = Vector2.new(left / w * src, (yCenter - rowH / 2) / h * src)
            row.ImageRectSize   = Vector2.new(rowW / w * src, rowH / h * src)
            row.ImageTransparency = texture.transparency or 0
            if texture.tint then row.ImageColor3 = texture.tint end
        else
            row = Instance.new("Frame")
            row.BackgroundColor3 = color
        end
        -- +1 on height so adjacent rows overlap by ~1px, hiding gaps.
        row.Size = UDim2.fromOffset(rowW, rowH + 1)
        row.Position = UDim2.fromOffset(w / 2, yCenter)
        row.AnchorPoint = Vector2.new(0.5, 0.5)
        row.BorderSizePixel = 0
        row.Parent = host
    end

    return host
end

-- Convenience: build a hex AND position it at `position` with `anchor`.
-- Used for placing small hex accents at specific points (container corners etc).
function hex.placed(parent, w, h, color, position, anchor, zIndex)
    local host = hex.build(parent, w, h, color, zIndex)
    host.Position = position
    host.AnchorPoint = anchor or Vector2.new(0, 0)
    return host
end

-- Recolor every row of an existing hex (built by hex.build). Used for
-- elements that need to flip color on a state change (ON/OFF indicators etc).
function hex.setColor(hexHost, color)
    for _, child in ipairs(hexHost:GetChildren()) do
        if child:IsA("Frame") then
            child.BackgroundColor3 = color
        end
    end
end

return hex
end

_MODULES["ui.components"] = function()
-- UI primitives: Section, Label, Button, Toggle, Slider, KeybindSetter.
-- Sharp angular corners — no UICorner anywhere — to match the hex/HUD theme.

local theme = require("ui.theme")

local UIS = game:GetService("UserInputService")

local components = {}

-- Slider drag + KeybindSetter listen-mode need GLOBAL UserInputService
-- connections (a drag/keypress lands outside the row). Destroying the row's
-- GUI does NOT sever those, so we track them here and disconnect on teardown.
-- Without this, every Auto Re-Execute (teleport) stacked ~2 dead InputChanged
-- handlers per slider on UIS, firing on every mouse move forever.
-- NB: named trackConn (not `track`) on purpose -- Slider has a local `track`
-- Frame, and a bare `track` here would be shadowed by it, turning track(...)
-- into "call a Frame value" at runtime.
local conns = {}   -- [conn] = true
local function trackConn(c) conns[c] = true; return c end
local function untrackConn(c) conns[c] = nil end

local function baseRow(parent, height)
    local f = Instance.new("Frame")
    f.Size = UDim2.new(1, 0, 0, height or theme.rowHeight)
    f.BackgroundColor3 = theme.bgAlt
    f.BorderSizePixel = 0
    f.Parent = parent
    return f
end

function components.Section(parent, text)
    local f = Instance.new("TextLabel")
    f.Size = UDim2.new(1, 0, 0, 22)
    f.BackgroundTransparency = 1
    f.Text = string.upper(text or "")
    f.TextColor3 = theme.accent
    f.Font = theme.fontBold
    f.TextSize = 11
    f.TextXAlignment = Enum.TextXAlignment.Left
    f.Parent = parent
    return f
end

function components.Label(parent, text)
    local f = Instance.new("TextLabel")
    f.Size = UDim2.new(1, 0, 0, 20)
    f.BackgroundTransparency = 1
    f.Text = text or ""
    f.TextColor3 = theme.fgDim
    f.Font = theme.font
    f.TextSize = 12
    f.TextXAlignment = Enum.TextXAlignment.Left
    f.Parent = parent
    return f
end

function components.Button(parent, opts)
    opts = opts or {}
    local f = baseRow(parent)
    local btn = Instance.new("TextButton")
    btn.Size = UDim2.fromScale(1, 1)
    btn.BackgroundTransparency = 1
    btn.Text = opts.text or "Button"
    btn.TextColor3 = theme.fg
    btn.Font = theme.font
    btn.TextSize = 13
    btn.Parent = f
    if opts.onClick then
        btn.MouseButton1Click:Connect(opts.onClick)
    end
    return f
end

function components.Toggle(parent, opts)
    opts = opts or {}
    local state = opts.default == true
    local f = baseRow(parent)

    local label = Instance.new("TextLabel")
    label.Size = UDim2.new(1, -56, 1, 0)
    label.Position = UDim2.fromOffset(10, 0)
    label.BackgroundTransparency = 1
    label.Text = opts.text or "Toggle"
    label.TextColor3 = theme.fg
    label.Font = theme.font
    label.TextSize = 12
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Parent = f

    local switch = Instance.new("TextButton")
    switch.Size = UDim2.fromOffset(36, 18)
    switch.Position = UDim2.new(1, -44, 0.5, -9)
    switch.AutoButtonColor = false
    switch.Text = ""
    switch.Parent = f

    local knob = Instance.new("Frame")
    knob.Size = UDim2.fromOffset(14, 14)
    knob.BackgroundColor3 = theme.fg
    knob.BorderSizePixel = 0
    knob.Parent = switch

    local function apply()
        switch.BackgroundColor3 = state and theme.accent or theme.bgDark
        knob.Position = state and UDim2.new(1, -16, 0.5, -7) or UDim2.fromOffset(2, 2)
    end
    apply()

    switch.MouseButton1Click:Connect(function()
        state = not state
        apply()
        if opts.onChange then opts.onChange(state) end
    end)

    local api = {}
    function api:Set(v)
        v = v and true or false
        if state ~= v then
            state = v
            apply()
            if opts.onChange then opts.onChange(state) end
        end
    end
    function api:Get() return state end
    return api
end

function components.Slider(parent, opts)
    opts = opts or {}
    local min   = opts.min or 0
    local max   = opts.max or 100
    local step  = opts.step or 1
    local value = opts.default or min

    local f = baseRow(parent, 42)

    local label = Instance.new("TextLabel")
    label.Size = UDim2.new(1, -20, 0, 18)
    label.Position = UDim2.fromOffset(10, 2)
    label.BackgroundTransparency = 1
    label.Font = theme.font
    label.TextSize = 12
    label.TextColor3 = theme.fg
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Text = string.format("%s: %s", opts.text or "Slider", tostring(value))
    label.Parent = f

    local track = Instance.new("Frame")
    track.Size = UDim2.new(1, -20, 0, 6)
    track.Position = UDim2.fromOffset(10, 26)
    track.BackgroundColor3 = theme.bgDark
    track.BorderSizePixel = 0
    track.Parent = f

    local fill = Instance.new("Frame")
    fill.BackgroundColor3 = theme.accent
    fill.BorderSizePixel = 0
    fill.Size = UDim2.new((value - min) / (max - min), 0, 1, 0)
    fill.Parent = track

    local dragging = false

    local function setFromX(x)
        local relX = math.clamp(x - track.AbsolutePosition.X, 0, track.AbsoluteSize.X)
        local pct = (track.AbsoluteSize.X == 0) and 0 or relX / track.AbsoluteSize.X
        local v = min + pct * (max - min)
        v = math.floor(v / step + 0.5) * step
        v = math.clamp(v, min, max)
        if math.abs(v - value) > 1e-6 then
            value = v
            fill.Size = UDim2.new((v - min) / (max - min), 0, 1, 0)
            label.Text = string.format("%s: %s", opts.text or "Slider", tostring(v))
            if opts.onChange then opts.onChange(v) end
        end
    end

    track.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
           or input.UserInputType == Enum.UserInputType.Touch then
            dragging = true
            setFromX(input.Position.X)
        end
    end)
    trackConn(UIS.InputChanged:Connect(function(input)
        if not dragging then return end
        if input.UserInputType == Enum.UserInputType.MouseMovement
           or input.UserInputType == Enum.UserInputType.Touch then
            setFromX(input.Position.X)
        end
    end))
    trackConn(UIS.InputEnded:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
           or input.UserInputType == Enum.UserInputType.Touch then
            dragging = false
        end
    end))

    local api = {}
    function api:Get() return value end
    function api:Set(v)
        v = math.clamp(v, min, max)
        value = v
        fill.Size = UDim2.new((v - min) / (max - min), 0, 1, 0)
        label.Text = string.format("%s: %s", opts.text or "Slider", tostring(v))
        if opts.onChange then opts.onChange(v) end
    end
    return api
end

local function keyDisplayName(k)
    if not k or k == Enum.KeyCode.Unknown then return "<none>" end
    return (tostring(k):gsub("Enum.KeyCode.", ""))
end

function components.KeybindSetter(parent, opts)
    opts = opts or {}
    local current = opts.default or Enum.KeyCode.Unknown
    local listening = false

    local f = baseRow(parent, 28)

    local label = Instance.new("TextLabel")
    label.Size = UDim2.new(0.5, -10, 1, 0)
    label.Position = UDim2.fromOffset(10, 0)
    label.BackgroundTransparency = 1
    label.Text = opts.label or "Keybind"
    label.TextColor3 = theme.fg
    label.Font = theme.font
    label.TextSize = 12
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Parent = f

    -- Setter button (click to enter listen mode, then press any key to bind)
    local btn = Instance.new("TextButton")
    btn.Position = UDim2.new(0.5, 4, 0.5, -10)
    btn.Size = UDim2.new(0.5, -38, 0, 20)
    btn.BackgroundColor3 = theme.bgDark
    btn.AutoButtonColor = false
    btn.TextColor3 = theme.fgDim
    btn.Font = theme.fontMono
    btn.TextSize = 11
    btn.Text = keyDisplayName(current)
    btn.Parent = f

    -- Unbind button: clears the keybind in one click
    local unbind = Instance.new("TextButton")
    unbind.Position = UDim2.new(1, -22, 0.5, -10)
    unbind.Size = UDim2.fromOffset(20, 20)
    unbind.BackgroundColor3 = theme.danger
    unbind.AutoButtonColor = false
    unbind.Text = "X"
    unbind.TextColor3 = theme.fg
    unbind.Font = theme.fontBold
    unbind.TextSize = 10
    unbind.Parent = f

    btn.MouseButton1Click:Connect(function()
        if listening then return end
        listening = true
        btn.Text = "<press a key>"
        btn.BackgroundColor3 = theme.accent

        local conn
        conn = trackConn(UIS.InputBegan:Connect(function(input)
            if input.UserInputType ~= Enum.UserInputType.Keyboard then return end
            if input.KeyCode == Enum.KeyCode.Unknown then return end
            local k = input.KeyCode
            if k == Enum.KeyCode.Escape then
                listening = false
                btn.Text = keyDisplayName(current)
                btn.BackgroundColor3 = theme.bgDark
                conn:Disconnect(); untrackConn(conn)
                return
            end
            if k == Enum.KeyCode.Backspace then
                current = Enum.KeyCode.Unknown
                listening = false
                btn.Text = keyDisplayName(current)
                btn.BackgroundColor3 = theme.bgDark
                if opts.onChange then opts.onChange(current) end
                conn:Disconnect(); untrackConn(conn)
                return
            end
            current = k
            listening = false
            btn.Text = keyDisplayName(current)
            btn.BackgroundColor3 = theme.bgDark
            if opts.onChange then opts.onChange(current) end
            conn:Disconnect(); untrackConn(conn)
        end))
    end)

    unbind.MouseButton1Click:Connect(function()
        current = Enum.KeyCode.Unknown
        btn.Text = keyDisplayName(current)
        if opts.onChange then opts.onChange(current) end
    end)

    return {
        get = function() return current end,
        set = function(k)
            current = k
            btn.Text = keyDisplayName(current)
            if opts.onChange then opts.onChange(current) end
        end,
    }
end

-- Dropdown: a header row showing the current value; clicking it expands an
-- inline list of options below (pushes following rows down via the panel's
-- UIListLayout -- no overlay z-fighting). Returns api:Get()/api:Set(v).
function components.Dropdown(parent, opts)
    opts = opts or {}
    local options  = opts.options or {}
    local value    = opts.default or options[1]
    local onChange = opts.onChange

    local root = Instance.new("Frame")
    root.Size = UDim2.new(1, 0, 0, 0)
    root.AutomaticSize = Enum.AutomaticSize.Y
    root.BackgroundTransparency = 1
    root.Parent = parent
    local rl = Instance.new("UIListLayout", root)
    rl.SortOrder = Enum.SortOrder.LayoutOrder
    rl.Padding = UDim.new(0, 2)

    local header = baseRow(root, 28)
    header.LayoutOrder = 1
    local label = Instance.new("TextLabel")
    label.Size = UDim2.new(0.5, -10, 1, 0); label.Position = UDim2.fromOffset(10, 0)
    label.BackgroundTransparency = 1; label.Text = opts.label or "Select"
    label.TextColor3 = theme.fg; label.Font = theme.font; label.TextSize = 12
    label.TextXAlignment = Enum.TextXAlignment.Left; label.Parent = header

    local cur = Instance.new("TextButton")
    cur.Position = UDim2.new(0.5, 4, 0.5, -10); cur.Size = UDim2.new(0.5, -14, 0, 20)
    cur.BackgroundColor3 = theme.bgDark; cur.AutoButtonColor = false
    cur.TextColor3 = theme.fg; cur.Font = theme.font; cur.TextSize = 11
    cur.Text = tostring(value or ""); cur.Parent = header

    local listHost = Instance.new("Frame")
    listHost.Size = UDim2.new(1, 0, 0, 0); listHost.AutomaticSize = Enum.AutomaticSize.Y
    listHost.BackgroundTransparency = 1; listHost.Visible = false; listHost.LayoutOrder = 2
    listHost.Parent = root
    local ll = Instance.new("UIListLayout", listHost)
    ll.SortOrder = Enum.SortOrder.LayoutOrder; ll.Padding = UDim.new(0, 1)

    local optCount = 0
    local function addOption(o)
        optCount = optCount + 1
        local ob = Instance.new("TextButton")
        ob.Size = UDim2.new(1, -20, 0, 22); ob.Position = UDim2.fromOffset(20, 0)
        ob.BackgroundColor3 = theme.bgAlt; ob.AutoButtonColor = true; ob.BorderSizePixel = 0
        ob.TextColor3 = theme.fgDim; ob.Font = theme.font; ob.TextSize = 11
        ob.Text = tostring(o); ob.LayoutOrder = optCount; ob.Parent = listHost
        ob.MouseButton1Click:Connect(function()
            value = o; cur.Text = tostring(o); listHost.Visible = false
            if onChange then onChange(value) end
        end)
    end
    for _, o in ipairs(options) do addOption(o) end

    cur.MouseButton1Click:Connect(function()
        listHost.Visible = not listHost.Visible
    end)

    local api = {}
    function api:Get() return value end
    function api:Set(v)
        value = v; cur.Text = tostring(v or "")
        if onChange then onChange(value) end
    end
    function api:AddOption(o) addOption(o) end   -- append a new option (e.g. a saved custom preset)
    return api
end

-- Text input row: label on the left, a TextBox on the right. onChange fires on
-- focus-lost with the entered text. Used to name custom shader presets.
function components.TextBox(parent, opts)
    opts = opts or {}
    local f = baseRow(parent, 28)

    local label = Instance.new("TextLabel")
    label.Size = UDim2.new(0.4, -10, 1, 0); label.Position = UDim2.fromOffset(10, 0)
    label.BackgroundTransparency = 1; label.Text = opts.label or "Name"
    label.TextColor3 = theme.fg; label.Font = theme.font; label.TextSize = 12
    label.TextXAlignment = Enum.TextXAlignment.Left; label.Parent = f

    local box = Instance.new("TextBox")
    box.Position = UDim2.new(0.4, 4, 0.5, -10); box.Size = UDim2.new(0.6, -14, 0, 20)
    box.BackgroundColor3 = theme.bgDark; box.BorderSizePixel = 0
    box.TextColor3 = theme.fg; box.PlaceholderColor3 = theme.fgDim
    box.Font = theme.font; box.TextSize = 11
    box.Text = opts.default or ""; box.PlaceholderText = opts.placeholder or ""
    box.ClearTextOnFocus = false; box.TextXAlignment = Enum.TextXAlignment.Left
    box.Parent = f
    local pad = Instance.new("UIPadding", box); pad.PaddingLeft = UDim.new(0, 6)

    box.FocusLost:Connect(function()
        if opts.onChange then opts.onChange(box.Text) end
    end)

    local api = {}
    function api:Get() return box.Text end
    function api:Set(v) box.Text = v or "" end
    return api
end

-- Disconnect every tracked global-UIS connection (slider drag handlers + any
-- live keybind listen). Called from init.lua's shutdown so a re-execute doesn't
-- stack listeners across teleports.
function components.destroy()
    for c in pairs(conns) do pcall(function() c:Disconnect() end) end
    conns = {}
end

return components
end

_MODULES["ui.window"] = function()
-- Pantheon root UI. Hosts a ScreenGui that contains a `Containers` parent
-- (for draggable category windows) plus a floating hexagonal open/close button.
-- Master hotkey (default RightControl) toggles visibility.
--
-- Show/hide animation:
--   * The "P" button spins 360 degrees clockwise on show, counterclockwise on
--     hide. Anchor is centered so the spin happens in place.
--   * Each container slides in from off-screen left to its captured original
--     position with a STAGGER_DELAY between consecutive containers, so they
--     appear one after another, not all at once. Hide reverses the motion.

local env       = require("core.env")
local theme     = require("ui.theme")
local hex       = require("ui.hex")
local keybinds  = require("core.keybinds")
local container = require("ui.container")
local persist   = require("core.persist")

local UIS          = game:GetService("UserInputService")
local TweenService = game:GetService("TweenService")
local SoundService = game:GetService("SoundService")
local Debris       = game:GetService("Debris")

local Window = {}

local TWEEN_DURATION = 0.35
local STAGGER_DELAY  = 0.20
local OFF_SCREEN_X   = -400
local SPIN_DURATION  = 0.55

local s = {
    screenGui = nil,
    container = nil,
    openBtn   = nil,
    visible   = true,
    masterKey = Enum.KeyCode.RightControl,
    dragConns = {},   -- global UIS connections for the "P" button drag; cleared on destroy
    spinTarget = 0,   -- accumulated target Rotation for the spin (always a multiple of 360)
    spinTween = nil,
    tweens   = {},    -- [container] = running slide tween
    targets  = {},    -- [container] = {x,y} the slide is heading to (for settle-snap)
    animating = {},   -- [container] = true while mid-toggle (running OR pending stagger)
    animGen  = 0,     -- bumped per toggle so stale staggered starts no-op
}

-- [container Frame] = { x = origX, y = origY } captured the first time we see
-- a container in its on-screen position. Used so we can slide it back home.
local origPositions = {}

local function captureOrig(c)
    if origPositions[c] then return origPositions[c] end
    local p = { x = c.Position.X.Offset, y = c.Position.Y.Offset }
    origPositions[c] = p
    return p
end

-- Custom slide SFX via getcustomasset: download the bundled swoosh from the repo
-- once, cache it to the Wave workspace, and resolve a content id. This sidesteps
-- Roblox's private-audio wall (uploaded audio only plays in games you own). The
-- Sound is parented INTO the protected gethui ScreenGui (not SoundService) so a
-- game scanning instances for a foreign custom-asset SoundId can't see it.
local SFX_URL  = "https://raw.githubusercontent.com/6014m/Pantheon/main/assets/swoosh.mp3"
local SFX_PATH = "Pantheon/sfx/slide_v1.mp3"
local customSoundId
local customTried = false

local function httpBinary(url)
    if env.request then
        local ok, res = pcall(env.request, { Url = url, Method = "GET" })
        if ok and res and res.Body and #res.Body > 0
           and (not res.StatusCode or res.StatusCode == 200) then
            return res.Body
        end
    end
    local ok, body = pcall(env.HttpGet, url)
    if ok and body and #body > 0 then return body end
    return nil
end

local function resolveCustomSound()
    if customTried then return customSoundId end
    customTried = true
    if not env.getcustomasset then return nil end
    pcall(function()
        if not (env.isfile and env.isfile(SFX_PATH)) then
            if env.makefolder and env.isfolder then
                if not env.isfolder("Pantheon")     then env.makefolder("Pantheon")     end
                if not env.isfolder("Pantheon/sfx") then env.makefolder("Pantheon/sfx") end
            end
            local data = httpBinary(SFX_URL)
            if data and env.writefile then env.writefile(SFX_PATH, data) end
        end
        if env.isfile and env.isfile(SFX_PATH) then
            customSoundId = env.getcustomasset(SFX_PATH)
        end
    end)
    return customSoundId
end

-- Per-event Sound (NEVER persistent -- a Sound created at load crashes Wave);
-- Debris reaps it. Uses the custom swoosh once resolved, else the library id.
local function playSlideSound()
    local id = customSoundId or theme.slideSoundId
    if not id or id == "" then return end
    pcall(function()
        local snd = Instance.new("Sound")
        snd.SoundId = id
        snd.Volume  = theme.slideVolume or 0.5
        snd.Parent  = s.screenGui or SoundService   -- hide inside the protected GUI
        snd:Play()
        Debris:AddItem(snd, 2)
    end)
end

local function animateContainers(showing)
    -- Settle any in-flight animation FIRST: cancel running tweens, snap each
    -- container to the spot it was heading to, and bump a generation token so
    -- still-pending staggered starts from the previous toggle no-op. Without this,
    -- a fast open/close captured a mid-slide position as "home" and panels
    -- reopened overlapping. Only the OPEN (visible) containers participate.
    s.animGen = s.animGen + 1
    local gen = s.animGen
    -- Settle EVERY container still mid-toggle -- running tween OR pending stagger
    -- start -- by snapping it to where it was heading. Containers at rest (e.g.
    -- the user dragged one) aren't in s.animating, so their position is left
    -- alone and captured correctly below.
    for c in pairs(s.animating) do
        if s.tweens[c] then pcall(function() s.tweens[c]:Cancel() end) end
        local t = s.targets[c]
        if t and c and c.Parent then c.Position = UDim2.fromOffset(t.x, t.y) end
    end
    s.animating = {}
    s.tweens = {}

    local list = {}
    for _, c in ipairs(s.container:GetChildren()) do
        if c:IsA("GuiObject") and c.Visible then
            table.insert(list, c)
        end
    end

    -- On hide, capture each container's now-SETTLED spot as its home so it slides
    -- back exactly there on the next show (honoring user drags + auto-slots).
    if not showing then
        for _, c in ipairs(list) do
            origPositions[c] = { x = c.Position.X.Offset, y = c.Position.Y.Offset }
        end
    end

    local function homeX(c)
        local h = origPositions[c]
        return h and h.x or c.Position.X.Offset
    end
    table.sort(list, function(a, b) return homeX(a) < homeX(b) end)

    for i, c in ipairs(list) do
        local home = origPositions[c] or { x = c.Position.X.Offset, y = c.Position.Y.Offset }
        origPositions[c] = home
        local targetX = showing and home.x or OFF_SCREEN_X
        s.targets[c] = { x = targetX, y = home.y }
        s.animating[c] = true     -- mark NOW so a re-toggle during the stagger still settles it

        -- Pre-position off-screen before the show tween so the user doesn't
        -- see it teleport visually first.
        if showing then
            c.Position = UDim2.fromOffset(OFF_SCREEN_X, home.y)
        end

        task.delay((i - 1) * STAGGER_DELAY, function()
            if gen ~= s.animGen then return end          -- superseded by a newer toggle
            if not (c and c.Parent) then return end
            playSlideSound()
            local info = TweenInfo.new(
                TWEEN_DURATION,
                Enum.EasingStyle.Quad,
                showing and Enum.EasingDirection.Out or Enum.EasingDirection.In
            )
            local tw = TweenService:Create(c, info, { Position = UDim2.fromOffset(targetX, home.y) })
            s.tweens[c] = tw
            tw.Completed:Connect(function()
                if s.tweens[c] == tw then s.tweens[c] = nil; s.animating[c] = nil end
            end)
            tw:Play()
        end)
    end
end

local function spinButton(clockwise)
    if not s.openBtn then return end
    -- Accumulate the TARGET (kept a multiple of 360 so it always lands upright)
    -- instead of reading the live, mid-tween Rotation -- rapid toggling otherwise
    -- compounds partial spins and leaves the P at a crooked angle. Cancel the
    -- in-flight spin so overlapping tweens don't fight.
    s.spinTarget = (s.spinTarget or 0) + (clockwise and 360 or -360)
    if s.spinTween then pcall(function() s.spinTween:Cancel() end) end
    s.spinTween = TweenService:Create(s.openBtn,
        TweenInfo.new(SPIN_DURATION, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
        { Rotation = s.spinTarget }
    )
    s.spinTween:Play()
end

local function buildHexButton(sg)
    local host = Instance.new("Frame")
    host.Name = "PantheonOpenButton"
    host.Size = UDim2.fromOffset(46, 40)
    -- AnchorPoint centered so Rotation spins in place. Position adjusted so
    -- the visible location matches the previous top-left placement.
    host.AnchorPoint = Vector2.new(0.5, 0.5)
    host.Position = UDim2.new(0, 39, 1, -36)
    host.BackgroundTransparency = 1
    host.ZIndex = 10
    host.Parent = sg

    if theme.panelTexture and theme.panelTexture ~= "" then
        -- Same carbon-fiber treatment as the panels, over the accent base.
        hex.build(host, 46, 40, theme.headerBand, 10, {
            image        = theme.panelTexture,
            src          = theme.panelTextureSrc or 128,
            transparency = theme.panelTextureTransparency,
            tint         = theme.panelTextureTint,
        })
    else
        hex.build(host, 46, 40, theme.headerBand, 10)
    end

    local label = Instance.new("TextLabel")
    label.Size = UDim2.fromScale(1, 1)
    label.BackgroundTransparency = 1
    label.Text = "P"
    label.TextColor3 = theme.headerBand      -- match the hex button it sits on
    label.Font = theme.fontBold
    label.TextSize = 18
    label.ZIndex = 12
    label.Parent = host

    -- Border so the same-colored "P" stays visible against its hex fill.
    local labelStroke = Instance.new("UIStroke")
    labelStroke.Thickness = theme.logoStrokeThickness or 1.5
    labelStroke.Color     = theme.logoStroke or theme.fg
    labelStroke.Parent    = label

    local btn = Instance.new("TextButton")
    btn.Size = UDim2.fromScale(1, 1)
    btn.BackgroundTransparency = 1
    btn.Text = ""
    btn.AutoButtonColor = false
    btn.ZIndex = 13
    btn.Parent = host

    -- Drag + click-to-toggle (click only fires if not dragged)
    local dragging, dragStart, startPos = false, nil, nil
    local moved = false
    btn.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
           or input.UserInputType == Enum.UserInputType.Touch then
            dragging  = true
            dragStart = input.Position
            startPos  = host.Position
            moved     = false
        end
    end)
    s.dragConns[#s.dragConns + 1] = UIS.InputChanged:Connect(function(input)
        if not dragging then return end
        if input.UserInputType == Enum.UserInputType.MouseMovement
           or input.UserInputType == Enum.UserInputType.Touch then
            local delta = input.Position - dragStart
            if delta.Magnitude > 4 then moved = true end
            local g = theme.gridSize or 16
            -- Snap the DELTA so the grid starts where the button was grabbed.
            local nx = startPos.X.Offset + math.floor(delta.X / g + 0.5) * g
            local ny = startPos.Y.Offset + math.floor(delta.Y / g + 0.5) * g
            -- Clamp on-screen (centered anchor; Y is bottom-anchored so offsets
            -- are negative-up).
            local pSz   = host.Parent.AbsoluteSize
            local hw, hh = host.AbsoluteSize.X / 2, host.AbsoluteSize.Y / 2
            nx = math.clamp(nx, hw, math.max(hw, pSz.X - hw))
            ny = math.clamp(ny, hh - pSz.Y, -hh)
            host.Position = UDim2.new(startPos.X.Scale, nx, startPos.Y.Scale, ny)
        end
    end)
    s.dragConns[#s.dragConns + 1] = UIS.InputEnded:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
           or input.UserInputType == Enum.UserInputType.Touch then
            if dragging and not moved then Window.toggle() end
            dragging = false
        end
    end)

    return host
end

function Window.init()
    if s.screenGui then return end

    -- One-time: drop legacy saved panel positions so panels re-home to the new
    -- below-topbar / grid-aligned defaults. Guarded so it runs once per game.
    if not persist.get("ui.posReset_v1", false) then
        persist.clearPrefix("ui.pos.")
        persist.set("ui.posReset_v1", true)
    end

    local sg = Instance.new("ScreenGui")
    sg.Name = "PantheonGui"
    sg.IgnoreGuiInset = true
    sg.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
    sg.ResetOnSpawn = false
    sg.Parent = env.guiParent()
    env.protectGui(sg)

    local containerHost = Instance.new("Frame")
    containerHost.Name = "Containers"
    containerHost.Size = UDim2.fromScale(1, 1)
    containerHost.BackgroundTransparency = 1
    containerHost.Parent = sg

    s.screenGui = sg
    s.container = containerHost
    s.openBtn   = buildHexButton(sg)
    s.spinTarget, s.spinTween = 0, nil   -- match the fresh button's Rotation = 0
    task.spawn(resolveCustomSound)       -- download/cache the custom swoosh off the boot path

    keybinds.set("ui.master_toggle", s.masterKey, Window.toggle)
end

function Window.toggle()
    Window.setVisible(not s.visible)
end

function Window.setVisible(v)
    if s.visible == v then return end
    s.visible = v
    -- Keep the parent visible during animations; children move off-screen
    -- via Position rather than via Visible flips, so the slide tween is
    -- actually seen.
    if s.container then s.container.Visible = true end
    animateContainers(v)
    spinButton(v)
end

function Window.isVisible()
    return s.visible
end

function Window.parent()
    return s.container
end

function Window.setMasterKey(key)
    s.masterKey = key
    keybinds.set("ui.master_toggle", key, Window.toggle)
end

function Window.destroy()
    -- Disconnect the "P" button's global UIS drag handlers and every container's
    -- (both live on the global service, so destroying the GUI doesn't sever them).
    for _, c in ipairs(s.dragConns) do pcall(function() c:Disconnect() end) end
    s.dragConns = {}
    for _, tw in pairs(s.tweens) do pcall(function() tw:Cancel() end) end
    s.tweens, s.targets, s.animating = {}, {}, {}
    pcall(function() container.cleanup() end)

    if s.screenGui then
        pcall(function() s.screenGui:Destroy() end)
    end
    s.screenGui, s.container, s.openBtn = nil, nil, nil
    -- origPositions keys hold references to GuiObjects that just died; reset
    -- so a fresh Window.init() doesn't try to slide-animate stale frames.
    origPositions = {}
end

return Window
end

_MODULES["ui.container"] = function()
-- Draggable category container as a single unified chamfered shape.
--
-- One ImageLabel renders the whole outline (using the uploaded chamfered_panel
-- asset as a 9-slice). A UIGradient on the ImageLabel provides the accent
-- header-color to body-color vertical transition with a sharp boundary at
-- HEADER_H pixels from the top. The gradient's color-stop position is in
-- normalized 0..1 space, so when AutomaticSize grows the container as
-- features are added, we update the gradient stops to keep the seam at the
-- same absolute pixel height.

local theme   = require("ui.theme")
local persist = require("core.persist")

local UIS        = game:GetService("UserInputService")
local GuiService = game:GetService("GuiService")

local Container = {}
Container.__index = Container

local nextIndex = 0

-- Drag handlers are connected to the GLOBAL UserInputService (mouse moves
-- happen outside the small drag handle), so destroying the container's GUI
-- does NOT sever them. We track them here and disconnect on teardown --
-- otherwise every Auto Re-Execute (teleport) leaks one pair per container
-- that keeps firing on every mouse move forever.
local dragConns = {}

-- Every live container, in creation order. The navigator lists these so the
-- user can open/close each menu (Wurst-style) instead of all showing at once.
local instances = {}

-- When true, newly-created containers start hidden -- the navigator toggles
-- them on. The navigator itself is built with this still false so it stays
-- visible. Reset on cleanup so a re-execute starts fresh.
Container.startHidden = false

-- Auto-placement: opened containers without a user-saved position pack into
-- slots immediately to the right of the navigator (slot 0 = nearest). Closing
-- one frees its slot. navRef points at the navigator so the slots follow it
-- even if the user drags it.
local slots  = {}
local navRef = nil

local function posKey(name)  return "ui.pos."  .. persist.slug(name) end
local function openKey(name) return "ui.open." .. persist.slug(name) end

-- Default Y for auto-placed containers: the Roblox topbar height + a margin.
-- The ScreenGui uses IgnoreGuiInset, so without this offset panels spawn UNDER
-- the topbar in games that show it. The bottom-anchored P button is unaffected.
local function baseTopY()
    local ok, inset = pcall(function() return GuiService:GetGuiInset() end)
    return ((ok and inset and inset.Y) or 36) + 16
end

-- Quantize a position to the drag-snap grid so panels snap to a grid instead
-- of free pixel drag.
local function snap(v)
    local g = theme.gridSize or 16
    return math.floor(v / g + 0.5) * g
end

local IMAGE_ID     = "rbxassetid://77797049442743"
local CHAMFER      = 24
local SLICE_CENTER = Rect.new(CHAMFER, CHAMFER, 64 - CHAMFER, 64 - CHAMFER)
local HEADER_H     = 36                                  -- accent-colored band height in pixels

function Container.new(parent, name)
    local self = setmetatable({}, Container)

    local idx = nextIndex
    nextIndex = nextIndex + 1
    local containerW = theme.containerWidth
    local x = 16 + idx * (containerW + theme.containerGap)

    local container = Instance.new("ImageLabel")
    container.Name = "Container_" .. name
    container.Size = UDim2.new(0, containerW, 0, HEADER_H + CHAMFER + 4)
    container.AutomaticSize = Enum.AutomaticSize.Y
    container.Position = UDim2.fromOffset(x, baseTopY())
    container.BackgroundTransparency = 1
    container.Image = IMAGE_ID
    container.ImageColor3 = Color3.new(1, 1, 1)          -- white so the UIGradient tints freely
    container.ScaleType = Enum.ScaleType.Slice
    container.SliceCenter = SLICE_CENTER
    container.Parent = parent

    -- Reserve space at the bottom so feature rows don't sit on top of the
    -- chamfered bottom corners. PaddingTop = HEADER_H so the Features
    -- frame (UIListLayout-stacked, sitting at the top of the padded area)
    -- starts right after the accent header band.
    local pad = Instance.new("UIPadding", container)
    pad.PaddingTop    = UDim.new(0, HEADER_H)
    pad.PaddingBottom = UDim.new(0, CHAMFER + 4)
    pad.PaddingLeft   = UDim.new(0, 6)
    pad.PaddingRight  = UDim.new(0, 6)

    -- Accent (header band) -> body color, sharp seam at HEADER_H pixels from
    -- the top. UIGradient stops are normalized so we recompute on size changes.
    local gradient = Instance.new("UIGradient")
    gradient.Rotation = 90                                -- top -> bottom
    gradient.Parent = container

    local lastGradPct = -1
    local function updateGradient()
        local h = container.AbsoluteSize.Y
        if h <= 0 then return end
        local pct = math.clamp(HEADER_H / h, 0.001, 0.999)
        -- The seam sits at `pct` of the height; skip rebuilding the 4-stop
        -- ColorSequence when a size change doesn't move it visibly (AbsoluteSize
        -- fires repeatedly as feature/cog panels expand and collapse).
        if math.abs(pct - lastGradPct) < 0.002 then return end
        lastGradPct = pct
        gradient.Color = ColorSequence.new({
            ColorSequenceKeypoint.new(0,                                 theme.headerBand),
            ColorSequenceKeypoint.new(pct,                               theme.headerBand),
            ColorSequenceKeypoint.new(math.min(pct + 0.005, 1),          theme.bg),
            ColorSequenceKeypoint.new(1,                                 theme.bg),
        })
    end
    updateGradient()
    container:GetPropertyChangedSignal("AbsoluteSize"):Connect(updateGradient)

    -- Carbon-fiber texture over the panel so the near-black bodies stay distinct
    -- from each other and the world. Tiled, behind content (ZIndex 0), rounded
    -- so the rectangular tile doesn't poke past the chamfered edge. Skipped
    -- entirely when no texture asset is configured (theme.panelTexture == "").
    if theme.panelTexture and theme.panelTexture ~= "" then
        local carbon = Instance.new("ImageLabel")
        carbon.Name = "CarbonTexture"
        carbon.BackgroundTransparency = 1
        carbon.Image = theme.panelTexture
        carbon.ScaleType = Enum.ScaleType.Tile
        carbon.TileSize = UDim2.fromOffset(theme.panelTextureTile or 96, theme.panelTextureTile or 96)
        carbon.ImageColor3 = theme.panelTextureTint or Color3.new(1, 1, 1)
        carbon.ImageTransparency = theme.panelTextureTransparency or 0.85
        -- Cover the full panel, countering the container's UIPadding (like headerHost).
        carbon.Size = UDim2.new(1, 12, 1, HEADER_H + CHAMFER + 4)
        carbon.Position = UDim2.fromOffset(-6, -HEADER_H)
        carbon.ZIndex = 0
        carbon.Parent = container
        local cc = Instance.new("UICorner", carbon)
        cc.CornerRadius = UDim.new(0, CHAMFER)
    end

    -- Header text sits over the accent band. Positioned in the unpadded
    -- top region (0 .. HEADER_H) so it doesn't get shoved by UIPadding.
    local headerText = Instance.new("TextLabel")
    headerText.Name = "HeaderText"
    headerText.Size = UDim2.new(1, 0, 0, HEADER_H)
    headerText.Position = UDim2.fromOffset(0, 0)
    headerText.AnchorPoint = Vector2.new(0, 0)
    headerText.BackgroundTransparency = 1
    headerText.Text = name
    headerText.TextColor3 = theme.fg
    headerText.Font = theme.fontBold
    headerText.TextSize = 13
    headerText.TextXAlignment = Enum.TextXAlignment.Center
    headerText.TextYAlignment = Enum.TextYAlignment.Center
    headerText.ZIndex = 5
    -- IMPORTANT: UIPadding shifts ALL children by default. Parent the header
    -- text under a child Frame that bypasses the padding by anchoring outside
    -- the padded area.
    local headerHost = Instance.new("Frame")
    headerHost.Size = UDim2.new(1, 12, 0, HEADER_H)        -- +12 to undo the -6 left + -6 right padding
    headerHost.Position = UDim2.fromOffset(-6, -HEADER_H)   -- undo PaddingLeft (-6) and PaddingTop (-HEADER_H)
    headerHost.BackgroundTransparency = 1
    headerHost.ZIndex = 4
    headerHost.Parent = container
    headerText.Parent = headerHost

    local dragHandle = Instance.new("TextButton")
    dragHandle.Size = UDim2.fromScale(1, 1)
    dragHandle.BackgroundTransparency = 1
    dragHandle.Text = ""
    dragHandle.AutoButtonColor = false
    dragHandle.ZIndex = 8
    dragHandle.Parent = headerHost

    -- Features: stacked inside the padded body area. UIListLayout owns the
    -- height; AutomaticSize on the container propagates up.
    local features = Instance.new("ScrollingFrame")
    features.Name = "Features"
    features.Size = UDim2.new(1, 0, 0, 0)                  -- height set by fitFeatures()
    features.AutomaticCanvasSize = Enum.AutomaticSize.Y    -- canvas tracks content
    features.CanvasSize = UDim2.new(0, 0, 0, 0)
    features.BackgroundTransparency = 1
    features.BorderSizePixel = 0
    features.ScrollingDirection = Enum.ScrollingDirection.Y
    features.ScrollBarThickness = 4
    features.ScrollBarImageColor3 = theme.accent
    features.Parent = container

    local featuresList = Instance.new("UIListLayout", features)
    featuresList.SortOrder = Enum.SortOrder.LayoutOrder
    featuresList.Padding = UDim.new(0, 1)

    -- Body height = content height, capped to the viewport so a tall panel scrolls
    -- instead of running off-screen. (AutomaticSize on a ScrollingFrame fights
    -- AutomaticCanvasSize and never actually scrolls -- size from the layout's
    -- content height instead, and only enable scrolling once it overflows.)
    local vph = (workspace.CurrentCamera and workspace.CurrentCamera.ViewportSize.Y) or 720
    local capH = math.max(160, vph - baseTopY() - 90)
    local function fitFeatures()
        local h = featuresList.AbsoluteContentSize.Y
        features.Size = UDim2.new(1, 0, 0, math.min(h, capH))
        features.ScrollingEnabled = h > capH
    end
    featuresList:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(fitFeatures)
    fitFeatures()

    -- Drag
    do
        local dragging, dragStart, startPos = false, nil, nil
        dragHandle.InputBegan:Connect(function(input)
            if input.UserInputType == Enum.UserInputType.MouseButton1
               or input.UserInputType == Enum.UserInputType.Touch then
                dragging  = true
                dragStart = input.Position
                startPos  = container.Position
            end
        end)
        dragConns[#dragConns + 1] = UIS.InputChanged:Connect(function(input)
            if not dragging then return end
            if input.UserInputType == Enum.UserInputType.MouseMovement
               or input.UserInputType == Enum.UserInputType.Touch then
                local delta = input.Position - dragStart
                -- Snap the DELTA so the grid starts where the panel was grabbed.
                local nx = startPos.X.Offset + snap(delta.X)
                local ny = startPos.Y.Offset + snap(delta.Y)
                -- Clamp so the panel can't be dragged off-screen.
                local pSz = container.Parent.AbsoluteSize
                local sSz = container.AbsoluteSize
                nx = math.clamp(nx, 0, math.max(0, pSz.X - sSz.X))
                ny = math.clamp(ny, 0, math.max(0, pSz.Y - sSz.Y))
                container.Position = UDim2.new(startPos.X.Scale, nx, startPos.Y.Scale, ny)
            end
        end)
        dragConns[#dragConns + 1] = UIS.InputEnded:Connect(function(input)
            if input.UserInputType == Enum.UserInputType.MouseButton1
               or input.UserInputType == Enum.UserInputType.Touch then
                if dragging then
                    dragging = false
                    -- A real drag (not just a click) pins this container: save
                    -- the spot so it reopens here, and free its auto-slot.
                    local p = container.Position
                    if startPos and (p.X.Offset ~= startPos.X.Offset
                                     or p.Y.Offset ~= startPos.Y.Offset) then
                        self.userMoved = true
                        self:_freeSlot()
                        persist.set(posKey(name), { x = p.X.Offset, y = p.Y.Offset })
                    end
                end
            end
        end)
    end

    self.root     = container
    self.features = features
    self.name     = name
    self._count   = 0

    -- Restore a user-dragged position if we saved one before; otherwise the
    -- navigator auto-places us next to it on open.
    local sp = persist.get(posKey(name))
    if type(sp) == "table" and tonumber(sp.x) and tonumber(sp.y) then
        self.userMoved = true
        container.Position = UDim2.fromOffset(tonumber(sp.x), tonumber(sp.y))
    end

    -- Start hidden when the navigator is driving visibility; it flips us on.
    self.visible = not Container.startHidden
    container.Visible = self.visible
    instances[#instances + 1] = self

    return self
end

function Container:isVisible()
    return self.visible ~= false
end

-- Place an auto-positioned (not user-moved) container in the first free slot to
-- the right of the navigator. No-op if the user dragged it (honor the saved
-- spot) or it already holds a slot.
function Container:_placeIfNeeded()
    if self.userMoved or self.slot ~= nil then return end
    local k = 0
    while slots[k] ~= nil do k = k + 1 end
    slots[k] = self
    self.slot = k
    local w, gap = theme.containerWidth, theme.containerGap
    local baseX, baseY = 16 + w + gap, baseTopY()
    if navRef and navRef.root then
        baseX = navRef.root.Position.X.Offset + w + gap
        baseY = navRef.root.Position.Y.Offset
    end
    self.root.Position = UDim2.fromOffset(baseX + k * (w + gap), baseY)
end

function Container:_freeSlot()
    if self.slot ~= nil then slots[self.slot] = nil; self.slot = nil end
end

function Container:setVisible(v)
    v = v and true or false
    self.visible = v
    self.root.Visible = v
    if v then self:_placeIfNeeded() else self:_freeSlot() end
    persist.set(openKey(self.name), v)
    if self._onVis then self._onVis(v) end
end

function Container.list()
    return instances
end

function Container:add(featureRoot)
    self._count = self._count + 1
    featureRoot.LayoutOrder = self._count
    featureRoot.Parent = self.features
    return self
end

-- The single "menu" that opens/closes every other container (Wurst-style).
-- Build it BEFORE the feature containers (so it's leftmost + stays visible),
-- then call nav.populate() AFTER all modules register so it lists every menu.
function Container.buildNavigator(parent, title)
    local nav = Container.new(parent, title or "Pantheon")
    nav.isNav = true
    navRef = nav

    function nav.populate()
        for _, c in ipairs(instances) do
            if c ~= nav and not c.isNav then
                local row = Instance.new("TextButton")
                row.Name = "Nav_" .. tostring(c.name)
                row.Size = UDim2.new(1, 0, 0, 26)
                row.BackgroundColor3 = theme.bgAlt
                row.AutoButtonColor = true
                row.BorderSizePixel = 0
                row.Font = theme.font
                row.TextSize = 12
                row.TextColor3 = theme.fg
                row.TextXAlignment = Enum.TextXAlignment.Left
                row.Text = "  " .. tostring(c.name)

                local pill = Instance.new("TextLabel")
                pill.Size = UDim2.fromOffset(42, 16)
                pill.Position = UDim2.new(1, -46, 0.5, -8)
                pill.BorderSizePixel = 0
                pill.Font = theme.fontBold
                pill.TextSize = 10
                pill.TextColor3 = theme.fg
                pill.Parent = row

                local function refresh()
                    local on = c:isVisible()
                    pill.Text = on and "ON" or "OFF"
                    pill.BackgroundColor3 = on and theme.on or theme.off
                end
                c._onVis = refresh
                row.MouseButton1Click:Connect(function()
                    c:setVisible(not c:isVisible())
                end)
                refresh()
                nav:add(row)
                -- Restore the saved open/closed state (default closed) so the
                -- user's layout comes back on reload.
                c:setVisible(persist.get(openKey(c.name), false) == true)
            end
        end
    end

    return nav
end

-- Disconnect every container's global drag handlers. Called from Window.destroy()
-- (the UI teardown entry point) so re-execute doesn't stack listeners. Also reset
-- nextIndex so a fresh boot lays containers out from the left again.
function Container.cleanup()
    for _, c in ipairs(dragConns) do pcall(function() c:Disconnect() end) end
    dragConns = {}
    nextIndex = 0
    instances = {}
    slots     = {}
    navRef    = nil
    Container.startHidden = false
end

return Container
end

_MODULES["ui.feature"] = function()
-- Feature row: [name] [hex ON/OFF indicator] [hex info] [hex cog].
-- Cog click expands an inline settings panel below the row.
-- "i" click expands a description label below the row (separate from settings).
-- All three buttons are real hex shapes (built via ui/hex).
--
-- Dependency cascading:
-- Each feature.declare({ ... }) can take a `dependencies = { "id", ... }`
-- list. When the feature is enabled, every dependency is auto-enabled first.
-- When the feature is disabled, every other feature that lists it as a
-- dependency is auto-disabled too (so e.g. turning off Target Select turns
-- off Lock-On / Highlight / Swap Target instead of leaving them stuck "on"
-- with no target source).
--
-- Per-game persistence ([[core.persist]]):
-- Saved values override declared defaults on boot. Each setting persists
-- under "<id>.<slug-or-key>"; the feature row's master toggle and keybind
-- persist under "<id>.enabled" / "<id>.keybind". Nested keybinds in the
-- settings array persist under "<opt.id>.keybind" (so e.g. the rotation_lock
-- key declared inside Lock-On's panel survives reloads keyed to its own id).

local theme      = require("ui.theme")
local hex        = require("ui.hex")
local keybinds   = require("core.keybinds")
local components = require("ui.components")
local persist    = require("core.persist")

local Feature = {}

local nextId     = 0
local registry   = {} -- [id] = { setEnabled, getEnabled }
local dependents = {} -- [depId] = { dependentId, ... }

-- Resolve a persisted value against a declared default. A saved setting counts
-- even when its value is the literal `false` an OFF toggle writes, so we test
-- for nil explicitly. The old `(saved ~= nil) and saved or default` idiom
-- collapsed a saved `false` back to a truthy default -- e.g. a default=true
-- toggle (Battlegrounds-safe, Camera Lock, Auto prediction, ...) turned OFF
-- sprang back ON on every reload, which read as "settings don't save".
local function resolveSaved(saved, default)
    if saved ~= nil then return saved end
    return default
end

local function hexButton(parent, w, h, color, text, font, textSize)
    local host = Instance.new("Frame")
    host.Size = UDim2.fromOffset(w, h)
    host.BackgroundTransparency = 1
    host.Parent = parent

    local hexFrame = hex.build(host, w, h, color, 2)

    local label = Instance.new("TextLabel")
    label.Size = UDim2.fromScale(1, 1)
    label.BackgroundTransparency = 1
    label.Text = text or ""
    label.TextColor3 = theme.fg
    label.Font = font or theme.font
    label.TextSize = textSize or 12
    label.ZIndex = 5
    label.Parent = host

    local btn = Instance.new("TextButton")
    btn.Size = UDim2.fromScale(1, 1)
    btn.BackgroundTransparency = 1
    btn.Text = ""
    btn.AutoButtonColor = false
    btn.ZIndex = 6
    btn.Parent = host

    return host, hexFrame, label, btn
end

function Feature.declare(def)
    nextId = nextId + 1
    local id = def.id or ("feature_" .. nextId)
    local hasDesc = def.description and #def.description > 0

    -- Register reverse-dep edges so the disable cascade works.
    if def.dependencies then
        for _, depId in ipairs(def.dependencies) do
            dependents[depId] = dependents[depId] or {}
            table.insert(dependents[depId], id)
        end
    end

    local root = Instance.new("Frame")
    root.Name = "Feature_" .. id
    root.Size = UDim2.new(1, 0, 0, 0)
    root.AutomaticSize = Enum.AutomaticSize.Y
    root.BackgroundTransparency = 1

    local rootList = Instance.new("UIListLayout", root)
    rootList.SortOrder = Enum.SortOrder.LayoutOrder

    local row = Instance.new("Frame")
    row.Size = UDim2.new(1, 0, 0, theme.featureHeight)
    row.BackgroundColor3 = theme.bgAlt
    row.BorderSizePixel = 0
    row.LayoutOrder = 1
    row.Parent = root

    local nameLabel = Instance.new("TextLabel")
    nameLabel.Position = UDim2.fromOffset(8, 0)
    nameLabel.Size = UDim2.new(1, hasDesc and -112 or -84, 1, 0)
    nameLabel.BackgroundTransparency = 1
    nameLabel.Text = def.name or "Feature"
    nameLabel.TextColor3 = theme.fgDim
    nameLabel.Font = theme.font
    nameLabel.TextSize = 13
    nameLabel.TextXAlignment = Enum.TextXAlignment.Left
    nameLabel.Parent = row

    local indicatorHost, indicatorHex, indicatorLabel, indicatorBtn =
        hexButton(row, 40, 22, theme.off, "OFF", theme.fontBold, 10)
    indicatorHost.Position = UDim2.new(1, hasDesc and -104 or -76, 0.5, 0)
    indicatorHost.AnchorPoint = Vector2.new(0, 0.5)

    local infoHex, infoBtn
    if hasDesc then
        local _, hx, _, b = hexButton(row, 22, 18, theme.bgDark, "i", theme.fontBold, 12)
        local infoHost = b.Parent
        infoHost.Position = UDim2.new(1, -54, 0.5, 0)
        infoHost.AnchorPoint = Vector2.new(0, 0.5)
        infoHex, infoBtn = hx, b
    end

    local _, cogHex, _, cogBtn =
        hexButton(row, 22, 18, theme.bgDark, "\u{2699}", theme.font, 14)
    local cogHost = cogBtn.Parent
    cogHost.Position = UDim2.new(1, -28, 0.5, 0)
    cogHost.AnchorPoint = Vector2.new(0, 0.5)

    local desc
    if hasDesc then
        desc = Instance.new("TextLabel")
        desc.Size = UDim2.new(1, 0, 0, 0)
        desc.AutomaticSize = Enum.AutomaticSize.Y
        desc.BackgroundColor3 = theme.bgDark
        desc.BorderSizePixel = 0
        desc.Text = def.description
        desc.TextColor3 = theme.fgDim
        desc.Font = theme.font
        desc.TextSize = 11
        desc.TextWrapped = true
        desc.TextXAlignment = Enum.TextXAlignment.Left
        desc.TextYAlignment = Enum.TextYAlignment.Top
        desc.Visible = false
        desc.LayoutOrder = 2
        desc.Parent = root

        local pad = Instance.new("UIPadding", desc)
        pad.PaddingTop    = UDim.new(0, 6)
        pad.PaddingBottom = UDim.new(0, 6)
        pad.PaddingLeft   = UDim.new(0, 8)
        pad.PaddingRight  = UDim.new(0, 8)
    end

    local panel = Instance.new("Frame")
    panel.Size = UDim2.new(1, 0, 0, 0)
    panel.AutomaticSize = Enum.AutomaticSize.Y
    panel.BackgroundColor3 = theme.bgDark
    panel.BorderSizePixel = 0
    panel.Visible = false
    panel.LayoutOrder = 3
    panel.Parent = root

    local panelPad = Instance.new("UIPadding", panel)
    panelPad.PaddingTop    = UDim.new(0, 4)
    panelPad.PaddingBottom = UDim.new(0, 4)
    panelPad.PaddingLeft   = UDim.new(0, 6)
    panelPad.PaddingRight  = UDim.new(0, 6)

    local panelList = Instance.new("UIListLayout", panel)
    panelList.Padding   = UDim.new(0, 4)
    panelList.SortOrder = Enum.SortOrder.LayoutOrder

    -- enabled starts FALSE; the initial value (saved or declared default) is
    -- applied at the bottom of declare(), after the registry entry exists,
    -- so it can route through setEnabled without losing the dependency cascade.
    local enabled = false

    local function applyToggle()
        hex.setColor(indicatorHex, enabled and theme.on or theme.off)
        indicatorLabel.Text = enabled and "ON" or "OFF"
        nameLabel.TextColor3 = enabled and theme.fg or theme.fgDim
        if def.onToggle then
            local ok, err = pcall(def.onToggle, enabled)
            if not ok then warn("[Pantheon] feature onToggle error:", err) end
        end
    end

    -- Suppresses the persist write during the boot-time initial-state apply
    -- so loading the saved value doesn't immediately re-write the same value
    -- back to disk.
    local suppressPersist = false

    local function setEnabled(v)
        v = v and true or false
        if enabled == v then return end

        -- Enable cascade: turn on every dependency before turning on us.
        if v and def.dependencies then
            for _, depId in ipairs(def.dependencies) do
                local dep = registry[depId]
                if dep and not dep.getEnabled() then
                    dep.setEnabled(true)
                end
            end
        end

        enabled = v
        applyToggle()
        if not suppressPersist then
            persist.set(id .. ".enabled", v)
        end

        -- Disable cascade: anyone who lists us as a dependency goes off too.
        if not v and dependents[id] then
            for _, depId in ipairs(dependents[id]) do
                local dep = registry[depId]
                if dep and dep.getEnabled() then
                    dep.setEnabled(false)
                end
            end
        end
    end

    local function toggleEnabled() setEnabled(not enabled) end

    indicatorBtn.MouseButton1Click:Connect(toggleEnabled)

    local panelOpen = false
    cogBtn.MouseButton1Click:Connect(function()
        panelOpen = not panelOpen
        panel.Visible = panelOpen
        hex.setColor(cogHex, panelOpen and theme.accent or theme.bgDark)
    end)

    if infoBtn then
        local descOpen = false
        infoBtn.MouseButton1Click:Connect(function()
            descOpen = not descOpen
            desc.Visible = descOpen
            hex.setColor(infoHex, descOpen and theme.accent or theme.bgDark)
        end)
    end

    local function onPress()
        if def.onKey then
            local ok, err = pcall(def.onKey)
            if not ok then warn("[Pantheon] feature onKey error:", err) end
        else
            toggleEnabled()
        end
    end
    local function onRelease()
        if def.onKeyRelease then
            local ok, err = pcall(def.onKeyRelease)
            if not ok then warn("[Pantheon] feature onKeyRelease error:", err) end
        end
    end

    -- Master keybind: saved value overrides declared default.
    do
        local savedKey = persist.stringToKey(persist.get(id .. ".keybind", nil))
        local effectiveKey = savedKey or def.defaultKey
        if effectiveKey and effectiveKey ~= Enum.KeyCode.Unknown then
            keybinds.set(id, effectiveKey, onPress, onRelease)
        end
        components.KeybindSetter(panel, {
            label    = "Keybind",
            default  = effectiveKey,
            onChange = function(newKey)
                keybinds.set(id, newKey, onPress, onRelease)
                persist.set(id .. ".keybind", persist.keyToString(newKey))
            end,
        })
    end

    if def.settings and #def.settings > 0 then
        local sep = Instance.new("Frame")
        sep.Size = UDim2.new(1, 0, 0, 1)
        sep.BackgroundColor3 = theme.border
        sep.BorderSizePixel = 0
        sep.Parent = panel

        for _, opt in ipairs(def.settings) do
            -- Settings persist under "<id>.<opt.key or slug(opt.name)>".
            -- Nested keybinds use "<opt.id>.keybind" instead so their saved
            -- value matches the standalone-feature key format.
            local optSlug = opt.key or persist.slug(opt.name or "?")
            local saveKey = id .. "." .. optSlug

            if opt.type == "section" then
                components.Section(panel, opt.name)

            elseif opt.type == "toggle" then
                local saved = persist.get(saveKey)
                local effective = resolveSaved(saved, opt.default)
                components.Toggle(panel, {
                    text     = opt.name,
                    default  = effective,
                    onChange = function(v)
                        persist.set(saveKey, v)
                        if opt.onChange then opt.onChange(v) end
                    end,
                })
                -- Fire onChange once with the effective value so the impl
                -- side picks up the persisted (or declared) state instead of
                -- relying on whatever the impl's own initial state happened
                -- to be in [[modules.aim.state]].
                if opt.onChange then
                    local ok, err = pcall(opt.onChange, effective)
                    if not ok then warn("[Pantheon] setting init error:", err) end
                end

            elseif opt.type == "slider" then
                local saved = persist.get(saveKey)
                local effective = resolveSaved(saved, opt.default)
                local sh = components.Slider(panel, {
                    text     = opt.name,
                    min      = opt.min, max = opt.max, step = opt.step,
                    default  = effective,
                    onChange = function(v)
                        persist.set(saveKey, v)
                        if opt.onChange then opt.onChange(v) end
                    end,
                })
                if opt.onCreate then opt.onCreate(sh) end
                if opt.onChange then
                    local ok, err = pcall(opt.onChange, effective)
                    if not ok then warn("[Pantheon] setting init error:", err) end
                end

            elseif opt.type == "dropdown" then
                local saved     = persist.get(saveKey)
                local effective = resolveSaved(saved, opt.default)
                local dh = components.Dropdown(panel, {
                    label    = opt.name,
                    options  = opt.options,
                    default  = effective,
                    onChange = function(v)
                        persist.set(saveKey, v)
                        if opt.onChange then opt.onChange(v) end
                    end,
                })
                if opt.onCreate then opt.onCreate(dh) end
                if opt.onChange then
                    local ok, err = pcall(opt.onChange, effective)
                    if not ok then warn("[Pantheon] setting init error:", err) end
                end

            elseif opt.type == "textbox" then
                local tb = components.TextBox(panel, {
                    label       = opt.name,
                    placeholder = opt.placeholder,
                    default     = resolveSaved(persist.get(saveKey), opt.default),
                    onChange    = function(v)
                        persist.set(saveKey, v)
                        if opt.onChange then opt.onChange(v) end
                    end,
                })
                if opt.onCreate then opt.onCreate(tb) end

            elseif opt.type == "button" then
                components.Button(panel, {
                    text    = opt.name,
                    onClick = opt.onClick,
                })

            elseif opt.type == "keybind" then
                local persistKey  = opt.id and (opt.id .. ".keybind") or saveKey
                local savedNested = persist.stringToKey(persist.get(persistKey, nil))
                local effectiveK  = savedNested or opt.default
                if opt.id and effectiveK and effectiveK ~= Enum.KeyCode.Unknown then
                    keybinds.set(opt.id, effectiveK, opt.onPress, opt.onRelease)
                end
                components.KeybindSetter(panel, {
                    label    = opt.name or "Key",
                    default  = effectiveK,
                    onChange = function(newKey)
                        if opt.id then
                            keybinds.set(opt.id, newKey, opt.onPress, opt.onRelease)
                        end
                        persist.set(persistKey, persist.keyToString(newKey))
                    end,
                })
            end
        end
    end

    registry[id] = {
        setEnabled = setEnabled,
        getEnabled = function() return enabled end,
        def        = def,
    }

    -- Apply initial value LAST, after registry[id] exists so dependents that
    -- ran their cascade earlier (i.e. when WE were the dependency) already
    -- saw us. The cascade itself is suppressed for the initial value: we
    -- trust the saved snapshot to already be internally consistent, and
    -- don't want a default=true child to drag a default=false parent on.
    do
        local saved = persist.get(id .. ".enabled")
        local initial = resolveSaved(saved, def.default == true)
        if initial then
            -- Direct assign + applyToggle (no setEnabled) so we don't run
            -- the dependency cascade at boot. Pre-existing behavior, kept.
            enabled = true
            suppressPersist = true
            applyToggle()
            suppressPersist = false
        else
            applyToggle()
        end
    end

    return {
        root       = root,
        id         = id,
        setEnabled = setEnabled,
        getEnabled = function() return enabled end,
    }
end

-- ---- Invoke-by-id API (used by the Tech Builder to call features as steps) ----
-- Besides declared features, modules can register "invokables": toggleable things
-- that aren't standalone feature rows (e.g. Lock-On's Rotation Lock / Camera Lock
-- sub-toggles) so the Tech Builder's "Use" step can call them too.
local invokables = {}   -- [id] = { name, get, set }

function Feature.addInvokable(def)
    if def and def.id then
        invokables[def.id] = { name = def.name or def.id, get = def.get, set = def.set }
    end
end

function Feature.setEnabled(id, v)
    local e = registry[id]
    if e then e.setEnabled(v); return end
    local iv = invokables[id]
    if iv and iv.set then iv.set(v and true or false) end
end

function Feature.getEnabled(id)
    local e = registry[id]
    if e then return e.getEnabled() end
    local iv = invokables[id]
    return (iv and iv.get and iv.get()) and true or false
end

-- Fire a feature's key action (its onKey), or toggle the feature / invokable.
function Feature.fire(id)
    local e = registry[id]
    if e then
        if e.def and e.def.onKey then pcall(e.def.onKey) else e.setEnabled(not e.getEnabled()) end
        return
    end
    local iv = invokables[id]
    if iv and iv.set then iv.set(not (iv.get and iv.get())) end
end

-- List declared features + invokables as { {id=, name=}, ... } for the Tech Builder.
function Feature.all()
    local out = {}
    for id, e in pairs(registry) do out[#out + 1] = { id = id, name = (e.def and e.def.name) or id } end
    for id, iv in pairs(invokables) do out[#out + 1] = { id = id, name = iv.name } end
    return out
end

return Feature
end

_MODULES["ui.notify"] = function()
-- Stacked corner toasts. Stateless caller API.

local env   = require("core.env")
local theme = require("ui.theme")

local notify = {}
local container

local function ensureContainer()
    if container and container.Parent then return container end
    local sg = Instance.new("ScreenGui")
    sg.Name = "PantheonNotify"
    sg.IgnoreGuiInset = true
    sg.ResetOnSpawn = false
    sg.Parent = env.guiParent()
    env.protectGui(sg)

    local f = Instance.new("Frame")
    f.AnchorPoint = Vector2.new(1, 1)
    f.Position = UDim2.new(1, -16, 1, -16)
    f.Size = UDim2.new(0, 300, 1, -32)
    f.BackgroundTransparency = 1
    f.Parent = sg

    local list = Instance.new("UIListLayout", f)
    list.VerticalAlignment = Enum.VerticalAlignment.Bottom
    list.SortOrder = Enum.SortOrder.LayoutOrder
    list.Padding = UDim.new(0, 6)

    container = f
    return f
end

local function toast(text, duration, color)
    duration = duration or 3
    local parent = ensureContainer()

    local frame = Instance.new("Frame")
    frame.Size = UDim2.new(1, 0, 0, 0)
    frame.AutomaticSize = Enum.AutomaticSize.Y
    frame.BackgroundColor3 = theme.bgAlt
    frame.BorderSizePixel = 0
    frame.Parent = parent
    Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 6)

    local accent = Instance.new("Frame")
    accent.Size = UDim2.new(0, 3, 1, 0)
    accent.BackgroundColor3 = color or theme.accent
    accent.BorderSizePixel = 0
    accent.Parent = frame

    local label = Instance.new("TextLabel")
    label.Size = UDim2.new(1, -20, 0, 0)
    label.Position = UDim2.fromOffset(12, 0)
    label.AutomaticSize = Enum.AutomaticSize.Y
    label.BackgroundTransparency = 1
    label.Text = text or ""
    label.TextColor3 = theme.fg
    label.Font = theme.font
    label.TextSize = 13
    label.TextWrapped = true
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Parent = frame

    local pad = Instance.new("UIPadding", frame)
    pad.PaddingTop = UDim.new(0, 8)
    pad.PaddingBottom = UDim.new(0, 8)

    task.delay(duration, function()
        if frame and frame.Parent then frame:Destroy() end
    end)
end

function notify.info(text, duration)    toast(text, duration, theme.accent)  end
function notify.success(text, duration) toast(text, duration, theme.success) end
function notify.warn(text, duration)    toast(text, duration, theme.danger)  end

notify.toast = toast

function notify.destroy()
    if container and container.Parent then
        local sg = container:FindFirstAncestorWhichIsA("ScreenGui")
        if sg then pcall(function() sg:Destroy() end) end
    end
    container = nil
end

return notify
end

_MODULES["games.registry"] = function()
-- Per-game module registry. Keys are tostring(id), where id is either a PlaceId
-- or a GameId (universe id). A game module is a table with a .register() function.
--
-- Matching by GameId is the robust option: a game can have many PlaceIds (lobby,
-- combat, VIP servers) that all share ONE GameId, so registering under the GameId
-- catches every place. registry.current() checks both game.PlaceId and game.GameId.

local games = {}
local registry = {}

-- ids may be a single id or a list of ids (place ids and/or the game id).
function registry.register(ids, mod)
    if type(ids) == "table" then
        for _, id in ipairs(ids) do games[tostring(id)] = mod end
    else
        games[tostring(ids)] = mod
    end
end

function registry.current()
    return games[tostring(game.PlaceId)] or games[tostring(game.GameId)]
end

function registry.all()
    return games
end

return registry
end

_MODULES["modules.aim.state"] = function()
-- Shared state for the aim-assist subsystem.
-- Target Select writes the target; Lock-On (camera) and Rotation Lock read it.

local Signal = require("core.signal")

local state = {
    -- Target (set by Target Select, read by Lock-On / Rotation Lock / Highlight)
    target              = nil,
    target_type         = nil, -- "player" or "npc"

    -- Target Select
    target_select_enabled = false,
    -- Bot Mode: when true, Target Select also considers NPCs / mobs (any model
    -- with a Humanoid that isn't a player), targeted as target_type == "npc".
    botMode               = false,

    -- Targeting filters
    realisticEnabled       = false,
    checkHealthEnabled     = true,
    visibilityCheckEnabled = false,
    rangeLimit             = 0,    -- 0 = infinite

    -- Lock-On master + sub-toggles
    lockon_enabled       = false,
    cameraLockEnabled    = true,   -- camera force on/off
    rotationLockEnabled  = false,  -- rotation lock on/off (was lockonPlusEnabled)
    bgSafeEnabled        = true,   -- battlegrounds-safe modifier on rotation lock

    -- Resistance (modifies camera lock)
    resistance_enabled   = false,
    resistance_threshold = 5,
    resistance_strength  = 0.5,

    -- Highlight
    highlightEnabled       = true,
    highlightSecondEnabled = true,    -- yellow outline on the swap target (next-best) by default
    targetInfoEnabled      = true,    -- healthbar + username billboard over highlighted targets
    selfFadeEnabled        = false,

    -- Shiftlock
    shiftlock_enabled = false,
    shiftlock_active  = false,
    killForeign       = true,
    -- Mirror mode: FOLLOW the game's own shiftlock (shiftlock_active tracks its
    -- cursor lock) and write nothing ourselves, so the two never overlap. Turn
    -- on per-game in games that ship their own shiftlock (e.g. JJS).
    shiftlockMirror   = false,
    -- When true, the locked-mode rotation pass skips root.CFrame writes when
    -- we're welded to another character (grab moves) so we don't drag them
    -- around. Default OFF so we match normal-player behavior in games like
    -- JJS where strikes weld the victim but the game doesn't actually lock
    -- rotation -- the PlatformStand / Ragdoll / Physics / Dead state checks
    -- already handle the cases where the game DOES lock you (bleedout, etc).
    -- Turn ON in Battlegrounds-style games where the welded victim follows
    -- your rotation and that's not what you want.
    weldSafetyEnabled = false,
    -- When true AND Pantheon shiftlock is OFF, the pin pass + hook yield so
    -- the game's base shiftlock (custom in-game script and/or Roblox's
    -- vanilla MouseLockController) can drive the cursor. Pantheon still
    -- fully owns cursor state while its own shiftlock is on. Default OFF
    -- because the default expectation is "Pantheon shiftlock off = no
    -- shiftlock"; turn ON per-game when you want the game's shiftlock as
    -- a fallback.
    allowGameShiftlock = false,

    -- Swap
    swap_enabled = true,

    -- Tech Builder: while a tech is driving the camera/body (a Look/Rotate step),
    -- Lock-On (camera) and Rotation Lock (body) yield so they don't fight it.
    techCamOverride  = false,
    techBodyOverride = false,
    -- Tech Builder: a tech with "Ignore welds" set turns this on while it runs, so
    -- isGrabbing() reports false and Lock-On/Rotation stay active even when welded.
    techIgnoreWelds  = false,

    -- Misc
    lockHeightOffset = 0,
    friendlies       = {},

    -- Aim-assist prediction window. lockon's camera tracking and rotation_lock's
    -- body facing both add (target.AssemblyLinearVelocity * predictionTime) to
    -- the target's read position so the aim leads them. Without this we sit on
    -- the last network-replicated position, which feels "insanely inaccurate"
    -- on fast-moving enemies because they've already moved by the time we
    -- write the camera/body CFrame. 0 = no prediction; 0.1 leads ~5 studs
    -- against a 50-stud/s sprinter, which is closer to the typical ping
    -- compensation a battlegrounds-style game needs.
    predictionTime = 0.1,

    -- Velocity-adaptive prediction. When predictionAuto is on, getLeadTime()
    -- derives the lead from the TARGET'S TANGENTIAL VELOCITY RELATIVE TO YOU
    -- (the orbit/strafe component the camera must rotate through). Static
    -- targets get 0 lead; a player side-dashing close around you pumps the
    -- lead via the angular-velocity term (close + fast = high angular
    -- rate, the regime where lock-on+ alone falls behind). predictionTime
    -- (slider) is the manual fallback when auto is off.
    predictionAuto      = true,
    predictionFactor    = 0.003, -- seconds of lead per stud/sec of tangential speed
    predictionCap       = 0.3,   -- hard cap (seconds) on the lead
    -- Deadzone: target must be moving faster than this (stud/s, TANGENTIAL
    -- speed = perpendicular orbit/strafe relative to you) before auto
    -- prediction kicks in. Below the threshold lead = 0 -- lock-on+ alone
    -- handles slow movement and casual approach without prediction churn.
    -- 20 stud/s defaults below sprint (~30 stud/s) but above walk (~16),
    -- so casual movement skips prediction and aggressive movement triggers
    -- it. Slider in the Lock-On cog persists it.
    predictionThreshold = 20,

    -- Signals
    onTargetChanged = Signal.new(),
}

function state.setTarget(target, type_)
    if state.target ~= target then
        state.target = target
        state.target_type = type_
        state.onTargetChanged:Fire(target, type_)
    end
end

function state.isFriendly(plr)
    -- Guard with IsA: an NPC target (a Model) reaches here via Highlight's
    -- friendly check, and reading `.UserId` off a Model throws ("not a valid
    -- member of Model"). Only players can ever be friendlies anyway.
    if not plr or not plr:IsA("Player") then return false end
    return state.friendlies[plr.UserId] == true
end

-- True when `character` is rigidly attached (Weld / WeldConstraint / Motor6D)
-- to another *player's* character -- i.e. a grab move has stuck you to them.
-- Used by shiftlock's rotation drag-protect (gated by weldSafetyEnabled) and
-- lockon's camera suspension.
--
-- Specifically uses Players:GetPlayerFromCharacter, not just "any model
-- with a Humanoid". The any-humanoid check was tripping permanently in
-- games where the local character is welded to NPCs / dummies / mounts /
-- vehicles, leaving lockon paused forever. Only welds to actual player
-- characters should count for grab-style suspension.
local PlayersService = game:GetService("Players")
local StatsService   = game:GetService("Stats")

-- Effective aim lead (seconds), shared by lockon (camera) and rotation_lock
-- (body). Velocity-adaptive when predictionAuto: takes the TARGET'S TANGENTIAL
-- velocity relative to YOU (perpendicular to the line from your root to
-- theirs -- the "side-dash / orbit" component the camera must chase) and
-- the corresponding ANGULAR velocity from your POV (= tangential / distance),
-- and uses the larger of the two leads.
--
-- Why both:
--  * Linear (tangential) lead handles a fast target at any range -- 60 stud/s
--    strafe at 25 studs needs the same lead as 60 stud/s at 5 studs at the
--    LINEAR scale, but in practice the close one is harder to track.
--  * Angular lead handles "stick close to me" -- a skilled player orbiting at
--    moderate linear speed but tiny radius (1-3 studs) has very high angular
--    rate, the regime where lock-on+ rotation alone visibly falls behind.
-- Taking max() lets each formula dominate where it should.
--
-- A stationary target -- or one moving radially toward/away from you -- gets
-- zero lead by construction (no orbit/strafe to chase). Ping-based lead was
-- the V0 formula but user wanted velocity-driven; the math here doesn't need
-- ping (replicated position lag on a stationary target is uninteresting).
local lastReadT, lastReadV = 0, 0
function state.getLeadTime()
    if not state.predictionAuto then return state.predictionTime or 0 end
    -- Cache the heavy property reads -- getLeadTime is called several times
    -- per frame and the same target position rarely changes between calls.
    local now = os.clock()
    if now - lastReadT < 0.03 then return lastReadV end
    lastReadT = now

    local LP = PlayersService.LocalPlayer
    local myChar = LP.Character
    local me = myChar and myChar:FindFirstChild("HumanoidRootPart")
    local t = state.target
    if not (me and t) then lastReadV = 0; return 0 end
    local targetChar = (state.target_type == "npc") and t or t.Character
    local targetRoot = targetChar and targetChar:FindFirstChild("HumanoidRootPart")
    if not targetRoot then lastReadV = 0; return 0 end

    local relVel = targetRoot.AssemblyLinearVelocity - me.AssemblyLinearVelocity
    local toTarget = targetRoot.Position - me.Position
    local distance = toTarget.Magnitude
    if distance < 0.5 then lastReadV = 0; return 0 end

    -- Strip the radial component (motion straight at/away from you), leaving
    -- only the tangential (orbit/strafe) part.
    local radialDir = toTarget.Unit
    local radialSpeed = relVel:Dot(radialDir)
    local tangentialSpeed = (relVel - radialDir * radialSpeed).Magnitude

    -- Deadzone: target moving slower than threshold? lock-on+ alone covers it;
    -- prediction would just add jitter on a stationary or casually-walking
    -- opponent. Returns 0 lead (= raw replicated position).
    local threshold = state.predictionThreshold or 20
    if tangentialSpeed < threshold then lastReadV = 0; return 0 end

    local factor      = state.predictionFactor or 0.003
    local linearLead  = tangentialSpeed * factor
    local angularLead = (tangentialSpeed / math.max(distance, 1)) * 0.05
    local lead = math.max(linearLead, angularLead)

    lead = math.clamp(lead, 0, state.predictionCap or 0.3)
    lastReadV = lead
    return lead
end

-- A part that belongs to a different *player's* character (not ours, and not an
-- NPC / dummy / mount). Hoisted to module scope (was a per-call closure) so
-- isGrabbing's ~20Hz polling doesn't reallocate two closures every call;
-- `character` is threaded through as a parameter.
local function foreignPlayerPart(p, character)
    if not p or not p.Parent then return false end
    if p:IsDescendantOf(character) then return false end
    local m = p:FindFirstAncestorOfClass("Model")
    return m ~= nil and m ~= character
        and PlayersService:GetPlayerFromCharacter(m) ~= nil
end

local function joinsToForeign(j, character)
    return (j:IsA("Weld") or j:IsA("WeldConstraint") or j:IsA("Motor6D"))
        and (foreignPlayerPart(j.Part0, character) or foreignPlayerPart(j.Part1, character))
end

function state.isWeldedToOther(character)
    if not character then return false end
    for _, d in ipairs(character:GetDescendants()) do
        if d:IsA("BasePart") then
            -- GetJoints() finds joints by their Part0/Part1 references no matter
            -- where the joint instance is *parented*. Grab moves frequently
            -- parent the weld on the VICTIM's character (or in workspace) so it
            -- replicates with them -- a walk that only inspects our own
            -- descendants misses those entirely, which is why we still dragged
            -- enemies around. Parent-agnostic lookup catches both sides.
            local ok, joints = pcall(function() return d:GetJoints() end)
            if ok and joints then
                for _, j in ipairs(joints) do
                    if joinsToForeign(j, character) then return true end
                end
            end
        elseif d:IsA("Weld") or d:IsA("WeldConstraint") or d:IsA("Motor6D") then
            -- Fallback: a weld instance parented inside our own character, in
            -- case GetJoints under-reports WeldConstraints on this executor.
            if joinsToForeign(d, character) then return true end
        end
    end
    return false
end

-- Cached "am I welded to another player right now" = a grab is happening (e.g.
-- JJS Decisive Strikes). 50ms cache so the rotation passes can cheaply ASK
-- without walking descendants every frame. Independent of weldSafetyEnabled:
-- that toggle decides what to DO with a grab; this just detects it. The rotation
-- passes use it to keep rotating THROUGH a grab (the game parks you in
-- PlatformStand/Physics during it, but you still want to aim).
-- "Am I grabbed by / grabbing another PLAYER right now" = a grab.
-- TRUE only when we're rigidly welded to ANY part of another player's character
-- (part-agnostic -- grabs use HRP<->HRP, arm<->leg, etc., confirmed via the grab
-- inspector). While true, the rotation passes write NOTHING to our body and
-- disable their AlignOrientation so we don't drag the welded player (attacker) or
-- glitch their grab of us (victim).
--
-- Deliberately does NOT count a foreign BodyGyro/BodyPosition/AlignOrientation on
-- our HRP: SELF-moves (e.g. Naoya's ult) hold you with those WITHOUT welding you
-- to a player, and those should NOT block lockon. A grab means another player is
-- involved, which the weld check captures.
local grabCacheT, grabCacheV = 0, false
function state.isGrabbing()
    -- a tech opted out of grab-suppression so Lock-On keeps working while welded
    if state.techIgnoreWelds then return false end
    local now = os.clock()
    if now - grabCacheT > 0.05 then
        grabCacheT = now
        local c = PlayersService.LocalPlayer and PlayersService.LocalPlayer.Character
        grabCacheV = c ~= nil and state.isWeldedToOther(c)
    end
    return grabCacheV
end

return state
end

_MODULES["modules.aim.targeting"] = function()
-- Target picking. Ports LockOnTargetingModule. Pure -- does not mutate aim state.
--
-- Returns TWO values: the target and its type ("player" or "npc"). Players are
-- always considered; NPCs (any model with a Humanoid that isn't a player) are
-- only considered when state.botMode ("Bot Mode") is on. Lock-On / Rotation Lock
-- / Highlight all branch on target_type, so an NPC target works the same as a
-- player one.

local state = require("modules.aim.state")

local Players   = game:GetService("Players")
local Workspace = game:GetService("Workspace")

local Targeting = {}

-- Reused across isVisibleChar calls so the per-candidate visibility raycast
-- (Target Select runs getBestTarget at 30Hz x N players when the visibility check
-- is on) doesn't allocate a fresh RaycastParams + ignore table every time.
local visParams = RaycastParams.new()
visParams.FilterType = Enum.RaycastFilterType.Blacklist
local visIgnore = {}

local function rootOf(char)
    return char and char:FindFirstChild("HumanoidRootPart")
end

local function isInFront(root)
    if not state.realisticEnabled then return true end
    local cam = Workspace.CurrentCamera
    if not cam then return true end
    local camCF = cam.CFrame
    local toTarget = root.Position - camCF.Position
    local mag = toTarget.Magnitude
    if mag <= 0.01 then return false end
    return (toTarget / mag):Dot(camCF.LookVector) >= math.cos(math.rad(60))
end

local function isAlive(char)
    if not char then return false end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return false end
    if state.checkHealthEnabled then
        if hum.Health <= 0 then return false end
        if char:FindFirstChildOfClass("ForceField") then return false end
    end
    return true
end

-- Line-of-sight check for a character (player OR npc). Punches through transparent
-- non-colliding parts (glass / decorative) the same way the original did.
local function isVisibleChar(char)
    local root = rootOf(char)
    if not root then return false end
    local cam = Workspace.CurrentCamera
    if not cam then return true end

    local origin = cam.CFrame.Position
    local direction = root.Position - origin
    if direction.Magnitude <= 0.01 then return true end

    table.clear(visIgnore)
    visIgnore[1] = Players.LocalPlayer.Character
    visParams.FilterDescendantsInstances = visIgnore

    while true do
        local result = Workspace:Raycast(origin, direction, visParams)
        if not result then return true end

        local hit = result.Instance
        if hit:IsDescendantOf(char) then return true end

        if hit:IsA("BasePart") and (hit.Transparency or 0) > 0.4 and not hit.CanCollide then
            visIgnore[#visIgnore + 1] = hit
            visParams.FilterDescendantsInstances = visIgnore
            local dirUnit = direction.Unit
            origin = result.Position + dirUnit * 0.05
            direction = root.Position - origin
            if direction.Magnitude <= 0.01 then return true end
        else
            return false
        end
    end
end

-- NPC list cache. Walking workspace:GetDescendants() every getBestTarget() call
-- (Target Select recomputes at 30 Hz) would be brutal in a big place, so we cache
-- the living-NPC models and refresh on a 0.5s throttle. Only built while Bot Mode
-- is on. A "real" NPC = a model with a Humanoid + HumanoidRootPart that no player
-- owns and isn't us (HRP required so Lock-On / Rotation Lock can actually aim).
local npcList, npcStamp = {}, 0
local NPC_REFRESH = 0.5
local function getNpcs()
    local now = os.clock()
    if (now - npcStamp) <= NPC_REFRESH and npcStamp ~= 0 then return npcList end
    npcStamp = now
    local out, seen = {}, {}
    local myChar = Players.LocalPlayer.Character
    for _, d in ipairs(Workspace:GetDescendants()) do
        if d:IsA("Humanoid") then
            local model = d.Parent
            if model and not seen[model] and model ~= myChar
               and model:FindFirstChild("HumanoidRootPart")
               and not Players:GetPlayerFromCharacter(model) then
                seen[model] = true
                out[#out + 1] = model
            end
        end
    end
    npcList = out
    return npcList
end

-- Returns (target, targetType). target is a Player when targetType=="player" and
-- the NPC's Model when targetType=="npc". `exclude` (a Player or a Model) is
-- skipped -- used by Swap Target to cycle to the next-best.
function Targeting.getBestTarget(exclude)
    local localPlayer = Players.LocalPlayer
    local myRoot = rootOf(localPlayer.Character)
    if not myRoot then return nil end

    local visCheck = state.visibilityCheckEnabled
    local best, bestType, bestDist = nil, nil, math.huge

    -- Cheap distance gate FIRST, then the expensive front/alive/visibility checks
    -- (visibility raycasts were the crowded-server hitch). Anyone farther than the
    -- current best can't win; if the closest fails a check we fall through to the
    -- next, so "closest visible" semantics hold across players AND npcs.
    local function consider(target, ttype, char)
        if not char or target == exclude then return end
        local root = rootOf(char)
        if not root then return end
        local dist = (root.Position - myRoot.Position).Magnitude
        if state.rangeLimit > 0 and dist > state.rangeLimit then return end
        if dist >= bestDist then return end
        if isInFront(root) and isAlive(char) and (not visCheck or isVisibleChar(char)) then
            best, bestType, bestDist = target, ttype, dist
        end
    end

    for _, plr in ipairs(Players:GetPlayers()) do
        if plr ~= localPlayer and not state.isFriendly(plr) then
            consider(plr, "player", plr.Character)
        end
    end

    if state.botMode then
        for _, model in ipairs(getNpcs()) do
            consider(model, "npc", model)
        end
    end

    return best, bestType
end

return Targeting
end

_MODULES["modules.aim.highlight"] = function()
-- Target visuals: outline highlight (red active / yellow swap target) + a fixed
-- top-center on-screen HUD showing the current target's name and health bar,
-- matching the original lock-on script's indicator. Plus optional self-fade.

local state = require("modules.aim.state")
local env   = require("core.env")

local Players = game:GetService("Players")

local Highlight = {}

local RED    = Color3.fromRGB(255, 60, 60)
local YELLOW = Color3.fromRGB(255, 215, 40)

local highlights = {} -- [target] = Highlight instance  (target = Player OR NPC model)

-- Resolve the character to outline: a Player target outlines its .Character; an
-- NPC target IS its own character model. Works for both the primary (red) target
-- and the next-best (yellow) one, whose type isn't tracked in state.
local function charOf(target)
    if not target then return nil end
    if target:IsA("Player") then return target.Character end
    return target
end

-- outline ---------------------------------------------------------------------
local function setHighlight(plr, color, on)
    local h = highlights[plr]
    if on then
        local char = charOf(plr)
        if not char then
            if h then h:Destroy() end; highlights[plr] = nil; return
        end
        if not h or not h.Parent then
            h = Instance.new("Highlight")
            h.Name = "_" .. math.random(100000, 999999)
            h.FillTransparency = 0.5
            h.OutlineTransparency = 0
            h.DepthMode = Enum.HighlightDepthMode.AlwaysOnTop
            highlights[plr] = h
        end
        h.Adornee = char
        h.FillColor = color
        h.OutlineColor = color
        h.Parent = char
    else
        if h then h:Destroy() end; highlights[plr] = nil
    end
end

-- top-center target info HUD (name + health bar) -- on-screen, NOT over the head,
-- mirroring the original lock-on script's indicator. Current target only.
local info  -- { gui, indicator, container, bar, text }
local function ensureInfo()
    if info and info.gui.Parent then return info end
    local gui = Instance.new("ScreenGui")
    gui.Name = "_" .. math.random(100000, 999999)
    gui.ResetOnSpawn = false
    gui.IgnoreGuiInset = true
    env.protectGui(gui)
    gui.Parent = env.guiParent()

    local indicator = Instance.new("TextLabel")
    indicator.Size = UDim2.new(0, 160, 0, 28)
    indicator.Position = UDim2.new(0.5, -80, 0, 10)
    indicator.BackgroundColor3 = Color3.fromRGB(16, 16, 20)
    indicator.BackgroundTransparency = 0.1
    indicator.TextColor3 = Color3.new(1, 1, 1)
    indicator.Font = Enum.Font.GothamBold
    indicator.TextSize = 13
    indicator.Visible = false
    indicator.Parent = gui
    Instance.new("UICorner", indicator).CornerRadius = UDim.new(0, 10)
    local iStroke = Instance.new("UIStroke", indicator); iStroke.Thickness = 2; iStroke.Color = RED

    local container = Instance.new("Frame")
    container.Size = UDim2.new(0, 160, 0, 20)
    container.Position = UDim2.new(0.5, -80, 0, 42)
    container.BackgroundColor3 = Color3.fromRGB(16, 16, 20)
    container.BackgroundTransparency = 0.1
    container.Visible = false
    container.Parent = gui
    Instance.new("UICorner", container).CornerRadius = UDim.new(0, 10)
    local cStroke = Instance.new("UIStroke", container); cStroke.Thickness = 2; cStroke.Color = RED

    local bar = Instance.new("Frame")
    bar.Size = UDim2.new(1, -8, 1, -8)
    bar.Position = UDim2.new(0, 4, 0, 4)
    bar.BackgroundColor3 = Color3.fromRGB(0, 255, 100)
    bar.BorderSizePixel = 0
    bar.Parent = container
    Instance.new("UICorner", bar).CornerRadius = UDim.new(0, 6)

    local text = Instance.new("TextLabel")
    text.Size = UDim2.fromScale(1, 1)
    text.BackgroundTransparency = 1
    text.TextColor3 = Color3.new(1, 1, 1)
    text.Font = Enum.Font.GothamBold
    text.TextSize = 11
    text.Text = ""
    text.Parent = container

    info = { gui = gui, indicator = indicator, container = container, bar = bar, text = text }
    return info
end

local function hideInfo()
    if info then info.indicator.Visible = false; info.container.Visible = false end
end

local function updateInfo(currentTarget)
    if not state.targetInfoEnabled or not currentTarget then hideInfo(); return end
    local isNpc = not currentTarget:IsA("Player")
    local char  = charOf(currentTarget)
    local hum   = char and char:FindFirstChildOfClass("Humanoid")
    if not hum then hideInfo(); return end

    local i = ensureInfo()
    i.indicator.Visible = true
    i.container.Visible = true

    local nm = currentTarget.Name
    if not isNpc then
        local dn = currentTarget.DisplayName
        nm = (dn and dn ~= "" and dn) or currentTarget.Name
    end
    i.indicator.Text = (isNpc and "👾 " or "🎯 ") .. tostring(nm)

    local maxHp = math.max(hum.MaxHealth, 1)
    local ratio = math.clamp(hum.Health / maxHp, 0, 1)
    i.bar.Size = UDim2.new(ratio * (1 - 8 / 160), 0, 1, -8)
    if ratio > 0.5 then
        i.bar.BackgroundColor3 = Color3.fromRGB(0, 255, 100)
    elseif ratio > 0.25 then
        i.bar.BackgroundColor3 = Color3.fromRGB(255, 200, 0)
    else
        i.bar.BackgroundColor3 = Color3.fromRGB(255, 50, 50)
    end
    i.text.Text = math.floor(hum.Health) .. "/" .. math.floor(hum.MaxHealth)
end

function Highlight.clearAll()
    for plr in pairs(highlights) do setHighlight(plr, nil, false) end
    hideInfo()
end

-- Diff-based outline update (reuse instances) + the top-center info HUD.
function Highlight.update(currentTarget, getSecondFn)
    if not state.highlightEnabled or not currentTarget then
        Highlight.clearAll()
        return
    end

    local desired = {}
    if not state.isFriendly(currentTarget) then desired[currentTarget] = RED end
    if state.highlightSecondEnabled and getSecondFn then
        local second = getSecondFn(currentTarget)
        if second and second ~= currentTarget and not state.isFriendly(second) then
            desired[second] = YELLOW
        end
    end

    for plr in pairs(highlights) do if not desired[plr] then setHighlight(plr, nil, false) end end
    for plr, color in pairs(desired) do setHighlight(plr, color, true) end

    updateInfo(currentTarget)
end

-- self-fade -------------------------------------------------------------------
local function applySelfFade(char)
    if not char then return end
    for _, d in ipairs(char:GetDescendants()) do
        if d:IsA("BasePart") then
            d.LocalTransparencyModifier = state.selfFadeEnabled and 0.6 or 0
        elseif d:IsA("Decal") then
            d.Transparency = state.selfFadeEnabled and 0.6 or 0
        end
    end
end

function Highlight.setSelfFade(v)
    state.selfFadeEnabled = v and true or false
    applySelfFade(Players.LocalPlayer.Character)
end

function Highlight.setEnabled(v)
    state.highlightEnabled = v and true or false
    if not v then Highlight.clearAll() end
end

function Highlight.setSecondEnabled(v)
    state.highlightSecondEnabled = v and true or false
end

function Highlight.setTargetInfo(v)
    state.targetInfoEnabled = v and true or false
    if not v then hideInfo() end
end

local charConn

function Highlight.init()
    charConn = Players.LocalPlayer.CharacterAdded:Connect(function(char)
        if state.selfFadeEnabled then
            char:WaitForChild("HumanoidRootPart", 5)
            applySelfFade(char)
        end
    end)
end

function Highlight.destroy()
    if charConn then charConn:Disconnect(); charConn = nil end
    Highlight.clearAll()
    if info and info.gui then pcall(function() info.gui:Destroy() end); info = nil end
end

return Highlight
end

_MODULES["modules.aim.shiftlock"] = function()
-- Custom shiftlock. Replaces Roblox's built-in and any competing custom
-- shiftlock loops. Three layers of foreign-killer:
--   1. PlayerGui sweep: destroy ScreenGuis with known foreign names.
--   2. Connection sweep: walk RenderStepped/Heartbeat/Stepped and disconnect
--      any callback whose bytecode constants include both "MouseBehavior" AND
--      "LockCenter" — every shiftlock loop has to reference those literals to
--      actually do anything. Backup heuristic looks at upvalue tables for a
--      shiftLocked-flag + Humanoid-ref pattern.
--   3. PlayerScripts sweep: disable LocalScripts whose name contains
--      "shiftlock".
-- Runs on boot, enable, disable, and respawn so foreign code that reconnects
-- doesn't quietly take back over.

local env      = require("core.env")
local state    = require("modules.aim.state")
local log      = require("core.log")
local keybinds = require("core.keybinds")
local notify   = require("ui.notify")

local Players             = game:GetService("Players")
local UserInputService    = game:GetService("UserInputService")
local RunService          = game:GetService("RunService")
local VirtualInputManager = game:GetService("VirtualInputManager")

local Shiftlock = {}

local ZERO3 = Vector3.new(0, 0, 0)
local RENDER_BIND = "PantheonShiftlock"
-- Randomised at script-load so game-side ScreenGui-name scanners can't
-- pattern-match "PantheonShiftLockVGui" / "ShiftLockVGui". Lives in
-- self_state once the GUI is built; killForeignGuis(), which only checks
-- PlayerGui anyway, doesn't need to know it (the GUI is parented to
-- env.guiParent() = gethui sandbox, not PlayerGui, so scans miss it).
local GUI_NAME    = "_" .. tostring(math.random(100000, 999999))

local FOREIGN_GUI_NAMES = {
    "ShiftLockVGui", "ShiftLockIcon", "ShiftLockHud", "ShiftLockButton",
    "CustomShiftLock", "ShiftLockGui", "ShiftlockGui",
}

local self_state = {
    character = nil,
    humanoid  = nil,
    root      = nil,
    gui       = nil,
    vIcon     = nil,
    charConn  = nil,
    humConn   = nil,
    focusConn = nil,
    externalSkipRotation = nil,
    bound = false,
    hookInstalled = false,
    blockedWrites = 0,
    lastBlockedLog = 0,
    weldCheckLast = 0,
    weldCheckResult = false,
    -- pair mode: are we currently hiding the game's shiftlock icon?
    iconsHidden = false,
    -- Set true by Shiftlock.destroy() so the previously-installed hook
    -- becomes a pure pass-through and the hookGuard task exits, letting a
    -- freshly re-executed Pantheon take over without thrashing.
    shutdown = false,
}

-- Cached weld-to-other-character check. Battlegrounds-style grab moves
-- weld the attacker to the victim; if we then rotate our own root via
-- shiftlock, the weld drags the victim around too. Wraps the shared helper
-- in [[modules.aim.state]] with a 50ms cache so the rotation pass isn't
-- walking the character descendants on every render.
local function isLocalWeldedToOther()
    return state.isWeldedToOther(self_state.character)
end

local function weldedToOther()
    -- User can opt out of the safety entirely (per-game via persisted
    -- setting). Used to recover rotation through grab-style welds that
    -- some games rely on for "nerf" moves -- e.g. JJS locking your aim by
    -- welding your HRP to the victim. With the safety off, root.CFrame
    -- writes still go through and the rotation tracks the camera.
    if not state.weldSafetyEnabled then return false end
    -- 50ms cache so we don't walk descendants every frame.
    local now = os.clock()
    if now - self_state.weldCheckLast > 0.05 then
        self_state.weldCheckResult = isLocalWeldedToOther()
        self_state.weldCheckLast = now
    end
    return self_state.weldCheckResult
end

local function lp() return Players.LocalPlayer end

local function disableGameShiftLock()
    pcall(function() lp().DevEnableMouseLock = false end)
end

-- ---------- foreign killer helpers --------------------------------------

local function getConnectionFunction(conn)
    for _, key in ipairs({ "Function", "Func", "func" }) do
        local ok, fn = pcall(function() return conn[key] end)
        if ok and type(fn) == "function" then return fn end
    end
    return nil
end

local function getConstants(fn)
    local f = (getconstants) or (debug and debug.getconstants)
    if not f then return nil end
    local ok, c = pcall(f, fn)
    if not ok then return nil end
    return c
end

local function getUpvalues(fn)
    local f = (getupvalues) or (debug and debug.getupvalues)
    if not f then return nil end
    local ok, c = pcall(f, fn)
    if not ok then return nil end
    return c
end

-- Strong signature: function code contains both literals.
local function functionLooksLikeShiftlock(fn)
    local consts = getConstants(fn)
    if not consts then return false end
    local hasMB, hasLC = false, false
    for _, c in pairs(consts) do
        if type(c) == "string" then
            if c == "MouseBehavior" then hasMB = true end
            if c == "LockCenter"    then hasLC = true end
        end
    end
    return hasMB and hasLC
end

-- Backup signature: upvalue table looks like a ShiftLockModule self-state.
local function upvaluesLookLikeShiftlock(fn)
    local ups = getUpvalues(fn)
    if not ups then return false end
    for _, up in pairs(ups) do
        if type(up) == "table" then
            local hasFlag = (up.shiftLocked ~= nil) or (up.shiftlock_locked ~= nil)
                         or (up.locked ~= nil) or (up.isLocked ~= nil)
            local hasInstRef = (typeof(up.humanoid)  == "Instance")
                            or (typeof(up.character) == "Instance")
                            or (typeof(up.root)      == "Instance")
                            or (typeof(up.hrp)       == "Instance")
            if hasFlag and hasInstRef then return true end
        end
    end
    return false
end

local function killForeignGuis()
    local pg = lp():FindFirstChildOfClass("PlayerGui")
    if not pg then return 0 end
    local count = 0
    for _, gui in ipairs(pg:GetChildren()) do
        if gui:IsA("ScreenGui") and gui.Name ~= GUI_NAME then
            for _, foreign in ipairs(FOREIGN_GUI_NAMES) do
                if gui.Name == foreign then
                    gui:Destroy()
                    count = count + 1
                    break
                end
            end
        end
    end
    return count
end

local function killForeignLoops()
    if not getconnections then return 0, 0 end
    local killed, scanned = 0, 0
    for _, signal in ipairs({ RunService.RenderStepped, RunService.Heartbeat, RunService.Stepped }) do
        local ok, conns = pcall(getconnections, signal)
        if ok and type(conns) == "table" then
            for _, conn in pairs(conns) do
                scanned = scanned + 1
                local fn = getConnectionFunction(conn)
                if fn and (functionLooksLikeShiftlock(fn) or upvaluesLookLikeShiftlock(fn)) then
                    local dok = pcall(function() conn:Disconnect() end)
                    if dok then killed = killed + 1 end
                end
            end
        end
    end
    return killed, scanned
end

-- (deliberately no disableForeignScripts / reEnableForeignScripts: the
-- __newindex hook and the step-pin pass already block the game's writes when
-- Pantheon is on, and the LocalScript stays running the whole time. When
-- Pantheon goes off the hook is pass-through and the game's shiftlock works
-- exactly as if Pantheon were never loaded. This avoids the toggle lag from
-- walking PlayerScripts:GetDescendants() and the re-enable race that left
-- the cursor stuck locked after disable.)

-- Install a __newindex hook on UserInputService so we intercept every write to
-- MouseBehavior. With killForeign on, only writes that match Pantheon's
-- current desired state get through; everything else is silently swallowed.
-- This is what actually beats foreign shiftlocks that win via BindToRenderStep
-- at higher priority than us, or that run on Heartbeat, or that use any other
-- path - they can't write the property at all.
--
-- Persists `realOriginal` across re-installs so if a foreign script also hooks
-- __newindex and we re-install on top of theirs, we still pass through to the
-- real engine setter at the end of the chain (not theirs). The TRUE engine
-- setter is additionally cached in getgenv() (PANTHEON_UIS_NEWINDEX), which
-- survives teleports + Auto Re-Execute -- see installMouseBehaviorHook for why
-- that stops the hook chain (and its per-write cost) growing on every teleport.
local genv = (env.getgenv and env.getgenv()) or _G
local realOriginal = nil

-- Forward declarations. These are referenced by closures defined ABOVE their
-- real definitions: the hook closure uses shouldEnforce(), and Shiftlock.setEnabled
-- uses the lazy aliases. Declaring them as locals here means those references
-- capture the right upvalue instead of resolving to a nil global -- the previous
-- ordering made the hook error on every write and setEnabled error on every
-- enable/respawn.
local shouldEnforce
local installMouseBehaviorHookLazy, spawnHookGuardLazy

local function installMouseBehaviorHook()
    if type(hookmetamethod) ~= "function" then
        log.debug("shiftlock: hookmetamethod unavailable; relying on connection sweep")
        return false
    end

    -- Decides whether to swallow a write. Run via pcall in hookFn below so a bug
    -- in here can never error on -- or crash -- the game's property writes (this
    -- runs on EVERY Instance __newindex, since they share one metatable).
    local function shouldBlock(self, key, value)
        if self_state.shutdown then return false end
        -- shouldEnforce() gates the hook the same as the pin pass: on while
        -- killForeign is on, EXCEPT when allowGameShiftlock is on AND Pantheon
        -- shiftlock is off (so the game's shiftlock can drive the cursor).
        if not (shouldEnforce() and self == UserInputService) then return false end
        local block = false
        if key == "MouseBehavior" then
            local wanted = state.shiftlock_active
                and Enum.MouseBehavior.LockCenter
                or Enum.MouseBehavior.Default
            if value ~= wanted then block = true end
        elseif key == "MouseIconEnabled" then
            if value ~= (not state.shiftlock_active) then block = true end
        elseif key == "MouseIcon" then
            if value ~= "" then block = true end
        end
        if block then
            self_state.blockedWrites = self_state.blockedWrites + 1
            local now = os.clock()
            if now - self_state.lastBlockedLog > 2 then
                log.info(string.format(
                    "shiftlock: blocked %d foreign UIS write(s) (last %s)",
                    self_state.blockedWrites, tostring(key)))
                self_state.blockedWrites = 0
                self_state.lastBlockedLog = now
            end
        end
        return block
    end

    local hookFn = function(self, key, value)
        local ok, blocked = pcall(shouldBlock, self, key, value)
        if ok and blocked then return end   -- swallow the foreign write
        if realOriginal then return realOriginal(self, key, value) end
    end

    -- Wrap the hook in newcclosure so the metamethod looks like a C function
    -- when an anticheat reads back UIS's metatable. Without this, the hook
    -- is a plain Lua closure and a debug.info / typeof comparison can
    -- separate it from the engine's original native __newindex.
    local wrapped = (env.newcclosure and env.newcclosure(hookFn)) or hookFn

    local ok, returned = pcall(hookmetamethod, UserInputService, "__newindex", wrapped)
    if not ok or not returned then
        if not self_state.hookInstalled then
            log.warn("shiftlock: hookmetamethod failed:", tostring(returned))
        end
        return false
    end

    -- First install in this executor session: `returned` IS the real engine
    -- setter -- stash it in getgenv(), which survives teleports + re-executes.
    -- Every later install (including a freshly re-executed instance after a
    -- teleport) then chains to THAT real original instead of to the previous
    -- wrapped hook, so the previous hook is left unreferenced (GC'd) rather than
    -- chained-through. Before this, each Auto Re-Execute stacked another live
    -- hook layer on the persistent UserInputService: the chain -- and the
    -- pcall(shouldBlock) paid on EVERY Instance property write game-wide -- grew
    -- unbounded across a teleport-heavy session (JJS lobby<->match), the slow
    -- "Roblox closes itself after a while" leak. A re-install's `returned` (our
    -- previous hook, or a foreign hook chained atop us) is deliberately discarded.
    if not genv.PANTHEON_UIS_NEWINDEX then
        genv.PANTHEON_UIS_NEWINDEX = returned
    end
    realOriginal = genv.PANTHEON_UIS_NEWINDEX

    if not self_state.hookInstalled then
        log.info("shiftlock: MouseBehavior hook installed (foreign writes will be blocked)")
    end
    self_state.hookInstalled = true
    return true
end

-- Lazy-install entry points: aliases used by Shiftlock.setEnabled /
-- Shiftlock.setKillForeign (the upvalues forward-declared further up the
-- file). Defers the hookmetamethod call past script-load until the user
-- actually enables the feature.
installMouseBehaviorHookLazy = installMouseBehaviorHook

-- Periodically re-install the hook. If a game's own script hooks __newindex
-- AFTER us, their hook wraps ours and a foreign value might leak through.
-- Re-installing every second puts our hook back on top of theirs.
local function spawnHookGuard()
    if self_state.hookGuardStarted then return end
    self_state.hookGuardStarted = true
    task.spawn(function()
        while task.wait(1) do
            if self_state.shutdown then return end
            if state.killForeign and state.shiftlock_enabled then
                installMouseBehaviorHook()
            end
        end
    end)
end

spawnHookGuardLazy = spawnHookGuard

local function sweepForeigns(label)
    local g = killForeignGuis()
    local k, s = killForeignLoops()
    if g > 0 or k > 0 then
        log.info(string.format(
            "shiftlock [%s]: killed %d GUI(s), %d/%d connection(s)",
            label, g, k, s
        ))
    else
        log.debug(string.format(
            "shiftlock [%s]: scanned %d connection(s), nothing matched",
            label, s
        ))
    end
end

-- PAIR mode: hide the GAME's own shiftlock icon while Pantheon's shiftlock is
-- active, so only our icon shows -- WITHOUT destroying it (we still pair with the
-- game's shiftlock state for sync + rotation). Match: ScreenGui/GuiObject under
-- PlayerGui whose own OR parent's name contains "shiftlock". Remembers exactly
-- what it hid and restores it when Pantheon's shiftlock goes inactive.
-- NOTE: dropped the "small image near screen center" heuristic -- it was a JJS
-- fallback that caught everything else near center (crosshairs / status icons /
-- hit markers) since JJS has no visible PC shiftlock icon at all. If a future
-- game has one with an off-pattern name, grab it via [Dev] explorer and we add
-- to a per-game name list instead of guessing by position.
local hiddenStore = {}   -- { {inst, prop, originalValue}, ... }
local iconScanT = 0

-- (re)scan PlayerGui for shiftlock-named GUIs, recording any new ones with their
-- original value (so we can restore later). Throttled by the caller.
local function nameClean(s) return (s and (s:lower():gsub("%s", ""))) or "" end
local lastReportedN = -1
local function scanShiftlockIcons()
    local pg = lp():FindFirstChildOfClass("PlayerGui")
    if not pg then return end
    local known = {}
    for _, e in ipairs(hiddenStore) do known[e[1]] = true end
    for _, gobj in ipairs(pg:GetDescendants()) do
        if not known[gobj] then
            local isSG = gobj:IsA("ScreenGui")
            if isSG or gobj:IsA("GuiObject") then
                local hit = (string.find(nameClean(gobj.Name), "shiftlock") ~= nil)
                    or (gobj.Parent and string.find(nameClean(gobj.Parent.Name), "shiftlock") ~= nil)
                if hit then
                    local prop = isSG and "Enabled" or "Visible"
                    local ok, cur = pcall(function() return gobj[prop] end)
                    if ok then hiddenStore[#hiddenStore + 1] = { gobj, prop, cur } end
                end
            end
        end
    end
    -- Log whenever the hidden-count changes. Only surface a user-facing toast
    -- when we actually hid something (count > 0): in pair-mode games with no PC
    -- shiftlock icon (e.g. JJS) the count stays 0, and the old unconditional
    -- toast popped a spurious "Shiftlock hide: 0 []" every time you loaded in.
    if #hiddenStore ~= lastReportedN then
        lastReportedN = #hiddenStore
        local names = {}
        for _, e in ipairs(hiddenStore) do names[#names + 1] = e[1].Name end
        local msg = "Shiftlock hide: " .. #hiddenStore .. " [" .. table.concat(names, ", ") .. "]"
        log.info(msg)
        if #hiddenStore > 0 then pcall(function() notify.info(msg, 8) end) end
    end
end

-- Keep the game's shiftlock icon hidden. Re-asserts EVERY frame (cheap -- only a
-- few stored instances) so it stays hidden even if the game's own script re-shows
-- it each frame, and re-scans periodically to catch icons created later. Called
-- from step() which runs at RenderPriority.Last, so our hide wins end-of-frame --
-- a one-shot hide loses to a game that re-shows its icon, which is why the icon
-- kept reappearing.
local function enforceShiftlockHidden()
    if os.clock() - iconScanT > 0.4 then
        iconScanT = os.clock()
        scanShiftlockIcons()
    end
    for i = #hiddenStore, 1, -1 do
        local gobj, prop = hiddenStore[i][1], hiddenStore[i][2]
        if gobj and gobj.Parent then
            pcall(function() if gobj[prop] ~= false then gobj[prop] = false end end)
        else
            table.remove(hiddenStore, i)
        end
    end
end

local function restoreShiftlockIcons()
    for _, e in ipairs(hiddenStore) do
        local gobj, prop, orig = e[1], e[2], e[3]
        if gobj and gobj.Parent then
            pcall(function() gobj[prop] = (orig == nil) and true or orig end)
        end
    end
    hiddenStore = {}
    iconScanT = 0
end

-- ---------- gui ----------------------------------------------------------

local function buildGui()
    if self_state.gui and self_state.gui.Parent then return end

    local gui = Instance.new("ScreenGui")
    gui.Name = GUI_NAME
    gui.ResetOnSpawn = false
    gui.IgnoreGuiInset = true
    gui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
    -- env.guiParent() = gethui() (or CoreGui fallback). PlayerGui is fully
    -- enumerable by any game script (TSB-style anticheats scan it for
    -- unknown ScreenGuis and detach the camera as a punishment); gethui's
    -- container is hidden from those scans.
    gui.Parent = env.guiParent()
    env.protectGui(gui)

    local vIcon = Instance.new("ImageLabel")
    vIcon.Name = "VIcon"
    vIcon.BackgroundTransparency = 1
    vIcon.Size = UDim2.new(0, 150, 0, 150)
    vIcon.AnchorPoint = Vector2.new(0.5, 0.5)
    vIcon.Position = UDim2.new(0.5, 0, 0.5, 0)
    vIcon.Visible = false
    vIcon.Image = "rbxassetid://18913450789"
    vIcon.ScaleType = Enum.ScaleType.Fit
    vIcon.BorderSizePixel = 5
    vIcon.BorderColor3 = Color3.new(1, 1, 1)
    vIcon.Parent = gui

    self_state.gui = gui
    self_state.vIcon = vIcon
end

local function updateCharRefs(char)
    self_state.character = char
    self_state.humanoid  = char:WaitForChild("Humanoid")
    self_state.root      = char:WaitForChild("HumanoidRootPart")

    if self_state.humConn then self_state.humConn:Disconnect() end
    self_state.humConn = self_state.humanoid.Died:Connect(function()
        state.shiftlock_active = false
        Shiftlock.forceOff()
    end)
end

local function applyLock()
    state.shiftlock_active = true
    disableGameShiftLock()
    if self_state.humanoid then self_state.humanoid.AutoRotate = false end
    if self_state.vIcon    then self_state.vIcon.Visible = true end
    UserInputService.MouseIconEnabled = false
    UserInputService.MouseBehavior    = Enum.MouseBehavior.LockCenter
end

function Shiftlock.forceOff()
    state.shiftlock_active = false
    if self_state.humanoid then self_state.humanoid.AutoRotate = true end
    if self_state.vIcon    then self_state.vIcon.Visible = false end
    UserInputService.MouseIconEnabled = true
    UserInputService.MouseBehavior    = Enum.MouseBehavior.Default
end

function Shiftlock.toggle()
    -- Gated on the feature master toggle so the Shift key only locks the
    -- cursor when the user has explicitly enabled Pantheon shiftlock.
    -- Same pattern as target_select / rotation_lock hotkeys.
    if not state.shiftlock_enabled then return end
    if state.shiftlockMirror then return end   -- mirror mode: the game owns Shift; we just follow its state
    if state.shiftlock_active then
        Shiftlock.forceOff()
    else
        applyLock()
    end
end

-- (installMouseBehaviorHookLazy / spawnHookGuardLazy are forward-declared at the
-- top of the file and assigned right after their implementations above, so the
-- functions below see the real functions instead of nil.)

function Shiftlock.setEnabled(v)
    v = v and true or false
    if state.shiftlock_enabled == v then return end
    state.shiftlock_enabled = v
    if v then
        -- Mirror mode follows the game's shiftlock, so DON'T disable or sweep it
        -- away -- that would kill the very thing we're mirroring.
        if not state.shiftlockMirror then
            disableGameShiftLock()
            if state.killForeign then
                sweepForeigns("enable")
                -- Lazy hook install: only when the user actually wants enforcement
                -- (killForeign on + master toggled on). Defers the hookmetamethod
                -- call past script-load so anticheats scanning UIS metatable at
                -- execute time (TSB-style) don't see the hook.
                installMouseBehaviorHookLazy()
                spawnHookGuardLazy()
            end
        end
    else
        Shiftlock.forceOff()
        -- No release cooldown needed -- when killForeign is on the pin pass
        -- and hook are always enforcing free-movement state whenever
        -- shouldLock is false, so the post-disable transition is
        -- self-stabilising on every frame.
        -- If the user wants the game's vanilla MouseLockController as their
        -- shiftlock fallback, restore DevEnableMouseLock so it can engage.
        -- (Custom in-game shiftlock scripts don't care about DevEnableMouseLock,
        -- but the pin-pass + hook gate handles them via shouldEnforce()).
        if state.allowGameShiftlock then
            pcall(function() lp().DevEnableMouseLock = true end)
        end
    end
end

function Shiftlock.setAllowGameShiftlock(v)
    state.allowGameShiftlock = v and true or false
    -- Wake Roblox's vanilla MouseLockController if the user just opted in
    -- and Pantheon's master is off. The shouldEnforce() gate is what
    -- actually lets foreign LockCenter writes through; this is just the
    -- DevEnableMouseLock side of the same intent.
    if state.allowGameShiftlock and not state.shiftlock_enabled then
        pcall(function() lp().DevEnableMouseLock = true end)
    end
end

-- PAIR mode: Pantheon syncs its shiftlock on/off to the game's own shiftlock and
-- keeps rotating in lockstep, but lets the game own the CURSOR (no pin/hook fight).
-- Replaces the old independent toggle that drifted out of sync and overlapped.
-- Enabling it releases our current cursor writes once so the game takes the cursor.
function Shiftlock.setShiftlockMirror(v)
    state.shiftlockMirror = v and true or false
    if state.shiftlockMirror then Shiftlock.forceOff() end
end

-- Pin pass + hook enforce when this is true. Returns false to fully yield
-- (cursor management is whatever the game scripts and Roblox engine want).
-- NOTE: assigns the forward-declared upvalue (no `local`) so the hook closure
-- defined earlier captures it instead of a nil global.
-- Enforce (pin pass + __newindex hook) ONLY while Pantheon is actively locking.
-- When our lock is off we fully RELEASE so the game's own shiftlock stays in sync
-- with ours (both react to Shift) and the body free-rotates normally. The old
-- always-on enforcement dominated the game's shiftlock and left rotation stuck
-- when toggled off -- the user wants the two paired, not Pantheon winning.
function shouldEnforce()
    if state.shiftlockMirror then return false end   -- mirror mode: never touch/fight the game's cursor
    if not state.killForeign then return false end
    return state.shiftlock_enabled and state.shiftlock_active
end

function Shiftlock.setExternalSkipRotation(fn)
    self_state.externalSkipRotation = fn
end

-- Auto-repair pairing with the game's shiftlock after respawn.
--
-- Symptom: the user has Pantheon shiftlock running alongside the game's own
-- shiftlock script and they're normally in sync (Pantheon's Shift keybind
-- triggers both because UIS.InputBegan fans out to every listener). Sometimes
-- the game's shiftlock state machine resets on respawn while Pantheon's
-- still thinks it was locked from before death; the result is a glitched
-- "free rotate broken" (cursor stuck LockCenter or AutoRotate stuck false).
--
-- Fix: 0.5s after CharacterAdded, if shiftlock_active says we should be
-- free but the cursor/AutoRotate disagree, cycle Pantheon's master once
-- to reset our internal state, then fire a single synthetic Shift key
-- event so the game's state machine retriggers and lands in the same
-- state Pantheon now has.
local function autoRepair()
    if state.shiftlock_active then return end  -- we expect locked; not glitched
    local cursorLocked = UserInputService.MouseBehavior == Enum.MouseBehavior.LockCenter
    local hum = self_state.humanoid
    local rotLocked = hum and (not hum.AutoRotate)
    if not (cursorLocked or rotLocked) then return end

    log.info("shiftlock: post-respawn pairing glitch detected, re-pairing")

    if state.shiftlock_enabled then
        Shiftlock.setEnabled(false)
        task.wait(0.05)
        Shiftlock.setEnabled(true)
    end

    -- Retrigger the game's shiftlock keybind handler. Use the user's actual
    -- bound key so custom binds still work.
    local key = (keybinds.get and keybinds.get("aim.shiftlock")) or Enum.KeyCode.LeftShift
    if key and key ~= Enum.KeyCode.Unknown then
        pcall(function()
            VirtualInputManager:SendKeyEvent(true,  key, false, game)
            task.wait(0.03)
            VirtualInputManager:SendKeyEvent(false, key, false, game)
        end)
    end
end

local function step()
    -- PAIR mode: instead of toggling our shiftlock independently (which drifts out
    -- of sync with the game's and overlaps it), SYNC our shiftlock_active to the
    -- game's own shiftlock by reading its cursor lock. We do NOT pin the cursor
    -- (shouldEnforce() returns false in pair mode, so the game owns the cursor --
    -- no fight), but we FALL THROUGH to our own rotation pass below, so Pantheon's
    -- shiftlock stays ACTIVE (rotating in lockstep) alongside the game's -- paired,
    -- not replaced. They lock/unlock together because our state tracks the game's.
    if state.shiftlockMirror then
        state.shiftlock_active = state.shiftlock_enabled
            and (UserInputService.MouseBehavior == Enum.MouseBehavior.LockCenter) or false
        -- pair mode doesn't call applyLock(), so drive our shiftlock icon here so it
        -- shows while the paired shiftlock is active...
        if self_state.vIcon then self_state.vIcon.Visible = state.shiftlock_active end
        -- ...and ALWAYS hide the game's own shiftlock icon while in pair mode (i.e.
        -- the whole time you're in JJS). NOT gated on shiftlock_enabled/active --
        -- that gate is likely why it kept showing. Pantheon shows its own vIcon.
        enforceShiftlockHidden()
        self_state.iconsHidden = true
    elseif self_state.iconsHidden then
        -- left pair mode (or shiftlock off) -> give the game its icon back
        restoreShiftlockIcons()
        self_state.iconsHidden = false
    end

    -- "shouldLock" is the SINGLE source of truth for whether the cursor should
    -- be locked right now. It is true only when Pantheon's shiftlock is both
    -- enabled and currently active.
    local shouldLock = state.shiftlock_enabled and state.shiftlock_active

    -- ===== pin pass =====
    -- Forces all four shiftlock-related properties to our desired state every
    -- frame so foreign scripts can't ghost-control them. Runs continuously
    -- whenever shouldEnforce() is true -- including when Pantheon shiftlock
    -- is off (so a game shiftlock script's CharacterAdded handler / delayed
    -- task / off-cycle render binding can't sneak the cursor back into
    -- LockCenter after the user toggles Pantheon shiftlock off). The
    -- allowGameShiftlock toggle yields this enforcement when Pantheon
    -- shiftlock is off, so the game's base shiftlock can drive the cursor.
    if shouldEnforce() then
        local hum = self_state.humanoid
        local rotLockActive = self_state.externalSkipRotation
            and self_state.externalSkipRotation()

        -- Skip AutoRotate writes while Rotation Lock is driving the body,
        -- otherwise we fight it for free-rotate vs locked-rotate.
        if hum and not rotLockActive then
            -- hand AutoRotate back during a grab so the game can turn/move us
            -- instead of leaving the body frozen ("stuck in place").
            local wantedAR = (not shouldLock) or state.isGrabbing()
            if hum.AutoRotate ~= wantedAR then
                hum.AutoRotate = wantedAR
            end
        end

        local wantedMB = shouldLock
            and Enum.MouseBehavior.LockCenter
            or Enum.MouseBehavior.Default
        if UserInputService.MouseBehavior ~= wantedMB then
            UserInputService.MouseBehavior = wantedMB
        end

        local wantedEnabled = not shouldLock
        if UserInputService.MouseIconEnabled ~= wantedEnabled then
            UserInputService.MouseIconEnabled = wantedEnabled
        end

        if UserInputService.MouseIcon ~= "" then
            UserInputService.MouseIcon = ""
        end
    end

    -- ===== locked-mode rotation pass (only when our shiftlock is engaged) =====
    if not state.shiftlock_enabled then return end

    local hum = self_state.humanoid
    if hum and hum.CameraOffset ~= ZERO3 then hum.CameraOffset = ZERO3 end

    if not state.shiftlock_active or not self_state.root or not hum then return end
    if state.techBodyOverride then return end   -- a Tech Builder Rotate step owns the body; don't overwrite it
    if hum.Health <= 0 then return end

    local st = hum:GetState()
    if st == Enum.HumanoidStateType.Dead then return end

    -- Being grabbed (welded to a player, or held by a foreign BodyGyro/Position)
    -- => never rotate the body: it drags the grabbed player (we're the attacker)
    -- or fights + glitches their grab of us (we're the victim). Grabs can keep
    -- the humanoid in the RUNNING state, so check this DIRECTLY, not via state.
    if state.isGrabbing() then return end
    -- Hard locks (bleedout / downed / seated) + knockback/ragdoll physics:
    -- suppress so the body doesn't spin while the game controls us.
    if hum.PlatformStand then return end
    if st == Enum.HumanoidStateType.Ragdoll
       or st == Enum.HumanoidStateType.FallingDown
       or st == Enum.HumanoidStateType.Physics then
        return
    end

    if self_state.externalSkipRotation and self_state.externalSkipRotation() then
        return
    end

    -- Knockback: don't pin facing while being launched fast with no movement input
    -- -- the per-frame root.CFrame write fights / cancels the knockback (TSB). A
    -- dash holds a direction (MoveDirection > 0) so it isn't caught.
    if state.bgSafeEnabled and hum.MoveDirection.Magnitude < 0.1 then
        local v = self_state.root.AssemblyLinearVelocity
        if Vector3.new(v.X, 0, v.Z).Magnitude > (hum.WalkSpeed * 1.6 + 8) then return end
    end

    local cam = workspace.CurrentCamera
    if not cam then return end
    local look = cam.CFrame.LookVector
    local flat = Vector3.new(look.X, 0, look.Z)
    if flat.Magnitude > 0 then
        self_state.root.CFrame = CFrame.lookAt(self_state.root.Position, self_state.root.Position + flat)
    end
end

function Shiftlock.init()
    buildGui()

    local char = lp().Character or lp().CharacterAdded:Wait()
    updateCharRefs(char)

    self_state.charConn = lp().CharacterAdded:Connect(function(c)
        updateCharRefs(c)
        -- Only intervene on respawn when Pantheon shiftlock is actually enabled.
        -- When Pantheon shiftlock is OFF the game's shiftlock script (which we
        -- never disabled) owns the cursor; calling forceOff here races its own
        -- CharacterAdded and left free movement broken after dying.
        if state.shiftlock_enabled and not state.shiftlockMirror then
            Shiftlock.forceOff()
            if state.killForeign then
                task.defer(function() sweepForeigns("respawn") end)
            end
            -- Auto-repair pairing with the game's shiftlock once the
            -- game's post-respawn scripts have settled (~0.5s).
            task.delay(0.5, autoRepair)
        end
    end)

    self_state.focusConn = UserInputService.WindowFocusReleased:Connect(function()
        if state.shiftlock_active then Shiftlock.forceOff() end
    end)

    if not self_state.bound then
        -- RenderPriority.Last (= 2000) so we run AFTER every other
        -- BindToRenderStep callback in the frame. The pin pass alone is
        -- enough to keep our wanted state at end-of-frame; the property
        -- hook is a within-frame extra that's installed lazily on first
        -- user enable, so anticheats scanning the UIS metatable at
        -- script-load (TSB-style) don't see it.
        RunService:BindToRenderStep(RENDER_BIND, Enum.RenderPriority.Last.Value, step)
        self_state.bound = true
    end

    -- NB: hookmetamethod + hookGuard are no longer installed at boot.
    -- Deferred to Shiftlock.setEnabled(true) so that simply loading the
    -- script doesn't write the UIS metatable at all (anticheat surface).
end

-- Called by the "Kill foreign shiftlock GUIs / loops" cog toggle. Lazy-
-- installs the hook + guard if the user toggles killForeign on while
-- Pantheon shiftlock is already enabled (otherwise the hook was deferred
-- and would never install in that direction).
function Shiftlock.setKillForeign(v)
    state.killForeign = v and true or false
    if state.killForeign and state.shiftlock_enabled then
        installMouseBehaviorHookLazy()
        spawnHookGuardLazy()
    end
end

function Shiftlock.destroy()
    -- Flips the previously-installed hookmetamethod into pass-through mode
    -- and stops the hookGuard re-install loop.
    self_state.shutdown = true

    -- restore the game's shiftlock icon if we were hiding it
    if self_state.iconsHidden then
        restoreShiftlockIcons()
        self_state.iconsHidden = false
    end

    if self_state.bound then
        pcall(function() RunService:UnbindFromRenderStep(RENDER_BIND) end)
        self_state.bound = false
    end

    Shiftlock.forceOff()

    if self_state.charConn  then self_state.charConn:Disconnect();  self_state.charConn  = nil end
    if self_state.humConn   then self_state.humConn:Disconnect();   self_state.humConn   = nil end
    if self_state.focusConn then self_state.focusConn:Disconnect(); self_state.focusConn = nil end

    if self_state.gui then pcall(function() self_state.gui:Destroy() end) end
    self_state.gui, self_state.vIcon = nil, nil
end

return Shiftlock
end

_MODULES["modules.aim.rotation_lock"] = function()
-- Rotation Lock (formerly Lock-On+): rotates the local body to face the
-- target while the camera stays free. Has its own keybind (default Q, set in
-- Lock-On's settings panel) with hold/toggle mode. Gated by:
--   - state.lockon_enabled       (Lock-On master toggle)
--   - state.rotationLockEnabled  (Rotation Lock sub-toggle)
--   - state.target               (Target Select has acquired someone)
--   - s.holdActive               (hotkey is engaged per hold/toggle mode)
-- Battlegrounds-safe gate (state.bgSafeEnabled) suppresses rotation only
-- while OUR humanoid is in a non-walking state (PlatformStand / Ragdoll /
-- Physics / etc). We deliberately don't check the target's state -- doing
-- so was losing block windows during their attacks, because knockback
-- briefly puts attackers into Physics state and we'd stop tracking.

local state = require("modules.aim.state")

local Players    = game:GetService("Players")
local RunService = game:GetService("RunService")

local RotationLock = {}

local BIND = "PantheonRotationLock"

local SUPPRESS_STATES = {
    [Enum.HumanoidStateType.Physics]          = true,
    [Enum.HumanoidStateType.FallingDown]      = true,
    [Enum.HumanoidStateType.Ragdoll]          = true,
    [Enum.HumanoidStateType.Seated]           = true,
    [Enum.HumanoidStateType.PlatformStanding] = true,
}

local s = {
    align      = nil,
    attachment = nil,
    bound      = false,
    holdMode   = true,   -- default: hold-to-engage
    holdActive = false,  -- unified flag: true when rotation should engage
    wasActive  = false,  -- active->inactive edge, so we hand AutoRotate back once
}

local function rootOf(charOrModel)
    return charOrModel and charOrModel:FindFirstChild("HumanoidRootPart")
end

local function targetCharacter()
    local t = state.target
    if not t then return nil end
    if state.target_type == "player" then return t.Character end
    return t
end

local function getHumanoids()
    local myChar = Players.LocalPlayer.Character
    local myHum  = myChar and myChar:FindFirstChildOfClass("Humanoid")
    local tChar  = targetCharacter()
    local tHum   = tChar and tChar:FindFirstChildOfClass("Humanoid")
    return myHum, tHum
end

local function shouldRotate()
    if state.techBodyOverride then return false end   -- a Tech Builder step is driving the body; yield
    if not state.lockon_enabled then return false end
    if not state.rotationLockEnabled then return false end
    if not state.target then return false end
    if not s.holdActive then return false end
    return true
end

local function myHumanoid()
    local myChar = Players.LocalPlayer.Character
    return myChar and myChar:FindFirstChildOfClass("Humanoid")
end

local function bgSuppressed(myHum, myRoot)
    -- A grab (welded to a player, or held by a foreign BodyGyro/BodyPosition)
    -- can keep the humanoid in the RUNNING state -- the SwingForce throw does
    -- exactly that (grab inspector: their HRP welded to ours, state=Running). A
    -- state-only check misses it, so we'd write root.CFrame and either DRAG the
    -- welded player (we're the attacker) or fight + GLITCH their grab of us
    -- (we're the victim). So: being grabbed => ALWAYS suppress, regardless of
    -- state or the weld-safety toggle. Returning true makes step() deactivate(),
    -- which also disables our AlignOrientation so it stops torquing against the
    -- grab and hands AutoRotate back.
    if state.isGrabbing() then return true end
    if not state.bgSafeEnabled then return false end
    myHum = myHum or myHumanoid()
    if myHum then
        local st = myHum:GetState()
        -- Hard locks (bleedout / downed / seated) and knockback/ragdoll physics:
        -- suppress so the body doesn't spin while the game controls us.
        if myHum.PlatformStand
           or st == Enum.HumanoidStateType.PlatformStanding
           or st == Enum.HumanoidStateType.Seated
           or SUPPRESS_STATES[st] then
            return true
        end
        -- Knockback: being launched fast with NO movement input. Our per-frame
        -- root.CFrame write fights/cancels the knockback (TSB), so yield. A dash
        -- holds a direction (MoveDirection > 0) so it's NOT caught here.
        local hrp = myRoot or rootOf(Players.LocalPlayer.Character)
        if hrp and myHum.MoveDirection.Magnitude < 0.1 then
            local v = hrp.AssemblyLinearVelocity
            if Vector3.new(v.X, 0, v.Z).Magnitude > (myHum.WalkSpeed * 1.6 + 8) then return true end
        end
    end
    -- Intentionally NOT checking the target's state -- knockback briefly puts
    -- them in Physics during their attacks and we still want to track for blocks.
    return false
end

local function ensureConstraint(myRoot)
    if not s.attachment or not s.attachment.Parent then
        s.attachment = Instance.new("Attachment")
        s.attachment.Name = "PantheonRotationLockAttachment"
        s.attachment.Parent = myRoot
    end
    if not s.align or not s.align.Parent then
        s.align = Instance.new("AlignOrientation")
        s.align.Name = "PantheonRotationLockAlign"
        s.align.Mode = Enum.OrientationAlignmentMode.OneAttachment
        s.align.Attachment0 = s.attachment
        s.align.RigidityEnabled = true
        s.align.Responsiveness = 200
        s.align.MaxTorque = math.huge
        s.align.Parent = myRoot
    end
end

local function disableAlign()
    if s.align then s.align.Enabled = false end
end

-- Disengage: drop the constraint and, on the active->inactive edge only, hand
-- AutoRotate back to the humanoid so the body can turn normally again. The
-- one-shot guard (s.wasActive) means we DON'T set AutoRotate every idle frame
-- and fight shiftlock's per-frame pin: if shiftlock is on it re-takes AutoRotate
-- next frame; if it's off, AutoRotate correctly stays true.
local function deactivate()
    disableAlign()
    if s.wasActive then
        local myHum = getHumanoids()
        if myHum then myHum.AutoRotate = true end
        s.wasActive = false
    end
end

local function step()
    if not shouldRotate() then
        deactivate()
        return
    end

    local myChar = Players.LocalPlayer.Character
    if not myChar then return end
    local myRoot = rootOf(myChar)
    local myHum  = myChar:FindFirstChildOfClass("Humanoid")
    if not myRoot or not myHum then return end
    if myHum.Health <= 0 then deactivate(); return end  -- never rotate a dead body

    local tRoot = rootOf(targetCharacter())
    if not tRoot then return end

    if bgSuppressed(myHum, myRoot) then
        deactivate()
        return
    end

    -- Lead the target the same way [[modules.aim.lockon]] does, so the body
    -- faces where they'll be at impact, not where they were on the last
    -- network update. Critical for block timing on fast-moving attackers.
    local tVel = tRoot.AssemblyLinearVelocity
    local predicted = tRoot.Position + (tVel * state.getLeadTime())
    local dir = predicted - myRoot.Position
    local flat = Vector3.new(dir.X, 0, dir.Z)
    -- Only skip when the target is genuinely co-located with us (a 0.1
    -- stud guard was conservative; lowering keeps the rotation engaged
    -- right up against the target so combat-range facing never glitches).
    if flat.Magnitude < 0.001 then return end

    myHum.AutoRotate = false
    s.wasActive = true
    ensureConstraint(myRoot)
    if s.align then
        s.align.Enabled = true
        s.align.CFrame = CFrame.lookAt(Vector3.zero, flat)
    end

    -- Direct root.CFrame write every frame -- no smooth-resume window.
    -- The old 0.15s smoothing after an unsuppression cost block windows
    -- (target ragdolls briefly -> suppression -> unsuppression -> 0.15s
    -- of catch-up where direct CFrame write was skipped -> hit lands).
    -- Snap-to-face is what the user wants for combat.
    local cf = CFrame.lookAt(myRoot.Position, myRoot.Position + flat)
    local _, yAngle, _ = cf:ToEulerAnglesYXZ()
    myRoot.CFrame = CFrame.new(myRoot.Position) * CFrame.Angles(0, yAngle, 0)
end

function RotationLock.hotkeyPress()
    if not state.rotationLockEnabled then return end
    if s.holdMode then
        s.holdActive = true
    else
        s.holdActive = not s.holdActive
    end
end

function RotationLock.hotkeyRelease()
    if s.holdMode then
        s.holdActive = false
    end
end

function RotationLock.setHoldMode(v)
    s.holdMode = v and true or false
    -- Switching to toggle mode while engaged would leave holdActive stuck on.
    if not s.holdMode then s.holdActive = false end
end

function RotationLock.setEnabled(v)
    state.rotationLockEnabled = v and true or false
    if not v then
        s.holdActive = false
        deactivate()
    end
end

-- True when Rotation Lock is currently driving the body. Shiftlock uses this
-- to yield: when Rotation Lock is active, shiftlock skips its own rotation.
function RotationLock.isActive()
    return shouldRotate() and not bgSuppressed()
end

function RotationLock.init()
    if s.bound then return end
    -- Bound to BOTH RenderStepped (pre-render) and Stepped (pre-physics) so
    -- we rotate twice per frame -- once for what physics sees this tick,
    -- once for what render shows. The user wants godspeed; doubling the
    -- write rate eliminates the half-frame visual lag where rotation
    -- "catches up" between physics and render, and ensures the
    -- physics-side rotation (used for hit registration on movable parts)
    -- always reflects the latest target position.
    RunService:BindToRenderStep(BIND, Enum.RenderPriority.Camera.Value + 150, step)
    s.steppedConn = RunService.Stepped:Connect(function() step() end)
    s.bound = true
end

function RotationLock.destroy()
    if s.bound then
        pcall(function() RunService:UnbindFromRenderStep(BIND) end)
        if s.steppedConn then s.steppedConn:Disconnect(); s.steppedConn = nil end
        s.bound = false
    end
    -- hand the body back to the humanoid on teardown / re-exec
    if s.wasActive then
        local myHum = getHumanoids()
        if myHum then pcall(function() myHum.AutoRotate = true end) end
        s.wasActive = false
    end
    if s.align then pcall(function() s.align:Destroy() end); s.align = nil end
    if s.attachment then pcall(function() s.attachment:Destroy() end); s.attachment = nil end
end

return RotationLock
end

_MODULES["modules.aim.lockon"] = function()
-- Lock-On: aim-assist applicator. Reads target from Target Select, applies
-- the camera force when state.lockon_enabled AND state.cameraLockEnabled AND a
-- target exists. Resistance gate is the same dt-scaled exponential approach.
--
-- Rotation Lock lives in a separate module (rotation_lock.lua) with its own
-- keybind and hold/toggle mode.

local state = require("modules.aim.state")

local Players    = game:GetService("Players")
local RunService = game:GetService("RunService")

local LockOn = {}

local CAM_BIND = "PantheonLockOnCamera"

local s = {
    bound   = false,
    lastDir = nil,
}

local function rootOf(charOrModel)
    return charOrModel and charOrModel:FindFirstChild("HumanoidRootPart")
end

local function targetCharacter()
    local t = state.target
    if not t then return nil end
    if state.target_type == "player" then return t.Character end
    return t
end

local function cameraStep(dt)
    if not state.lockon_enabled then return end
    if state.techCamOverride then return end   -- a Tech Builder step is driving the camera; yield
    if not state.cameraLockEnabled then return end
    if not state.target then return end

    local cam = workspace.CurrentCamera
    if not cam then return end

    -- Suspend the camera-tracking write whenever we're welded to another
    -- character (grab moves). Uses the shared 50ms-cached check instead of
    -- walking every character descendant + its joints on EVERY frame -- that
    -- per-frame walk was a real cost while locked on. ~3 frames of resume
    -- latency after the weld breaks is imperceptible next to the saved work.
    if state.isGrabbing() then return end

    local tRoot = rootOf(targetCharacter())
    if not tRoot then return end

    local camPos = cam.CFrame.Position
    -- Lead the target by (velocity * predictionTime). Without this we aim
    -- at the last network-replicated position, which on a fast-moving
    -- target is several studs behind where they actually are -- that's
    -- the "insanely inaccurate" feedback. AssemblyLinearVelocity is the
    -- right velocity source for a HumanoidRootPart in a movable assembly.
    local tVel = tRoot.AssemblyLinearVelocity
    local lookPos = tRoot.Position
        + (tVel * state.getLeadTime())
        + Vector3.new(0, state.lockHeightOffset or 0, 0)
    local desired = lookPos - camPos
    if desired.Magnitude < 0.5 then
        if s.lastDir then
            cam.CFrame = CFrame.new(camPos, camPos + s.lastDir)
        end
        return
    end
    local dir = desired.Unit

    if state.resistance_enabled then
        local currentLook = cam.CFrame.LookVector
        local cosTheta = math.clamp(currentLook:Dot(dir), -1, 1)
        local angleDeg = math.deg(math.acos(cosTheta))
        if angleDeg < (state.resistance_threshold or 0) then
            s.lastDir = currentLook
            return
        end
        local smoothness = (state.resistance_strength or 0.5) * 20
        local alpha = 1 - math.exp(-smoothness * (dt or 1/60))
        local blended = currentLook:Lerp(dir, alpha)
        if blended.Magnitude > 0.001 then dir = blended.Unit end
    end

    s.lastDir = dir
    cam.CFrame = CFrame.new(camPos, camPos + dir)
end

function LockOn.setEnabled(v)
    state.lockon_enabled = v and true or false
end

function LockOn.init()
    if s.bound then return end
    RunService:BindToRenderStep(CAM_BIND, Enum.RenderPriority.Camera.Value + 1, cameraStep)
    s.bound = true
end

function LockOn.destroy()
    if s.bound then
        pcall(function() RunService:UnbindFromRenderStep(CAM_BIND) end)
        s.bound = false
    end
end

return LockOn
end

_MODULES["modules.aim.target_select"] = function()
-- Target Select: picks and holds a target, triggers Highlight. Lock-On and
-- Rotation Lock read state.target to know who to aim at. Owns the toggle/hold
-- hotkey (default X).

local state     = require("modules.aim.state")
local targeting = require("modules.aim.targeting")
local highlight = require("modules.aim.highlight")

local RunService = game:GetService("RunService")

local TargetSelect = {}

local s = {
    holdMode   = false,
    holdActive = false,
    heartConn  = nil,
    lastStep   = 0,
}

-- Target validity + highlight/swap-target recompute run on a throttle, not every
-- frame. getBestTarget() loops every player (and raycasts per player when the
-- visibility check is on) -- doing that 240x/s in a crowded server is the main
-- source of the "choppy sometimes" hitching. 30 Hz keeps the health bar and
-- target-release responsive while cutting the scan rate ~8x. The actual aim
-- (lockon camera + rotation_lock body) stays per-frame and is untouched.
local STEP_INTERVAL = 1 / 30

local function releaseTarget()
    state.setTarget(nil, nil)
    s.holdActive = false
    highlight.update(nil, nil)
end

local function engageTarget()
    local t, ty = targeting.getBestTarget()
    if not t then return false end
    state.setTarget(t, ty)
    return true
end

function TargetSelect.swapTarget()
    if not state.swap_enabled then return end
    if not state.target_select_enabled or not state.target then return end
    local next_, ty = targeting.getBestTarget(state.target)
    if next_ then state.setTarget(next_, ty) end
end

local function step()
    if not state.target_select_enabled then return end
    if not state.target then return end

    local now = os.clock()
    if now - s.lastStep < STEP_INTERVAL then return end
    s.lastStep = now

    local t = state.target
    if state.target_type == "player" then
        local char = t and t.Character
        local hum  = char and char:FindFirstChildOfClass("Humanoid")
        if not hum or hum.Health <= 0 or not char.Parent or state.isFriendly(t) then
            releaseTarget()
            return
        end
    elseif state.target_type == "npc" then
        local hum = t and t:FindFirstChildOfClass("Humanoid")
        if not hum or hum.Health <= 0 or not t.Parent then
            releaseTarget()
            return
        end
    end

    highlight.update(t, function(exclude) return targeting.getBestTarget(exclude) end)
end

function TargetSelect.hotkeyPress()
    if not state.target_select_enabled then return end
    if s.holdMode then
        if not state.target then engageTarget() end
        s.holdActive = true
    else
        if state.target then releaseTarget() else engageTarget() end
    end
end

function TargetSelect.hotkeyRelease()
    if s.holdMode and s.holdActive and state.target then
        releaseTarget()
    end
end

function TargetSelect.setHoldMode(v)
    s.holdMode = v and true or false
end

function TargetSelect.setEnabled(v)
    state.target_select_enabled = v and true or false
    if not v then releaseTarget() end
end

function TargetSelect.init()
    s.heartConn = RunService.Heartbeat:Connect(step)
end

function TargetSelect.destroy()
    if s.heartConn then s.heartConn:Disconnect(); s.heartConn = nil end
end

return TargetSelect
end

_MODULES["modules.aim.init"] = function()
-- Aim Assist: declarative feature definitions across three categories.
-- Target Select picks the target, Lock-On applies aim assist (camera + rotation
-- sub-toggles), Highlight reflects the selected target.

local window       = require("ui.window")
local container    = require("ui.container")
local feature      = require("ui.feature")
local state        = require("modules.aim.state")
local highlight    = require("modules.aim.highlight")
local shiftlock    = require("modules.aim.shiftlock")
local rotationLock = require("modules.aim.rotation_lock")
local lockon       = require("modules.aim.lockon")
local targetSelect = require("modules.aim.target_select")
local log          = require("core.log")

local module = {}

function module.register()
    -- Boot the implementations
    highlight.init()
    shiftlock.init()
    rotationLock.init()
    lockon.init()
    targetSelect.init()
    -- Shiftlock's rotation pin yields while Rotation Lock drives the body so
    -- the two don't fight over the character's facing.
    shiftlock.setExternalSkipRotation(function()
        return rotationLock.isActive()
    end)

    -- Expose Lock-On's sub-toggles to the Tech Builder's "Use" step (they aren't
    -- standalone feature rows, so feature.all() wouldn't list them otherwise).
    feature.addInvokable({
        id   = "aim.rotationlock",
        name = "Rotation Lock (Lock-On+)",
        get  = function() return state.rotationLockEnabled and rotationLock.isActive() end,
        set  = function(v)
            rotationLock.setEnabled(v)
            if v then rotationLock.hotkeyPress() else rotationLock.hotkeyRelease() end
        end,
    })
    feature.addInvokable({
        id   = "aim.cameralock",
        name = "Camera Lock",
        get  = function() return state.cameraLockEnabled end,
        set  = function(v) state.cameraLockEnabled = v and true or false end,
    })

    local parent = window.parent()

    -- 1. Movement -------------------------------------------------------------
    local move = container.new(parent, "Movement")
    move:add(feature.declare({
        id          = "aim.shiftlock",
        name        = "Custom Shiftlock",
        description = "Locks your mouse to the center of the screen and rotates your character to face the camera. Replaces Roblox's built-in shift-lock and disconnects competing shift-lock loops from other scripts on enable, disable, and boot.",
        default     = false,
        defaultKey  = Enum.KeyCode.LeftShift,
        onToggle    = function(v) shiftlock.setEnabled(v) end,
        -- Key only toggles the lock when the feature master toggle is on.
        -- shiftlock.toggle() returns early otherwise, matching target_select
        -- and rotation_lock's pattern. Previously this auto-enabled the
        -- feature on Shift press, which made walking silently turn shiftlock
        -- on while the UI button still showed OFF.
        onKey       = function() shiftlock.toggle() end,
        settings = {
            -- Pair WITH the game's own shiftlock instead of running a competing one:
            -- Pantheon syncs its on/off to the game's and keeps rotating, but lets
            -- the game own the cursor (no fight). Turn on in games with their own
            -- shiftlock, e.g. JJS (the JJS module auto-enables it). Off => Pantheon
            -- runs its own standalone shiftlock.
            { type = "toggle", name = "Pair with game's shiftlock",
              key = "mirror", default = false,
              onChange = function(v) shiftlock.setShiftlockMirror(v) end },
            { type = "toggle", name = "Kill foreign shiftlock GUIs / loops", default = true,
              onChange = function(v) shiftlock.setKillForeign(v) end },
            -- Off (default) => rotation fires through grab welds, matching
            -- the normal-player behavior in games like JJS where Decisive
            -- Strikes welds the victim but the game doesn't lock rotation.
            -- Game-imposed lock states (bleedout / PlatformStand / Ragdoll
            -- / Physics / Dead) are already caught further up the rotation
            -- pass. On => Battlegrounds-style safety: skip rotation while
            -- welded so the victim isn't dragged around with you.
            { type = "toggle", name = "Skip rotation while welded to enemy",
              key = "weld_safety", default = false,
              onChange = function(v) state.weldSafetyEnabled = v end },
            -- On => when Pantheon shiftlock is off, yield the pin pass +
            -- hook so the game's own shiftlock (custom in-game script or
            -- Roblox's vanilla MouseLockController) can drive the cursor.
            -- Pantheon still fully owns cursor state while its own
            -- shiftlock is on. Off (default) => Pantheon enforces free
            -- movement when its shiftlock is off; no game shiftlock.
            { type = "toggle", name = "Allow game shiftlock when Pantheon off",
              key = "allow_game", default = false,
              onChange = function(v) shiftlock.setAllowGameShiftlock(v) end },
        },
    }).root)

    -- 2. Combat ---------------------------------------------------------------
    local combat = container.new(parent, "Combat")

    -- Target Select: owns the X hotkey, picks targets, triggers Highlight.
    combat:add(feature.declare({
        id           = "aim.target_select",
        name         = "Target Select",
        description  = "Picks the nearest valid target (with optional FOV / health / visibility / range filters) and triggers the Highlight. Lock-On and Rotation Lock read the chosen target. Hold-mode releases when you release the key; toggle-mode latches.",
        default      = false,
        defaultKey   = Enum.KeyCode.X,
        onToggle     = function(v) targetSelect.setEnabled(v) end,
        onKey        = function() targetSelect.hotkeyPress()   end,
        onKeyRelease = function() targetSelect.hotkeyRelease() end,
        settings = {
            { type = "toggle", name = "Hold mode (vs toggle)", default = false,
              onChange = function(v) targetSelect.setHoldMode(v) end },
            -- Bot Mode: also consider NPCs / mobs (anything with a Humanoid that
            -- isn't a player), not just other players. Lock-On / Rotation Lock /
            -- Highlight all handle an NPC target the same as a player one.
            { type = "toggle", name = "Bot Mode (lock onto NPCs)", key = "bot_mode", default = false,
              onChange = function(v) state.botMode = v and true or false end },
            { type = "toggle", name = "Skip dead / shielded", default = true,
              onChange = function(v) state.checkHealthEnabled = v end },
            { type = "slider", name = "Range (0 = inf)",
              min = 0, max = 500, step = 5, default = 0,
              onChange = function(v) state.rangeLimit = v end },
        },
    }).root)

    -- Lock-On: aim-assist applicator. Master toggle plus sub-toggles for
    -- Camera Lock and Rotation Lock so the user can mix-and-match.
    -- Depends on Target Select (needs a target to lock onto).
    combat:add(feature.declare({
        id           = "aim.lockon",
        name         = "Lock-On",
        description  = "Applies aim assist to the target picked by Target Select. Sub-toggles let you mix the type: Camera Lock forces the camera to look at the target, Rotation Lock (its own keybind) spins your body to face them. Resistance gives you a free-aim deadzone before the camera pull kicks in.",
        default      = false,
        dependencies = { "aim.target_select" },
        onToggle     = function(v) lockon.setEnabled(v) end,
        settings = {
            { type = "section", name = "Types" },
            { type = "toggle", name = "Camera Lock", default = true,
              onChange = function(v) state.cameraLockEnabled = v end },
            { type = "toggle", name = "Rotation Lock", default = false,
              onChange = function(v) rotationLock.setEnabled(v) end },
            { type = "keybind", name = "Rotation Lock key",
              id       = "aim.rotation_lock",
              default  = Enum.KeyCode.Q,
              onPress  = function() rotationLock.hotkeyPress()   end,
              onRelease= function() rotationLock.hotkeyRelease() end },
            { type = "toggle", name = "Rotation Lock hold mode", default = true,
              onChange = function(v) rotationLock.setHoldMode(v) end },
            { type = "toggle", name = "Battlegrounds-safe", default = true,
              onChange = function(v) state.bgSafeEnabled = v end },

            -- Aim lead: lockon's camera + rotation_lock's body both shift
            -- their aim by (target.AssemblyLinearVelocity * lead). With
            -- Auto on, the lead self-tunes from the TARGET'S TANGENTIAL
            -- VELOCITY RELATIVE TO YOU (the orbit/strafe part the camera
            -- must rotate to chase) -- pumps up for fast players + skilled
            -- close orbits (high angular rate), drops to zero for stationary
            -- or charging-at-you targets. The slider below is the manual
            -- fallback used only when Auto is off.
            { type = "toggle", name = "Auto prediction (velocity-based)", default = true,
              onChange = function(v) state.predictionAuto = v end },
            -- Below this tangential speed (stud/s, orbit/strafe component
            -- relative to you), auto prediction returns 0 lead -- so casual
            -- walking targets don't get pre-judged. Persists via feature.lua
            -- like every other slider in this panel.
            { type = "slider", name = "Auto prediction threshold (stud/s)",
              key = "prediction_threshold", min = 0, max = 50, step = 1, default = 20,
              onChange = function(v) state.predictionThreshold = v end },
            { type = "slider", name = "Aim prediction (s, manual)",
              key = "prediction", min = 0, max = 0.3, step = 0.01, default = 0.1,
              onChange = function(v) state.predictionTime = v end },

            { type = "section", name = "Resistance" },
            { type = "toggle", name = "Enable Resistance", default = false,
              onChange = function(v) state.resistance_enabled = v end },
            { type = "slider", name = "Threshold (deg)",
              min = 0, max = 30, step = 1, default = 5,
              onChange = function(v) state.resistance_threshold = v end },
            { type = "slider", name = "Strength",
              min = 0.05, max = 1, step = 0.05, default = 0.5,
              onChange = function(v) state.resistance_strength = v end },
        },
    }).root)

    -- Swap Target: cycles to the next-best target while Target Select is engaged.
    -- Depends on Target Select (nothing to swap from without a current target).
    combat:add(feature.declare({
        id           = "aim.swap_target",
        name         = "Swap Target",
        description  = "While Target Select has a target, press this key to cycle to the next-best target.",
        default      = true,
        defaultKey   = Enum.KeyCode.C,
        dependencies = { "aim.target_select" },
        onToggle     = function(v) state.swap_enabled = v end,
        onKey        = function() targetSelect.swapTarget() end,
    }).root)

    -- 3. Visuals --------------------------------------------------------------
    -- Highlight depends on Target Select (renders nothing without a target).
    local vis = container.new(parent, "Visuals")
    vis:add(feature.declare({
        id           = "aim.highlight",
        name         = "Highlight",
        description  = "Target visuals: red outline on the active target, yellow on the swap target (the next-best one Swap Target would cycle to), and a top-center HUD showing the current target's name + a live health bar. Self-fade drops your own character's opacity so you don't get blocked by your own back.",
        default      = true,
        dependencies = { "aim.target_select" },
        onToggle     = function(v) highlight.setEnabled(v) end,
        settings = {
            { type = "toggle", name = "Highlight swap target (yellow)", key = "swap_highlight", default = true,
              onChange = function(v) highlight.setSecondEnabled(v) end },
            { type = "toggle", name = "Target info (health bar + name)", key = "target_info", default = true,
              onChange = function(v) highlight.setTargetInfo(v) end },
            { type = "toggle", name = "Self-fade", default = false,
              onChange = function(v) highlight.setSelfFade(v) end },
        },
    }).root)

    log.info("Aim Assist registered (Movement / Combat / Visuals)")
end

function module.destroy()
    pcall(function() if targetSelect.destroy then targetSelect.destroy() end end)
    pcall(function() if rotationLock.destroy then rotationLock.destroy() end end)
    pcall(function() if lockon.destroy       then lockon.destroy()       end end)
    pcall(function() if shiftlock.destroy    then shiftlock.destroy()    end end)
    pcall(function() if highlight.destroy    then highlight.destroy()    end end)
end

return module
end

_MODULES["modules.tech.engine"] = function()
-- Tech Builder engine.
--
-- A "tech" = a TRIGGER (event + conditions) -> an ordered list of ACTIONS. The
-- engine is data-driven and extensible: EVENTS, CONDITIONS and ACTIONS are open
-- registries so new types drop in without reworking the runner.
--
--   trigger = { event = "key"|"keyhold"|"move", key = KeyCode, move = "ServiceName",
--               conditions = { "locked_on", ... } }
--   actions = { {type="look", x=180,y=0,z=0}, {type="wait", seconds=0.5}, {type="return"},
--               {type="rotate", x=180}, {type="feature", feature="aim.rotation_lock", value=true} }
--
-- Look/Rotate are TARGET-RELATIVE (yaw 0 = at the lock target, 180 = facing away),
-- ported from the lock-on script's reverse-lock. While a Look/Rotate step is held,
-- the engine sets state.techCamOverride / techBodyOverride so Lock-On / Rotation
-- Lock yield; Return clears them and hands control back (re-aims at the target).

local state    = require("modules.aim.state")
local feature  = require("ui.feature")
local keybinds = require("core.keybinds")
local persist  = require("core.persist")
local log      = require("core.log")
local Signal   = require("core.signal")
local scanner  = require("modules.tech.scanner")

local Players    = game:GetService("Players")
local RunService = game:GetService("RunService")
local Workspace  = game:GetService("Workspace")
local RS         = game:GetService("ReplicatedStorage")
local VIM        = game:GetService("VirtualInputManager")
local UIS        = game:GetService("UserInputService")
local CAS        = game:GetService("ContextActionService")

local Engine = {}
Engine.changed = Signal.new()   -- fires when the tech set changes (UI list re-reads it)
local LP = Players.LocalPlayer

local techs = {}     -- id -> tech def
local conns = {}     -- id -> { Connection, ... } (move-trigger listeners)
local casBound = {}  -- id -> CAS action name (suppress move triggers that sink the key)
local RENDER_BIND = "PantheonTechHold"
local bound = false
local drainConn          -- Heartbeat that runs queued techs off the trigger signal thread
local targetChangedConn  -- state.onTargetChanged subscription (re-hooks target_anim)
local charAddedConn      -- LP.CharacterAdded subscription (re-hooks the Animator on respawn)

-- held camera/body facings; the render loop enforces these each frame while set.
local held = { cam = nil, body = nil }   -- each = { yaw, pitch } degrees, target-relative
local startCamLook                        -- camera LookVector at tech start (no-target fallback)
local startBodyLook                        -- root LookVector at tech start (no-target fallback)
local bodyARDisabled = false              -- did a Rotate step turn off Humanoid.AutoRotate?
local techAlign, techAttach               -- rigid AlignOrientation body-rotate (same type as Lock-On+)

-- ===== geometry =====
local function myChar() return LP.Character end
local function myRoot() local c = myChar(); return c and c:FindFirstChild("HumanoidRootPart") end
local function targetRoot()
    local t = state.target
    if not t then return nil end
    local ch = (state.target_type == "npc") and t or t.Character
    return ch and ch:FindFirstChild("HumanoidRootPart")
end

local function offsetDir(baseFlat, yawDeg)
    if baseFlat.Magnitude < 1e-3 then return baseFlat end
    return (CFrame.fromAxisAngle(Vector3.yAxis, math.rad(yawDeg or 0)) * baseFlat).Unit
end

local function camBaseFlat()
    local cam = Workspace.CurrentCamera
    local tr = targetRoot()
    if tr and cam then local d = tr.Position - cam.CFrame.Position; return Vector3.new(d.X, 0, d.Z) end
    if startCamLook then return Vector3.new(startCamLook.X, 0, startCamLook.Z) end
    return cam and Vector3.new(cam.CFrame.LookVector.X, 0, cam.CFrame.LookVector.Z) or Vector3.zAxis
end

-- Rotate is BODY-ONLY: yaw is an offset from the body's facing CAPTURED AT TECH
-- START (yaw 0 = same as start, 180 = opposite). NOT camera-relative, NOT
-- target-relative (Look handles target-relative camera). Anchoring to the start
-- facing (not live LookVector) avoids per-frame yaw compounding -> spin.
local function bodyBaseFlat()
    if startBodyLook then return Vector3.new(startBodyLook.X, 0, startBodyLook.Z) end
    local r = myRoot()
    if r then local l = r.CFrame.LookVector; return Vector3.new(l.X, 0, l.Z) end
    return Vector3.zAxis
end

-- Lock-On+ (rotation_lock) faces the body with a rigid AlignOrientation; the
-- Rotate action reuses that exact mechanism (its own instance so it doesn't fight
-- rotation_lock's) for identical feel/replication instead of a raw CFrame snap.
local function ensureBodyConstraint(root)
    if not techAttach or not techAttach.Parent then
        techAttach = Instance.new("Attachment")
        techAttach.Name = "PantheonTechAlignAtt"
        techAttach.Parent = root
    end
    if not techAlign or not techAlign.Parent then
        techAlign = Instance.new("AlignOrientation")
        techAlign.Name = "PantheonTechAlign"
        techAlign.Mode = Enum.OrientationAlignmentMode.OneAttachment
        techAlign.Attachment0 = techAttach
        techAlign.RigidityEnabled = true
        techAlign.Responsiveness = 200
        techAlign.MaxTorque = math.huge
        techAlign.Parent = root
    end
end

local function applyCamHold()
    if not held.cam then return end
    local cam = Workspace.CurrentCamera
    local base = camBaseFlat()
    if cam and base.Magnitude > 1e-3 then
        local dir = offsetDir(base, held.cam.yaw)
        local pitch = math.rad(held.cam.pitch or 0)
        local look = Vector3.new(dir.X * math.cos(pitch), math.sin(pitch), dir.Z * math.cos(pitch))
        cam.CFrame = CFrame.new(cam.CFrame.Position, cam.CFrame.Position + look)
    end
end
local function applyBodyHold()
    if not held.body then return end
    local root = myRoot()
    local base = bodyBaseFlat()
    if root and base.Magnitude > 1e-3 then
        local ch = myChar()
        local hum = ch and ch:FindFirstChildOfClass("Humanoid")
        if hum and hum.AutoRotate then hum.AutoRotate = false; bodyARDisabled = true end
        local dir = offsetDir(base, held.body.yaw)
        ensureBodyConstraint(root)
        techAlign.Enabled = true
        techAlign.CFrame = CFrame.lookAt(Vector3.zero, dir)
        local cf = CFrame.lookAt(root.Position, root.Position + dir)
        local _, yAngle = cf:ToEulerAnglesYXZ()
        root.CFrame = CFrame.new(root.Position) * CFrame.Angles(0, yAngle, 0)
    end
end
local function renderHold() applyCamHold(); applyBodyHold() end

-- Releases cam/body override flags. If `snap` is true (explicit Return / bounded
-- During->Wait / keyhold release / shutdown), also snaps cam+body back to where
-- the tech started. Default false: rotation PERSISTS until the next move/input
-- naturally turns you, which is the desired behavior when a tech rotates and
-- never adds a Return -- otherwise a 180 instantly snaps back at one-shot end.
local function releaseHold(snap)
    local didRotate = bodyARDisabled   -- a Rotate step actually turned the body
    -- The old "snap camera to body yaw under shiftlock so rotation persists"
    -- path is removed -- the camera flip at one-shot end was disorienting.
    -- Trade-off: without the snap, the rotation does NOT persist under
    -- shiftlock past tech end (the game's shiftlock snaps body back to face
    -- camera on its next pass). For techs that rotate just to align a quick
    -- cast (e.g. Rotate 180 + Use PB) this is exactly right -- rotation
    -- holds DURING the actions and naturally releases at the end. For
    -- "rotate-and-stay-rotated" use a keyhold-event tech instead.
    held.cam, held.body = nil, nil
    state.techCamOverride = false
    state.techBodyOverride = false
    if bodyARDisabled then
        local ch = myChar()
        local hum = ch and ch:FindFirstChildOfClass("Humanoid")
        if hum then hum.AutoRotate = true end
        bodyARDisabled = false
    end
    if techAlign then techAlign.Enabled = false end
    if snap and not (state.lockon_enabled and state.target) then
        local cam = Workspace.CurrentCamera
        if cam and startCamLook then cam.CFrame = CFrame.new(cam.CFrame.Position, cam.CFrame.Position + startCamLook) end
        if didRotate and startBodyLook then
            local root = myRoot()
            local flat = Vector3.new(startBodyLook.X, 0, startBodyLook.Z)
            if root and flat.Magnitude > 1e-3 then
                root.CFrame = CFrame.lookAt(root.Position, root.Position + flat.Unit)
            end
        end
    end
end

-- ===== actions =====
local ACTIONS = {}
-- Apply immediately (in addition to setting the held state for renderhold to
-- re-apply each frame), so a single-step Rotate/Look with no Wait after still
-- visibly turns the body/camera -- runner had time to finish the action and
-- restoreAll BEFORE the next render frame ever fired renderhold.
ACTIONS.look   = function(a) held.cam  = { yaw = a.x or 0, pitch = a.y or 0 }; state.techCamOverride  = true; applyCamHold()  end
ACTIONS.rotate = function(a) held.body = { yaw = a.x or 0, pitch = a.y or 0 }; state.techBodyOverride = true; applyBodyHold() end
ACTIONS.wait   = function(a) task.wait(a.seconds or a.x or 0.5) end
ACTIONS["return"] = function() releaseHold(true) end
ACTIONS.feature = function(a)
    if a.value == nil then feature.fire(a.feature) else feature.setEnabled(a.feature, a.value) end
end
-- send a real keyboard key (a.key is the short name, e.g. "R"), so a tech can
-- press keys -- e.g. fire a game move via its keybind, dash, jump, etc.
ACTIONS.key = function(a)
    local kc = a.key and Enum.KeyCode[a.key]
    if not kc then return end
    VIM:SendKeyEvent(true, kc, false, game)
    task.wait(tonumber(a.hold) or 0.04)
    VIM:SendKeyEvent(false, kc, false, game)
end
Engine.ACTIONS = ACTIONS

-- ===== conditions =====
-- Conditions receive the firing tech so parametrized checks (e.g. target
-- playing a specific anim) can read the id out of trigger.<field>. Stateless
-- checks just ignore the arg.
local CONDITIONS = {}
-- "Locked on" = TARGET SELECT is engaged on someone: the feature is on AND holds a
-- target. Bound to Target Select (the user's actual lock), NOT the Lock-On camera.
-- state.target is written/cleared ONLY by Target Select -- setEnabled(false) and
-- target death both releaseTarget() -- so this is true exactly while you're locked
-- onto a live target and false the instant you drop it. (state.target alone would
-- behave the same since only Target Select sets it; the explicit flag makes the
-- binding unambiguous.)
CONDITIONS.locked_on = function() return state.target_select_enabled == true and state.target ~= nil end
CONDITIONS.shiftlock = function() return state.shiftlock_active == true end

-- target_playing: TRUE iff the current target's Animator currently has a track
-- playing whose AnimationId contains the configured trigger.targetAnimId. Pairs
-- naturally with trigger.maxRange to give "within X studs AND target playing Y".
CONDITIONS.target_playing = function(tech)
    local want = tech and tech.trigger and tech.trigger.targetAnimId
    if not want or want == "" then return true end
    local t = state.target
    if not t then return false end
    local ch = (state.target_type == "npc") and t or t.Character
    if not ch then return false end
    local hum = ch:FindFirstChildOfClass("Humanoid")
    local animator = hum and hum:FindFirstChildOfClass("Animator")
    if not animator then return false end
    local idNum = tostring(want):match("(%d+)")
    if not idNum then return false end
    local ok, tracks = pcall(function() return animator:GetPlayingAnimationTracks() end)
    if not ok or not tracks then return false end
    for _, track in ipairs(tracks) do
        local a = track.Animation
        if a and tostring(a.AnimationId):find(idNum, 1, true) then return true end
    end
    return false
end

Engine.CONDITIONS = CONDITIONS

-- A move key hint can be a DIGIT ("1".."9") but Enum.KeyCode["1"] THROWS (the
-- member is "One"). Map digits to names and look up safely so a numbered move key
-- never errors out wiring/dispatch.
local DIGIT_NAMES = { ["0"]="Zero",["1"]="One",["2"]="Two",["3"]="Three",["4"]="Four",
                      ["5"]="Five",["6"]="Six",["7"]="Seven",["8"]="Eight",["9"]="Nine" }
local function safeKeyCode(name)
    if not name then return nil end
    name = DIGIT_NAMES[tostring(name)] or name
    local ok, kc = pcall(function() return Enum.KeyCode[name] end)
    return ok and kc or nil
end

-- optional modifier key that must be HELD for a key/move trigger to fire
-- (e.g. hold A + press Q). Takes a TRIGGER (not the whole tech) so multi-
-- trigger "or" techs can have per-subtrigger modkeys.
local function modifierHeld(trig)
    local m = trig and trig.modkey
    if not m then return true end
    local kc = safeKeyCode(m)
    return kc ~= nil and UIS:IsKeyDown(kc)
end

-- Iterate every trigger registered on a tech. For event="or" techs the
-- subtriggers[] array is the actual fire list; for legacy single-trigger
-- techs it's just {tech.trigger}. Yields (index, trig) so callers can
-- pass the index down to queueRun -> runTech.ctx.triggerIndex.
local function techTriggers(tech)
    local trig = tech.trigger
    if trig and trig.event == "or" and type(trig.subtriggers) == "table" then
        return trig.subtriggers
    elseif trig then
        return { trig }
    end
    return {}
end

-- Takes the FIRING trigger so an "or" tech's per-subtrigger conditions/maxRange
-- are honored (they live on each subtrigger, not the top-level "or" wrapper).
-- Legacy single-trigger techs pass trig == tech.trigger, so the fallback keeps
-- their behavior identical.
local function conditionsMet(tech, trig)
    trig = trig or tech.trigger
    for _, c in ipairs(trig.conditions or {}) do
        local fn = CONDITIONS[c]
        if fn and not fn(tech) then return false end
    end
    -- distance gate: only fire within maxRange studs of the target (0/nil = any).
    -- Needs a target (lock-on / target select); fails closed if there's none.
    local maxR = tonumber(trig.maxRange)
    if maxR and maxR > 0 then
        local mr, tr = myRoot(), targetRoot()
        if not (mr and tr) then return false end
        if (tr.Position - mr.Position).Magnitude > maxR then return false end
    end
    return true
end

-- Scope gate at trigger fire time. Universal techs always match; numeric scopes
-- match by PlaceId or GameId; "char:<name>" scopes call the current game's
-- detectCharacter() and compare. Unknown / unmatched scopes block the fire.
local function scopeMatches(tech)
    local s = tech.scope
    if s == nil or s == "universal" then return true end
    if s == game.PlaceId or s == game.GameId then return true end
    if type(s) == "string" then
        local want = s:match("^char:(.+)$")
        if want then
            local ok_reg, registry = pcall(require, "games.registry")
            if not ok_reg or not registry then return false end
            local mod = registry.current()
            local detect = mod and mod.detectCharacter
            if type(detect) ~= "function" then return false end
            local ok, cur = pcall(detect)
            return ok and cur == want or false
        end
    end
    return false
end
Engine.scopeMatches = scopeMatches

-- ===== move buttons: fire + suppress =====
-- Resolve a hotbar move button by the name the scanner recorded for it (e.g. TSB
-- slot "1"). Re-scans so it tracks the live GUI.
-- Pass a pre-scanned `res` to reuse one scan across many lookups (applySuppression
-- does this so it doesn't walk the whole PlayerGui once per suppressed tech).
local function findMoveButton(name, res)
    if not name then return nil end
    if not res then
        local ok, r = pcall(function() return scanner.scan() end)
        if not ok or not r then return nil end
        res = r
    end
    for _, b in ipairs(res.buttons or {}) do
        if b.name == name and b.button and b.button.Parent then return b.button end
    end
    return nil
end

-- executor connection helpers (Wave: getconnections/firesignal). Used to "cancel"
-- a move button's own click handlers so its key/click no longer fires the move,
-- and to fire it ourselves on demand.
local suppressed = {}   -- [button] = { connection, ... } we've disabled
local function getConns(sig)
    if typeof(getconnections) ~= "function" then return nil end
    local ok, r = pcall(getconnections, sig)
    if ok and type(r) == "table" then return r end
    return nil
end
local function suppressButton(btn)
    if not btn or suppressed[btn] then return end
    local cs = getConns(btn.Activated); if not cs then return end
    for _, c in ipairs(cs) do pcall(function() c:Disable() end) end
    suppressed[btn] = cs
end
local function unsuppressButton(btn)
    local cs = suppressed[btn]; if not cs then return end
    for _, c in ipairs(cs) do pcall(function() c:Enable() end) end
    suppressed[btn] = nil
end

-- Fire the click signal a button ACTUALLY has handlers on -- firing an empty signal
-- "succeeds" but does nothing, so we must check getconnections first and pick the
-- live one (Activated / MouseButton1Click / MouseButton1Down+Up). Returns true if
-- something was actually fired.
local function fireSignalsOf(b)
    if typeof(firesignal) ~= "function" then return false end
    -- Action move buttons fire on PRESS, and the MouseButton1Down/Up handlers take
    -- (x, y), so pass the button center. Try down(+up) FIRST (TSB fires here -- a
    -- prior build fired Click and nothing happened), then click, then activated.
    local cx = b.AbsolutePosition.X + b.AbsoluteSize.X / 2
    local cy = b.AbsolutePosition.Y + b.AbsoluteSize.Y / 2
    local down = getConns(b.MouseButton1Down)
    if down and #down > 0 then
        pcall(firesignal, b.MouseButton1Down, cx, cy)
        local up = getConns(b.MouseButton1Up)
        if up and #up > 0 then pcall(firesignal, b.MouseButton1Up, cx, cy) end
        return true
    end
    local click = getConns(b.MouseButton1Click)
    if click and #click > 0 then pcall(firesignal, b.MouseButton1Click); return true end
    local act = getConns(b.Activated)
    if act and #act > 0 then pcall(firesignal, b.Activated); return true end
    return false
end

-- Fire a move button as if clicked. If it's currently suppressed, briefly re-enable
-- its handlers so our fire lands, then re-suppress -- so a tech can be the ONLY
-- thing that fires a move whose key we've cancelled. Tries the button itself, then
-- any descendant button (the real handler is often on an inner "Base" button), then
-- a real mouse click as a last resort.
local function fireButton(btn)
    if not btn then return end
    local supp = suppressed[btn]
    if supp then for _, c in ipairs(supp) do pcall(function() c:Enable() end) end end
    local fired = fireSignalsOf(btn)
    if not fired then
        for _, c in ipairs(btn:GetDescendants()) do
            if (c:IsA("TextButton") or c:IsA("ImageButton")) and fireSignalsOf(c) then fired = true; break end
        end
    end
    if not fired then
        -- last resort: a real mouse click at the button's center (GuiInset offset)
        local p, s = btn.AbsolutePosition, btn.AbsoluteSize
        local x, y = p.X + s.X / 2, p.Y + s.Y / 2 + 36
        pcall(function()
            VIM:SendMouseButtonEvent(x, y, 0, true, game, 0)
            task.wait()
            VIM:SendMouseButtonEvent(x, y, 0, false, game, 0)
        end)
    end
    if supp then task.defer(function() for _, c in ipairs(supp) do pcall(function() c:Disable() end) end end) end
end

-- Flag-based CAS sink bypass: while bypassKeys[kc] is true, any Pantheon CAS
-- sink for that key returns Pass instead of Sink, so the VIM-sent key reaches
-- the game's handler instead of being swallowed (and re-triggering us). Cleaner
-- than unbind/rebind -- no race window, sink stays bound throughout.
Engine.bypassKeys = {}
local bypassKeys = Engine.bypassKeys

local function fireKeyBypass(kc)
    if not kc or kc == Enum.KeyCode.Unknown then return end
    -- Fully release the body-pin for the VIM key window. A previous AR-only
    -- restore wasn't enough: renderHold's applyBodyHold ran on every frame
    -- during the 60ms wait and (a) re-set AutoRotate=false, (b) re-enabled the
    -- rigid AlignOrientation with infinite torque, (c) re-wrote root.CFrame --
    -- which kept JJS's Projection Breaker (and similar gated casts) from
    -- starting even though we'd briefly set AR=true. Clearing held.body makes
    -- applyBodyHold early-exit, we also explicitly drop the AlignOrientation
    -- and lift AR, fire the key, then restore so the rotation snaps back via
    -- the next applyBodyHold tick (the held.body value is preserved).
    local ch = myChar()
    local hum = ch and ch:FindFirstChildOfClass("Humanoid")
    local wasARDisabled = bodyARDisabled
    local savedBody = held.body
    held.body = nil
    if techAlign then techAlign.Enabled = false end
    if hum and (not hum.AutoRotate) then hum.AutoRotate = true end
    bypassKeys[kc] = true
    pcall(function() VIM:SendKeyEvent(true, kc, false, game) end)
    task.wait(0.06)
    pcall(function() VIM:SendKeyEvent(false, kc, false, game) end)
    bypassKeys[kc] = nil
    held.body = savedBody
    if not savedBody then
        -- nothing left holding; if AR had been disabled, leave it for the
        -- runner's restoreAll/releaseHold to clean up (bodyARDisabled flag).
        if wasARDisabled and hum and hum.Parent then hum.AutoRotate = false end
    end
    -- if savedBody was set, next renderHold tick's applyBodyHold re-disables
    -- AR + re-enables techAlign + re-pins root.CFrame to the held facing.
end

-- ACTION: fire a move via its scanned entry. Order of attempts:
-- 1. Per-game `useMove(name, entry)` hook on the current game module (if it
--    exists and returns truthy) -- this is the DIRECT path that fires the
--    move's Knit RE itself (e.g. ProjectionBreakerService.RE.Activated:
--    FireServer()) -- the most reliable, since it bypasses VIM/CAS/animation
--    state gating entirely.
-- 2. useKey=true (JJS-style hotbar where keypress fires the move and the
--    button is visual-only): VIM-send the slot key with CAS bypass.
-- 3. Default: click the GUI button (TSB-style: button click fires the move).
-- a.move = scanned button name OR a hand-typed move name; a.key = key to press
-- (string name, e.g. "Q"/"One"); a.fire = "auto"|"button"|"key" (default auto).
ACTIONS.usebtn = function(a)
    local fire = a.fire or "auto"
    -- Always resolve the button from a LIVE scan -- the game rebuilds its hotbar
    -- (respawn, move swap) so any cached button reference goes dead. Never trust
    -- the cache for firing: re-find the CURRENT button by name on every fire.
    local res = scanner.scan()
    local entry
    for _, b in ipairs(res.buttons or {}) do
        if b.name == a.move then entry = b; break end
    end
    -- Explicit "press key": VIM the key. Works for MANUAL moves the scanner
    -- can't see (no live button to click) -- only needs a key.
    if fire == "key" then
        local kc = safeKeyCode(a.key or (entry and entry.key))
        if kc then fireKeyBypass(kc) end
        return
    end
    -- Auto: per-game direct hook first (fires the move's RE itself), then the
    -- JJS-style useKey hotbar (keypress fires, button is visual-only).
    if fire == "auto" then
        local ok_reg, registry = pcall(require, "games.registry")
        if ok_reg and registry then
            local mod = registry.current()
            if mod and type(mod.useMove) == "function" then
                local ok_um, handled = pcall(mod.useMove, a.move, entry)
                if ok_um and handled then return end
            end
        end
        if entry and entry.useKey and entry.key then
            local kc = safeKeyCode(entry.key)
            if kc then fireKeyBypass(kc); return end
        end
    end
    -- Click the GUI button ("button", or "auto" with a real button).
    if entry and entry.button then fireButton(entry.button); return end
    -- No live button (manual move / scan miss): fall back to a key press if one
    -- is set, so a typed move with a key still fires.
    local kc = safeKeyCode(a.key or (entry and entry.key))
    if kc then fireKeyBypass(kc) end
end

-- Reconcile which move buttons should be "cancelled" right now: every ENABLED
-- move tech whose trigger has suppress=true cancels its move button. Buttons no
-- longer wanted get re-enabled. Best-effort -- needs getconnections + the button
-- to exist; called from rewire and re-tried when techs change.
function Engine.applySuppression()
    local want = {}
    -- One hotbar scan for the whole pass; findMoveButton reuses it per tech.
    local ok, res = pcall(function() return scanner.scan() end)
    res = ok and res or nil
    for _, tech in pairs(techs) do
        local tr = tech.trigger
        if tech.enabled and tr and tr.event == "move" and tr.suppress then
            local b = findMoveButton(tr.move, res); if b then want[b] = true end
        end
    end
    for b in pairs(want) do suppressButton(b) end
    for b in pairs(suppressed) do if not want[b] then unsuppressButton(b) end end
end

-- ===== runner =====
-- Only one tech sequence drives the camera/body at a time. A second trigger
-- while one is mid-run (e.g. during a Wait) is ignored, so two techs can't fight
-- over the held facing. Hold techs run their (instant) actions and finish the
-- coroutine immediately, so `running` clears right away and re-pressing works.
local running = false

-- Single-step runner used by both the top-level action loop AND recursive
-- contexts (AND branches). ctx carries per-run state shared across branches
-- (releaseAfterWait flag, heldKeys, featRestore, restoreAll thunk) so e.g. a
-- key held in one branch is releasable from another or by the safety cleanup.
local function runStep(a, ctx)
    if a.type == "during" then
        -- the preceding Look/Rotate lasts only as long as the NEXT Wait,
        -- then auto-returns (so "Rotate -> During -> Wait 0.5" rotates for
        -- exactly 0.5s).
        ctx.releaseAfterWait = true
    elseif a.type == "wait" then
        task.wait(a.seconds or a.x or 0.5)
        if ctx.releaseAfterWait then releaseHold(true); ctx.releaseAfterWait = false end
    elseif a.type == "within" then
        -- gate: hold here until the target is within `studs`, then continue
        -- (e.g. rotate 90 -> Within 6 -> Use Rotation Lock -> side-dash).
        -- 6s cap so it can't hang if you never close the distance.
        local studs = tonumber(a.studs) or 5
        local t0 = os.clock()
        while os.clock() - t0 < 6 do
            local mr, tr = myRoot(), targetRoot()
            if mr and tr and (tr.Position - mr.Position).Magnitude <= studs then break end
            task.wait(0.05)
        end
        if ctx.releaseAfterWait then releaseHold(true); ctx.releaseAfterWait = false end
    elseif a.type == "hold" then
        -- press the key DOWN and keep it held until the matching Release
        -- (or the safety release at the end), so steps in between run while held.
        local kc = a.key and safeKeyCode(a.key)
        if kc then pcall(function() VIM:SendKeyEvent(true, kc, false, game) end); ctx.heldKeys[kc] = true end
    elseif a.type == "release" then
        local kc = a.key and safeKeyCode(a.key)
        if kc then pcall(function() VIM:SendKeyEvent(false, kc, false, game) end); ctx.heldKeys[kc] = nil end
    elseif a.type == "feature" then
        if a.feature then
            if ctx.featRestore[a.feature] == nil then ctx.featRestore[a.feature] = feature.getEnabled(a.feature) end
            if a.value == nil then feature.fire(a.feature) else feature.setEnabled(a.feature, a.value) end
        end
    elseif a.type == "return" then
        ctx.restoreAll(true)
    elseif a.type == "and" then
        -- AND step: run each branch as a parallel coroutine; the step finishes
        -- when ALL branches have completed. ctx is shared, so any Hold step
        -- in one branch is released by Release in another (or by the safety
        -- cleanup at tech end).
        local branches = a.branches or {}
        local n = #branches
        if n == 0 then return end
        local done = 0
        for _, branch in ipairs(branches) do
            task.spawn(function()
                for _, step in ipairs(branch or {}) do runStep(step, ctx) end
                done = done + 1
            end)
        end
        while done < n do task.wait(0.03) end
    elseif a.type == "or" then
        -- OR step: picks ONE branch based on which subtrigger fired this run.
        -- ctx.triggerIndex was set by runTech from the trigger that queueRun'd
        -- us. Branches and triggers are indexed 1:1; out-of-range falls
        -- through (no-op). Steps after the OR keep running in the main flow,
        -- so common "post-merge" actions can follow.
        local branches = a.branches or {}
        local idx = ctx.triggerIndex or 1
        local branch = branches[idx]
        if branch then
            for _, step in ipairs(branch) do runStep(step, ctx) end
        end
    else
        local fn = ACTIONS[a.type]
        if fn then
            local ok, err = pcall(fn, a)
            if not ok then log.warn("[tech] action " .. tostring(a.type) .. ": " .. tostring(err)) end
        end
    end
end

local function runTech(tech, hold, triggerIndex)
    if running then return end
    running = true
    task.spawn(function()
        local cam = Workspace.CurrentCamera
        startCamLook = cam and cam.CFrame.LookVector or nil
        local r0 = myRoot()
        startBodyLook = r0 and r0.CFrame.LookVector or nil
        -- "Ignore welds": keep Lock-On/Rotation alive even while welded for this run.
        -- For multi-trigger techs, the firing subtrigger's ignoreWelds wins.
        local triggers = techTriggers(tech)
        local firingTrig = triggers[triggerIndex or 1] or tech.trigger
        local ignoreWelds = firingTrig and firingTrig.ignoreWelds
        if ignoreWelds then state.techIgnoreWelds = true end
        local heldKeys = {}    -- keys pressed by a Hold step, released by a Release (or at the end)
        local featRestore = {} -- [featureId] = state BEFORE this tech toggled it, for Return/end
        local ctx = {
            releaseAfterWait = false, heldKeys = heldKeys, featRestore = featRestore,
            triggerIndex = triggerIndex or 1,   -- which subtrigger fired (OR step reads this)
        }
        ctx.restoreAll = function(snap)
            releaseHold(snap)
            for id, prev in pairs(featRestore) do pcall(function() feature.setEnabled(id, prev) end); featRestore[id] = nil end
            for kc in pairs(heldKeys) do pcall(function() VIM:SendKeyEvent(false, kc, false, game) end); heldKeys[kc] = nil end
        end
        -- Wrap the whole run so a throw in any step can't leave `running` stuck
        -- true -- that would silently brick EVERY tech (the guard at the top of
        -- runTech bails while running) until a re-execute. The most likely
        -- culprit is an invalid Enum.KeyCode[a.key] on a Hold/Release step with a
        -- bad/hand-edited key name (digit names throw). Cleanup runs either way.
        local ok, err = pcall(function()
            for _, a in ipairs(tech.actions or {}) do runStep(a, ctx) end
            -- one-shot techs auto-clean at the end -- features toggled go back,
            -- held keys release. If a Rotate ran, hold the rotation briefly past
            -- tech end so it is VISIBLE under shiftlock (the game's shiftlock
            -- snaps body back to face cam the instant we release techBodyOverride)
            -- AND so a move fired server-side at the rotated facing has time to
            -- land. ~0.6s = long enough to see + for a JJS cast handshake to
            -- commit; short enough not to feel stuck.
            if not hold then
                if bodyARDisabled then task.wait(0.6) end
                ctx.restoreAll(false)
            else
                for kc in pairs(heldKeys) do pcall(function() VIM:SendKeyEvent(false, kc, false, game) end) end
            end
        end)
        if not ok then
            log.warn("[tech] run error: " .. tostring(err))
            pcall(function() ctx.restoreAll(false) end)   -- release holds/keys/features even on error
        end
        -- one-shot: release the weld-ignore now; hold techs keep it until key release
        if ignoreWelds and not hold then state.techIgnoreWelds = false end
        running = false
    end)
end

-- Run a tech FROM A TRIGGER. One-shot techs are queued and dispatched on Heartbeat
-- (drainPending) instead of run straight from the trigger's signal callback: a
-- coroutine task.spawn'd inside an RBXScriptSignal handler doesn't reliably get its
-- task.wait resumed on some executors, which froze a tech at its first Wait. Hold
-- techs just set a facing instantly (no meaningful wait), so they run immediately
-- to avoid a 1-frame gap / fast-tap stuck-facing.
local pendingRuns = {}
local function queueRun(tech, hold, triggerIndex)
    if hold then
        runTech(tech, true, triggerIndex)
    else
        pendingRuns[#pendingRuns + 1] = { tech = tech, triggerIndex = triggerIndex or 1 }
    end
end
local function drainPending()
    if #pendingRuns == 0 then return end
    local q = pendingRuns; pendingRuns = {}
    for _, item in ipairs(q) do runTech(item.tech, false, item.triggerIndex) end
end

-- ===== animation triggers + capture =====
-- One persistent hook on the character's Animator drives ALL "anim" techs (and the
-- editor's "Capture" button), re-hooking on respawn. Gated on tech.enabled so
-- there's nothing to wire/unwire per tech.
local animCaptureCbs = {}     -- one-shot callbacks: next anim played -> cb(rawId)
local function animIdNum(s)    -- "rbxassetid://123" / "http://...id=123" / "123" -> "123"
    if not s then return nil end
    return tostring(s):match("(%d+)")
end
-- the character's default locomotion anim ids (walk/run/idle/jump/fall/climb/sit),
-- so history/Capture skip them -- otherwise they'd grab "walk" the instant you move.
-- Cached per character: locomotion ids are static once the Animate folder
-- populates, but this is queried on EVERY AnimationPlayed (frequent during
-- movement). The old per-call Animate:GetDescendants() walk + table alloc was
-- steady churn. Rebuild only when the character changes (or the cache hasn't
-- captured anything yet, e.g. Animate not populated on the first call).
local locomotionCache, locomotionCacheChar = nil, nil
local function locomotionIds()
    local ch = LP.Character
    if locomotionCache and locomotionCacheChar == ch and next(locomotionCache) ~= nil then
        return locomotionCache
    end
    local set = {}
    local animate = ch and ch:FindFirstChild("Animate")
    if animate then
        for _, d in ipairs(animate:GetDescendants()) do
            local v = (d:IsA("Animation") and d.AnimationId) or (d:IsA("StringValue") and d.Value)
            local n = v and animIdNum(v); if n then set[n] = true end
        end
    end
    locomotionCache, locomotionCacheChar = set, ch
    return set
end

-- Friendly names for anim ids, parsed lazily from pantheon_anim_dump.txt ("id  path")
-- so the editor dropdown can show "Dash7_Right" instead of a bare id.
local animNameMap, animNamesLoaded = {}, false
local function loadAnimNames()
    if animNamesLoaded then return end
    animNamesLoaded = true
    if typeof(readfile) ~= "function" then return end
    local ok, data = pcall(function()
        if typeof(isfile) == "function" and not isfile("pantheon_anim_dump.txt") then return nil end
        return readfile("pantheon_anim_dump.txt")
    end)
    if ok and data then
        for line in tostring(data):gmatch("[^\r\n]+") do
            local idp, path = line:match("^(%S+)%s+(.+)$")
            local n = idp and animIdNum(idp)
            if n and path then animNameMap[n] = path end
        end
    end
end
local function shortPath(p)              -- last 2 dot-segments of a GetFullName path
    local segs = {}
    for s in tostring(p):gmatch("[^%.]+") do segs[#segs + 1] = s end
    if #segs <= 2 then return p end
    return segs[#segs - 1] .. "." .. segs[#segs]
end

-- history of non-locomotion anims you've played this session, for the dropdown
local animLog, animLogSeen = {}, {}
local function recordAnim(track, id, raw)
    if animLogSeen[id] then return end
    loadAnimNames()
    local label = animNameMap[id] and shortPath(animNameMap[id])
    if not label then
        local a = track and track.Animation
        local ok, full = pcall(function() return a and a:GetFullName() end)
        if ok and full and full ~= "" and full ~= "Animation" then label = shortPath(full)
        elseif a and a.Name and a.Name ~= "" and a.Name ~= "Animation" then label = a.Name end
    end
    animLogSeen[id] = true
    animLog[#animLog + 1] = { id = id, raw = raw, label = label or ("anim " .. id) }
end
function Engine.animHistory() return animLog end
-- wipe the played-anim log (the dropdown gets cluttered with emotes/effects)
function Engine.clearAnimHistory()
    for i = #animLog, 1, -1 do animLog[i] = nil end
    for k in pairs(animLogSeen) do animLogSeen[k] = nil end
end

local function onAnimPlayed(track)
    local raw = track and track.Animation and track.Animation.AnimationId
    local id = animIdNum(raw)
    if not id then return end
    local watching = false
    for _, tech in pairs(techs) do
        if tech.enabled then
            for tidx, trig in ipairs(techTriggers(tech)) do
                if trig.event == "anim" then
                    watching = true
                    if animIdNum(trig.animId) == id and modifierHeld(trig) and conditionsMet(tech, trig) and scopeMatches(tech) then
                        if trig.animEnd then
                            log.info("[tech] anim trigger armed on-end: " .. tostring(tech.name))
                            local conn
                            conn = track.Stopped:Connect(function()
                                if conn then conn:Disconnect(); conn = nil end
                                if tech.enabled and modifierHeld(trig) and conditionsMet(tech, trig) and scopeMatches(tech) then
                                    log.info("[tech] anim trigger fired (end): " .. tostring(tech.name))
                                    queueRun(tech, false, tidx)
                                end
                            end)
                        else
                            log.info("[tech] anim trigger fired: " .. tostring(tech.name) .. " <- " .. id)
                            queueRun(tech, false, tidx)
                        end
                    end
                end
            end
        end
    end
    -- diagnostic: with an anim tech ON, log every id that plays so you can see
    -- whether the hook catches your move and what id to bind it to.
    if watching then log.info("[tech] anim played: " .. id) end
    -- below: moves only -- skip locomotion AND emotes so the dropdown/Capture
    -- stay clean. Emote anims live under paths containing "Emote" (e.g.
    -- ReplicatedStorage.Emotes.* in JJS); a played emote was flooding the picker
    -- as the moveset list. Note: existing anim techs bound to an emote id still
    -- fire (the firing check above runs before this filter); we just don't add
    -- new emote anims to history or hand them to Capture.
    if locomotionIds()[id] then return end
    do
        local path = animNameMap[id]
        if not path then
            local a = track and track.Animation
            local ok, full = pcall(function() return a and a:GetFullName() end)
            if ok and full then path = full end
        end
        if path and path:lower():find("emote", 1, true) then return end
    end
    recordAnim(track, id, raw)
    if #animCaptureCbs > 0 then
        local cbs = animCaptureCbs; animCaptureCbs = {}
        for _, cb in ipairs(cbs) do pcall(cb, raw) end
    end
end
local animHookConns = {}
local function hookAnimator()
    for _, c in ipairs(animHookConns) do pcall(function() c:Disconnect() end) end
    animHookConns = {}
    local ch = LP.Character
    local hum = ch and ch:FindFirstChildOfClass("Humanoid")
    local animator = hum and hum:FindFirstChildOfClass("Animator")
    if animator then
        animHookConns[#animHookConns + 1] = animator.AnimationPlayed:Connect(onAnimPlayed)
        log.info("[tech] anim hook connected")
    elseif hum then
        log.warn("[tech] anim hook: no Animator yet, waiting")
        animHookConns[#animHookConns + 1] = hum.ChildAdded:Connect(function(c)
            if c:IsA("Animator") then hookAnimator() end
        end)
    else
        log.warn("[tech] anim hook: no Humanoid yet")
    end
end
-- Arm a one-shot: the next animation you play is delivered to cb(rawId). Editor uses
-- this for "Capture" so you bind to the move's real runtime animation id.
function Engine.captureAnim(cb) animCaptureCbs[#animCaptureCbs + 1] = cb end

-- ===== target_anim event =====
-- Mirror of the local-player anim hook but watching state.target's Animator,
-- re-hooked whenever the target changes (state.onTargetChanged). The dispatcher
-- only fires target_anim-event techs (NOT the LP anim techs). target anim
-- history is kept separately so the editor picker doesn't conflate them.
local targetAnimLog, targetAnimLogSeen = {}, {}
local targetAnimCaptureCbs = {}
function Engine.targetAnimHistory() return targetAnimLog end
function Engine.clearTargetAnimHistory()
    for i = #targetAnimLog, 1, -1 do targetAnimLog[i] = nil end
    for k in pairs(targetAnimLogSeen) do targetAnimLogSeen[k] = nil end
end
function Engine.captureTargetAnim(cb) targetAnimCaptureCbs[#targetAnimCaptureCbs + 1] = cb end

local function recordTargetAnim(track, id, raw)
    if targetAnimLogSeen[id] then return end
    loadAnimNames()
    local label = animNameMap[id] and shortPath(animNameMap[id])
    if not label then
        local a = track and track.Animation
        local ok, full = pcall(function() return a and a:GetFullName() end)
        if ok and full and full ~= "" and full ~= "Animation" then label = shortPath(full)
        elseif a and a.Name and a.Name ~= "" and a.Name ~= "Animation" then label = a.Name end
    end
    targetAnimLogSeen[id] = true
    targetAnimLog[#targetAnimLog + 1] = { id = id, raw = raw, label = label or ("anim " .. id) }
end

local function onTargetAnimPlayed(track)
    local raw = track and track.Animation and track.Animation.AnimationId
    local id = animIdNum(raw)
    if not id then return end
    for _, tech in pairs(techs) do
        if tech.enabled then
            for tidx, trig in ipairs(techTriggers(tech)) do
                if trig.event == "target_anim" then
                    if animIdNum(trig.animId) == id and modifierHeld(trig) and conditionsMet(tech, trig) and scopeMatches(tech) then
                        if trig.animEnd then
                            local conn
                            conn = track.Stopped:Connect(function()
                                if conn then conn:Disconnect(); conn = nil end
                                if tech.enabled and modifierHeld(trig) and conditionsMet(tech, trig) and scopeMatches(tech) then
                                    log.info("[tech] target_anim trigger fired (end): " .. tostring(tech.name))
                                    queueRun(tech, false, tidx)
                                end
                            end)
                        else
                            log.info("[tech] target_anim trigger fired: " .. tostring(tech.name) .. " <- " .. id)
                            queueRun(tech, false, tidx)
                        end
                    end
                end
            end
        end
    end
    recordTargetAnim(track, id, raw)
    if #targetAnimCaptureCbs > 0 then
        local cbs = targetAnimCaptureCbs; targetAnimCaptureCbs = {}
        for _, cb in ipairs(cbs) do pcall(cb, raw) end
    end
end

local targetAnimConns = {}
local function clearTargetAnimHook()
    for _, c in ipairs(targetAnimConns) do pcall(function() c:Disconnect() end) end
    targetAnimConns = {}
end
local function hookTargetAnimator()
    clearTargetAnimHook()
    local t = state.target
    if not t then return end
    local ch = (state.target_type == "npc") and t or t.Character
    if not ch then
        -- Player target whose Character hasn't spawned yet -- wait for it.
        if state.target_type ~= "npc" and t.CharacterAdded then
            targetAnimConns[#targetAnimConns + 1] = t.CharacterAdded:Connect(function() hookTargetAnimator() end)
        end
        return
    end
    local hum = ch:FindFirstChildOfClass("Humanoid")
    if not hum then
        targetAnimConns[#targetAnimConns + 1] = ch.ChildAdded:Connect(function(c)
            if c:IsA("Humanoid") then hookTargetAnimator() end
        end)
        return
    end
    local animator = hum:FindFirstChildOfClass("Animator")
    if animator then
        targetAnimConns[#targetAnimConns + 1] = animator.AnimationPlayed:Connect(onTargetAnimPlayed)
        log.info("[tech] target_anim hook connected (" .. tostring(ch.Name) .. ")")
    else
        targetAnimConns[#targetAnimConns + 1] = hum.ChildAdded:Connect(function(c)
            if c:IsA("Animator") then hookTargetAnimator() end
        end)
    end
end

-- ===== trigger wiring =====
-- All trigger wiring takes (tech, trig, tidx) so multi-trigger "or" techs
-- bind each subtrigger with a unique keybind id + CAS action name. tidx
-- flows down to queueRun -> runTech.ctx.triggerIndex so the OR step picks
-- the right branch on fire.
local function wireKey(tech, trig, tidx)
    local key = trig.key
    if not key or key == Enum.KeyCode.Unknown then return end
    local isHold = trig.event == "keyhold"
    local bindId = "tech." .. tech.id .. "." .. tidx
    if trig.suppress then
        keybinds.clear(bindId)
        local action = "PantheonTech_" .. tech.id .. "_" .. tidx
        CAS:BindActionAtPriority(action, function(_, inputState)
            if bypassKeys[key] then return Enum.ContextActionResult.Pass end
            if inputState == Enum.UserInputState.Begin then
                if tech.enabled and modifierHeld(trig) and conditionsMet(tech, trig) and scopeMatches(tech) then queueRun(tech, isHold, tidx) end
            elseif inputState == Enum.UserInputState.End and isHold then
                releaseHold(true)
                if trig.ignoreWelds then state.techIgnoreWelds = false end
            end
            return Enum.ContextActionResult.Sink
        end, false, 3000, key)
        casBound[tech.id .. ".." .. tidx] = action
        return
    end
    keybinds.set(bindId, key,
        function() if tech.enabled and modifierHeld(trig) and conditionsMet(tech, trig) and scopeMatches(tech) then queueRun(tech, isHold, tidx) end end,
        function() if isHold then releaseHold(true); if trig.ignoreWelds then state.techIgnoreWelds = false end end end)
end

local function wireMove(tech, trig, tidx)
    local keyName = trig.movekey
    local kc = keyName and safeKeyCode(keyName)
    if not kc or kc == Enum.KeyCode.Unknown then
        log.warn("[tech] '" .. tostring(tech.name) .. "': move trigger has no key set -- pick the move's key")
        return
    end
    local bindId = "tech." .. tech.id .. "." .. tidx
    if trig.suppress then
        keybinds.clear(bindId)
        local action = "PantheonTech_" .. tech.id .. "_" .. tidx
        CAS:BindActionAtPriority(action, function(_, inputState)
            if bypassKeys[kc] then return Enum.ContextActionResult.Pass end
            if inputState == Enum.UserInputState.Begin
               and tech.enabled and modifierHeld(trig) and conditionsMet(tech, trig) and scopeMatches(tech) then
                queueRun(tech, false, tidx)
            end
            return Enum.ContextActionResult.Sink
        end, false, 3000, kc)
        casBound[tech.id .. ".." .. tidx] = action
        return
    end
    keybinds.set(bindId, kc,
        function() if tech.enabled and modifierHeld(trig) and conditionsMet(tech, trig) and scopeMatches(tech) then queueRun(tech, false, tidx) end end,
        nil)
end

function Engine.rewire()
    for _, list in pairs(conns) do for _, c in ipairs(list) do pcall(function() c:Disconnect() end) end end
    conns = {}
    for _, action in pairs(casBound) do pcall(function() CAS:UnbindAction(action) end) end
    casBound = {}
    for _, tech in pairs(techs) do
        -- Clear any prior trigger keybinds (legacy single-slot + multi-slot
        -- 1..8 for safety -- a tech that was an "or" with 5 subtriggers but
        -- got edited down to 2 shouldn't leave 3..5 bound).
        keybinds.clear("tech." .. tech.id)
        for i = 1, 8 do keybinds.clear("tech." .. tech.id .. "." .. i) end
        if tech.enabled then
            for tidx, trig in ipairs(techTriggers(tech)) do
                local ev = trig.event
                if ev == "key" or ev == "keyhold" then
                    wireKey(tech, trig, tidx)
                elseif ev == "move" then
                    wireMove(tech, trig, tidx)
                end
                -- anim / target_anim are dispatched by the persistent Animator
                -- hooks (onAnimPlayed / onTargetAnimPlayed) and don't need
                -- per-trigger wiring here.
            end
        end
    end
    pcall(Engine.applySuppression)   -- cancel/restore move buttons per current techs
end

-- ===== persistence =====
-- enabled-state is persisted per tech for EVERY tech (examples + custom) so
-- toggles survive reloads. Custom (user-built) techs also persist their full
-- definition under one "tech.custom" map, rehydrated on boot via loadCustom().
local ENABLED_KEY = "tech.enabled."
-- Custom techs are stored under this key in TWO tiers: the per-game store for
-- game/char-scoped techs, and the cross-game GLOBAL store (persist.*Global) for
-- "universal" techs so they transfer to every experience. saveCustom routes by
-- scope; loadCustom reads both (and migrates legacy per-game universals up).
local CUSTOM_KEY  = "tech.custom"

-- Serialize a single trigger table (used for tech.trigger AND each entry in
-- tech.trigger.subtriggers for "or" techs). Same field shape either way.
local function serializeTrigger(trig)
    if not trig then return {} end
    return {
        event      = trig.event,
        key        = persist.keyToString(trig.key),
        move       = trig.move,
        movekey    = trig.movekey,
        modkey     = trig.modkey,
        maxRange   = trig.maxRange,
        animId     = trig.animId,
        animEnd    = trig.animEnd,
        targetAnimId = trig.targetAnimId,
        suppress   = trig.suppress,
        ignoreWelds = trig.ignoreWelds,
    }
end
local function deserializeTrigger(s)
    if not s then return nil end
    return {
        event      = s.event,
        key        = persist.stringToKey(s.key),
        move       = s.move,
        movekey    = s.movekey,
        modkey     = s.modkey,
        maxRange   = s.maxRange,
        animId     = s.animId,
        animEnd    = s.animEnd,
        targetAnimId = s.targetAnimId,
        suppress   = s.suppress,
        ignoreWelds = s.ignoreWelds,
    }
end

local function serialize(tech)
    local trig = tech.trigger or {}
    local serTrig = serializeTrigger(trig)
    serTrig.conditions = trig.conditions or {}
    -- "or" techs carry an array of subtriggers; serialize each.
    if trig.event == "or" and type(trig.subtriggers) == "table" then
        local sub = {}
        for i, st in ipairs(trig.subtriggers) do sub[i] = serializeTrigger(st) end
        serTrig.subtriggers = sub
    end
    return {
        id      = tech.id,
        name    = tech.name,
        scope   = tech.scope,
        enabled = tech.enabled,
        trigger = serTrig,
        actions = tech.actions or {},
    }
end

local function deserialize(s)
    local trigOut = deserializeTrigger(s.trigger) or {}
    trigOut.conditions = (s.trigger and s.trigger.conditions) or {}
    if s.trigger and s.trigger.event == "or" and type(s.trigger.subtriggers) == "table" then
        local sub = {}
        for i, st in ipairs(s.trigger.subtriggers) do sub[i] = deserializeTrigger(st) end
        trigOut.subtriggers = sub
    end
    return {
        id      = s.id,
        name    = s.name,
        scope   = s.scope,
        enabled = s.enabled,
        custom  = true,
        trigger = trigOut,
        actions = s.actions or {},
    }
end

-- ===== public API =====
function Engine.add(tech)
    if not (tech and tech.id) then return end
    -- A user-saved custom override wins over a code-defined re-add of the same id.
    -- (Editing a built-in example saves a custom tech under the built-in's id; on
    -- reload loadCustom() adds the override, then the game/example module re-adds
    -- the original -- this keeps the override instead of clobbering it.)
    local existing = techs[tech.id]
    if existing and existing.custom and not tech.custom then return end
    if tech.enabled == nil then tech.enabled = true end
    -- Built-in techs persist their on/off per-game via ENABLED_KEY. Custom techs
    -- instead carry `enabled` inside their stored definition (per-game OR the
    -- cross-game map for universal techs), so don't let a stale per-game
    -- ENABLED_KEY override a custom's saved state.
    if not tech.custom then
        local savedEnabled = persist.get(ENABLED_KEY .. tech.id)
        if savedEnabled ~= nil then tech.enabled = savedEnabled and true or false end
    end
    techs[tech.id] = tech
    Engine.rewire()
    Engine.changed:Fire()
end

-- Persist a user-built tech's full definition (and add/replace it live).
function Engine.saveCustom(tech)
    tech.custom = true
    Engine.add(tech)
    local ser = serialize(tech)
    -- Route by scope: universal -> cross-game store, else per-game. Always clear
    -- the OTHER tier too, so changing a tech's scope MOVES it instead of leaving a
    -- stale duplicate that would reappear / fire in the wrong place.
    local g = persist.getGlobal(CUSTOM_KEY, {}) or {}
    local m = persist.get(CUSTOM_KEY, {}) or {}
    if tech.scope == "universal" then
        g[tech.id] = ser; m[tech.id] = nil
    else
        m[tech.id] = ser; g[tech.id] = nil
    end
    persist.setGlobal(CUSTOM_KEY, g)
    persist.set(CUSTOM_KEY, m)
    persist.scheduleSave()
end

-- Rehydrate persisted user-built techs. Call once at init.
function Engine.loadCustom()
    -- cross-game (universal) customs: load in EVERY game
    local g = persist.getGlobal(CUSTOM_KEY, {}) or {}
    for _, s in pairs(g) do
        if s and s.id then Engine.add(deserialize(s)) end
    end
    -- per-game customs: load here. Older builds saved UNIVERSAL techs in the
    -- per-game file (so they never transferred) -- migrate those up to the global
    -- store now, then they'll load everywhere from the branch above going forward.
    local m = persist.get(CUSTOM_KEY, {}) or {}
    local migrated = false
    for id, s in pairs(m) do
        if s and s.id then
            Engine.add(deserialize(s))
            if s.scope == "universal" then
                g[id] = s
                m[id] = nil          -- safe: deleting the current key during pairs()
                migrated = true
            end
        end
    end
    if migrated then
        persist.setGlobal(CUSTOM_KEY, g)
        persist.set(CUSTOM_KEY, m)
        persist.scheduleSave()
    end
end

function Engine.all() return techs end
function Engine.get(id) return techs[id] end

-- Run a tech's action sequence once, now, ignoring its trigger/conditions.
-- Used by the editor's "Test" button to preview a draft against the world.
-- Queued like a trigger so its Waits resume reliably.
function Engine.run(tech) if tech then queueRun(tech, false) end end

function Engine.setEnabled(id, v)
    local t = techs[id]; if not t then return end
    t.enabled = v and true or false
    -- Custom techs keep their on/off inside the stored definition (so a universal
    -- tech's state is the same in every game); built-ins persist it per-game.
    if t.custom then
        if t.scope == "universal" then
            local g = persist.getGlobal(CUSTOM_KEY, {}) or {}
            if g[id] then g[id].enabled = t.enabled; persist.setGlobal(CUSTOM_KEY, g) end
        else
            local m = persist.get(CUSTOM_KEY, {}) or {}
            if m[id] then m[id].enabled = t.enabled; persist.set(CUSTOM_KEY, m); persist.scheduleSave() end
        end
    else
        persist.set(ENABLED_KEY .. id, t.enabled)
    end
    Engine.rewire()
    Engine.changed:Fire()
end

function Engine.remove(id)
    local t = techs[id]
    techs[id] = nil
    persist.set(ENABLED_KEY .. id, nil)
    if t and t.custom then
        -- could live in either tier (universal -> global, else per-game); clear both
        local m = persist.get(CUSTOM_KEY, {}) or {}; m[id] = nil
        local g = persist.getGlobal(CUSTOM_KEY, {}) or {}; g[id] = nil
        persist.set(CUSTOM_KEY, m)
        persist.setGlobal(CUSTOM_KEY, g)
        persist.scheduleSave()
    end
    keybinds.clear("tech." .. id)
    Engine.rewire()
    Engine.changed:Fire()
end

function Engine.init()
    if bound then return end
    RunService:BindToRenderStep(RENDER_BIND, Enum.RenderPriority.Camera.Value + 2, renderHold)
    -- dispatch queued trigger runs from a stable thread so their Waits resume
    drainConn = RunService.Heartbeat:Connect(drainPending)
    -- persistent Animator hook for "anim" triggers + the editor's Capture, re-hooked
    -- on respawn (Humanoid/Animator aren't there the instant the character spawns).
    hookAnimator()
    -- retry for the CURRENT character too (executing mid-game, the Animator may not
    -- be resolved on the first pass)
    task.spawn(function()
        local ch = LP.Character
        if ch then
            local hum = ch:FindFirstChildOfClass("Humanoid") or ch:WaitForChild("Humanoid", 10)
            if hum then hum:WaitForChild("Animator", 10) end
            hookAnimator()
        end
    end)
    charAddedConn = LP.CharacterAdded:Connect(function(ch)
        task.spawn(function()
            local hum = ch:WaitForChild("Humanoid", 10)
            if hum then hum:WaitForChild("Animator", 5) end
            hookAnimator()
        end)
    end)
    -- target_anim hook: re-arm whenever the lock-on/target-select target changes
    -- so triggers can fire on the opponent's animation. Hook the initial target
    -- (if Target Select is already active when init runs) and reset on target
    -- becoming nil too (clearTargetAnimHook).
    hookTargetAnimator()
    targetChangedConn = state.onTargetChanged:Connect(function()
        hookTargetAnimator()
    end)
    bound = true
end

function Engine.destroy()
    if bound then pcall(function() RunService:UnbindFromRenderStep(RENDER_BIND) end); bound = false end
    if drainConn then pcall(function() drainConn:Disconnect() end); drainConn = nil end
    if targetChangedConn then pcall(function() targetChangedConn:Disconnect() end); targetChangedConn = nil end
    if charAddedConn then pcall(function() charAddedConn:Disconnect() end); charAddedConn = nil end
    -- the persistent Animator.AnimationPlayed hook survives a script reload (the
    -- Animator isn't destroyed), so disconnect it or the old instance keeps
    -- firing onAnimPlayed alongside the new one after a re-execute.
    for _, c in ipairs(animHookConns) do pcall(function() c:Disconnect() end) end
    animHookConns = {}
    clearTargetAnimHook()
    for _, list in pairs(conns) do for _, c in ipairs(list) do pcall(function() c:Disconnect() end) end end
    conns = {}
    releaseHold(true)
    if techAlign then pcall(function() techAlign:Destroy() end); techAlign = nil end
    if techAttach then pcall(function() techAttach:Destroy() end); techAttach = nil end
end

return Engine
end

_MODULES["modules.tech.scanner"] = function()
-- Move-button scanner: detect the game's on-screen MOVE buttons so you can see
-- which moves you can build techs around (and, later, trigger off a button press).
--
-- Heuristic -- Roblox has no "this is a move button" flag -- but the strong signal
-- is cross-referencing on-screen buttons against the REAL move list
-- (ReplicatedStorage.Knit.Knit.Services that own an RE). Plus skill-bar / cooldown
-- / keybind cues. You confirm the matches.

local Players  = game:GetService("Players")
local RS       = game:GetService("ReplicatedStorage")
local log      = require("core.log")
local registry = require("games.registry")

local Scanner = {}
local cached = nil

local function clean(s) return (s and (s:lower():gsub("%s", ""))) or "" end

-- Knit services that look like moves (own an RE) = the things "move used" can fire on.
function Scanner.moveServices()
    local out = {}
    local knit     = RS:FindFirstChild("Knit")
    local inner    = knit and knit:FindFirstChild("Knit")
    local services = inner and inner:FindFirstChild("Services")
    if services then
        for _, s in ipairs(services:GetChildren()) do
            if s:FindFirstChild("RE") then out[#out + 1] = s.Name end
        end
        table.sort(out)
    end
    return out
end

local SKILL_KW = { "move", "skill", "abilit", "hotbar", "combat", "slot", "action", "spell", "ult" }
local function ancestorSkill(inst)
    local cur, depth = inst.Parent, 0
    while cur and depth < 7 do
        local n = clean(cur.Name)
        for _, kw in ipairs(SKILL_KW) do if n:find(kw, 1, true) then return true end end
        cur, depth = cur.Parent, depth + 1
    end
    return false
end

-- on screen = the button AND every GuiObject ancestor is Visible -- so we skip
-- buttons sitting in a CLOSED menu (e.g. the emote list with "conga").
local function onScreen(d)
    local cur = d
    while cur and cur:IsA("GuiObject") do
        if not cur.Visible then return false end
        cur = cur.Parent
    end
    return true
end

-- a button's keybind letter (single capital) + whether it has a cooldown child
local function indicators(b)
    local keyHint, hasCD = nil, false
    for _, c in ipairs(b:GetDescendants()) do
        if not keyHint and c:IsA("TextLabel") and c.Text and c.Text:match("^%u$") then keyHint = c.Text end
        if not hasCD then
            local cn = clean(c.Name)
            if cn:find("cooldown") or cn == "cd" then hasCD = true end
        end
    end
    return keyHint, hasCD
end

-- A NAMED move slot: a button carrying a label like ToolName / MoveName with a
-- real move name (not "N/A"/empty), plus optionally a Number/keybind label.
-- Strongest, cleanest signal -- e.g. TSB hotbar slots have ToolName + Number.
-- Keywords are SPECIFIC compounds on purpose: a bare "name"/"displayname" matched
-- player-list / leaderboard labels, so whole players showed up as "moves".
local NAME_KW = { "toolname", "movename", "abilityname", "skillname", "moveslot", "skillslot" }
local KEY_KW  = { "number", "keybind", "bind", "input", "key", "slot" }
local function slotLabels(b)
    local moveName, keyHint
    for _, c in ipairs(b:GetDescendants()) do
        if c:IsA("TextLabel") then
            local nm, t = clean(c.Name), c.Text
            if not moveName and t and t ~= "" and string.upper(t) ~= "N/A" then
                for _, kw in ipairs(NAME_KW) do if string.find(nm, kw, 1, true) then moveName = t; break end end
            end
            if not keyHint and t and #t >= 1 and #t <= 3 then
                for _, kw in ipairs(KEY_KW) do if string.find(nm, kw, 1, true) then keyHint = t; break end end
            end
        end
    end
    return moveName, keyHint
end

-- Move-bar detection.
--   PRIMARY: named slots (a button with a ToolName/MoveName/... label = a hotbar
--     slot; gives the real move name + keybind -- equipped moves only, works for
--     TSB). Deduped by move name.
--   FALLBACK (games without named slots): a CLUSTER of 3+ similar on-screen
--     buttons in the lower screen, or a solo button with a keybind letter +
--     cooldown. Service names only label a match. Closed menus skipped (onScreen).
-- Returns { services, buttons = {{button,name,text,move,key},...}, diag = {...} }
-- Annotate a button entry's `move` (Knit service name) by matching its name/text
-- against service stems (e.g. "Projection Breaker" -> "ProjectionBreakerService"),
-- so per-game scans don't have to duplicate this logic.
local function annotateMove(b, stems)
    if b.move then return end
    local nm  = clean(b.name or "")
    local txt = clean(b.text or "")
    for stem, svc in pairs(stems) do
        if (nm ~= "" and nm:find(stem, 1, true)) or (txt ~= "" and txt:find(stem, 1, true)) then
            b.move = svc; return
        end
    end
end

function Scanner.scan()
    local LP = Players.LocalPlayer
    local pg = LP:FindFirstChildOfClass("PlayerGui")
    local services = Scanner.moveServices()
    local stems = {}
    for _, svc in ipairs(services) do
        local stem = clean((svc:gsub("Service$", "")))
        if #stem >= 3 then stems[stem] = svc end
    end

    -- PER-GAME HOOK: a game module (e.g. games/jjs.lua) may expose scanMoves(pg)
    -- that knows the game's exact moveset layout. Runs FIRST and is AUTHORITATIVE
    -- for that game: if registered, we never fall through to the generic
    -- heuristics (which would otherwise pick up unrelated clusters like the emote
    -- wheel when the game's UI isn't ready). Empty result -> return empty WITHOUT
    -- caching, so the next call re-scans (by which time the UI may be ready).
    if pg then
        local mod = registry.current()
        if mod and type(mod.scanMoves) == "function" then
            local ok, gameButtons = pcall(mod.scanMoves, pg)
            if ok and type(gameButtons) == "table" then
                if #gameButtons > 0 then
                    for _, b in ipairs(gameButtons) do annotateMove(b, stems) end
                    cached = { services = services, buttons = gameButtons, diag = { "per-game scan (" .. tostring(#gameButtons) .. ")" } }
                    return cached
                end
                -- hook ran, found nothing yet -- DON'T fall through to generic and
                -- DON'T cache the empty so next open retries
                return { services = services, buttons = {}, diag = { "per-game scan: empty (UI not ready)" } }
            end
        end
    end

    local buttons, diag, cand = {}, {}, {}
    if pg then
        for _, d in ipairs(pg:GetDescendants()) do
            if (d:IsA("ImageButton") or d:IsA("TextButton")) and onScreen(d) then cand[#cand + 1] = d end
        end
        -- PRIMARY: named slots (dedup by move name)
        local seenName = {}
        for _, b in ipairs(cand) do
            local moveName, keyHint = slotLabels(b)
            if moveName and not seenName[string.lower(moveName)] then
                seenName[string.lower(moveName)] = true
                buttons[#buttons + 1] = { button = b, name = b.Name, text = moveName, move = nil, key = keyHint }
            end
        end
    end

    -- FALLBACK: cluster / keybind+cooldown (only if no named slots were found)
    if #buttons == 0 and pg then
        local cam = workspace.CurrentCamera
        local vh = (cam and cam.ViewportSize.Y) or 1080
        local sized = {}
        for _, b in ipairs(cand) do
            local sz = b.AbsoluteSize
            if sz.X >= 22 and sz.X <= 180 and sz.Y >= 22 and sz.Y <= 180 then sized[#sized + 1] = b end
        end
        local picked, byParent = {}, {}
        for _, b in ipairs(sized) do byParent[b.Parent] = byParent[b.Parent] or {}; table.insert(byParent[b.Parent], b) end
        for p, list in pairs(byParent) do
            if #list >= 3 then
                local sumY = 0
                for _, b in ipairs(list) do sumY = sumY + (b.AbsolutePosition.Y + b.AbsoluteSize.Y / 2) end
                diag[#diag + 1] = (p and p.Name or "?") .. " x" .. #list
                if (sumY / #list) > vh * 0.30 then for _, b in ipairs(list) do picked[b] = true end end
            end
        end
        for _, b in ipairs(sized) do
            if not picked[b] then local k, cd = indicators(b); if k and cd then picked[b] = true end end
        end
        for b in pairs(picked) do
            local k = indicators(b)
            local nm = clean(b.Name); local txt = clean((b:IsA("TextButton") and b.Text) or "")
            local move
            for stem, svc in pairs(stems) do
                if nm:find(stem, 1, true) or (txt ~= "" and txt:find(stem, 1, true)) then move = svc; break end
            end
            buttons[#buttons + 1] = { button = b, name = b.Name, text = (b:IsA("TextButton") and b.Text) or "", move = move, key = k }
        end
    end

    if #buttons == 0 and #diag > 0 then
        log.info("scan: no move bar; clusters seen -> " .. table.concat(diag, ", "))
    end
    -- Only cache a non-empty result. Caching {buttons={}} traps the picker on a
    -- stale empty (or worse, on a one-time pick-up of unrelated clusters that
    -- happened to match the lower-half heuristic at scan time) for the rest of
    -- the session.
    local res = { services = services, buttons = buttons, diag = diag }
    if #buttons > 0 then cached = res end
    return res
end

-- Only hand back a cache that actually has moves -- callers fall back to scan().
function Scanner.cached()
    if cached and #(cached.buttons or {}) > 0 then return cached end
    return nil
end

-- Clear the cached scan so the next .scan() rebuilds from the LIVE PlayerGui.
-- Called from Builder.open(): without it, the first scan (often taken before
-- the game's hotbar UI is rebuilt for the current character / server) became
-- sticky for the rest of the session and the Use Move picker showed stale
-- (or empty) move names.
function Scanner.clearCache() cached = nil end

return Scanner
end

_MODULES["modules.tech.dumper"] = function()
-- Raw GUI dump, written to file, so per-game hotbar/menu detection can be set
-- up CORRECTLY instead of guessed. Run in-game and send the file:
--   pantheon_gui_dump.txt   -- every on-screen button (name/text/size/pos/path/children/conn counts)
-- (The old static anim dumper has been removed -- the Tech Builder editor's
-- live anim logging covers it; see Engine.animHistory / captureAnim.)

local Players = game:GetService("Players")

local Dumper = {}
local LP = Players.LocalPlayer
local hasWrite = (typeof(writefile) == "function")

-- How many handlers are connected to a signal (so we can see what the game ACTUALLY
-- listens on -- Activated vs MouseButton1Down vs ... -- and fire the right one).
local function connCount(sig)
    if typeof(getconnections) ~= "function" then return "?" end
    local ok, cs = pcall(getconnections, sig)
    if ok and type(cs) == "table" then return tostring(#cs) end
    return "?"
end
local function btnConns(b)
    local out = {}
    pcall(function()
        out[#out + 1] = "Act=" .. connCount(b.Activated)
        out[#out + 1] = "MB1Click=" .. connCount(b.MouseButton1Click)
        out[#out + 1] = "MB1Down=" .. connCount(b.MouseButton1Down)
        out[#out + 1] = "InputBegan=" .. connCount(b.InputBegan)
    end)
    return table.concat(out, " ")
end

function Dumper.dumpGui()
    local pg = LP:FindFirstChildOfClass("PlayerGui")
    local lines = { "=== Pantheon GUI dump ===" }
    local n = 0
    if pg then
        for _, sg in ipairs(pg:GetChildren()) do
            if sg:IsA("LayerCollector") or sg:IsA("GuiObject") or sg:IsA("Folder") then
                lines[#lines + 1] = "[" .. sg.ClassName .. "] " .. sg.Name ..
                    (sg:IsA("ScreenGui") and (" enabled=" .. tostring(sg.Enabled)) or "")
                local ok, descs = pcall(function() return sg:GetDescendants() end)
                if ok then
                    for _, d in ipairs(descs) do
                        if d:IsA("TextButton") or d:IsA("ImageButton") then
                            n = n + 1
                            local parts, cur = {}, d
                            while cur and cur ~= sg do table.insert(parts, 1, cur.Name); cur = cur.Parent end
                            local kids = {}
                            for _, c in ipairs(d:GetDescendants()) do
                                if c:IsA("TextLabel") then kids[#kids + 1] = "Lbl:" .. c.Name .. "='" .. tostring(c.Text) .. "'"
                                elseif c:IsA("ImageLabel") then kids[#kids + 1] = "Img:" .. c.Name
                                -- nested buttons + what THEY listen on (the real handler may be in here)
                                elseif c:IsA("TextButton") or c:IsA("ImageButton") then
                                    kids[#kids + 1] = "BTN:" .. c.ClassName .. ":" .. c.Name .. "{" .. btnConns(c) .. "}"
                                end
                            end
                            lines[#lines + 1] = ("  %s '%s' txt='%s' active=%s size=%s pos=%s vis=%s conns={%s}\n      path=%s\n      kids=[%s]")
                                :format(d.ClassName, d.Name, (d:IsA("TextButton") and d.Text or ""),
                                    tostring(d.Active), tostring(d.AbsoluteSize), tostring(d.AbsolutePosition),
                                    tostring(d.Visible), btnConns(d),
                                    table.concat(parts, "/"), table.concat(kids, ", "))
                        end
                    end
                end
            end
        end
    end
    local out = table.concat(lines, "\n")
    if hasWrite then pcall(writefile, "pantheon_gui_dump.txt", out) end
    print(out)
    return n
end

return Dumper
end

_MODULES["modules.tech.canvas_ui"] = function()
-- Scratch-style block canvas. Replaces the flat chip list inside the Tech
-- Builder. Blocks are absolutely positioned, draggable, and snap-to-connect
-- via their top-notch / bottom-tab connectors -- the same mental model as
-- Scratch's stack blocks. The chain order (hat -> next -> next -> ...) is the
-- tech's action sequence; disconnected blocks are saved in Y order so a
-- block floated off the chain doesn't silently vanish.
--
-- Public API:
--   Canvas.new(parent, opts)  -- opts = { onChange = fn, getPaletteColor, getLabel }
--   c:addBlock(type, params, x, y) -> block      -- spawn a block at canvas-local x,y
--   c:loadActions(actions)                       -- rebuild canvas from action array
--   c:toActions() -> { ... }                     -- read canvas back to action array
--   c:clear()                                    -- destroy all blocks
--   c.changed -- Signal fired when the canvas state changes
--
-- Limitations of V1 (V2 plans):
--   * Nested slots (C-blocks for AND / during / hold-release pair) are NOT
--     drawn as slot containers yet -- they snap into the linear chain like
--     any other block. The engine still consumes them (during/hold/release
--     act as sentinels in the chain; AND has branches[] that we treat as a
--     single-step block for V1, encoding the branches via a side-pane editor
--     that doesn't ship in V1).
--   * No trash zone -- delete is per-block via a tiny X button.

local UIS        = game:GetService("UserInputService")
local RunService = game:GetService("RunService")
local Players    = game:GetService("Players")

local theme   = require("ui.theme")
local Signal  = require("core.signal")
local feature = require("ui.feature")
local scanner = require("modules.tech.scanner")

local Canvas = {}
Canvas.__index = Canvas

-- Module-level exports (the builder_ui needs these to iterate hat-block
-- types for its palette + detect hats in the saved action stream).
Canvas.HAT_TYPES = nil      -- assigned below once HAT_TYPES exists
Canvas.isHat = nil
Canvas.colorOf = nil
Canvas.STEP_LABEL = nil

-- ---- visual constants ----
local BLOCK_W       = 200
local BLOCK_H       = 36
local TAB_W         = 20
local TAB_INSET_X   = 22       -- where the top-notch / bottom-tab sits (X offset from block left)
local SNAP_RADIUS   = 22       -- distance to snap when block's top meets another's bottom
local CANVAS_MIN_H  = 320      -- min height of the canvas frame; auto-grows when blocks drop below
local HAT_LABEL_COL = Color3.fromRGB(40, 30, 0)

local CATEGORY = {
    look = "motion", rotate = "motion",
    wait = "control", during = "control", ["return"] = "control",
    hold = "control", release = "control", ["and"] = "control", ["or"] = "control",
    within = "sense",
    feature = "action", key = "action", usebtn = "action",
    -- Hat blocks (event triggers). Each carries the trigger params on its
    -- own .params table; builder_ui detects a hat at the top of a chain at
    -- Save and extracts it into tech.trigger.
    event_key       = "event",
    event_anim      = "event",
    event_target_anim = "event",
    event_move      = "event",
}
local CAT_COLOR = {
    motion  = Color3.fromRGB(76, 151, 255),
    control = Color3.fromRGB(255, 171, 25),
    sense   = Color3.fromRGB(92, 177, 214),
    action  = Color3.fromRGB(159, 110, 220),
    event   = Color3.fromRGB(255, 191, 0),
}
local STEP_LABEL = {
    look = "Look", rotate = "Rotate", wait = "Wait", during = "During",
    within = "Within", ["return"] = "Return", feature = "Use", key = "Press",
    hold = "Hold", release = "Release", usebtn = "Use Move", ["and"] = "AND", ["or"] = "OR",
    event_key         = "When key",
    event_anim        = "When my anim",
    event_target_anim = "When target anim",
    event_move        = "When move",
}
local HAT_TYPES = { "event_key", "event_anim", "event_target_anim", "event_move" }
local function isHat(t) return t == "event_key" or t == "event_anim" or t == "event_target_anim" or t == "event_move" end
local YAW_PRESETS = { 180, 135, 90, 45, 0, -45, -90, -135, -180 }
local function nextYaw(cur)
    for i, v in ipairs(YAW_PRESETS) do if v == cur then return YAW_PRESETS[(i % #YAW_PRESETS) + 1] end end
    return YAW_PRESETS[1]
end
local function catOf(t) return CATEGORY[t] or "action" end
local function colorOf(t) return CAT_COLOR[catOf(t)] end

Canvas.HAT_TYPES = HAT_TYPES
Canvas.isHat = isHat
Canvas.colorOf = colorOf
Canvas.STEP_LABEL = STEP_LABEL

-- ---- small helpers ----
local function corner(o, r) local c = Instance.new("UICorner"); c.CornerRadius = UDim.new(0, r or 6); c.Parent = o; return c end
local function stroke(o, col, t) local s = Instance.new("UIStroke"); s.Color = col or theme.border; s.Thickness = t or 1; s.Parent = o; return s end
local function lerpCol(c, k) return Color3.fromRGB(math.floor(c.R * 255 * k), math.floor(c.G * 255 * k), math.floor(c.B * 255 * k)) end

-- Drag-window flag set briefly after a drag ends so the inner param buttons
-- can swallow the accidental MouseButton1Click that would otherwise fire
-- when MB1Up lands on the (now-moved) value button. Without this, a drag
-- that ends with the cursor still over the value button triggers its
-- onClick -- which for `key`/`hold` blocks blanked the inline label to
-- "press a key...", and for `look`/`rotate`/`feature` cycled the value.
local dragJustEnded = false
local function guardedClick(btn, fn)
    btn.MouseButton1Click:Connect(function(...)
        if dragJustEnded then return end
        fn(...)
    end)
end

-- mouse position in CANVAS-LOCAL coordinates (subtract canvas absolute origin)
local function canvasLocal(canvas, gx, gy)
    local origin = canvas.frame.AbsolutePosition
    return gx - origin.X, gy - origin.Y
end

-- ---- block param rendering ----
-- Each block type knows how to render its inline param controls onto the
-- block frame, and how to read changes back into block.params. Kept inline
-- here (rather than a big STEP_PARAMS table) so the canvas module is self-
-- contained and the chip layout can evolve without affecting the rest of the
-- builder.
local renderParams
do
    local function valArea(blk)
        local val = Instance.new("Frame")
        val.Size = UDim2.new(1, -118, 1, -10)
        val.Position = UDim2.new(0, 92, 0, 5)
        val.BackgroundColor3 = theme.bgDark
        val.BorderSizePixel = 0
        val.Parent = blk.frame
        corner(val, 6)
        return val
    end
    local function valBtn(blk, text, onClick)
        local v = valArea(blk)
        local b = Instance.new("TextButton")
        b.Size = UDim2.new(1, 0, 1, 0); b.BackgroundTransparency = 1; b.AutoButtonColor = false
        b.Text = text; b.TextColor3 = theme.fg; b.Font = theme.font; b.TextSize = 12; b.Parent = v
        if onClick then guardedClick(b, onClick) end
        return b
    end
    local function valTextbox(blk, text, onCommit)
        local v = valArea(blk)
        local tb = Instance.new("TextBox")
        tb.Size = UDim2.new(1, 0, 1, 0); tb.BackgroundTransparency = 1
        tb.Text = text; tb.TextColor3 = theme.fg; tb.Font = theme.font; tb.TextSize = 12
        tb.ClearTextOnFocus = false; tb.Parent = v
        tb.FocusLost:Connect(function() onCommit(tb.Text); tb.Text = onCommit(tb.Text, true) or tb.Text end)
        return tb
    end

    renderParams = function(blk)
        local t, p = blk.type, blk.params
        if t == "look" or t == "rotate" then
            valBtn(blk, tostring(p.x or 0) .. "\u{00B0}", function()
                p.x = nextYaw(p.x or 0)
                blk.canvas:_refreshBlockText(blk)
            end)
        elseif t == "wait" then
            valTextbox(blk, tostring(p.seconds or 0.5), function(s, isRead)
                local n = tonumber((tostring(s):gsub("[^%d%.]", "")))
                if n and not isRead then p.seconds = math.clamp(n, 0, 60) end
                return tostring(p.seconds or 0.5)
            end)
        elseif t == "within" then
            valTextbox(blk, tostring(p.studs or 5), function(s, isRead)
                local n = tonumber((tostring(s):gsub("[^%d%.]", "")))
                if n and not isRead then p.studs = math.clamp(n, 0, 500) end
                return tostring(p.studs or 5)
            end)
        elseif t == "during" or t == "return" then
            valBtn(blk, t == "during" and "holds prev step for next wait" or "re-face target")
        elseif t == "key" or t == "hold" or t == "release" then
            local b = valBtn(blk, p.key and ("key: " .. p.key) or "(click, press a key)")
            guardedClick(b, function()
                -- Disconnect a capture already armed on this block (double-click)
                -- so the previous global UIS connection doesn't leak.
                if blk._keyCaptureConn then blk._keyCaptureConn:Disconnect(); blk._keyCaptureConn = nil end
                b.Text = "press a key..."
                blk._keyCaptureConn = UIS.InputBegan:Connect(function(input)
                    if input.UserInputType ~= Enum.UserInputType.Keyboard then return end
                    if input.KeyCode == Enum.KeyCode.Unknown then return end
                    if input.KeyCode ~= Enum.KeyCode.Escape then
                        p.key = (tostring(input.KeyCode):gsub("Enum.KeyCode.", ""))
                    end
                    b.Text = p.key and ("key: " .. p.key) or "(click, press a key)"
                    if blk._keyCaptureConn then blk._keyCaptureConn:Disconnect(); blk._keyCaptureConn = nil end
                end)
            end)
        elseif t == "feature" then
            local function featName(id)
                for _, f in ipairs(feature.all()) do if f.id == id then return f.name or f.id end end
                return id or "(none)"
            end
            local b = valBtn(blk, featName(p.feature))
            guardedClick(b, function()
                local feats = feature.all()
                table.sort(feats, function(a, b) return (a.name or a.id) < (b.name or b.id) end)
                if #feats > 0 then
                    local idx = 0
                    for k, ft in ipairs(feats) do if ft.id == p.feature then idx = k end end
                    p.feature = feats[(idx % #feats) + 1].id
                    b.Text = featName(p.feature)
                end
            end)
        elseif t == "usebtn" then
            -- Click opens the Use Move editor modal (in builder_ui) via the
            -- editUseMoveRequested signal: move dropdown + manual name + key +
            -- fire method. (Was a cycle-only picker -- no manual entry / key.)
            local res = scanner.cached() or scanner.scan()
            local moveset = res.buttons or {}
            if not p.move and #moveset > 0 then p.move = moveset[1].name end
            local function label()
                local base = "(configure move)"
                if p.move and p.move ~= "" then
                    base = p.move
                    for _, b in ipairs(moveset) do if b.name == p.move then base = (b.text ~= "" and b.text) or b.name; break end end
                end
                if p.key and p.key ~= "" then base = base .. " [" .. tostring(p.key) .. "]" end
                return base
            end
            local b = valBtn(blk, label(), function()
                if blk.canvas and blk.canvas.editUseMoveRequested then blk.canvas.editUseMoveRequested:Fire(blk) end
            end)
            blk._refreshUseMoveLabel = function() b.Text = label() end
        elseif t == "and" then
            -- V2: clicking the param button opens a sub-editor modal where
            -- each branch is its own mini canvas. The block itself stays a
            -- single tile in the main chain (so flow stays linear); the
            -- modal handles the nested complexity.
            local function label()
                local n = #(p.branches or {})
                return string.format("[%d branches] - click to edit", n)
            end
            local b = valBtn(blk, label())
            guardedClick(b, function()
                if blk.canvas and blk.canvas.editBranchesRequested then
                    blk.canvas.editBranchesRequested:Fire(blk)
                end
            end)
            blk._refreshAndLabel = function() b.Text = label() end
        elseif t == "or" then
            -- OR block: forks between branches based on which trigger fired.
            -- Like AND, the block is a single tile on the main chain; the
            -- branches (each = a trigger + its action chain) are edited in
            -- a modal opened from the inline summary button.
            local function label()
                local n = math.max(#(p.triggers or {}), #(p.branches or {}))
                if n == 0 then n = 2 end
                return string.format("[%d-way fork] - click to edit", n)
            end
            local b = valBtn(blk, label())
            guardedClick(b, function()
                if blk.canvas and blk.canvas.editBranchesRequested then
                    blk.canvas.editBranchesRequested:Fire(blk)
                end
            end)
            blk._refreshAndLabel = function() b.Text = label() end
        elseif isHat(t) then
            -- Hat blocks (yellow, top of every chain) carry the trigger
            -- params (key / animId / move / etc.). The inline button is a
            -- one-liner summary that opens a modal for full editing -- the
            -- modal lives in builder_ui (renderHatConfig signal) so it has
            -- access to the scanner + Engine anim history without having
            -- to plumb them into the canvas module.
            local function summarize()
                if t == "event_key" then
                    -- p.key is a KeyCode EnumItem (from the hat modal's KeybindSetter);
                    -- "str " .. EnumItem THROWS in Luau, so normalize to a name string.
                    local kn = p.key and (typeof(p.key) == "EnumItem"
                        and (tostring(p.key):gsub("Enum.KeyCode.", "")) or tostring(p.key))
                    return ((kn and kn ~= "") and ("key: " .. kn) or "(no key set)") ..
                           (p.suppress and " [block]" or "") ..
                           ((p.event or "key") == "keyhold" and " [hold]" or "")
                elseif t == "event_anim" then
                    return p.animId and ("anim " .. tostring(p.animId)) or "(no anim set)"
                elseif t == "event_target_anim" then
                    return p.animId and ("target anim " .. tostring(p.animId)) or "(no anim set)"
                elseif t == "event_move" then
                    -- A move trigger fires off its KEY; the name is optional. Show
                    -- whichever is set so a key-only (scanner-less) config reads as
                    -- configured, not "(no move set)".
                    if p.move and p.move ~= "" then return "move: " .. tostring(p.move) end
                    if p.movekey and p.movekey ~= "" then return "key: " .. tostring(p.movekey) end
                    return "(set move/key)"
                end
                return "configure"
            end
            local b = valBtn(blk, summarize())
            guardedClick(b, function()
                if blk.canvas and blk.canvas.editHatRequested then
                    blk.canvas.editHatRequested:Fire(blk)
                end
            end)
            blk._refreshHatLabel = function() b.Text = summarize() end
        end
    end
end

-- ============ Canvas ============
function Canvas.new(parent, opts)
    local self = setmetatable({}, Canvas)
    opts = opts or {}
    self.onChange = opts.onChange

    self.frame = Instance.new("Frame")
    self.frame.Size = UDim2.new(1, 0, 0, CANVAS_MIN_H)
    self.frame.BackgroundColor3 = theme.bgDark
    self.frame.BorderSizePixel = 0
    self.frame.Parent = parent
    self.frame.ClipsDescendants = false   -- let blocks visually overflow downward; we grow height instead
    corner(self.frame, 8)
    stroke(self.frame, theme.border)

    self.blocks = {}   -- list of blocks, in insertion order
    self.changed = Signal.new()
    self.blockClicked = Signal.new()       -- (block) on click without drag
    self.editBranchesRequested = Signal.new() -- (andBlock) when AND's branch-edit button is clicked
    self.editHatRequested      = Signal.new() -- (hatBlock) when a hat's summary button is clicked
    self.editUseMoveRequested  = Signal.new() -- (useBlock) when a Use Move block's button is clicked
    self._uid = 0
    -- (Global trash zone removed -- per-block trash icons are the delete UX
    -- now; see _renderBlock. Drag-onto-trash was unreliable because the
    -- dragged block visually covered the trash zone and the user's cursor
    -- was offset by their click origin.)
    return self
end

function Canvas:_nextId() self._uid = self._uid + 1; return "blk_" .. self._uid end

function Canvas:_refreshBlockText(blk)
    if blk.lbl then
        blk.lbl.Text = (STEP_LABEL[blk.type] or blk.type)
    end
end

function Canvas:_fireChanged()
    self.changed:Fire()
    if self.onChange then pcall(self.onChange) end
end

-- Grow the canvas frame's height to cover the lowest block (+ padding) so
-- a tall stack stays visible without needing scroll inside the canvas.
function Canvas:_resizeToContent()
    local maxY = CANVAS_MIN_H
    for _, b in ipairs(self.blocks) do
        local by = b.frame.Position.Y.Offset + b.frame.Size.Y.Offset + 12
        if by > maxY then maxY = by end
    end
    self.frame.Size = UDim2.new(1, 0, 0, maxY)
end

-- Walk the chain rooted at `head` (head.prev == nil) and stack blocks
-- vertically so they butt up against each other -- used after a snap and
-- when dragging a chain root around.
function Canvas:_layoutChain(head)
    local cur = head
    local x = cur.frame.Position.X.Offset
    local y = cur.frame.Position.Y.Offset
    while cur do
        cur.frame.Position = UDim2.fromOffset(x, y)
        y = y + cur.frame.Size.Y.Offset
        cur = cur.next
    end
end

-- Find the head of `blk`'s chain (walk .prev to the topmost block).
local function chainHead(blk)
    while blk.prev do blk = blk.prev end
    return blk
end

-- Remove block from its current chain (if any) -- used at drag start so the
-- block can be repositioned freely without dragging its old neighbors along.
function Canvas:_detach(blk)
    if blk.prev then
        blk.prev.next = nil
        blk.prev = nil
    end
end

-- Try to snap `blk` to another block's bottom. Looks for any block whose
-- bottom-tab is within SNAP_RADIUS of `blk`'s top-notch, AND whose .next
-- slot is open. On success, rewires the chain and lays out the joined
-- chain so it stacks cleanly.
function Canvas:_trySnap(blk)
    if blk.prev then return end   -- already chained somewhere
    local myTopX = blk.frame.Position.X.Offset + TAB_INSET_X
    local myTopY = blk.frame.Position.Y.Offset
    for _, other in ipairs(self.blocks) do
        if other ~= blk and not other.next then
            -- block can't snap onto its own descendant (would create a loop)
            local descendant = false
            local cur = blk
            while cur do if cur == other then descendant = true; break end; cur = cur.next end
            if not descendant then
                local oBotX = other.frame.Position.X.Offset + TAB_INSET_X
                local oBotY = other.frame.Position.Y.Offset + other.frame.Size.Y.Offset
                local dx, dy = math.abs(myTopX - oBotX), math.abs(myTopY - oBotY)
                if dx < SNAP_RADIUS and dy < SNAP_RADIUS then
                    blk.frame.Position = UDim2.fromOffset(other.frame.Position.X.Offset, oBotY)
                    other.next = blk; blk.prev = other
                    self:_layoutChain(chainHead(blk))
                    return true
                end
            end
        end
    end
    return false
end

-- Drag wiring: hold MB1 on a block -> drag freely (chain follows); release
-- -> try to snap to a nearby block's bottom. We detach the block from its
-- previous chain on drag start so it lifts cleanly out of the stack.
function Canvas:_wireDrag(blk)
    local moveConn, endConn, dragging
    blk.frame.InputBegan:Connect(function(input)
        if input.UserInputType ~= Enum.UserInputType.MouseButton1 then return end
        dragging = {
            startMouse = UIS:GetMouseLocation(),
            startPos = blk.frame.Position,
            moved = false,
        }
        -- defer detach + ZIndex bump until we know it's a real drag (so a
        -- click-without-move can fire :blockClicked cleanly)
    end)
    moveConn = UIS.InputChanged:Connect(function(input)
        if not dragging or input.UserInputType ~= Enum.UserInputType.MouseMovement then return end
        local mm = UIS:GetMouseLocation()
        local dx = mm.X - dragging.startMouse.X
        local dy = mm.Y - dragging.startMouse.Y
        if not dragging.moved and (dx * dx + dy * dy) > 36 then
            dragging.moved = true
            self:_detach(blk)
            blk.frame.ZIndex = 100
            local cur = blk.next; while cur do cur.frame.ZIndex = 100; cur = cur.next end
        end
        if dragging.moved then
            blk.frame.Position = UDim2.fromOffset(
                dragging.startPos.X.Offset + dx,
                dragging.startPos.Y.Offset + dy
            )
            self:_layoutChain(blk)
        end
    end)
    endConn = UIS.InputEnded:Connect(function(input)
        if not dragging or input.UserInputType ~= Enum.UserInputType.MouseButton1 then return end
        local moved = dragging.moved
        dragging = nil
        if not moved then
            self.blockClicked:Fire(blk)
            return
        end
        -- drag finish: try-snap then settle. Brief click-guard window
        -- prevents the MB1Up over a value button (now sitting under the
        -- cursor after the drag) from firing its onClick handler -- that
        -- was blanking the label on key blocks and cycling values on
        -- look/rotate/feature blocks. Delete is now per-block via the
        -- trash icon (top-right corner).
        dragJustEnded = true
        task.delay(0.12, function() dragJustEnded = false end)
        self:_trySnap(blk)
        blk.frame.ZIndex = 2
        local cur = blk.next; while cur do cur.frame.ZIndex = 2; cur = cur.next end
        self:_resizeToContent()
        self:_fireChanged()
    end)
    blk._dragConns = { moveConn, endConn }
end

function Canvas:_destroyBlock(blk)
    -- Re-knit prev and next so a middle-block delete keeps the chain
    -- continuous instead of leaving the tail floating where it was.
    local prev, nxt = blk.prev, blk.next
    if prev and nxt then prev.next = nxt; nxt.prev = prev
    elseif prev then prev.next = nil
    elseif nxt then nxt.prev = nil
    end
    if blk._dragConns then
        for _, c in ipairs(blk._dragConns) do pcall(function() c:Disconnect() end) end
    end
    if blk._keyCaptureConn then pcall(function() blk._keyCaptureConn:Disconnect() end); blk._keyCaptureConn = nil end
    blk.frame:Destroy()
    for i, b in ipairs(self.blocks) do if b == blk then table.remove(self.blocks, i); break end end
    -- Tighten layout: chain prev belonged to gets re-laid so the tail
    -- moves up to fill the gap. Free-floating tail (no prev) stays where
    -- it was -- that's a deliberate gap the user can re-snap if desired.
    if prev then self:_layoutChain(chainHead(prev)) end
    self:_resizeToContent()
    self:_fireChanged()
end

-- Explicit teardown: clear all blocks (disconnects drag conns) and destroy
-- the canvas frame. Use from Builder.open/close + the AND branch sub-modal
-- so re-opens don't leak per-block UIS.InputChanged/InputEnded connections.
function Canvas:destroy()
    self:clear()
    if self.frame then pcall(function() self.frame:Destroy() end); self.frame = nil end
end

-- Render the visual block (rounded fill, label, decorative top notch + bottom
-- tab, X button to delete). Inline param controls are added by renderParams.
function Canvas:_renderBlock(blk)
    local f = blk.frame
    f.BackgroundColor3 = colorOf(blk.type)
    corner(f, 10)
    stroke(f, lerpCol(colorOf(blk.type), 0.55), 1)

    local lbl = Instance.new("TextLabel")
    lbl.Size = UDim2.new(0, 78, 1, 0); lbl.Position = UDim2.fromOffset(10, 0)
    lbl.BackgroundTransparency = 1; lbl.Text = STEP_LABEL[blk.type] or blk.type
    lbl.TextColor3 = theme.fg; lbl.Font = theme.fontBold; lbl.TextSize = 13
    lbl.TextXAlignment = Enum.TextXAlignment.Left
    -- Pin label above the rest of the block's children (the val Frame and
    -- the trash icon both render in the same parent; sibling ZIndex ties
    -- can occasionally hide a label in screenshots -- defensive bump).
    lbl.ZIndex = 5
    lbl.Parent = f
    blk.lbl = lbl

    -- bottom tab decoration (visual connector cue)
    local tab = Instance.new("Frame")
    tab.Size = UDim2.fromOffset(TAB_W, 3); tab.Position = UDim2.new(0, TAB_INSET_X, 1, 0)
    tab.BackgroundColor3 = colorOf(blk.type); tab.BorderSizePixel = 0; tab.Parent = f

    -- Per-block trash icon (top-right corner of every block). The global
    -- drag-to-trash zone was removed -- this is the only delete affordance
    -- now and we make it readable: bigger, with a clearer label, higher
    -- ZIndex so it always lands above the inline value button on its left.
    local del = Instance.new("TextButton")
    del.Size = UDim2.fromOffset(22, 22); del.Position = UDim2.new(1, -26, 0, 4)
    del.BackgroundColor3 = theme.danger; del.AutoButtonColor = true
    del.TextColor3 = theme.fg; del.Font = theme.fontBold; del.TextSize = 13
    del.Text = "X"; del.ZIndex = 10
    del.Parent = f; corner(del, 4)
    guardedClick(del, function() self:_destroyBlock(blk) end)

    renderParams(blk)
end

function Canvas:addBlock(blockType, params, x, y)
    local f = Instance.new("Frame")
    f.Size = UDim2.fromOffset(BLOCK_W, BLOCK_H)
    -- Explicitly pin AutomaticSize off so no parent layout / inherited size
    -- mode can shrink the block to 0 height (which was the most plausible
    -- explanation for the "thin sliver" rendering in the user's screenshot).
    f.AutomaticSize = Enum.AutomaticSize.None
    f.Position = UDim2.fromOffset(x or 12, y or (#self.blocks * (BLOCK_H + 4) + 12))
    f.BackgroundColor3 = colorOf(blockType); f.BorderSizePixel = 0
    f.ZIndex = 2; f.Parent = self.frame

    local blk = {
        id = self:_nextId(), type = blockType, params = params or {},
        frame = f, next = nil, prev = nil, canvas = self,
    }
    self.blocks[#self.blocks + 1] = blk
    self:_renderBlock(blk)
    self:_wireDrag(blk)
    -- try auto-snap to last block's bottom if visually close enough -- so
    -- click-to-add from a palette button still produces a stack on the
    -- canvas (V1 keeps the palette tap path even with drag enabled).
    self:_trySnap(blk)
    self:_resizeToContent()
    self:_fireChanged()
    return blk
end

function Canvas:clear()
    for _, b in ipairs(self.blocks) do
        if b._dragConns then for _, c in ipairs(b._dragConns) do pcall(function() c:Disconnect() end) end end
        if b._keyCaptureConn then pcall(function() b._keyCaptureConn:Disconnect() end); b._keyCaptureConn = nil end
        b.frame:Destroy()
    end
    self.blocks = {}
end

-- Read canvas state -> linear action array. Strategy: find chain heads (no
-- .prev), walk each chain head -> next -> ... to produce a list per chain,
-- then concat all chains in order of their head's Y position (so the
-- top-most chain is the "main" sequence, with disconnected blocks tacked on
-- in Y order). Includes block.params verbatim.
function Canvas:toActions()
    local heads = {}
    for _, b in ipairs(self.blocks) do if not b.prev then heads[#heads + 1] = b end end
    table.sort(heads, function(a, b)
        return a.frame.Position.Y.Offset < b.frame.Position.Y.Offset
    end)
    local out = {}
    for _, h in ipairs(heads) do
        local cur = h
        while cur do
            local a = { type = cur.type }
            for k, v in pairs(cur.params or {}) do a[k] = v end
            out[#out + 1] = a
            cur = cur.next
        end
    end
    return out
end

-- Hydrate canvas from a saved action array -- place blocks vertically and
-- chain them. Anything that came in chained stays chained on load (so a
-- saved tech opens visually identical to a Scratch stack).
function Canvas:loadActions(actions)
    self:clear()
    local y = 12
    local prev
    for _, a in ipairs(actions or {}) do
        local params = {}
        for k, v in pairs(a) do if k ~= "type" then params[k] = v end end
        local blk = self:addBlock(a.type, params, 12, y)
        -- _trySnap on add will chain with last block; if it didn't snap
        -- (unlikely on identical x), manually wire it
        if prev and not blk.prev then prev.next = blk; blk.prev = prev end
        y = y + BLOCK_H + 4
        prev = blk
    end
    if prev then self:_layoutChain(chainHead(prev)) end
end

return Canvas
end

_MODULES["modules.tech.builder_ui"] = function()
-- Tech Builder editor window -- JJS-skill-builder style, two panes:
--   LEFT  = the tech form (name, trigger, conditions, step palette + chips).
--   RIGHT = a ViewportFrame preview on a CLONE of your avatar, so "Play" runs the
--           tech (look/rotate/wait/return reenactment) INSIDE the window instead
--           of on your real character. Rig-clone/viewport approach is ported from
--           the [Uni] Animation Logger.
--
-- Built techs persist via [[modules.tech.engine]].saveCustom.

local env        = require("core.env")
local theme      = require("ui.theme")
local components = require("ui.components")
local engine     = require("modules.tech.engine")
local scanner    = require("modules.tech.scanner")
local feature    = require("ui.feature")
local persist    = require("core.persist")
local notify     = require("ui.notify")
local CanvasUI   = require("modules.tech.canvas_ui")

local UIS        = game:GetService("UserInputService")
local RunService = game:GetService("RunService")
local Players    = game:GetService("Players")

local Builder = {}

local gui, rootFrame, formScroll
local canvas, canvasContainer   -- Scratch canvas + its wrapper Frame; persist across rebuilds so blocks don't get destroyed when the form re-renders
local winDragConns = {}         -- global UIS connections for the window-drag handle; disconnected in Builder.destroy()
local draft
local animDropOpen = false   -- is the played-anim dropdown expanded right now

local CONDITIONS = {
    { id = "locked_on",      label = "Locked on"          },
    { id = "shiftlock",      label = "Shiftlock on"       },
    { id = "target_playing", label = "Target playing anim" },
}
-- palette buttons (Release is added automatically with Hold, not its own button)
local ACTION_TYPES = { "look", "rotate", "during", "wait", "within", "return", "feature", "key", "hold", "usebtn" }
local STEP_LABEL   = { look = "Look", rotate = "Rotate", wait = "Wait", during = "During",
                       within = "Within", ["return"] = "Return", feature = "Use", key = "Press",
                       hold = "Hold", release = "Release", usebtn = "Use Move" }
local YAW_PRESETS  = { 180, 135, 90, 45, 0, -45, -90, -135, -180 }

-- Scratch-style category coloring. Block fill = category color; the action's
-- specific look is the category palette + its label. Sticking to Scratch's
-- conventional groupings so the visual maps to player expectation: motion blue,
-- control orange, sensing cyan, events yellow, custom/actions purple.
local CATEGORY = {
    -- motion / facing
    look = "motion", rotate = "motion",
    -- control flow / timing
    wait = "control", during = "control", ["return"] = "control",
    hold = "control", release = "control",
    -- sensing / gating
    within = "sense",
    -- actions / "operators"
    feature = "action", key = "action", usebtn = "action",
}
local CAT_COLOR = {
    motion  = Color3.fromRGB(76, 151, 255),    -- blue
    control = Color3.fromRGB(255, 171, 25),    -- orange
    sense   = Color3.fromRGB(92, 177, 214),    -- cyan
    action  = Color3.fromRGB(159, 110, 220),   -- purple
    event   = Color3.fromRGB(255, 191, 0),     -- yellow (hat blocks)
}
local function catOf(t) return CATEGORY[t] or "action" end
local function colorOf(t) return CAT_COLOR[catOf(t)] end

-- ---------- small helpers ----------
local function corner(o, r) local c = Instance.new("UICorner"); c.CornerRadius = UDim.new(0, r or 6); c.Parent = o; return c end
local function stroke(o, col) local s = Instance.new("UIStroke"); s.Color = col or theme.border; s.Thickness = 1; s.Parent = o; return s end

local function wrap(height, fn)
    local w = Instance.new("Frame")
    w.Size = UDim2.new(1, 0, 0, height); w.BackgroundTransparency = 1
    fn(w); return w
end

local function cycleRow(parent, labelText, options, currentIndex, onPick)
    local f = Instance.new("Frame")
    f.Size = UDim2.new(1, 0, 0, 28); f.BackgroundColor3 = theme.bgAlt; f.BorderSizePixel = 0; f.Parent = parent
    local lbl = Instance.new("TextLabel")
    lbl.Size = UDim2.new(0.4, -8, 1, 0); lbl.Position = UDim2.fromOffset(8, 0); lbl.BackgroundTransparency = 1
    lbl.Text = labelText; lbl.TextColor3 = theme.fgDim; lbl.Font = theme.font; lbl.TextSize = 12
    lbl.TextXAlignment = Enum.TextXAlignment.Left; lbl.Parent = f
    local btn = Instance.new("TextButton")
    btn.Size = UDim2.new(0.6, -12, 0, 20); btn.Position = UDim2.new(0.4, 4, 0.5, -10); btn.BackgroundColor3 = theme.bgDark
    btn.AutoButtonColor = false; btn.TextColor3 = theme.fg; btn.Font = theme.font; btn.TextSize = 12
    btn.TextTruncate = Enum.TextTruncate.AtEnd; btn.Text = options[currentIndex] or "<none>"; btn.Parent = f
    btn.MouseButton1Click:Connect(function()
        if #options == 0 then return end
        currentIndex = (currentIndex % #options) + 1
        btn.Text = options[currentIndex]; onPick(currentIndex)
    end)
    return f
end

local function textRow(parent, labelText, value, onCommit)
    local f = Instance.new("Frame")
    f.Size = UDim2.new(1, 0, 0, 28); f.BackgroundColor3 = theme.bgAlt; f.BorderSizePixel = 0; f.Parent = parent
    local lbl = Instance.new("TextLabel")
    lbl.Size = UDim2.new(0.4, -8, 1, 0); lbl.Position = UDim2.fromOffset(8, 0); lbl.BackgroundTransparency = 1
    lbl.Text = labelText; lbl.TextColor3 = theme.fgDim; lbl.Font = theme.font; lbl.TextSize = 12
    lbl.TextXAlignment = Enum.TextXAlignment.Left; lbl.Parent = f
    local box = Instance.new("TextBox")
    box.Size = UDim2.new(0.6, -12, 0, 20); box.Position = UDim2.new(0.4, 4, 0.5, -10); box.BackgroundColor3 = theme.bgDark
    box.TextColor3 = theme.fg; box.Font = theme.font; box.TextSize = 12; box.Text = value or ""; box.ClearTextOnFocus = false
    box.PlaceholderText = "..."; box.Parent = f
    box.FocusLost:Connect(function() onCommit(box.Text) end)
    return f
end

local function smallBtn(parent, txt, posX, color)
    local b = Instance.new("TextButton")
    b.Size = UDim2.fromOffset(20, 22); b.Position = UDim2.new(1, posX, 0.5, -11); b.BackgroundColor3 = color or theme.bgAlt
    b.AutoButtonColor = false; b.TextColor3 = theme.fg; b.Font = theme.fontBold; b.TextSize = 11; b.Text = txt; b.Parent = parent
    return b
end

local function featName(id)
    if not id then return "(pick)" end
    for _, ft in ipairs(feature.all()) do if ft.id == id then return ft.name end end
    return id
end
local function nextPreset(list, cur)
    for i, v in ipairs(list) do if math.abs(v - (cur or 0)) < 1e-3 then return list[(i % #list) + 1] end end
    return list[1]
end

-- A hotbar keybind label is often a DIGIT ("1".."9") but Enum.KeyCode has no "1"
-- member -- it's "One" -- and Enum.KeyCode["1"] THROWS. Map digits to their names
-- and look up safely so a numbered move key can't blow up the form.
local DIGIT_NAMES = { ["0"]="Zero",["1"]="One",["2"]="Two",["3"]="Three",["4"]="Four",
                      ["5"]="Five",["6"]="Six",["7"]="Seven",["8"]="Eight",["9"]="Nine" }
local function keyNameNorm(hint)
    if not hint then return nil end
    hint = tostring(hint)
    return DIGIT_NAMES[hint] or hint
end
local function toKeyCode(name)
    name = keyNameNorm(name)
    if not name then return nil end
    local ok, kc = pcall(function() return Enum.KeyCode[name] end)
    return ok and kc or nil
end

-- Resolve the current character name from the active per-game module's
-- detectCharacter() hook, used by char-scoped techs. Returns nil when there's
-- no per-game module or it can't determine the character yet.
local function detectCurrentCharacter()
    local ok, registry = pcall(require, "games.registry")
    if not ok or not registry then return nil end
    local mod = registry.current()
    local fn = mod and mod.detectCharacter
    if type(fn) ~= "function" then return nil end
    local ok2, name = pcall(fn)
    return ok2 and name or nil
end

-- ---------- draft <-> tech ----------
local function newDraft()
    return { name = "New Tech", scope = "game", event = "key",
             key = Enum.KeyCode.Unknown, move = nil, conditions = {}, actions = {} }
end
-- Deep-copy an action table so the in-flight draft can't accidentally mutate
-- the saved tech. AND blocks carry a `branches = {[steps],[steps]}` nested
-- structure and any new step type may add fields we haven't enumerated; the
-- generic copy keeps everything in sync without per-type maintenance.
local function copyAction(a)
    local out = {}
    for k, v in pairs(a) do
        if type(v) == "table" then
            -- shallow into branches[]: each branch is a list of actions;
            -- recurse one more level so per-step params survive.
            if k == "branches" then
                local bs = {}
                for i, branch in ipairs(v) do
                    local cb = {}
                    for j, step in ipairs(branch) do cb[j] = copyAction(step) end
                    bs[i] = cb
                end
                out[k] = bs
            else
                out[k] = v   -- non-branches tables: reference-share (rare; defensive)
            end
        else
            out[k] = v
        end
    end
    return out
end

-- Map an engine trigger.event string -> the matching canvas hat block type.
local function hatTypeForEvent(ev)
    if ev == "key" or ev == "keyhold" then return "event_key"
    elseif ev == "anim" then return "event_anim"
    elseif ev == "target_anim" then return "event_target_anim"
    elseif ev == "move" then return "event_move"
    end
    return nil
end
-- Inverse: hat type -> engine trigger.event. event_key carries the
-- key/keyhold distinction in its own .event param (set by the hat modal's
-- "Hold the key" toggle).
local function eventForHat(hat)
    if hat.type == "event_key" then return hat.event == "keyhold" and "keyhold" or "key"
    elseif hat.type == "event_anim" then return "anim"
    elseif hat.type == "event_target_anim" then return "target_anim"
    elseif hat.type == "event_move" then return "move"
    end
    return "key"
end

local function draftFromTech(t)
    local conds = {}
    for _, c in ipairs(t.trigger.conditions or {}) do conds[c] = true end
    local actions = {}
    local trigEvent = t.trigger and t.trigger.event
    if trigEvent == "or" then
        -- Multi-trigger OR tech. Reconstruct the OR block carrying
        -- subtriggers + branches; the engine "or" step in t.actions[1]
        -- gets folded into the OR block (its branches list lives there
        -- in the canvas representation). Post-OR actions stay as a tail.
        local first = t.actions and t.actions[1]
        local branches = (first and first.type == "or" and first.branches) or {}
        local subts = {}
        for i, s in ipairs(t.trigger.subtriggers or {}) do
            local copy = {}
            for k, v in pairs(s) do copy[k] = v end
            subts[i] = copy
        end
        actions[#actions + 1] = { type = "or", triggers = subts, branches = branches }
        local startAt = (first and first.type == "or") and 2 or 1
        for i = startAt, #(t.actions or {}) do
            actions[#actions + 1] = copyAction(t.actions[i])
        end
    else
        -- Single-trigger flow: prepend a hat block carrying the trigger
        -- params so the user sees the trigger as a real block on the canvas
        -- (and can drag/configure/delete it like any other step).
        local hatType = hatTypeForEvent(trigEvent)
        if hatType then
            local hat = { type = hatType }
            for k, v in pairs(t.trigger or {}) do
                if k ~= "event" and k ~= "conditions" and k ~= "subtriggers" then hat[k] = v end
            end
            if hatType == "event_key" then hat.event = t.trigger.event end   -- "key" vs "keyhold"
            actions[#actions + 1] = hat
        end
        for _, a in ipairs(t.actions or {}) do
            actions[#actions + 1] = copyAction(a)
        end
    end
    -- Decode scope. Numeric or unspecified -> "game" (saved as PlaceId/GameId on
    -- save). "universal" stays as-is. "char:<name>" maps to "char" and the
    -- pinned name (so editing preserves the char binding even if we're not
    -- currently playing as that character).
    local scope, pinChar = "game", nil
    if t.scope == "universal" then scope = "universal"
    elseif type(t.scope) == "string" then
        local cn = t.scope:match("^char:(.+)$")
        if cn then scope = "char"; pinChar = cn end
    end
    return {
        editId = t.id, name = t.name,
        scope = scope, pinChar = pinChar,
        event = t.trigger.event, key = t.trigger.key, move = t.trigger.move, movekey = t.trigger.movekey,
        modkey = t.trigger.modkey, maxRange = t.trigger.maxRange,
        animId = t.trigger.animId, animEnd = t.trigger.animEnd,
        targetAnimId = t.trigger.targetAnimId,
        suppress = t.trigger.suppress, ignoreWelds = t.trigger.ignoreWelds,
        conditions = conds, actions = actions,
    }
end
local function draftConditions()
    local conds = {}
    for _, c in ipairs(CONDITIONS) do if draft.conditions[c.id] then conds[#conds + 1] = c.id end end
    return conds
end
local function draftActions()
    -- Generic deep copy: previously a hard-coded per-type whitelist that
    -- silently DROPPED any field not in the list (which is how AND's
    -- branches were getting lost on Save). copyAction handles branches[]
    -- recursively + future-proofs against new step fields.
    local actions = {}
    for _, a in ipairs(draft.actions) do actions[#actions + 1] = copyAction(a) end
    return actions
end
local function buildTechFromDraft(id)
    -- Resolve scope (game / char / universal).
    local scope
    if draft.scope == "universal" then
        scope = "universal"
    elseif draft.scope == "char" then
        local cn = draft.pinChar or detectCurrentCharacter()
        scope = cn and ("char:" .. cn) or game.GameId
    else
        scope = game.GameId
    end

    -- Base trigger from the legacy form fields. The hat-block-on-canvas
    -- path BELOW will overwrite event + relevant params if a hat is
    -- present, taking precedence over the form. Form fields are kept as
    -- a fallback for techs the user hasn't migrated to a hat yet.
    local trigger = {
        event = draft.event, key = draft.key, move = draft.move, movekey = draft.movekey,
        modkey = draft.modkey, maxRange = draft.maxRange,
        animId = draft.animId, animEnd = draft.animEnd,
        targetAnimId = draft.targetAnimId,
        suppress = draft.suppress, ignoreWelds = draft.ignoreWelds,
        conditions = draftConditions(),
    }

    local actions = draftActions()
    -- Canvas head extraction. Three cases:
    --  * OR block at top  -> multi-trigger fork: subtriggers move to
    --    tech.trigger.subtriggers (event="or"), and the engine OR step
    --    {type="or", branches=...} re-inserts at actions[1] so runStep
    --    can pick branches[ctx.triggerIndex] at fire time.
    --  * Hat block at top -> single trigger: hat params become tech.trigger.
    --  * Neither           -> trigger came from legacy form fields (untouched).
    if actions[1] and actions[1].type == "or" then
        local orBlock = table.remove(actions, 1)
        trigger.event = "or"
        trigger.subtriggers = orBlock.triggers or {}
        table.insert(actions, 1, { type = "or", branches = orBlock.branches or {} })
    elseif actions[1] and CanvasUI.isHat(actions[1].type) then
        local hat = table.remove(actions, 1)
        trigger.event = eventForHat(hat)
        for k, v in pairs(hat) do
            if k ~= "type" and k ~= "event" then trigger[k] = v end
        end
    end

    return {
        id = id, name = (draft.name and #draft.name > 0) and draft.name or "Tech", custom = true,
        scope = scope, enabled = true,
        trigger = trigger, actions = actions,
    }
end
local function onSave()
    local name = (draft.name and #draft.name > 0) and draft.name or "Tech"
    local id = draft.editId
    if not id then
        local base = "custom." .. persist.slug(name); id = base
        local n = 2
        while engine.get(id) do id = base .. "_" .. n; n = n + 1 end
    end
    -- Sync from canvas before save: param edits (Wait seconds, Within studs,
    -- key bindings, etc.) update block.params in place but DON'T fire the
    -- canvas's onChange -- only chain ops do. Without this resync, edits made
    -- after the last drag/snap were dropped on Save.
    if canvas then draft.actions = canvas:toActions() end
    local tech = buildTechFromDraft(id)
    engine.saveCustom(tech)
    notify.success("Tech saved: " .. tech.name)
    Builder.close()
end

-- ---------- viewport preview (clone rig, ported from Animation Logger) ----------
local vpFrame, worldModel, vpCam, rigTemplate, curRig, curTrack
local camTarget, camDist = Vector3.new(0, 2.5, 0), 12
local curYaw, previewing = 0, false

local function captureRig()
    local char = Players.LocalPlayer.Character
    if not char then return end
    local ok, clone = pcall(function()
        local was = char.Archivable; char.Archivable = true
        local c = char:Clone(); char.Archivable = was; return c
    end)
    if not ok or not clone then return end
    for _, d in ipairs(clone:GetDescendants()) do
        if d:IsA("LuaSourceContainer") or d:IsA("Tool") or d:IsA("Sound") or d:IsA("BodyMover") then
            pcall(function() d:Destroy() end)
        end
    end
    if rigTemplate then rigTemplate:Destroy() end
    rigTemplate = clone
end

local function rigSetYaw(yaw)
    curYaw = yaw
    if curRig and curRig.PrimaryPart then pcall(function() curRig:PivotTo(CFrame.Angles(0, math.rad(yaw), 0)) end) end
end

local function buildRigPreview()
    if curTrack then pcall(function() curTrack:Stop(0) end); curTrack = nil end
    if curRig then curRig:Destroy(); curRig = nil end
    if not rigTemplate then captureRig() end
    if not (rigTemplate and worldModel) then return end
    local rig = rigTemplate:Clone()
    local hum = rig:FindFirstChildOfClass("Humanoid")
    local hrp = rig:FindFirstChild("HumanoidRootPart") or rig.PrimaryPart
    if hum then pcall(function() hum.EvaluateStateMachine = false end) end
    rig.Parent = worldModel
    curRig = rig
    if hrp then rig.PrimaryPart = hrp; rig:PivotTo(CFrame.new(0, 0, 0)); hrp.Anchored = true end
    local cf, size = rig:GetBoundingBox()
    camTarget = cf.Position
    camDist = math.max(size.X, size.Y, size.Z) * 1.7 + 2
    -- fixed front-ish camera so the body's turn is readable
    if vpCam then vpCam.CFrame = CFrame.lookAt(camTarget + Vector3.new(0, camDist * 0.12, camDist), camTarget) end
    curYaw = 0
end

-- play an animation on the clone's Animator (ported from the Animation Logger):
-- HRP is anchored, the rest stay jointed by Motor6D and get posed by the track.
-- VFX isn't reproduced (it's spawned by the game's own scripts, not the track).
local function playAnimOnRig(id, loop)
    if not curRig then buildRigPreview() end
    if not curRig then return end
    if curTrack then pcall(function() curTrack:Stop(0) end); curTrack = nil end
    local num = tostring(id):match("%d+"); if not num then return end
    local hum = curRig:FindFirstChildOfClass("Humanoid")
    local animator = hum and hum:FindFirstChildOfClass("Animator")
    if hum and not animator then animator = Instance.new("Animator"); animator.Parent = hum end
    if not animator then return end
    local a = Instance.new("Animation"); a.AnimationId = "rbxassetid://" .. num
    local ok, tr = pcall(function() return animator:LoadAnimation(a) end)
    if ok and tr then
        tr.Looped = loop and true or false
        pcall(function() tr.Priority = Enum.AnimationPriority.Action end)
        pcall(function() tr:Play() end)
        curTrack = tr
    end
end

local function tweenYaw(target, dur)
    dur = dur or 0.15
    local start, t0 = curYaw, os.clock()
    while os.clock() - t0 < dur do
        rigSetYaw(start + (target - start) * ((os.clock() - t0) / dur)); task.wait()
    end
    rigSetYaw(target)
end

-- play the tech's look/rotate/wait/return as a body-turn reenactment on the clone
local function previewDraft()
    if previewing then return end
    -- Pull the latest blocks off the canvas: canvas.onChange only refreshes
    -- draft.actions on chain ops, not inline param edits, so without this a
    -- Play right after editing a Wait/Look value would replay the old values.
    if canvas then draft.actions = canvas:toActions() end
    buildRigPreview()
    if not curRig then notify.warn("Preview: couldn't clone your avatar"); return end
    -- if this tech is animation-triggered, play that anim on the clone too
    if draft.event == "anim" and draft.animId then playAnimOnRig(draft.animId, true) end
    previewing = true
    task.spawn(function()
        rigSetYaw(0)
        local releaseAfter = false
        for _, a in ipairs(draft.actions or {}) do
            if a.type == "look" or a.type == "rotate" then
                tweenYaw(a.x or 0)
            elseif a.type == "wait" then
                task.wait(a.seconds or 0.5)
                if releaseAfter then tweenYaw(0); releaseAfter = false end
            elseif a.type == "during" then
                releaseAfter = true
            elseif a.type == "within" then
                task.wait(0.3)   -- can't gauge range in the preview; brief beat
                if releaseAfter then tweenYaw(0); releaseAfter = false end
            elseif a.type == "return" then
                tweenYaw(0)
            end
        end
        tweenYaw(0)
        previewing = false
    end)
end

-- ---------- step chip (Scratch-style block) ----------
-- V0 of the Scratch rewrite: visual restyle of the existing chip rows. Colored
-- by category, rounded with category-tinted background, decorative top-notch
-- and bottom-tab so blocks visually "join" in the column. Drag-and-drop +
-- snap-to-connect + nested slots arrive in V1; this layer keeps the proven
-- click-to-add palette + ^/v reorder so we ship working blocks today.
local rebuild
local function buildChip(parent, i, act)
    local cat = catOf(act.type)
    local fill = colorOf(act.type)

    -- decorative "notch" above (in the gap of the UIListLayout) so the column
    -- reads as one chain. The UIListLayout padding is set to 0 on the form so
    -- consecutive blocks visually butt up against each other.
    local f = Instance.new("Frame")
    f.Size = UDim2.new(1, 0, 0, 38); f.BackgroundColor3 = fill; f.BorderSizePixel = 0
    f.Parent = parent
    corner(f, 10)
    local s = stroke(f, theme.bgDark); s.Thickness = 2; s.Transparency = 0.4

    -- bottom "tab" -- a tiny rectangle protruding from the block's bottom edge.
    -- Visual only; on snap-connect (V1) this is the actual connector.
    local tab = Instance.new("Frame")
    tab.Size = UDim2.fromOffset(20, 3); tab.Position = UDim2.new(0, 22, 1, 0)
    tab.BackgroundColor3 = fill; tab.BorderSizePixel = 0; tab.ZIndex = (f.ZIndex or 1) + 1
    tab.Parent = f
    local tabC = Instance.new("UICorner"); tabC.CornerRadius = UDim.new(0, 2); tabC.Parent = tab

    -- left grip column = drag handle (visual only in V0; V1 wires it to a
    -- real reorder drag). Currently the ^/v buttons handle reordering.
    local grip = Instance.new("TextLabel")
    grip.Size = UDim2.fromOffset(10, 24); grip.Position = UDim2.new(0, 4, 0.5, -12)
    grip.BackgroundTransparency = 1
    grip.Text = "::"; grip.TextColor3 = theme.fg
    grip.Font = theme.fontBold; grip.TextSize = 14
    grip.TextTransparency = 0.5
    grip.Parent = f

    local lbl = Instance.new("TextLabel")
    lbl.Size = UDim2.new(0, 78, 1, 0); lbl.Position = UDim2.fromOffset(18, 0); lbl.BackgroundTransparency = 1
    lbl.Text = i .. ".  " .. (STEP_LABEL[act.type] or act.type)
    lbl.TextColor3 = theme.fg; lbl.Font = theme.fontBold; lbl.TextSize = 13
    lbl.TextXAlignment = Enum.TextXAlignment.Left; lbl.Parent = f

    local val
    if act.type == "wait" then
        val = Instance.new("TextBox"); val.ClearTextOnFocus = false; val.PlaceholderText = "seconds"
        val.Text = tostring(act.seconds or 0.5)
        val.FocusLost:Connect(function()
            local n = tonumber((val.Text:gsub("[^%d%.]", "")))
            if n then act.seconds = math.clamp(n, 0, 60) end
            val.Text = tostring(act.seconds or 0.5)
        end)
    elseif act.type == "within" then
        -- wait here until the target is within this many studs, then continue
        val = Instance.new("TextBox"); val.ClearTextOnFocus = false; val.PlaceholderText = "studs"
        val.Text = tostring(act.studs or 5)
        val.FocusLost:Connect(function()
            local n = tonumber((val.Text:gsub("[^%d%.]", "")))
            if n then act.studs = math.clamp(n, 0, 500) end
            val.Text = tostring(act.studs or 5)
        end)
    elseif act.type == "key" or act.type == "hold" or act.type == "release" then
        val = Instance.new("TextButton"); val.AutoButtonColor = false
        val.Text = act.key and ("key: " .. act.key) or "(click, press a key)"
        val.MouseButton1Click:Connect(function()
            val.Text = "press a key..."
            local conn
            conn = UIS.InputBegan:Connect(function(input)
                if input.UserInputType ~= Enum.UserInputType.Keyboard then return end
                if input.KeyCode == Enum.KeyCode.Unknown then return end
                if input.KeyCode ~= Enum.KeyCode.Escape then
                    local kn = (tostring(input.KeyCode):gsub("Enum.KeyCode.", ""))
                    act.key = kn
                    -- Hold + Release share one key, so set both halves of the pair
                    if act.holdId then
                        for _, o in ipairs(draft.actions) do if o.holdId == act.holdId then o.key = kn end end
                    end
                end
                val.Text = act.key and ("key: " .. act.key) or "(click, press a key)"
                conn:Disconnect()
            end)
        end)
    elseif act.type == "usebtn" then
        -- pick which hotbar move's GUI button this step fires (from the live scan)
        local res = scanner.cached() or scanner.scan()
        local moveset = res.buttons or {}
        if act.move == nil and #moveset > 0 then act.move = moveset[1].name end
        val = Instance.new("TextButton"); val.AutoButtonColor = false
        local function moveLabel()
            if #moveset == 0 then return "(no moves - Dump GUI)" end
            for _, b in ipairs(moveset) do
                if b.name == act.move then return (b.text ~= "" and b.text) or b.name end
            end
            return "(pick move)"
        end
        val.Text = moveLabel()
        val.MouseButton1Click:Connect(function()
            if #moveset == 0 then return end
            local idx = 0
            for k, b in ipairs(moveset) do if b.name == act.move then idx = k end end
            act.move = moveset[(idx % #moveset) + 1].name
            val.Text = moveLabel()
        end)
    else
        val = Instance.new("TextButton"); val.AutoButtonColor = false
        local function valText()
            if act.type == "look" or act.type == "rotate" then return tostring(act.x or 0) .. "\u{00B0}"
            elseif act.type == "feature" then return featName(act.feature)
            elseif act.type == "during" then return "holds prev step for next wait"
            else return "re-face target" end
        end
        val.Text = valText()
        if act.type ~= "return" and act.type ~= "during" then
            val.MouseButton1Click:Connect(function()
                if act.type == "look" or act.type == "rotate" then
                    act.x = nextPreset(YAW_PRESETS, act.x)
                elseif act.type == "feature" then
                    local feats = feature.all()
                    table.sort(feats, function(a, b) return (a.name or a.id) < (b.name or b.id) end)
                    if #feats > 0 then
                        local idx = 0
                        for k, ft in ipairs(feats) do if ft.id == act.feature then idx = k end end
                        act.feature = feats[(idx % #feats) + 1].id
                    end
                end
                val.Text = valText()
            end)
        end
    end
    val.Size = UDim2.new(1, -174, 1, -10); val.Position = UDim2.new(0, 100, 0, 5)
    val.BackgroundColor3 = theme.bgDark
    val.TextColor3 = (act.type == "return" or act.type == "during") and theme.fgDim or theme.fg
    val.Font = theme.font; val.TextSize = 12; val.Parent = f
    pcall(function() local vc = Instance.new("UICorner"); vc.CornerRadius = UDim.new(0, 6); vc.Parent = val end)

    local up = smallBtn(f, "^", -68)
    up.MouseButton1Click:Connect(function()
        if i > 1 then draft.actions[i], draft.actions[i-1] = draft.actions[i-1], draft.actions[i]; rebuild() end
    end)
    local down = smallBtn(f, "v", -46)
    down.MouseButton1Click:Connect(function()
        if i < #draft.actions then draft.actions[i], draft.actions[i+1] = draft.actions[i+1], draft.actions[i]; rebuild() end
    end)
    local rem = smallBtn(f, "X", -22, theme.danger)
    rem.MouseButton1Click:Connect(function() table.remove(draft.actions, i); rebuild() end)
    return f
end

-- "Hat block" wrapper for the trigger section header. Yellow band with a flat
-- bottom that visually connects into the first action block underneath. This
-- is decoration-only in V0 -- the trigger form fields render normally below.
local function buildHatHeader(parent, label)
    local f = Instance.new("Frame")
    f.Size = UDim2.new(1, 0, 0, 28); f.BackgroundColor3 = CAT_COLOR.event; f.BorderSizePixel = 0
    f.Parent = parent
    corner(f, 10)
    -- pin the bottom flat so it lies flush against the first action block
    local flat = Instance.new("Frame")
    flat.Size = UDim2.new(1, 0, 0, 10); flat.Position = UDim2.new(0, 0, 1, -10)
    flat.BackgroundColor3 = CAT_COLOR.event; flat.BorderSizePixel = 0; flat.Parent = f
    -- tab on the bottom matching action-block notch position
    local tab = Instance.new("Frame")
    tab.Size = UDim2.fromOffset(20, 3); tab.Position = UDim2.new(0, 22, 1, 0)
    tab.BackgroundColor3 = CAT_COLOR.event; tab.BorderSizePixel = 0; tab.Parent = f
    local tc = Instance.new("UICorner"); tc.CornerRadius = UDim.new(0, 2); tc.Parent = tab
    local lbl = Instance.new("TextLabel")
    lbl.Size = UDim2.new(1, -16, 1, 0); lbl.Position = UDim2.fromOffset(12, 0); lbl.BackgroundTransparency = 1
    lbl.Text = label; lbl.TextColor3 = Color3.fromRGB(40, 30, 0); lbl.Font = theme.fontBold; lbl.TextSize = 13
    lbl.TextXAlignment = Enum.TextXAlignment.Left; lbl.Parent = f
    return f
end

-- ---------- Hat-block trigger editor (sub-modal) ----------
-- Click on a hat block's summary button -> open this modal. Per-type rows
-- (key picker / anim picker / move picker / etc.) write into the hat's
-- params; on Save the hat refreshes its inline summary and the draft is
-- re-synced from canvas. Each hat type renders only the params relevant
-- to that trigger event (no global show-all-fields like the legacy form).
local function openHatEditor(hatBlock)
    local t, p = hatBlock.type, hatBlock.params

    local modal = Instance.new("Frame")
    modal.Size = UDim2.new(0, 360, 0, 280)
    modal.Position = UDim2.new(0.5, -180, 0.5, -140)
    modal.BackgroundColor3 = theme.bg; modal.BorderSizePixel = 0
    modal.ZIndex = 200; modal.Parent = rootFrame
    corner(modal, 8); stroke(modal, theme.accent, 2)

    local TITLE = ({
        event_key = "When key pressed", event_anim = "When my anim plays",
        event_target_anim = "When target's anim plays", event_move = "When move pressed",
    })[t] or "Configure trigger"
    local title = Instance.new("TextLabel")
    title.Size = UDim2.new(1, -20, 0, 24); title.Position = UDim2.fromOffset(10, 8)
    title.BackgroundTransparency = 1; title.Text = TITLE
    title.TextColor3 = theme.fg; title.Font = theme.fontBold; title.TextSize = 14
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.ZIndex = 201; title.Parent = modal

    local body = Instance.new("ScrollingFrame")
    body.Size = UDim2.new(1, -20, 1, -76); body.Position = UDim2.fromOffset(10, 36)
    body.BackgroundTransparency = 1; body.BorderSizePixel = 0
    body.ScrollBarThickness = 4; body.CanvasSize = UDim2.new(0, 0, 0, 0)
    body.AutomaticCanvasSize = Enum.AutomaticSize.Y; body.ZIndex = 201; body.Parent = modal
    local bl = Instance.new("UIListLayout", body); bl.Padding = UDim.new(0, 6); bl.SortOrder = Enum.SortOrder.LayoutOrder

    local ord = 0
    local function place(inst) ord = ord + 1; inst.LayoutOrder = ord; inst.Parent = body; return inst end

    -- per-type rows. KeybindSetter / textRow / Toggle are the same components
    -- the legacy form section used -- DRY without refactoring.
    if t == "event_key" then
        place(wrap(28, function(host)
            local def = toKeyCode(p.key) or (typeof(p.key) == "EnumItem" and p.key) or Enum.KeyCode.Unknown
            components.KeybindSetter(host, { label = "Key", default = def,
                onChange = function(k) p.key = k end })
        end))
        place(wrap(28, function(host) components.Toggle(host, { text = "Hold (release = return)",
            default = p.event == "keyhold",
            onChange = function(v) p.event = v and "keyhold" or "key" end }) end))
        place(wrap(28, function(host) components.Toggle(host, { text = "Block this key's normal action",
            default = p.suppress == true,
            onChange = function(v) p.suppress = v or nil end }) end))
        place(wrap(28, function(host)
            local def = toKeyCode(p.modkey) or Enum.KeyCode.Unknown
            components.KeybindSetter(host, { label = "Hold-key (optional)", default = def,
                onChange = function(k) p.modkey = (k and k ~= Enum.KeyCode.Unknown) and (tostring(k):gsub("Enum.KeyCode.", "")) or nil end })
        end))
    elseif t == "event_anim" or t == "event_target_anim" then
        local isTarget = (t == "event_target_anim")
        place(textRow(body, "Anim ID", p.animId, function(s)
            local id = s and s:match("%d+"); p.animId = id or (s ~= "" and s) or nil
        end))
        place(wrap(28, function(host)
            local b = Instance.new("TextButton")
            b.Size = UDim2.new(1, 0, 0, 24); b.BackgroundColor3 = theme.bgDark
            b.AutoButtonColor = true; b.TextColor3 = theme.accent
            b.Font = theme.fontBold; b.TextSize = 12
            b.Text = isTarget and "Capture (target plays the move)" or "Capture (play the move now)"
            b.Parent = host; corner(b, 4)
            b.MouseButton1Click:Connect(function()
                b.Text = "Capturing..."
                local cap = isTarget and engine.captureTargetAnim or engine.captureAnim
                if cap then
                    cap(function(raw)
                        p.animId = tostring(raw):match("%d+") or tostring(raw)
                        b.Text = isTarget and "Capture (target plays the move)" or "Capture (play the move now)"
                    end)
                end
            end)
        end))
        place(wrap(28, function(host) components.Toggle(host, { text = "Fire on animation END (not start)",
            default = p.animEnd == true,
            onChange = function(v) p.animEnd = v or nil end }) end))
    elseif t == "event_move" then
        -- The engine fires a move trigger off the move's KEY (wireMove uses
        -- trig.movekey); the move NAME is optional (label + "block normal fire"
        -- button lookup). So the Move-key setter and a manual name box must
        -- ALWAYS show -- even when the scanner sees no hotbar -- or a game whose
        -- moves we can't auto-detect has NO way to build a move trigger (this was
        -- the dead-end: empty scan -> only a "No moves" label). Mirrors the
        -- Use Move action editor, which already does manual name + key.
        local res = scanner.cached() or scanner.scan()
        local moveset = res.buttons or {}
        if #moveset > 0 then
            if not p.move then
                p.move = moveset[1].name
                if moveset[1].key and not p.movekey then p.movekey = keyNameNorm(moveset[1].key) end
            end
            local labels = {}
            for _, b in ipairs(moveset) do
                local lbl = (b.text ~= "" and b.text) or b.name
                if b.key then lbl = lbl .. " [" .. b.key .. "]" end
                labels[#labels + 1] = lbl
            end
            local idx = 1
            for i, b in ipairs(moveset) do if b.name == p.move then idx = i end end
            place(cycleRow(body, "Detected move", labels, idx, function(i)
                p.move = moveset[i].name
                if moveset[i].key then p.movekey = keyNameNorm(moveset[i].key) end
            end))
        else
            place(components.Label(body, "No moves auto-detected -- set the move's key below (name optional)."))
        end
        -- Manual move name (optional): only needed so "Block move's normal fire"
        -- can find the button, and as a readable label.
        place(textRow(body, "Move name (optional)", p.move, function(s)
            p.move = (s and s ~= "") and s or nil
        end))
        -- Move key -- the ACTUAL trigger. Required; the tech fires on this press.
        place(wrap(28, function(host)
            local def = toKeyCode(p.movekey) or Enum.KeyCode.Unknown
            components.KeybindSetter(host, { label = "Move key (required)", default = def,
                onChange = function(k) p.movekey = (k and k ~= Enum.KeyCode.Unknown) and (tostring(k):gsub("Enum.KeyCode.", "")) or nil end })
        end))
        place(wrap(28, function(host) components.Toggle(host, { text = "Block move's normal fire",
            default = p.suppress == true,
            onChange = function(v) p.suppress = v or nil end }) end))
    end

    -- Save / Cancel
    local btnRow = Instance.new("Frame")
    btnRow.Size = UDim2.new(1, -20, 0, 28); btnRow.Position = UDim2.new(0, 10, 1, -34)
    btnRow.BackgroundTransparency = 1; btnRow.ZIndex = 201; btnRow.Parent = modal
    local rowL = Instance.new("UIListLayout", btnRow); rowL.FillDirection = Enum.FillDirection.Horizontal
    rowL.HorizontalAlignment = Enum.HorizontalAlignment.Right; rowL.Padding = UDim.new(0, 8)

    local close = Instance.new("TextButton")
    close.Size = UDim2.fromOffset(80, 26); close.BackgroundColor3 = theme.accent
    close.AutoButtonColor = false; close.TextColor3 = theme.fg
    close.Font = theme.fontBold; close.TextSize = 12; close.Text = "Done"
    close.ZIndex = 202; close.Parent = btnRow
    corner(close, 4)
    close.MouseButton1Click:Connect(function()
        if hatBlock._refreshHatLabel then hatBlock._refreshHatLabel() end
        if draft and canvas then draft.actions = canvas:toActions() end
        modal:Destroy()
    end)
end

-- ---------- Use Move editor (sub-modal) ----------
-- Click a "Use Move" (usebtn) block -> configure which move it fires and how.
-- Rows: a dropdown of detected hotbar moves, a manual move-name box (for moves
-- the scanner can't see), a key to press (key-fire / manual moves), and the
-- fire method. The engine's ACTIONS.usebtn reads block.params.move/key/fire.
-- Stored on the block's params so it round-trips through toActions() like any
-- other step. NOTE: key is stored as a STRING name (not an EnumItem) so the
-- block label can show it and safeKeyCode() can resolve it.
local function openUseMoveEditor(block)
    local p = block.params

    local modal = Instance.new("Frame")
    modal.Size = UDim2.new(0, 360, 0, 300)
    modal.Position = UDim2.new(0.5, -180, 0.5, -150)
    modal.BackgroundColor3 = theme.bg; modal.BorderSizePixel = 0
    modal.ZIndex = 200; modal.Parent = rootFrame
    corner(modal, 8); stroke(modal, theme.accent, 2)

    local title = Instance.new("TextLabel")
    title.Size = UDim2.new(1, -20, 0, 24); title.Position = UDim2.fromOffset(10, 8)
    title.BackgroundTransparency = 1; title.Text = "Use Move"
    title.TextColor3 = theme.fg; title.Font = theme.fontBold; title.TextSize = 14
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.ZIndex = 201; title.Parent = modal

    local body = Instance.new("ScrollingFrame")
    body.Size = UDim2.new(1, -20, 1, -76); body.Position = UDim2.fromOffset(10, 36)
    body.BackgroundTransparency = 1; body.BorderSizePixel = 0
    body.ScrollBarThickness = 4; body.CanvasSize = UDim2.new(0, 0, 0, 0)
    body.AutomaticCanvasSize = Enum.AutomaticSize.Y; body.ZIndex = 201; body.Parent = modal
    local bl = Instance.new("UIListLayout", body); bl.Padding = UDim.new(0, 6); bl.SortOrder = Enum.SortOrder.LayoutOrder

    local ord = 0
    local function place(inst) ord = ord + 1; inst.LayoutOrder = ord; inst.Parent = body; return inst end

    -- 1. detected-move dropdown (auto-fills the key from the scan if unset)
    local res = scanner.cached() or scanner.scan()
    local moveset = res.buttons or {}
    if #moveset > 0 then
        local labels = {}
        for _, b in ipairs(moveset) do
            local lbl = (b.text ~= "" and b.text) or b.name
            if b.key then lbl = lbl .. " [" .. b.key .. "]" end
            labels[#labels + 1] = lbl
        end
        local idx = 1
        for i, b in ipairs(moveset) do if b.name == p.move then idx = i end end
        place(cycleRow(body, "Detected move", labels, idx, function(i)
            p.move = moveset[i].name
            if moveset[i].key and (not p.key or p.key == "") then p.key = keyNameNorm(moveset[i].key) end
        end))
    else
        place(components.Label(body, "No moves detected (run Dump GUI, or type the name below)"))
    end

    -- 2. manual move name -- works when the scanner can't see the move
    place(textRow(body, "Or move name", p.move, function(t)
        p.move = (t and t ~= "") and t or nil
    end))

    -- 3. key to press (used by key-fire + manual moves with no live button)
    place(wrap(28, function(host)
        local def = toKeyCode(p.key) or Enum.KeyCode.Unknown
        components.KeybindSetter(host, { label = "Key (key-fire)", default = def,
            onChange = function(k) p.key = (k and k ~= Enum.KeyCode.Unknown) and (tostring(k):gsub("Enum.KeyCode.", "")) or nil end })
    end))

    -- 4. fire method
    local FIRE_LABELS = { "Auto (smart)", "Click button", "Press key" }
    local FIRE_KEYS   = { "auto", "button", "key" }
    local fidx = 1
    for i, k in ipairs(FIRE_KEYS) do if p.fire == k then fidx = i end end
    place(cycleRow(body, "Fire method", FIRE_LABELS, fidx, function(i) p.fire = FIRE_KEYS[i] end))

    place(components.Label(body, "Auto = hook, else button, else key. Press key = VIM the key (use for typed/manual moves)."))

    -- Done
    local btnRow = Instance.new("Frame")
    btnRow.Size = UDim2.new(1, -20, 0, 28); btnRow.Position = UDim2.new(0, 10, 1, -34)
    btnRow.BackgroundTransparency = 1; btnRow.ZIndex = 201; btnRow.Parent = modal
    local rowL = Instance.new("UIListLayout", btnRow); rowL.FillDirection = Enum.FillDirection.Horizontal
    rowL.HorizontalAlignment = Enum.HorizontalAlignment.Right; rowL.Padding = UDim.new(0, 8)

    local close = Instance.new("TextButton")
    close.Size = UDim2.fromOffset(80, 26); close.BackgroundColor3 = theme.accent
    close.AutoButtonColor = false; close.TextColor3 = theme.fg
    close.Font = theme.fontBold; close.TextSize = 12; close.Text = "Done"
    close.ZIndex = 202; close.Parent = btnRow
    corner(close, 4)
    close.MouseButton1Click:Connect(function()
        if block._refreshUseMoveLabel then block._refreshUseMoveLabel() end
        if draft and canvas then draft.actions = canvas:toActions() end
        modal:Destroy()
    end)
end

-- ---------- OR fork editor (sub-modal) ----------
-- Each branch = a SUBTRIGGER (hat block at the top) + an action chain. Two
-- branches by default; engine wires each subtrigger independently and the
-- OR step picks branch[ctx.triggerIndex] at fire time. Mini canvases reuse
-- the main CanvasUI class so hat / action blocks behave identically inside.
local function openOrEditor(orBlock)
    local modal = Instance.new("Frame")
    modal.Size = UDim2.new(1, -16, 1, -52)
    modal.Position = UDim2.fromOffset(8, 44)
    modal.BackgroundColor3 = theme.bg; modal.BorderSizePixel = 0
    modal.ZIndex = 200; modal.Parent = rootFrame
    corner(modal, 8); stroke(modal, theme.accent, 2)

    local title = Instance.new("TextLabel")
    title.Size = UDim2.new(1, -20, 0, 26); title.Position = UDim2.fromOffset(10, 6)
    title.BackgroundTransparency = 1
    title.Text = "OR fork - configure triggers + per-branch chains"
    title.TextColor3 = theme.fg; title.Font = theme.fontBold; title.TextSize = 14
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.ZIndex = 201; title.Parent = modal

    local hint = Instance.new("TextLabel")
    hint.Size = UDim2.new(1, -20, 0, 16); hint.Position = UDim2.fromOffset(10, 32)
    hint.BackgroundTransparency = 1
    hint.Text = "Each branch starts with a hat (its trigger), then steps. Engine fires the branch whose trigger fired."
    hint.TextColor3 = theme.fgDim; hint.Font = theme.font; hint.TextSize = 11
    hint.TextXAlignment = Enum.TextXAlignment.Left
    hint.ZIndex = 201; hint.Parent = modal

    local scroll = Instance.new("ScrollingFrame")
    scroll.Size = UDim2.new(1, -20, 1, -88); scroll.Position = UDim2.fromOffset(10, 54)
    scroll.BackgroundTransparency = 1; scroll.BorderSizePixel = 0
    scroll.ScrollBarThickness = 4; scroll.CanvasSize = UDim2.new(0, 0, 0, 0)
    scroll.AutomaticCanvasSize = Enum.AutomaticSize.Y; scroll.ZIndex = 201; scroll.Parent = modal
    local scrollLay = Instance.new("UIListLayout", scroll); scrollLay.Padding = UDim.new(0, 8); scrollLay.SortOrder = Enum.SortOrder.LayoutOrder

    local miniCanvases = {}

    local function makeBranchSection(idx)
        local sec = Instance.new("Frame")
        sec.Size = UDim2.new(1, 0, 0, 0); sec.AutomaticSize = Enum.AutomaticSize.Y
        sec.BackgroundTransparency = 1; sec.LayoutOrder = idx; sec.Parent = scroll
        local secLay = Instance.new("UIListLayout", sec); secLay.Padding = UDim.new(0, 4); secLay.SortOrder = Enum.SortOrder.LayoutOrder

        local hdr = Instance.new("TextLabel")
        hdr.Size = UDim2.new(1, 0, 0, 20); hdr.BackgroundTransparency = 1
        hdr.Text = "Branch " .. idx .. " (trigger + steps)"; hdr.TextColor3 = theme.accent
        hdr.Font = theme.fontBold; hdr.TextSize = 12
        hdr.TextXAlignment = Enum.TextXAlignment.Left
        hdr.LayoutOrder = 1; hdr.Parent = sec

        local pal = Instance.new("Frame")
        pal.Size = UDim2.new(1, 0, 0, 0); pal.AutomaticSize = Enum.AutomaticSize.Y
        pal.BackgroundTransparency = 1; pal.LayoutOrder = 2; pal.Parent = sec
        local pl = Instance.new("UIGridLayout", pal)
        pl.CellSize = UDim2.new(0, 84, 0, 32); pl.CellPadding = UDim2.new(0, 4, 0, 4)

        local mc = CanvasUI.new(sec, {})
        mc.frame.LayoutOrder = 3
        -- Mini canvas's editHatRequested -> reuse the main openHatEditor.
        mc.editHatRequested:Connect(function(h) openHatEditor(h) end)
        mc.editUseMoveRequested:Connect(function(b) openUseMoveEditor(b) end)

        -- Pre-populate from orBlock.params: triggers[idx] -> hat block,
        -- branches[idx] -> action chain after the hat.
        local triggers = orBlock.params.triggers or {}
        local branches = orBlock.params.branches or {}
        local trig = triggers[idx]
        local hatActions = {}
        if trig then
            local hatType = hatTypeForEvent(trig.event)
            if hatType then
                local hat = { type = hatType }
                for k, v in pairs(trig) do if k ~= "event" then hat[k] = v end end
                if hatType == "event_key" then hat.event = trig.event end
                hatActions[#hatActions + 1] = hat
            end
        end
        for _, a in ipairs(branches[idx] or {}) do hatActions[#hatActions + 1] = copyAction(a) end
        mc:loadActions(hatActions)
        miniCanvases[idx] = mc

        -- Palette: include hat types (so a new branch can pick a trigger
        -- type) AND the same action set the AND modal exposes.
        local function defaultParamsFor(t)
            if t == "look" then return { x = 180, y = 0 }
            elseif t == "rotate" then return { x = 180 }
            elseif t == "wait" then return { seconds = 0.5 }
            elseif t == "within" then return { studs = 5 }
            end
            return {}
        end
        local function paletteBtn(t)
            local c = colorOf(t)
            local b = Instance.new("TextButton")
            b.BackgroundColor3 = Color3.fromRGB(math.floor(c.R*255*0.78), math.floor(c.G*255*0.78), math.floor(c.B*255*0.78))
            b.AutoButtonColor = true; b.TextColor3 = theme.fg
            b.Font = theme.fontBold; b.TextSize = 12
            b.Text = "+ " .. (CanvasUI.STEP_LABEL[t] or STEP_LABEL[t] or t); b.Parent = pal
            corner(b, 8)
            b.MouseButton1Click:Connect(function() mc:addBlock(t, defaultParamsFor(t)) end)
        end
        for _, t in ipairs(CanvasUI.HAT_TYPES) do paletteBtn(t) end
        for _, t in ipairs({ "look", "rotate", "wait", "within", "return", "feature", "key", "usebtn" }) do paletteBtn(t) end
    end

    makeBranchSection(1)
    makeBranchSection(2)

    -- buttons
    local btnRow = Instance.new("Frame")
    btnRow.Size = UDim2.new(1, -20, 0, 28); btnRow.Position = UDim2.new(0, 10, 1, -34)
    btnRow.BackgroundTransparency = 1; btnRow.ZIndex = 201; btnRow.Parent = modal
    local rowL = Instance.new("UIListLayout", btnRow); rowL.FillDirection = Enum.FillDirection.Horizontal
    rowL.HorizontalAlignment = Enum.HorizontalAlignment.Right; rowL.Padding = UDim.new(0, 8)

    local function closeModal()
        for _, mc in ipairs(miniCanvases) do pcall(function() mc:destroy() end) end
        modal:Destroy()
    end

    local cancel = Instance.new("TextButton")
    cancel.Size = UDim2.fromOffset(80, 26); cancel.BackgroundColor3 = theme.bgAlt
    cancel.AutoButtonColor = false; cancel.TextColor3 = theme.fg
    cancel.Font = theme.font; cancel.TextSize = 12; cancel.Text = "Cancel"
    cancel.LayoutOrder = 1; cancel.ZIndex = 202; cancel.Parent = btnRow
    corner(cancel, 4)
    cancel.MouseButton1Click:Connect(closeModal)

    local save = Instance.new("TextButton")
    save.Size = UDim2.fromOffset(80, 26); save.BackgroundColor3 = theme.accent
    save.AutoButtonColor = false; save.TextColor3 = theme.fg
    save.Font = theme.fontBold; save.TextSize = 12; save.Text = "Save"
    save.LayoutOrder = 2; save.ZIndex = 202; save.Parent = btnRow
    corner(save, 4)
    save.MouseButton1Click:Connect(function()
        -- For each branch's mini canvas, extract its hat (if present) into
        -- a subtrigger + the remaining steps into branches[idx]. A branch
        -- without a hat saves an empty subtrigger (no event) which the
        -- engine ignores -- the user can re-open the modal and pick a hat.
        local triggers, branches = {}, {}
        for i, mc in ipairs(miniCanvases) do
            local acts = mc:toActions()
            local sub = {}
            if acts[1] and CanvasUI.isHat(acts[1].type) then
                local hat = table.remove(acts, 1)
                sub.event = eventForHat(hat)
                for k, v in pairs(hat) do
                    if k ~= "type" and k ~= "event" then sub[k] = v end
                end
            end
            triggers[i] = sub
            branches[i] = acts
        end
        orBlock.params.triggers = triggers
        orBlock.params.branches = branches
        if orBlock._refreshAndLabel then orBlock._refreshAndLabel() end
        if draft and canvas then draft.actions = canvas:toActions() end
        closeModal()
    end)
end

-- ---------- AND branch editor (sub-modal) ----------
-- Click on an AND block's branch button -> open this modal. Two mini Canvas
-- instances, one per branch, each with its own palette. Save serializes
-- branch contents back into andBlock.params.branches. Cancel discards.
local function openBranchEditor(andBlock)
    local modal = Instance.new("Frame")
    modal.Size = UDim2.new(1, -16, 1, -52)
    modal.Position = UDim2.fromOffset(8, 44)
    modal.BackgroundColor3 = theme.bg; modal.BorderSizePixel = 0
    modal.ZIndex = 200; modal.Parent = rootFrame
    corner(modal, 8); stroke(modal, theme.accent, 2)

    local title = Instance.new("TextLabel")
    title.Size = UDim2.new(1, -20, 0, 26); title.Position = UDim2.fromOffset(10, 6)
    title.BackgroundTransparency = 1
    title.Text = "AND step - configure parallel branches"
    title.TextColor3 = theme.fg; title.Font = theme.fontBold; title.TextSize = 14
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.ZIndex = 201; title.Parent = modal

    local hint = Instance.new("TextLabel")
    hint.Size = UDim2.new(1, -20, 0, 16); hint.Position = UDim2.fromOffset(10, 32)
    hint.BackgroundTransparency = 1
    hint.Text = "Each branch runs in parallel; the AND finishes when both branches do."
    hint.TextColor3 = theme.fgDim; hint.Font = theme.font; hint.TextSize = 11
    hint.TextXAlignment = Enum.TextXAlignment.Left
    hint.ZIndex = 201; hint.Parent = modal

    local scroll = Instance.new("ScrollingFrame")
    scroll.Size = UDim2.new(1, -20, 1, -88); scroll.Position = UDim2.fromOffset(10, 54)
    scroll.BackgroundTransparency = 1; scroll.BorderSizePixel = 0
    scroll.ScrollBarThickness = 4; scroll.CanvasSize = UDim2.new(0, 0, 0, 0)
    scroll.AutomaticCanvasSize = Enum.AutomaticSize.Y; scroll.ZIndex = 201; scroll.Parent = modal
    local scrollLay = Instance.new("UIListLayout", scroll); scrollLay.Padding = UDim.new(0, 8); scrollLay.SortOrder = Enum.SortOrder.LayoutOrder

    local miniCanvases = {}

    -- Helper: make a "Branch N" section with its own header + mini canvas +
    -- palette of draggable blocks. Mini canvases reuse the same CanvasUI
    -- class so drag/snap/trash all work identically; their onChange writes
    -- back into the AND block's branches array at save-time.
    local function makeBranchSection(idx)
        local sec = Instance.new("Frame")
        sec.Size = UDim2.new(1, 0, 0, 0); sec.AutomaticSize = Enum.AutomaticSize.Y
        sec.BackgroundTransparency = 1; sec.LayoutOrder = idx; sec.Parent = scroll
        local secLay = Instance.new("UIListLayout", sec); secLay.Padding = UDim.new(0, 4); secLay.SortOrder = Enum.SortOrder.LayoutOrder

        local hdr = Instance.new("TextLabel")
        hdr.Size = UDim2.new(1, 0, 0, 20); hdr.BackgroundTransparency = 1
        hdr.Text = "Branch " .. idx; hdr.TextColor3 = theme.accent
        hdr.Font = theme.fontBold; hdr.TextSize = 12
        hdr.TextXAlignment = Enum.TextXAlignment.Left
        hdr.LayoutOrder = 1; hdr.Parent = sec

        -- Palette inside the branch section, scoped to its mini canvas.
        local pal = Instance.new("Frame")
        pal.Size = UDim2.new(1, 0, 0, 0); pal.AutomaticSize = Enum.AutomaticSize.Y
        pal.BackgroundTransparency = 1; pal.LayoutOrder = 2; pal.Parent = sec
        local pl = Instance.new("UIGridLayout", pal)
        pl.CellSize = UDim2.new(0, 84, 0, 32); pl.CellPadding = UDim2.new(0, 4, 0, 4)

        local mc = CanvasUI.new(sec, {})
        mc.frame.LayoutOrder = 3
        mc.editUseMoveRequested:Connect(function(b) openUseMoveEditor(b) end)
        if andBlock.params.branches and andBlock.params.branches[idx] then
            mc:loadActions(andBlock.params.branches[idx])
        end
        miniCanvases[idx] = mc

        local function defaultParamsFor(t)
            if t == "look" then return { x = 180, y = 0 }
            elseif t == "rotate" then return { x = 180 }
            elseif t == "wait" then return { seconds = 0.5 }
            elseif t == "within" then return { studs = 5 }
            end
            return {}
        end

        for _, t in ipairs({ "look", "rotate", "wait", "within", "return", "feature", "key", "usebtn" }) do
            local c = colorOf(t)
            local b = Instance.new("TextButton")
            b.BackgroundColor3 = Color3.fromRGB(math.floor(c.R*255*0.78), math.floor(c.G*255*0.78), math.floor(c.B*255*0.78))
            b.AutoButtonColor = true; b.TextColor3 = theme.fg
            b.Font = theme.fontBold; b.TextSize = 12
            b.Text = "+ " .. (CanvasUI.STEP_LABEL[t] or STEP_LABEL[t] or t); b.Parent = pal
            corner(b, 8)
            b.MouseButton1Click:Connect(function()
                mc:addBlock(t, defaultParamsFor(t))
            end)
        end
    end

    makeBranchSection(1)
    makeBranchSection(2)

    -- Save / Cancel buttons at the bottom of the modal.
    local btnRow = Instance.new("Frame")
    btnRow.Size = UDim2.new(1, -20, 0, 28); btnRow.Position = UDim2.new(0, 10, 1, -34)
    btnRow.BackgroundTransparency = 1; btnRow.ZIndex = 201; btnRow.Parent = modal
    local rowL = Instance.new("UIListLayout", btnRow); rowL.FillDirection = Enum.FillDirection.Horizontal
    rowL.HorizontalAlignment = Enum.HorizontalAlignment.Right; rowL.Padding = UDim.new(0, 8)

    -- Tear down both mini canvases (drag conns + frames) and then drop
    -- the modal. Called from both Save and Cancel so the cleanup is the
    -- same regardless of which button closed the dialog.
    local function closeModal()
        for _, mc in ipairs(miniCanvases) do pcall(function() mc:destroy() end) end
        modal:Destroy()
    end

    local cancel = Instance.new("TextButton")
    cancel.Size = UDim2.fromOffset(80, 26); cancel.BackgroundColor3 = theme.bgAlt
    cancel.AutoButtonColor = false; cancel.TextColor3 = theme.fg
    cancel.Font = theme.font; cancel.TextSize = 12; cancel.Text = "Cancel"
    cancel.LayoutOrder = 1; cancel.ZIndex = 202; cancel.Parent = btnRow
    corner(cancel, 4)
    cancel.MouseButton1Click:Connect(closeModal)

    local save = Instance.new("TextButton")
    save.Size = UDim2.fromOffset(80, 26); save.BackgroundColor3 = theme.accent
    save.AutoButtonColor = false; save.TextColor3 = theme.fg
    save.Font = theme.fontBold; save.TextSize = 12; save.Text = "Save"
    save.LayoutOrder = 2; save.ZIndex = 202; save.Parent = btnRow
    corner(save, 4)
    save.MouseButton1Click:Connect(function()
        andBlock.params.branches = {
            miniCanvases[1]:toActions(),
            miniCanvases[2]:toActions(),
        }
        if andBlock._refreshAndLabel then andBlock._refreshAndLabel() end
        if draft and canvas then draft.actions = canvas:toActions() end
        closeModal()
    end)
end

-- ---------- form (left pane) ----------
rebuild = function()
    for _, c in ipairs(formScroll:GetChildren()) do
        -- Preserve the Scratch canvas container so the user's placed blocks
        -- survive a form re-render (toggling event type / scope must not
        -- wipe in-progress tech building). LayoutOrder is reset below when
        -- place() reaches the canvas section.
        if not c:IsA("UIListLayout") and c ~= canvasContainer then c:Destroy() end
    end
    local ord = 0
    local function place(inst) ord = ord + 1; inst.LayoutOrder = ord; inst.Parent = formScroll; return inst end

    place(textRow(formScroll, "Name", draft.name, function(t) draft.name = t end))
    -- Scope: This Game / This Character / Universal. "This Character" pins the
    -- name detected by the active per-game module (so the tech only triggers
    -- when you're playing as that character); when no char is detectable, the
    -- cycle hides the option and falls back to This Game on save.
    do
        local detectedChar = detectCurrentCharacter()
        local pinned = draft.pinChar
        local labels = { "This Game" }
        local keys   = { "game" }
        if detectedChar or pinned then
            local cn = pinned or detectedChar
            labels[#labels + 1] = "This Char (" .. tostring(cn) .. ")"
            keys[#keys + 1] = "char"
        end
        labels[#labels + 1] = "Universal"
        keys[#keys + 1] = "universal"
        local idx = 1
        for i, k in ipairs(keys) do if draft.scope == k then idx = i end end
        if not (draft.scope == "char" and (detectedChar or pinned)) and draft.scope ~= "universal" then idx = 1 end
        place(cycleRow(formScroll, "Scope", labels, idx, function(i)
            draft.scope = keys[i]
            if keys[i] == "char" then
                draft.pinChar = pinned or detectedChar
            else
                draft.pinChar = nil
            end
            rebuild()
        end))
    end

    -- Trigger lives on the canvas as a hat block now (V3.1). The legacy
    -- in-form trigger UI is gone -- drag a "When ..." block from the
    -- palette and click its inline summary to configure. The block below
    -- (suppress/modkey/hold/anim-picker/move-picker etc.) used to live
    -- here and is preserved only behind `false` so a future merge can
    -- compare; the hat-block modal in openHatEditor covers all of it.
    if false then  -- legacy form trigger UI (disabled; hat block replaces it)
    if draft.event == "anim" then
        -- bind to a played animation via a collapsible dropdown, Capture, or paste.
        local hist = engine.animHistory()
        local selLabel = "(pick an animation)"
        if draft.animId then
            for _, h in ipairs(hist) do if tostring(h.id) == tostring(draft.animId) then selLabel = h.label end end
            if selLabel == "(pick an animation)" then selLabel = "anim " .. tostring(draft.animId) end
        end
        place(wrap(28, function(p)
            local b = Instance.new("TextButton")
            b.Size = UDim2.new(1, 0, 0, 26); b.BackgroundColor3 = theme.bgDark; b.AutoButtonColor = true
            b.TextColor3 = theme.fg; b.Font = theme.font; b.TextSize = 12
            b.TextXAlignment = Enum.TextXAlignment.Left; b.TextTruncate = Enum.TextTruncate.AtEnd
            b.Text = "  " .. selLabel .. (animDropOpen and "    [x]" or "    [v]"); b.Parent = p; corner(b, 4)
            b.MouseButton1Click:Connect(function() animDropOpen = not animDropOpen; rebuild() end)
        end))
        if animDropOpen then
          if #hist == 0 then
            place(components.Label(formScroll, "(none yet - play your moves, or hit Capture below)"))
          else
            place(components.Label(formScroll, "click=preview, double-click=select"))
            place(wrap(24, function(p)
                local cb = Instance.new("TextButton")
                cb.Size = UDim2.new(1, 0, 0, 22); cb.BackgroundColor3 = theme.bgAlt; cb.AutoButtonColor = true
                cb.TextColor3 = theme.danger; cb.Font = theme.font; cb.TextSize = 11
                cb.Text = "Clear logged anims (" .. #hist .. ")"; cb.Parent = p; corner(cb, 4)
                cb.MouseButton1Click:Connect(function() engine.clearAnimHistory(); rebuild() end)
            end))
            local n = math.min(#hist, 7)
            local listWrap = Instance.new("Frame")
            listWrap.Size = UDim2.new(1, 0, 0, n * 24 + 4); listWrap.BackgroundColor3 = theme.bgDark
            listWrap.BorderSizePixel = 0; corner(listWrap, 4)
            local sf = Instance.new("ScrollingFrame")
            sf.Size = UDim2.new(1, -4, 1, -4); sf.Position = UDim2.fromOffset(2, 2)
            sf.BackgroundTransparency = 1; sf.BorderSizePixel = 0; sf.ScrollBarThickness = 4
            sf.CanvasSize = UDim2.new(0, 0, 0, 0); sf.AutomaticCanvasSize = Enum.AutomaticSize.Y; sf.Parent = listWrap
            local sl = Instance.new("UIListLayout", sf); sl.Padding = UDim.new(0, 2); sl.SortOrder = Enum.SortOrder.LayoutOrder
            for hi, h in ipairs(hist) do
                local row = Instance.new("TextButton")
                row.Size = UDim2.new(1, 0, 0, 22); row.AutoButtonColor = true; row.LayoutOrder = hi
                row.BackgroundColor3 = (tostring(draft.animId) == tostring(h.id)) and theme.accent or theme.bgAlt
                row.TextColor3 = theme.fg; row.Font = theme.font; row.TextSize = 11
                row.TextXAlignment = Enum.TextXAlignment.Left; row.TextTruncate = Enum.TextTruncate.AtEnd
                row.Text = "  " .. (h.label or tostring(h.id)) .. "  (" .. tostring(h.id) .. ")"; row.Parent = sf
                -- single click = audition in the preview; double click = fully select
                local lastClick = 0
                row.MouseButton1Click:Connect(function()
                    playAnimOnRig(h.id, true)   -- preview (looped) on every click
                    if os.clock() - lastClick < 0.35 then
                        draft.animId = tostring(h.id)   -- commit the selection
                        animDropOpen = false            -- collapse the dropdown on select
                        rebuild()
                    end
                    lastClick = os.clock()
                end)
            end
            place(listWrap)
          end
        end
        -- fire when the animation ENDS instead of when it starts
        place(wrap(30, function(p) components.Toggle(p, { text = "Fire on animation END (not start)",
            default = draft.animEnd == true,
            onChange = function(v) draft.animEnd = v or nil end }) end))
        place(wrap(28, function(p)
            local b = Instance.new("TextButton")
            b.Size = UDim2.new(1, 0, 0, 24); b.BackgroundColor3 = theme.bgDark; b.AutoButtonColor = true
            b.TextColor3 = theme.accent; b.Font = theme.fontBold; b.TextSize = 12
            b.Text = "Capture (play the move now)"; b.Parent = p; corner(b, 4)
            b.MouseButton1Click:Connect(function()
                b.Text = "Capturing... play the move now"
                pcall(function() notify.info("Capturing -- play the move now", 3) end)
                engine.captureAnim(function(raw)
                    draft.animId = tostring(raw):match("%d+") or tostring(raw)
                    animDropOpen = false
                    pcall(function() notify.success("Captured anim " .. tostring(draft.animId)) end)
                    rebuild()
                end)
            end)
        end))
        place(textRow(formScroll, "Or paste ID", draft.animId, function(t)
            local id = t and t:match("%d+")
            draft.animId = id or (t ~= "" and t) or nil
        end))
    elseif draft.event == "target_anim" then
        -- mirror of the anim branch but the picker uses the TARGET'S anim
        -- history (Engine.targetAnimHistory) and Capture binds via captureTarget
        -- Anim, so you bind to an opponent's animation. Falls back to a paste
        -- box if you haven't seen any target anims yet (no lock-on / Target
        -- Select target ever held during this session).
        local hist = engine.targetAnimHistory and engine.targetAnimHistory() or {}
        place(components.Label(formScroll, "Hint: lock onto an opponent so their played anims show up below."))
        place(wrap(28, function(p)
            local b = Instance.new("TextButton")
            b.Size = UDim2.new(1, 0, 0, 24); b.BackgroundColor3 = theme.bgDark; b.AutoButtonColor = true
            b.TextColor3 = theme.accent; b.Font = theme.fontBold; b.TextSize = 12
            b.Text = "Capture target anim (play it on the opponent)"; b.Parent = p; corner(b, 4)
            b.MouseButton1Click:Connect(function()
                b.Text = "Capturing... bait the move on opponent"
                pcall(function() notify.info("Capturing target anim", 4) end)
                if engine.captureTargetAnim then
                    engine.captureTargetAnim(function(raw)
                        draft.animId = tostring(raw):match("%d+") or tostring(raw)
                        pcall(function() notify.success("Captured target anim " .. tostring(draft.animId)) end)
                        rebuild()
                    end)
                end
            end)
        end))
        place(textRow(formScroll, "Or paste ID", draft.animId, function(t)
            local id = t and t:match("%d+")
            draft.animId = id or (t ~= "" and t) or nil
        end))
        if #hist > 0 then
            place(components.Label(formScroll, "Recently seen on target (click=set):"))
            local n = math.min(#hist, 7)
            local sf = Instance.new("ScrollingFrame")
            sf.Size = UDim2.new(1, 0, 0, n * 22 + 4); sf.BackgroundColor3 = theme.bgDark
            sf.BorderSizePixel = 0; sf.ScrollBarThickness = 4
            sf.CanvasSize = UDim2.new(0, 0, 0, 0); sf.AutomaticCanvasSize = Enum.AutomaticSize.Y
            corner(sf, 4)
            local sl = Instance.new("UIListLayout", sf); sl.Padding = UDim.new(0, 2)
            for hi, h in ipairs(hist) do
                local row = Instance.new("TextButton")
                row.Size = UDim2.new(1, 0, 0, 20); row.LayoutOrder = hi
                row.BackgroundColor3 = (tostring(draft.animId) == tostring(h.id)) and theme.accent or theme.bgAlt
                row.TextColor3 = theme.fg; row.Font = theme.font; row.TextSize = 11
                row.TextXAlignment = Enum.TextXAlignment.Left; row.TextTruncate = Enum.TextTruncate.AtEnd
                row.Text = "  " .. (h.label or tostring(h.id)) .. "  (" .. tostring(h.id) .. ")"
                row.Parent = sf
                row.MouseButton1Click:Connect(function()
                    draft.animId = tostring(h.id); rebuild()
                end)
            end
            place(sf)
        end
        place(wrap(30, function(p) components.Toggle(p, { text = "Fire on animation END (not start)",
            default = draft.animEnd == true,
            onChange = function(v) draft.animEnd = v or nil end }) end))
    elseif draft.event == "move" then
        local res = scanner.cached() or scanner.scan()
        local moveset = res.buttons or {}
        if #moveset == 0 then
            place(components.Label(formScroll, "No moves detected yet (run 'Dump GUI' so I can map your hotbar)"))
        else
            local labels = {}
            for _, b in ipairs(moveset) do
                local lbl = (b.text ~= "" and b.text) or b.name
                if b.key then lbl = lbl .. " [" .. b.key .. "]" end
                labels[#labels + 1] = lbl
            end
            if not draft.move then
                draft.move = moveset[1].name
                if moveset[1].key and not draft.movekey then draft.movekey = keyNameNorm(moveset[1].key) end
            end
            local idx = 1
            for i, b in ipairs(moveset) do if b.name == draft.move then idx = i end end
            place(cycleRow(formScroll, "Move", labels, idx, function(i)
                draft.move = moveset[i].name
                if moveset[i].key then draft.movekey = keyNameNorm(moveset[i].key) end
                rebuild()
            end))
            place(wrap(28, function(p)
                local def = toKeyCode(draft.movekey) or Enum.KeyCode.Unknown
                components.KeybindSetter(p, { label = "Move key", default = def,
                    onChange = function(k)
                        draft.movekey = (k and k ~= Enum.KeyCode.Unknown) and (tostring(k):gsub("Enum.KeyCode.", "")) or nil
                    end })
            end))
        end
    else
        place(wrap(28, function(p)
            components.KeybindSetter(p, { label = "Key", default = draft.key, onChange = function(k) draft.key = k end })
        end))
    end
    -- optional modifier that must be HELD for the trigger to fire (hold A + press Q)
    place(wrap(28, function(p)
        local def = toKeyCode(draft.modkey) or Enum.KeyCode.Unknown
        components.KeybindSetter(p, { label = "Hold-key (optional)", default = def,
            onChange = function(k)
                draft.modkey = (k and k ~= Enum.KeyCode.Unknown) and (tostring(k):gsub("Enum.KeyCode.", "")) or nil
            end })
    end))
    -- Block this key's normal action (key & move triggers): the engine sinks the
    -- key so the game can't fire its move -- only this tech runs (which can fire the
    -- move itself via a Use Move step). Pointless for an anim trigger.
    if draft.event ~= "anim" then
        place(wrap(30, function(p) components.Toggle(p, { text = "Block this key's normal action",
            default = draft.suppress == true,
            onChange = function(v) draft.suppress = v or nil end }) end))
    end
    if draft.event == "key" or draft.event == "keyhold" then
        place(wrap(30, function(p) components.Toggle(p, { text = "Hold the key (release = return)",
            default = draft.event == "keyhold",
            onChange = function(v)
                if v then draft.event = "keyhold" elseif draft.event == "keyhold" then draft.event = "key" end
                rebuild()
            end }) end))
    end
    place(wrap(30, function(p) components.Toggle(p, { text = "Trigger on a move instead",
        default = draft.event == "move",
        onChange = function(v) draft.event = v and "move" or "key"; rebuild() end }) end))
    place(wrap(30, function(p) components.Toggle(p, { text = "Trigger on an animation instead",
        default = draft.event == "anim",
        onChange = function(v) draft.event = v and "anim" or "key"; rebuild() end }) end))
    place(wrap(30, function(p) components.Toggle(p, { text = "Trigger on TARGET's animation instead",
        default = draft.event == "target_anim",
        onChange = function(v) draft.event = v and "target_anim" or "key"; rebuild() end }) end))
    end   -- end of `if false then` legacy trigger UI block
    place(wrap(30, function(p) components.Toggle(p, { text = "Only while locked on",
        default = draft.conditions.locked_on == true,
        onChange = function(v) draft.conditions.locked_on = v or nil end }) end))
    -- "Within X studs" gate: pair with target_playing to get the
    -- "within 5 studs AND target plays anim X" check the user asked for.
    place(textRow(formScroll, "Within X studs (0=any)", tostring(draft.maxRange or 0), function(t)
        local n = tonumber(t); draft.maxRange = (n and n > 0) and n or nil
    end))
    -- target_playing condition: parametrized; the anim id lives separately
    -- from the trigger's animId so you can fire on one anim and gate on
    -- another. Empty id = no-op (condition auto-passes).
    place(wrap(30, function(p) components.Toggle(p, { text = "Only while target is playing an anim",
        default = draft.conditions.target_playing == true,
        onChange = function(v) draft.conditions.target_playing = v or nil; rebuild() end }) end))
    if draft.conditions.target_playing then
        place(textRow(formScroll, "  Target anim ID (gate)", draft.targetAnimId, function(t)
            local id = t and t:match("%d+")
            draft.targetAnimId = id or (t ~= "" and t) or nil
        end))
        place(wrap(28, function(p)
            local b = Instance.new("TextButton")
            b.Size = UDim2.new(1, 0, 0, 24); b.BackgroundColor3 = theme.bgDark; b.AutoButtonColor = true
            b.TextColor3 = theme.accent; b.Font = theme.fontBold; b.TextSize = 12
            b.Text = "  Capture (target plays the gate move now)"; b.Parent = p; corner(b, 4)
            b.MouseButton1Click:Connect(function()
                b.Text = "  Capturing gate anim..."
                pcall(function() notify.info("Capturing target anim (gate)", 4) end)
                if engine.captureTargetAnim then
                    engine.captureTargetAnim(function(raw)
                        draft.targetAnimId = tostring(raw):match("%d+") or tostring(raw)
                        rebuild()
                    end)
                end
            end)
        end))
    end
    -- keep Lock-On / Rotation alive even while welded (grabs normally suppress them)
    place(wrap(30, function(p) components.Toggle(p, { text = "Ignore welds (keep Lock-On while grabbed)",
        default = draft.ignoreWelds == true,
        onChange = function(v) draft.ignoreWelds = v or nil end }) end))

    place(components.Section(formScroll, "Steps - drag from palette into canvas"))
    -- Scratch canvas section. The container Frame holds:
    --   * a horizontal palette of draggable block sources (top)
    --   * the CanvasUI itself (below) -- absolute-positioned blocks, drag +
    --     snap-to-connect, save back to draft.actions on change.
    -- The container is created ONCE per Builder.open lifecycle and
    -- preserved across rebuild() calls so user-placed blocks survive form
    -- re-renders (toggling event type re-runs rebuild but must not wipe
    -- the user's tech progress). LayoutOrder is reset each rebuild.
    if not canvasContainer then
        canvasContainer = Instance.new("Frame")
        canvasContainer.Size = UDim2.new(1, 0, 0, 0)
        canvasContainer.AutomaticSize = Enum.AutomaticSize.Y
        canvasContainer.BackgroundTransparency = 1
        canvasContainer.Parent = formScroll

        local stack = Instance.new("UIListLayout", canvasContainer)
        stack.SortOrder = Enum.SortOrder.LayoutOrder
        stack.Padding = UDim.new(0, 6)

        -- Palette row: tap to spawn at top of canvas, OR drag to drop at a
        -- specific canvas-local position. Drag is the primary "scratch
        -- feel"; tap remains as a one-click shortcut.
        local palette = Instance.new("Frame")
        palette.Size = UDim2.new(1, 0, 0, 0); palette.AutomaticSize = Enum.AutomaticSize.Y
        palette.BackgroundTransparency = 1; palette.LayoutOrder = 1; palette.Parent = canvasContainer
        local pl = Instance.new("UIGridLayout", palette)
        pl.CellSize = UDim2.new(0, 84, 0, 32); pl.CellPadding = UDim2.new(0, 4, 0, 4)
        pl.SortOrder = Enum.SortOrder.LayoutOrder

        local function defaultParamsFor(t)
            if t == "look" then return { x = 180, y = 0 }
            elseif t == "rotate" then return { x = 180 }
            elseif t == "wait" then return { seconds = 0.5 }
            elseif t == "within" then return { studs = 5 }
            elseif t == "feature" then local fa = feature.all(); return { feature = fa[1] and fa[1].id or nil }
            elseif t == "usebtn" then local res = scanner.cached() or scanner.scan(); local m = (res.buttons or {})[1]; return { move = m and m.name or nil }
            end
            return {}
        end

        -- Canvas itself (sits below palette in the container).
        canvas = CanvasUI.new(canvasContainer, {
            onChange = function() if draft then draft.actions = canvas:toActions() end end,
        })
        canvas.frame.LayoutOrder = 2

        -- Wire the AND-block branch editor: clicking an AND block's
        -- "[N branches] - click to edit" button on the main canvas fires
        -- editBranchesRequested with that block. We open a modal with one
        -- mini canvas per branch so each branch can be authored visually.
        -- AND and OR both fire editBranchesRequested; route to the right
        -- modal based on block.type.
        canvas.editBranchesRequested:Connect(function(block)
            if block.type == "or" then openOrEditor(block)
            else openBranchEditor(block) end
        end)

        -- Hat-block trigger editor: clicking a hat block's inline summary
        -- button fires editHatRequested with that block. Opens a per-type
        -- modal that edits the hat's trigger params in place; the hat's
        -- summary text refreshes on close and the draft re-syncs.
        canvas.editHatRequested:Connect(function(hatBlock) openHatEditor(hatBlock) end)

        -- Use Move block -> per-step config modal (move/key/fire method).
        canvas.editUseMoveRequested:Connect(function(block) openUseMoveEditor(block) end)

        -- Drag a palette button -> spawn a ghost that follows the mouse,
        -- and on release inside the canvas bounds, addBlock at the
        -- canvas-local coords so the block lands where the cursor was.
        -- (Drop outside canvas = no-op; ghost just disappears.) Click WITH
        -- no drag still works -- addBlock at canvas top so the existing
        -- click-to-add muscle memory keeps functioning.
        local function spawnDraggable(t)
            local c = colorOf(t)
            local b = Instance.new("TextButton")
            b.BackgroundColor3 = Color3.fromRGB(math.floor(c.R*255*0.78), math.floor(c.G*255*0.78), math.floor(c.B*255*0.78))
            b.AutoButtonColor = true; b.TextColor3 = theme.fg
            b.Font = theme.fontBold; b.TextSize = 12
            b.Text = "+ " .. (CanvasUI.STEP_LABEL[t] or STEP_LABEL[t] or t); b.Parent = palette
            corner(b, 8)

            local clickStart, dragged, ghost, moveConn, endConn
            local function cleanup()
                if moveConn then moveConn:Disconnect(); moveConn = nil end
                if endConn  then endConn:Disconnect();  endConn  = nil end
                if ghost    then ghost:Destroy();       ghost    = nil end
            end
            b.InputBegan:Connect(function(input)
                if input.UserInputType ~= Enum.UserInputType.MouseButton1 then return end
                clickStart = UIS:GetMouseLocation(); dragged = false

                moveConn = UIS.InputChanged:Connect(function(i)
                    if i.UserInputType ~= Enum.UserInputType.MouseMovement then return end
                    local m = UIS:GetMouseLocation()
                    if not dragged and (m - clickStart).Magnitude > 6 then
                        dragged = true
                        ghost = Instance.new("Frame")
                        ghost.Size = UDim2.fromOffset(180, 36)
                        ghost.BackgroundColor3 = colorOf(t)
                        ghost.BackgroundTransparency = 0.15
                        ghost.BorderSizePixel = 0; ghost.ZIndex = 5000
                        ghost.Parent = gui
                        corner(ghost, 10)
                        local gl = Instance.new("TextLabel")
                        gl.Size = UDim2.new(1, -16, 1, 0); gl.Position = UDim2.fromOffset(8, 0)
                        gl.BackgroundTransparency = 1; gl.Text = CanvasUI.STEP_LABEL[t] or STEP_LABEL[t] or t
                        gl.TextColor3 = theme.fg; gl.Font = theme.fontBold; gl.TextSize = 13
                        gl.TextXAlignment = Enum.TextXAlignment.Left
                        gl.ZIndex = 5001; gl.Parent = ghost
                    end
                    if ghost then ghost.Position = UDim2.fromOffset(m.X - 90, m.Y - 18 - 36) end
                end)

                endConn = UIS.InputEnded:Connect(function(i)
                    if i.UserInputType ~= Enum.UserInputType.MouseButton1 then return end
                    if dragged and canvas then
                        local m = UIS:GetMouseLocation()
                        local tl = canvas.frame.AbsolutePosition
                        local br = tl + canvas.frame.AbsoluteSize
                        if m.X >= tl.X and m.X <= br.X and m.Y >= tl.Y and m.Y <= br.Y then
                            local lx, ly = m.X - tl.X - 90, m.Y - tl.Y - 18
                            canvas:addBlock(t, defaultParamsFor(t), math.max(4, lx), math.max(4, ly))
                        end
                    elseif not dragged and canvas then
                        canvas:addBlock(t, defaultParamsFor(t))
                    end
                    cleanup()
                end)
            end)
        end

        -- Hat blocks first (yellow, the trigger). One per tech (V3.1); the
        -- canvas doesn't enforce uniqueness yet -- builder_ui's Save just
        -- takes the FIRST hat in toActions() as the trigger.
        for _, t in ipairs(CanvasUI.HAT_TYPES) do spawnDraggable(t) end
        for _, t in ipairs(ACTION_TYPES) do spawnDraggable(t) end
        -- AND palette entry too -- engine accepts type="and" but V1 doesn't
        -- yet support branch editing inside the block (placeholder text on
        -- the block; configure via nested editor in V2).
        spawnDraggable("and")
        -- OR palette entry (V3.2). Multi-trigger fork: drop the OR on the
        -- canvas, click its summary, configure each branch (trigger + its
        -- action chain) in the modal. Each branch wires its own subtrigger.
        spawnDraggable("or")

        -- initial load: hydrate from draft.actions
        canvas:loadActions(draft.actions)
    end
    place(canvasContainer)

    do
        local bf = Instance.new("Frame")
        bf.Size = UDim2.new(1, 0, 0, 36); bf.BackgroundTransparency = 1
        local bl = Instance.new("UIListLayout", bf)
        bl.FillDirection = Enum.FillDirection.Horizontal; bl.HorizontalAlignment = Enum.HorizontalAlignment.Right
        bl.VerticalAlignment = Enum.VerticalAlignment.Center; bl.Padding = UDim.new(0, 8)
        local cancel = Instance.new("TextButton")
        cancel.Size = UDim2.fromOffset(86, 26); cancel.BackgroundColor3 = theme.bgAlt; cancel.AutoButtonColor = false
        cancel.TextColor3 = theme.fg; cancel.Font = theme.font; cancel.TextSize = 12; cancel.Text = "Cancel"
        cancel.LayoutOrder = 1; cancel.Parent = bf
        cancel.MouseButton1Click:Connect(function() Builder.close() end)
        local save = Instance.new("TextButton")
        save.Size = UDim2.fromOffset(100, 26); save.BackgroundColor3 = theme.accent; save.AutoButtonColor = false
        save.TextColor3 = theme.fg; save.Font = theme.fontBold; save.TextSize = 12; save.Text = "Save Tech"
        save.LayoutOrder = 2; save.Parent = bf
        save.MouseButton1Click:Connect(onSave)
        place(bf)
    end
end

-- ---------- window ----------
local function ensureGui()
    if gui and gui.Parent then return end
    gui = Instance.new("ScreenGui")
    gui.Name = "_" .. math.random(100000, 999999)
    gui.ResetOnSpawn = false
    -- Sibling so children always render above their parents (modal config
    -- panels sit at ZIndex 200 over default-ZIndex(1) controls; under the
    -- legacy Global default those controls would hide BEHIND the modal bg).
    -- window.lua / shiftlock.lua set this too; the builder had been relying
    -- on the runtime default.
    gui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
    gui.Parent = env.guiParent()
    if env.protectGui then env.protectGui(gui) end

    rootFrame = Instance.new("Frame")
    rootFrame.Size = UDim2.fromOffset(620, 420)
    rootFrame.Position = UDim2.new(0.5, -310, 0.5, -210)
