    rootFrame.Parent = gui
    corner(rootFrame, 10); stroke(rootFrame, theme.accent)

    local header = Instance.new("Frame")
    header.Size = UDim2.new(1, 0, 0, 30); header.BackgroundColor3 = theme.accent; header.BorderSizePixel = 0; header.Parent = rootFrame
    corner(header, 10)
    local dragBtn = Instance.new("TextButton")
    dragBtn.Size = UDim2.fromScale(1, 1); dragBtn.BackgroundTransparency = 1; dragBtn.Text = ""; dragBtn.AutoButtonColor = false
    dragBtn.ZIndex = 2; dragBtn.Parent = header
    local title = Instance.new("TextLabel")
    title.Size = UDim2.new(1, -98, 1, 0); title.Position = UDim2.fromOffset(12, 0); title.BackgroundTransparency = 1
    title.Text = "Tech Builder"; title.TextColor3 = theme.fg; title.Font = theme.fontBold; title.TextSize = 13
    title.TextXAlignment = Enum.TextXAlignment.Left; title.ZIndex = 3; title.Parent = header
    local newBtn = Instance.new("TextButton")
    newBtn.Size = UDim2.fromOffset(58, 22); newBtn.Position = UDim2.new(1, -92, 0.5, -11); newBtn.BackgroundColor3 = theme.bgDark
    newBtn.AutoButtonColor = false; newBtn.Text = "+ New"; newBtn.TextColor3 = theme.fg; newBtn.Font = theme.fontBold
    newBtn.TextSize = 11; newBtn.ZIndex = 4; newBtn.Parent = header
    newBtn.MouseButton1Click:Connect(function() Builder.open() end)
    local close = Instance.new("TextButton")
    close.Size = UDim2.fromOffset(26, 22); close.Position = UDim2.new(1, -30, 0.5, -11); close.BackgroundColor3 = theme.danger
    close.AutoButtonColor = false; close.Text = "X"; close.TextColor3 = theme.fg; close.Font = theme.fontBold
    close.TextSize = 12; close.ZIndex = 4; close.Parent = header
    close.MouseButton1Click:Connect(function() Builder.close() end)

    do
        local dragging, dStart, sPos = false, nil, nil
        dragBtn.InputBegan:Connect(function(i)
            if i.UserInputType == Enum.UserInputType.MouseButton1 or i.UserInputType == Enum.UserInputType.Touch then
                dragging, dStart, sPos = true, i.Position, rootFrame.Position
            end
        end)
        winDragConns[#winDragConns + 1] = UIS.InputChanged:Connect(function(i)
            if dragging and (i.UserInputType == Enum.UserInputType.MouseMovement or i.UserInputType == Enum.UserInputType.Touch) then
                local d = i.Position - dStart
                rootFrame.Position = UDim2.new(sPos.X.Scale, sPos.X.Offset + d.X, sPos.Y.Scale, sPos.Y.Offset + d.Y)
            end
        end)
        winDragConns[#winDragConns + 1] = UIS.InputEnded:Connect(function(i)
            if i.UserInputType == Enum.UserInputType.MouseButton1 or i.UserInputType == Enum.UserInputType.Touch then dragging = false end
        end)
    end

    -- LEFT: form
    formScroll = Instance.new("ScrollingFrame")
    formScroll.Size = UDim2.new(0, 296, 1, -44); formScroll.Position = UDim2.fromOffset(8, 36)
    formScroll.BackgroundTransparency = 1; formScroll.BorderSizePixel = 0
    formScroll.ScrollBarThickness = 4; formScroll.CanvasSize = UDim2.new(0, 0, 0, 0)
    formScroll.AutomaticCanvasSize = Enum.AutomaticSize.Y; formScroll.Parent = rootFrame
    local fl = Instance.new("UIListLayout", formScroll); fl.SortOrder = Enum.SortOrder.LayoutOrder; fl.Padding = UDim.new(0, 3)

    -- RIGHT: preview
    local right = Instance.new("Frame")
    right.Size = UDim2.new(1, -320, 1, -44); right.Position = UDim2.fromOffset(312, 36)
    right.BackgroundColor3 = theme.bgAlt; right.BorderSizePixel = 0; right.Parent = rootFrame
    corner(right, 8); stroke(right)
    local rpad = Instance.new("UIPadding", right)
    rpad.PaddingTop = UDim.new(0, 8); rpad.PaddingBottom = UDim.new(0, 8); rpad.PaddingLeft = UDim.new(0, 8); rpad.PaddingRight = UDim.new(0, 8)

    vpFrame = Instance.new("ViewportFrame")
    vpFrame.Size = UDim2.new(1, 0, 1, -40); vpFrame.BackgroundColor3 = theme.bgDark; vpFrame.BorderSizePixel = 0
    vpFrame.Ambient = Color3.fromRGB(190, 190, 200); vpFrame.LightColor = Color3.fromRGB(255, 255, 255)
    vpFrame.LightDirection = Vector3.new(-0.4, -1, -0.2); vpFrame.Parent = right
    corner(vpFrame, 8)
    worldModel = Instance.new("WorldModel"); worldModel.Parent = vpFrame
    vpCam = Instance.new("Camera"); vpCam.FieldOfView = 50; vpCam.Parent = vpFrame; vpFrame.CurrentCamera = vpCam

    local playBtn = Instance.new("TextButton")
    playBtn.Size = UDim2.new(1, 0, 0, 32); playBtn.Position = UDim2.new(0, 0, 1, -32); playBtn.BackgroundColor3 = theme.accent
    playBtn.AutoButtonColor = true; playBtn.Text = "Play preview"; playBtn.TextColor3 = theme.fg; playBtn.Font = theme.fontBold
    playBtn.TextSize = 13; playBtn.Parent = right; corner(playBtn, 6)
    playBtn.MouseButton1Click:Connect(previewDraft)
end

function Builder.open(existingTech)
    local ok, err = pcall(function()
        ensureGui()
        -- Force a fresh hotbar scan every Open. The scanner caches a non-
        -- empty result for the session; on first Open the game's UI is
        -- often mid-build and we capture a stale snapshot (or worse, the
        -- pre-loadout one) which then survives every subsequent Open until
        -- script re-execute. Clearing forces re-scan against the LIVE PG.
        pcall(function() scanner.clearCache() end)
        draft = existingTech and draftFromTech(existingTech) or newDraft()
        animDropOpen = not (draft.animId)   -- expanded when nothing's picked yet
        -- Discard the canvas from a prior session if it exists. Use the
        -- explicit Canvas:destroy() to disconnect each block's UIS drag
        -- conns -- a bare Frame:Destroy() leaves the UIS connections
        -- registered (they internally check `dragging` and no-op, but
        -- they still fire on every mouse move + accumulate per re-open).
        if canvas then pcall(function() canvas:destroy() end); canvas = nil end
        if canvasContainer then pcall(function() canvasContainer:Destroy() end); canvasContainer = nil end
        rebuild()
        captureRig()
        buildRigPreview()
        rootFrame.Visible = true
    end)
    if not ok then
        warn("[Pantheon] Tech Builder open error: " .. tostring(err))
        pcall(function() notify.warn("Tech Builder error: " .. tostring(err), 8) end)
    end
end

function Builder.close()
    if rootFrame then rootFrame.Visible = false end
    if curTrack then pcall(function() curTrack:Stop(0) end); curTrack = nil end
    if curRig then pcall(function() curRig:Destroy() end); curRig = nil end
    -- Drop the canvas on close too -- next Open rebuilds fresh. Canvas:
    -- destroy() before the container Destroy() to disconnect drag conns.
    if canvas then pcall(function() canvas:destroy() end); canvas = nil end
    if canvasContainer then pcall(function() canvasContainer:Destroy() end); canvasContainer = nil end
end

function Builder.destroy()
    for _, c in ipairs(winDragConns) do pcall(function() c:Disconnect() end) end
    winDragConns = {}
    if curTrack then pcall(function() curTrack:Stop(0) end); curTrack = nil end
    if curRig then pcall(function() curRig:Destroy() end); curRig = nil end
    if rigTemplate then pcall(function() rigTemplate:Destroy() end); rigTemplate = nil end
    if gui then pcall(function() gui:Destroy() end); gui = nil end
end

return Builder
end

_MODULES["modules.tech.init"] = function()
-- Tech Builder UI: the "Tech Builder" container.
--
-- Top row  : "Open Tech Builder" -> the avatar+dummy viewport with the timeline
--            reenactment (stage 2; for now it announces it's coming).
-- Below    : the saved techs, split into "This Game" (scope matches the current
--            PlaceId/GameId) and "Universal" (scope == "universal"). Techs built
--            for OTHER games are hidden. Each row toggles the tech on/off.
--
-- The list re-reads [[modules.tech.engine]] on engine.changed, so techs added by
-- per-game modules (which register AFTER this section is built) appear live.

local window     = require("ui.window")
local container  = require("ui.container")
local components = require("ui.components")
local theme      = require("ui.theme")
local notify     = require("ui.notify")
local engine     = require("modules.tech.engine")
local builder    = require("modules.tech.builder_ui")
local scanner    = require("modules.tech.scanner")
local dumper     = require("modules.tech.dumper")
local log        = require("core.log")

local module = {}

local changedConn   -- engine.changed subscription; disconnected on destroy

-- Bucketize a scope for the list. Returns "here" (this game / this character),
-- "uni" (universal), or "other" (different game / different char -> hidden).
-- char-scoped techs go into "here" while you're playing as that character so
-- they appear in the same This Game section; out-of-game / out-of-character
-- techs are hidden so the list stays tight.
local registry = require("games.registry")
local function classifyScope(scope)
    if scope == "universal" then return "uni" end
    if scope == game.PlaceId or scope == game.GameId then return "here" end
    if type(scope) == "string" then
        local want = scope:match("^char:(.+)$")
        if want then
            local mod = registry.current()
            local fn = mod and mod.detectCharacter
            if type(fn) == "function" then
                local ok, name = pcall(fn)
                if ok and name == want then return "here" end
            end
            return "other"
        end
    end
    return "other"
end

-- A single tech row: name on the left, an ON/OFF button on the right.
local function buildRow(parent, tech)
    local f = Instance.new("Frame")
    f.Size = UDim2.new(1, 0, 0, 26)
    f.BackgroundColor3 = theme.bgAlt
    f.BorderSizePixel = 0
    f.Parent = parent

    -- name (custom techs leave room for a delete button on top of the edit one)
    local name = Instance.new("TextLabel")
    name.Size = UDim2.new(1, tech.custom and -106 or -82, 1, 0)
    name.Position = UDim2.fromOffset(8, 0)
    name.BackgroundTransparency = 1
    name.Text = tech.name or tech.id
    name.TextColor3 = tech.enabled and theme.fg or theme.fgDim
    name.Font = theme.font
    name.TextSize = 12
    name.TextXAlignment = Enum.TextXAlignment.Left
    name.TextTruncate = Enum.TextTruncate.AtEnd
    name.Parent = f

    -- ON/OFF toggle. Lets engine.changed rebuild the list to repaint (no per-row state).
    local btn = Instance.new("TextButton")
    btn.Size = UDim2.fromOffset(38, 18)
    btn.Position = UDim2.new(1, -44, 0.5, -9)
    btn.AutoButtonColor = false
    btn.BackgroundColor3 = tech.enabled and theme.on or theme.off
    btn.TextColor3 = theme.fg
    btn.Font = theme.fontBold
    btn.TextSize = 10
    btn.Text = tech.enabled and "ON" or "OFF"
    btn.Parent = f
    btn.MouseButton1Click:Connect(function() engine.setEnabled(tech.id, not tech.enabled) end)

    -- Edit (every tech). Editing a built-in saves a persistent custom override.
    local edit = Instance.new("TextButton")
    edit.Size = UDim2.fromOffset(30, 18)
    edit.Position = UDim2.new(1, -78, 0.5, -9)
    edit.AutoButtonColor = false
    edit.BackgroundColor3 = theme.bgDark
    edit.TextColor3 = theme.fg
    edit.Font = theme.font
    edit.TextSize = 10
    edit.Text = "Edit"
    edit.Parent = f
    edit.MouseButton1Click:Connect(function() builder.open(tech) end)

    -- Delete (custom techs only; deleting a custom override of a built-in reverts
    -- to the built-in on next load).
    if tech.custom then
        local del = Instance.new("TextButton")
        del.Size = UDim2.fromOffset(20, 18)
        del.Position = UDim2.new(1, -102, 0.5, -9)
        del.BackgroundColor3 = theme.danger
        del.AutoButtonColor = false
        del.TextColor3 = theme.fg
        del.Font = theme.fontBold
        del.TextSize = 10
        del.Text = "X"
        del.Parent = f
        del.MouseButton1Click:Connect(function() engine.remove(tech.id) end)
    end

    return f
end

local function refreshList(listFrame)
    for _, c in ipairs(listFrame:GetChildren()) do
        if not c:IsA("UIListLayout") then c:Destroy() end
    end

    local here, uni = {}, {}
    for _, t in pairs(engine.all()) do
        local cls = classifyScope(t.scope)
        if cls == "here" then here[#here + 1] = t
        elseif cls == "uni" then uni[#uni + 1] = t end
    end
    local byName = function(a, b) return (a.name or a.id) < (b.name or b.id) end
    table.sort(here, byName)
    table.sort(uni, byName)

    local ord = 0
    local function place(inst) ord = ord + 1; inst.LayoutOrder = ord; return inst end

    if #here > 0 then
        place(components.Section(listFrame, "This Game"))
        for _, t in ipairs(here) do place(buildRow(listFrame, t)) end
    end
    if #uni > 0 then
        place(components.Section(listFrame, "Universal"))
        for _, t in ipairs(uni) do place(buildRow(listFrame, t)) end
    end
    if #here == 0 and #uni == 0 then
        place(components.Label(listFrame, "No techs yet."))
    end
end

function module.register()
    engine.init()

    local box = container.new(window.parent(), "Tech Builder")

    local holder = Instance.new("Frame")
    holder.Size = UDim2.new(1, 0, 0, 0)
    holder.AutomaticSize = Enum.AutomaticSize.Y
    holder.BackgroundTransparency = 1
    local hl = Instance.new("UIListLayout", holder)
    hl.SortOrder = Enum.SortOrder.LayoutOrder
    hl.Padding = UDim.new(0, 2)

    local openBtn = components.Button(holder, {
        text    = "Open Tech Builder",
        onClick = function() builder.open() end,
    })
    openBtn.LayoutOrder = 1

    -- Dev dumps: write raw GUI + animation data to files so move-bar detection and
    -- move->animation mapping can be set up correctly per game (vs heuristics).
    local status = components.Label(holder, "")
    status.LayoutOrder = 4
    status.Visible = false

    local dumpGuiBtn = components.Button(holder, { text = "Dump GUI (for setup)", onClick = function()
        local n = dumper.dumpGui()
        status.Visible = true
        status.Text = "GUI dumped (" .. n .. " buttons) -> pantheon_gui_dump.txt"
        pcall(function() notify.info("GUI dumped: " .. n .. " buttons", 4) end)
    end })
    dumpGuiBtn.LayoutOrder = 2

    -- Static anim dumper removed -- the editor's active anim logging (animLog +
    -- Capture) covers what the dump file was for, and friendly names now fall
    -- back to Animation:GetFullName() live in recordAnim. The Dump GUI button
    -- stays since per-game hotbar setup still needs the GUI tree dump.

    local listFrame = Instance.new("Frame")
    listFrame.Size = UDim2.new(1, 0, 0, 0)
    listFrame.AutomaticSize = Enum.AutomaticSize.Y
    listFrame.BackgroundTransparency = 1
    listFrame.LayoutOrder = 5
    listFrame.Parent = holder
    local ll = Instance.new("UIListLayout", listFrame)
    ll.SortOrder = Enum.SortOrder.LayoutOrder
    ll.Padding = UDim.new(0, 1)

    box:add(holder)

    -- Rebuild the list whenever the tech set changes (toggles, or per-game
    -- modules adding their techs after this point).
    changedConn = engine.changed:Connect(function() refreshList(listFrame) end)

    engine.loadCustom()   -- rehydrate persisted user-built techs
    refreshList(listFrame)

    log.info("Tech Builder registered")
end

function module.destroy()
    if changedConn then pcall(function() changedConn:Disconnect() end); changedConn = nil end
    pcall(function() builder.destroy() end)
    pcall(function() engine.destroy() end)
end

return module
end

_MODULES["modules.friendlies"] = function()
-- Friendlies: a per-session list of players to NEVER target. Each row shows the
-- player's avatar headshot (rbxthumb), their name, and a FRIENDLY / neutral
-- toggle. Marking someone writes state.friendlies[UserId], which
-- targeting.getBestTarget() already skips -- so a friendly is excluded from
-- Target Select, Lock-On, Swap, Highlight, and Bot Mode all at once.
--
-- The "All" button flips EVERY player in the server friendly (or back to
-- neutral) in one click -- the usual "friendly all" for ceasefires / teammates.
--
-- Session-only on purpose: UserId entries are dropped on re-execute, so a fresh
-- server starts with a clean slate rather than silently carrying a whitelist.

local window     = require("ui.window")
local container  = require("ui.container")
local components = require("ui.components")
local theme      = require("ui.theme")
local state      = require("modules.aim.state")
local feature    = require("ui.feature")
local log        = require("core.log")

local Players = game:GetService("Players")

local Friendlies = {}

local conns = {}            -- PlayerAdded/Removing + the scroll fit-height signal
local listFrame             -- ScrollingFrame the player rows live in
local repaintAll            -- repaints the "All" button (set in register)
local rebuildPending = false

local function isFriendly(plr) return state.friendlies[plr.UserId] == true end
local function setFriendly(plr, v)
    state.friendlies[plr.UserId] = v and true or nil
end

-- True only when there's at least one other player AND every one is friendly.
local function allFriendly()
    local me, any = Players.LocalPlayer, false
    for _, plr in ipairs(Players:GetPlayers()) do
        if plr ~= me then
            any = true
            if not isFriendly(plr) then return false end
        end
    end
    return any
end

local function setAll(v)
    local me = Players.LocalPlayer
    for _, plr in ipairs(Players:GetPlayers()) do
        if plr ~= me then setFriendly(plr, v) end
    end
end

local function avatarImage(userId)
    return ("rbxthumb://type=AvatarHeadShot&id=%d&w=60&h=60"):format(userId)
end

local function buildRow(plr)
    local row = Instance.new("Frame")
    row.Size = UDim2.new(1, 0, 0, 34)
    row.BackgroundColor3 = theme.bgAlt
    row.BorderSizePixel = 0

    local avatar = Instance.new("ImageLabel")
    avatar.Size = UDim2.fromOffset(26, 26)
    avatar.Position = UDim2.fromOffset(4, 4)
    avatar.BackgroundColor3 = theme.bgDark
    avatar.BorderSizePixel = 0
    avatar.Image = avatarImage(plr.UserId)
    avatar.Parent = row

    local name = Instance.new("TextLabel")
    name.Position = UDim2.fromOffset(34, 0)
    name.Size = UDim2.new(1, -148, 1, 0)
    name.BackgroundTransparency = 1
    name.Text = (plr.DisplayName and plr.DisplayName ~= "" and plr.DisplayName) or plr.Name
    name.TextColor3 = theme.fg
    name.Font = theme.font
    name.TextSize = 12
    name.TextXAlignment = Enum.TextXAlignment.Left
    name.TextTruncate = Enum.TextTruncate.AtEnd
    name.Parent = row

    -- Target: make this player the current target (and turn Target Select on so
    -- the pick actually takes effect; Lock-On / Highlight act on it if they're on).
    local tgt = Instance.new("TextButton")
    tgt.Size = UDim2.fromOffset(48, 20)
    tgt.Position = UDim2.new(1, -110, 0.5, -10)
    tgt.AutoButtonColor = true
    tgt.BackgroundColor3 = theme.accent
    tgt.TextColor3 = theme.fg
    tgt.Font = theme.fontBold
    tgt.TextSize = 10
    tgt.BorderSizePixel = 0
    tgt.Text = "Target"
    tgt.Parent = row
    tgt.MouseButton1Click:Connect(function()
        feature.setEnabled("aim.target_select", true)
        state.setTarget(plr, "player")
    end)

    local btn = Instance.new("TextButton")
    btn.Size = UDim2.fromOffset(54, 20)
    btn.Position = UDim2.new(1, -58, 0.5, -10)
    btn.AutoButtonColor = false
    btn.Font = theme.fontBold
    btn.TextSize = 10
    btn.BorderSizePixel = 0
    btn.Parent = row

    local function paint()
        local f = isFriendly(plr)
        btn.BackgroundColor3 = f and theme.on or theme.bgDark
        btn.TextColor3 = f and theme.bgDark or theme.fgDim
        btn.Text = f and "FRIENDLY" or "neutral"
    end
    paint()
    btn.MouseButton1Click:Connect(function()
        setFriendly(plr, not isFriendly(plr))
        paint()
        if repaintAll then repaintAll() end
    end)

    return row
end

local function rebuild()
    rebuildPending = false
    if not listFrame then return end
    for _, c in ipairs(listFrame:GetChildren()) do
        if not c:IsA("UIListLayout") then c:Destroy() end
    end

    local me = Players.LocalPlayer
    local players = Players:GetPlayers()
    table.sort(players, function(a, b)
        return (a.DisplayName or a.Name):lower() < (b.DisplayName or b.Name):lower()
    end)

    local n = 0
    for _, plr in ipairs(players) do
        if plr ~= me then
            n = n + 1
            local row = buildRow(plr)
            row.LayoutOrder = n
            row.Parent = listFrame
        end
    end
    if n == 0 then
        local empty = components.Label(listFrame, "No other players in server.")
        empty.LayoutOrder = 1
    end
    if repaintAll then repaintAll() end
end

local function scheduleRebuild()
    if rebuildPending then return end
    rebuildPending = true
    task.delay(0.3, rebuild)   -- debounce so a mass join/leave rebuilds once
end

function Friendlies.register()
    local box = container.new(window.parent(), "Friendlies")

    local holder = Instance.new("Frame")
    holder.Size = UDim2.new(1, 0, 0, 0)
    holder.AutomaticSize = Enum.AutomaticSize.Y
    holder.BackgroundTransparency = 1
    local hl = Instance.new("UIListLayout", holder)
    hl.SortOrder = Enum.SortOrder.LayoutOrder
    hl.Padding = UDim.new(0, 3)

    -- Header: hint on the left, the "All" toggle on the right.
    local header = Instance.new("Frame")
    header.Size = UDim2.new(1, 0, 0, 22)
    header.BackgroundTransparency = 1
    header.LayoutOrder = 1
    header.Parent = holder

    local hint = Instance.new("TextLabel")
    hint.Size = UDim2.new(1, -60, 1, 0)
    hint.BackgroundTransparency = 1
    hint.Text = "Marked = never targeted"
    hint.TextColor3 = theme.fgDim
    hint.Font = theme.font
    hint.TextSize = 11
    hint.TextXAlignment = Enum.TextXAlignment.Left
    hint.Parent = header

    local allBtn = Instance.new("TextButton")
    allBtn.Size = UDim2.fromOffset(54, 18)
    allBtn.Position = UDim2.new(1, -56, 0.5, -9)
    allBtn.AutoButtonColor = false
    allBtn.Font = theme.fontBold
    allBtn.TextSize = 10
    allBtn.BorderSizePixel = 0
    allBtn.Parent = header

    local function paintAll()
        local on = allFriendly()
        allBtn.BackgroundColor3 = on and theme.on or theme.bgDark
        allBtn.TextColor3 = on and theme.bgDark or theme.fgDim
        allBtn.Text = on and "ALL ✓" or "All"
    end
    repaintAll = paintAll
    allBtn.MouseButton1Click:Connect(function()
        setAll(not allFriendly())
        rebuild()
    end)

    -- Player list: grows with the roster up to a cap, then scrolls (so a 40-player
    -- server doesn't make the window taller than the screen).
    local scroll = Instance.new("ScrollingFrame")
    scroll.Size = UDim2.new(1, 0, 0, 0)
    scroll.CanvasSize = UDim2.new(0, 0, 0, 0)
    scroll.AutomaticCanvasSize = Enum.AutomaticSize.Y
    scroll.ScrollBarThickness = 4
    scroll.ScrollBarImageColor3 = theme.fgDim
    scroll.BackgroundTransparency = 1
    scroll.BorderSizePixel = 0
    scroll.LayoutOrder = 2
    scroll.Parent = holder

    local sl = Instance.new("UIListLayout", scroll)
    sl.SortOrder = Enum.SortOrder.LayoutOrder
    sl.Padding = UDim.new(0, 2)

    local MAX_H = 220
    local function fitHeight()
        scroll.Size = UDim2.new(1, 0, 0, math.min(sl.AbsoluteContentSize.Y, MAX_H))
    end
    conns[#conns + 1] = sl:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(fitHeight)
    fitHeight()

    listFrame = scroll
    box:add(holder)

    conns[#conns + 1] = Players.PlayerAdded:Connect(scheduleRebuild)
    conns[#conns + 1] = Players.PlayerRemoving:Connect(scheduleRebuild)
    rebuild()

    log.info("Friendlies module registered")
end

function Friendlies.destroy()
    for _, c in ipairs(conns) do pcall(function() c:Disconnect() end) end
    conns = {}
    listFrame, repaintAll = nil, nil
end

return Friendlies
end

_MODULES["modules.system"] = function()
-- System / "Pantheon" container: global utilities.
--
-- Auto Re-Execute (teleport persistence): a Roblox teleport (e.g. JJS lobby ->
-- a match) drops every executor script. queue_on_teleport asks the executor to
-- run a payload after the next teleport; our payload waits for the new place to
-- load, then re-loadstrings the Pantheon bundle so the hub follows you across
-- teleports. Ported from the legacy lock-on script:
--   METHOD 1 -- queue once at startup (covers executors that need the queue set
--               before the teleport).
--   METHOD 2 -- re-queue when Player.OnTeleport fires Started, and flush settings
--               first so the new place loads your latest toggles.
--
-- Re-Execute Now: reload the latest bundle on demand (cog button).

local feature    = require("ui.feature")
local window     = require("ui.window")
local container  = require("ui.container")
local persist    = require("core.persist")
local notify     = require("ui.notify")
local log        = require("core.log")

local Players = game:GetService("Players")

local System = {}

-- The released bundle. ?v=tick() busts Wave's aggressive HttpGet cache.
local DIST_URL = "https://raw.githubusercontent.com/6014m/Pantheon/main/dist/main.lua"

-- queue_on_teleport varies by executor. Undefined names resolve to nil safely,
-- so this just picks the first one that exists.
local queueteleport = queue_on_teleport
    or (syn and syn.queue_on_teleport)
    or (fluxus and fluxus.queue_on_teleport)
    or (getgenv and getgenv().queue_on_teleport)

-- Payload run in the NEW place after a teleport. The `?v=" .. tostring(tick())`
-- is literal text INSIDE the payload string, so it evaluates (and cache-busts)
-- at re-exec time in the destination place.
local PAYLOAD =
    'repeat task.wait() until game:IsLoaded()\n' ..
    'task.wait(2)\n' ..
    'pcall(function() loadstring(game:HttpGet("' .. DIST_URL .. '?v=" .. tostring(tick())))() end)\n'

local s = { auto = false, tpConn = nil }

-- Manual reload (cog button): re-run the latest bundle right now. The bundle's
-- own teardown (getgenv().Pantheon.shutdown) replaces the current instance.
local function reexecNow()
    task.spawn(function()
        local ok, src = pcall(function()
            return game:HttpGet(DIST_URL .. "?v=" .. tostring(tick()))
        end)
        if not ok or type(src) ~= "string" or #src == 0 then
            notify.warn("Re-execute: download failed"); return
        end
        local fn, err = loadstring(src)
        if not fn then
            notify.warn("Re-execute: compile failed"); log.warn("reexec compile: " .. tostring(err)); return
        end
        local rok, rerr = pcall(fn)
        if not rok then log.warn("reexec run: " .. tostring(rerr)) end
    end)
end
System.reexec = reexecNow

-- "Unload Pantheon": the user-facing unexecute. Two-click confirm because the
-- button sits right next to "Re-Execute Now" -- a misclick here would otherwise
-- nuke the whole hub. Delegates to the bundle's full teardown + global-erase
-- (genv.Pantheon.unload), with a hand-rolled fallback for older bundles.
local unloadArmed = false
local function unloadPantheon()
    if not unloadArmed then
        unloadArmed = true
        notify.warn("Click 'Unload Pantheon' again to fully remove the hub.")
        task.delay(4, function() unloadArmed = false end)
        return
    end
    unloadArmed = false
    local genv = (getgenv and getgenv()) or _G
    if genv.Pantheon and type(genv.Pantheon.unload) == "function" then
        genv.Pantheon.unload()
    elseif genv.Pantheon and type(genv.Pantheon.shutdown) == "function" then
        pcall(genv.Pantheon.shutdown)
        genv.Pantheon          = nil
        genv.PANTHEON_TP_QUEUED = nil
    end
end

local function queuePayload()
    if not queueteleport then return false end
    return (pcall(queueteleport, PAYLOAD))
end

local function setAuto(v)
    s.auto = v and true or false
    local genv = (getgenv and getgenv()) or _G

    if s.auto then
        if not queueteleport then
            notify.warn("Teleport persistence: your executor has no queue_on_teleport")
            return
        end
        -- METHOD 1: queue once per executor session. Re-exec'd instances (after a
        -- teleport) see the persisted getgenv flag and skip; METHOD 2 carries the
        -- chain forward on each subsequent teleport.
        if not genv.PANTHEON_TP_QUEUED then
            if queuePayload() then genv.PANTHEON_TP_QUEUED = true end
        end
        -- METHOD 2: re-queue + flush settings the moment a teleport starts.
        if not s.tpConn then
            s.tpConn = Players.LocalPlayer.OnTeleport:Connect(function(st)
                if st == Enum.TeleportState.Started and s.auto then
                    pcall(function() persist.flush() end)
                    queuePayload()
                end
            end)
        end
    else
        if s.tpConn then s.tpConn:Disconnect(); s.tpConn = nil end
        -- An already-registered payload can't be un-queued on most executors, but
        -- METHOD 2 won't re-queue and the next teleport's instance will boot with
        -- the toggle persisted off, so the chain stops there.
    end
end

function System.register()
    local box = container.new(window.parent(), "Pantheon")
    box:add(feature.declare({
        id          = "system.auto_reexec",
        name        = "Auto Re-Execute (teleport)",
        description = "Re-runs Pantheon automatically after a Roblox teleport (e.g. JJS lobby to a match) so the hub follows you. Uses your executor's queue_on_teleport. Use 'Re-Execute Now' to reload the latest build on demand, or 'Unload Pantheon' to fully remove the hub (un-execute) -- it tears everything down and clears its globals so the game is left clean.",
        default     = true,
        onToggle    = setAuto,
        settings    = {
            { type = "button", name = "Re-Execute Now", onClick = function() reexecNow() end },
            { type = "button", name = "Unload Pantheon", onClick = function() unloadPantheon() end },
        },
    }).root)
    log.info("System module registered")
end

function System.destroy()
    if s.tpConn then s.tpConn:Disconnect(); s.tpConn = nil end
end

return System
end

_MODULES["modules.aesthetic"] = function()
-- Aesthetic: client-side "how the game looks" tweaks (Lighting + camera).
-- Each feature persists via [[ui.feature]] (per-game); SAVED shader presets are
-- stored GLOBALLY (persist.getGlobal/setGlobal) so they follow you to any game.
-- Everything is reverted on disable and on module teardown (re-execute safe).

local feature   = require("ui.feature")
local window    = require("ui.window")
local container = require("ui.container")
local persist   = require("core.persist")
local log       = require("core.log")

local Lighting   = game:GetService("Lighting")
local RunService = game:GetService("RunService")

local Aesthetic = {}

local orig = {
    Ambient        = Lighting.Ambient,
    OutdoorAmbient = Lighting.OutdoorAmbient,
    Brightness     = Lighting.Brightness,
    GlobalShadows  = Lighting.GlobalShadows,
    FogEnd         = Lighting.FogEnd,
    ClockTime      = Lighting.ClockTime,
    FieldOfView    = (workspace.CurrentCamera and workspace.CurrentCamera.FieldOfView) or 70,
}

local st = { fullbright = false, nofog = false, fovOn = false, fov = 90, timeOn = false, clock = 12 }
local enforceConn

-- Color constants hoisted out of the per-frame enforcers (apply / applyGrade run
-- on RenderStepped while active). Building these with Color3.fromRGB every frame
-- allocated a fresh userdata 60x/sec for a value that never changes -- pure GC churn.
local FB_GREY  = Color3.fromRGB(178, 178, 178)   -- fullbright ambient
local CC2_TINT = Color3.fromRGB(255, 247, 239)   -- color-grade pass 2 tint
local CC3_TINT = Color3.fromRGB(255, 255, 255)   -- color-grade pass 3 tint

local function apply()
    if st.fullbright then
        Lighting.Brightness = 2; Lighting.Ambient = FB_GREY
        Lighting.OutdoorAmbient = FB_GREY; Lighting.GlobalShadows = false
    end
    if st.nofog then Lighting.FogEnd = 1e9 end
    if st.timeOn then Lighting.ClockTime = st.clock end
    if st.fovOn then local cam = workspace.CurrentCamera; if cam then cam.FieldOfView = st.fov end end
end
local function ensureLoop()
    local need = st.fullbright or st.nofog or st.timeOn or st.fovOn
    if need and not enforceConn then enforceConn = RunService.RenderStepped:Connect(apply)
    elseif not need and enforceConn then enforceConn:Disconnect(); enforceConn = nil end
end

local function revertFullbright()
    Lighting.Brightness = orig.Brightness; Lighting.Ambient = orig.Ambient
    Lighting.OutdoorAmbient = orig.OutdoorAmbient; Lighting.GlobalShadows = orig.GlobalShadows
end
local function revertFog()  Lighting.FogEnd   = orig.FogEnd   end
local function revertTime() Lighting.ClockTime = orig.ClockTime end
local function revertFov() local cam = workspace.CurrentCamera; if cam then cam.FieldOfView = orig.FieldOfView end end

-- ===== RTX-style lighting + post-processing + presets =======================
-- Each effect is its own toggle (like Fullbright). "Preset Shaders" is the master
-- + the holder of saved presets: enabling it applies the lighting AND turns every
-- effect on; disabling it turns them all off AND resets every value to default.
-- A RenderStepped pass re-asserts all values each frame so the GAME can't override
-- the shader. Presets (and the "Default") live in the GLOBAL store, so a shader
-- you save in one game shows up in every game. NOTE: real client-side post-process
-- instances on Lighting/Camera -- a strict client AC can scan them; avoid there.
local GRADE_TINT = Color3.fromRGB(255, 220, 148)   -- baked warm RTX grade tint
local FIXED = {
    ambient = Color3.fromRGB(33, 33, 33), outdoor = Color3.fromRGB(51, 54, 67),
    csTop = Color3.fromRGB(255, 247, 237), csBottom = Color3.fromRGB(0, 0, 0),
}
local DEFAULTS = {
    brightness = 6.67, exposure = 0.75, shadowSoftness = 0.04, envDiffuse = 0.105,
    envSpecular = 0.522, geoLat = -15.525,
    bloomIntensity = 0.04, bloomSize = 1900, bloomThreshold = 0.915,
    dofFocus = 21.54, dofRadius = 20.77, dofNear = 0.277, dofFar = 0.077,
    sunIntensity = 0.01, sunSpread = 0.146,
    cc1B = 0.176, cc1C = 0.39, cc1S = 0.2, blurAmount = 10,
}
local NUM_KEYS = {
    "brightness", "exposure", "shadowSoftness", "envDiffuse", "envSpecular", "geoLat",
    "bloomIntensity", "bloomSize", "bloomThreshold",
    "dofFocus", "dofRadius", "dofNear", "dofFar", "sunIntensity", "sunSpread",
    "cc1B", "cc1C", "cc1S", "blurAmount",
}

local sv = {}
for k, v in pairs(DEFAULTS) do sv[k] = v end

local function builtin() local p = {}; for _, k in ipairs(NUM_KEYS) do p[k] = DEFAULTS[k] end; return p end
local PRESETS = { Default = builtin() }   -- Summer/Autumn removed; just a reset baseline

local customPresets = {}   -- name -> { numeric values } (GLOBAL: persist.getGlobal)
local customCount   = 0
local handles       = {}   -- sv-field -> component api; + .preset, .name

local fx = {}
local fxBlurConn = nil
local lightOrig  = nil
local shaderEnsureEnforce   -- forward decl (assigned after the apply* fns)
local shaderEnforceConn
-- effect keys the user enabled -> kept alive (recreated) even if the GAME deletes
-- the instance from Lighting; their class so the enforcer can rebuild them.
local FX_CLASS = { bloom = "BloomEffect", dof = "DepthOfFieldEffect", sun = "SunRaysEffect",
                   cc1 = "ColorCorrectionEffect", cc2 = "ColorCorrectionEffect", cc3 = "ColorCorrectionEffect" }
local want = {}

local SHADER_CHILDREN = { "aesthetic.bloom", "aesthetic.dof", "aesthetic.sunrays", "aesthetic.grade", "aesthetic.motionblur" }
local shaderBooting = true

local function newFx(key, class)
    want[key] = true
    if not fx[key] or fx[key].Parent == nil then
        local e = Instance.new(class); e.Enabled = true; e.Parent = Lighting; fx[key] = e
    end
    if shaderEnsureEnforce then shaderEnsureEnforce() end
    return fx[key]
end
local function killFx(key)
    want[key] = nil
    if fx[key] then pcall(function() fx[key]:Destroy() end); fx[key] = nil end
    if shaderEnsureEnforce then shaderEnsureEnforce() end
end

local function applyLighting()
    if not lightOrig then return end
    pcall(function()
        Lighting.Ambient = FIXED.ambient;                 Lighting.Brightness = sv.brightness
        Lighting.ColorShift_Top = FIXED.csTop;            Lighting.ColorShift_Bottom = FIXED.csBottom
        Lighting.EnvironmentDiffuseScale = sv.envDiffuse; Lighting.EnvironmentSpecularScale = sv.envSpecular
        Lighting.GlobalShadows = true;                    Lighting.OutdoorAmbient = FIXED.outdoor
        Lighting.ShadowSoftness = sv.shadowSoftness;      Lighting.GeographicLatitude = sv.geoLat
        Lighting.ExposureCompensation = sv.exposure
    end)
end
local function enableLighting(on)
    if on then
        lightOrig = lightOrig or {
            Ambient = Lighting.Ambient, Brightness = Lighting.Brightness,
            ColorShift_Top = Lighting.ColorShift_Top, ColorShift_Bottom = Lighting.ColorShift_Bottom,
            EnvironmentDiffuseScale = Lighting.EnvironmentDiffuseScale,
            EnvironmentSpecularScale = Lighting.EnvironmentSpecularScale,
            GlobalShadows = Lighting.GlobalShadows, OutdoorAmbient = Lighting.OutdoorAmbient,
            ShadowSoftness = Lighting.ShadowSoftness, GeographicLatitude = Lighting.GeographicLatitude,
            ExposureCompensation = Lighting.ExposureCompensation,
        }
        applyLighting()
    elseif lightOrig then
        for k, v in pairs(lightOrig) do pcall(function() Lighting[k] = v end) end
        lightOrig = nil
    end
    if shaderEnsureEnforce then shaderEnsureEnforce() end
end

local function applyBloom() local e = fx.bloom; if e then e.Intensity = sv.bloomIntensity; e.Size = sv.bloomSize; e.Threshold = sv.bloomThreshold end end
local function applyDof()   local e = fx.dof;   if e then e.FocusDistance = sv.dofFocus; e.InFocusRadius = sv.dofRadius; e.NearIntensity = sv.dofNear; e.FarIntensity = sv.dofFar end end
local function applySun()   local e = fx.sun;   if e then e.Intensity = sv.sunIntensity; e.Spread = sv.sunSpread end end
local function applyGrade()
    if fx.cc1 then fx.cc1.Brightness = sv.cc1B; fx.cc1.Contrast = sv.cc1C; fx.cc1.Saturation = sv.cc1S; fx.cc1.TintColor = GRADE_TINT end
    if fx.cc2 then fx.cc2.Brightness = 0;   fx.cc2.Contrast = -0.07; fx.cc2.Saturation = 0;    fx.cc2.TintColor = CC2_TINT end
    if fx.cc3 then fx.cc3.Brightness = 0.2; fx.cc3.Contrast = 0.45;  fx.cc3.Saturation = -0.1; fx.cc3.TintColor = CC3_TINT end
end

local function enableBlur(on)
    if on then
        local cam = workspace.CurrentCamera
        if cam then
            fx.blur = Instance.new("BlurEffect"); fx.blur.Parent = cam
            local last = cam.CFrame.LookVector
            fxBlurConn = RunService.Heartbeat:Connect(function()
                local c = workspace.CurrentCamera
                if not c then return end
                if not fx.blur or fx.blur.Parent == nil then fx.blur = Instance.new("BlurEffect"); fx.blur.Parent = c end
                local mag = (c.CFrame.LookVector - last).Magnitude
                fx.blur.Size = math.abs(mag) * (sv.blurAmount or 10) * 5 / 2
                last = c.CFrame.LookVector
            end)
        end
    else
        if fxBlurConn then pcall(function() fxBlurConn:Disconnect() end); fxBlurConn = nil end
        killFx("blur")
    end
    if shaderEnsureEnforce then shaderEnsureEnforce() end
end

-- Re-assert all active shader values every frame so the game can't override them.
-- Each apply* self-gates (no-op unless its part is enabled), so this only does
-- real work for what's on. Runs only while something is active.
shaderEnsureEnforce = function()
    local need = lightOrig ~= nil or next(want) ~= nil
    if need and not shaderEnforceConn then
        shaderEnforceConn = RunService.RenderStepped:Connect(function()
            applyLighting()
            -- rebuild any wanted effect the game may have deleted, then re-assert values
            for key in pairs(want) do
                if not fx[key] or fx[key].Parent == nil then
                    local e = Instance.new(FX_CLASS[key]); e.Enabled = true; e.Parent = Lighting; fx[key] = e
                end
            end
            applyBloom(); applyDof(); applySun(); applyGrade()
        end)
    elseif not need and shaderEnforceConn then
        shaderEnforceConn:Disconnect(); shaderEnforceConn = nil
    end
end

local function shaderTeardown()
    if shaderEnforceConn then shaderEnforceConn:Disconnect(); shaderEnforceConn = nil end
    enableLighting(false); enableBlur(false)
    for _, k in ipairs({ "bloom", "dof", "sun", "cc1", "cc2", "cc3" }) do killFx(k) end
end

-- Apply a preset's numeric values. `full` pushes them onto the sliders (which
-- re-apply the live effects); on boot `full` is false so each slider restores its
-- own saved value instead of the preset clobbering it.
local function applyPreset(name, full)
    local p = PRESETS[name] or customPresets[name]
    if not (p and full) then return end
    for _, k in ipairs(NUM_KEYS) do
        if p[k] ~= nil then sv[k] = p[k]; if handles[k] then handles[k]:Set(p[k]) end end
    end
end

local function saveCurrentPreset()
    local name = (handles.name and handles.name:Get()) or ""
    name = tostring(name):gsub("^%s*(.-)%s*$", "%1")
    if name == "" then customCount = customCount + 1; name = "Custom " .. customCount end
    local isNew = customPresets[name] == nil
    local p = {}
    for _, k in ipairs(NUM_KEYS) do p[k] = sv[k] end
    customPresets[name] = p
    persist.setGlobal("aesthetic.shaderPresets", customPresets)
    persist.setGlobal("aesthetic.shaderPresetCount", customCount)
    if handles.preset then
        if isNew and handles.preset.AddOption then handles.preset:AddOption(name) end
        handles.preset:Set(name)
    end
    if handles.name then handles.name:Set("") end
end

local function resetAll()
    if handles.preset then handles.preset:Set("Default") else applyPreset("Default", true) end
end

function Aesthetic.register()
    local box = container.new(window.parent(), "Aesthetic")

    box:add(feature.declare({
        id = "aesthetic.fullbright", name = "Fullbright",
        description = "Max ambient light and no shadows so dark areas are fully lit. Restores the game's lighting when off.",
        default = false, onToggle = function(v) st.fullbright = v; if not v then revertFullbright() end; apply(); ensureLoop() end,
    }).root)

    box:add(feature.declare({
        id = "aesthetic.nofog", name = "No Fog",
        description = "Pushes fog out to the horizon so distant geometry is visible.",
        default = false, onToggle = function(v) st.nofog = v; if not v then revertFog() end; apply(); ensureLoop() end,
    }).root)

    box:add(feature.declare({
        id = "aesthetic.fov", name = "Custom FOV",
        description = "Forces the camera field of view. Set the value with the cog slider.",
        default = false, onToggle = function(v) st.fovOn = v; if not v then revertFov() end; apply(); ensureLoop() end,
        settings = { { type = "slider", name = "FOV", key = "value", min = 40, max = 120, step = 1, default = 90,
            onChange = function(x) st.fov = x; if st.fovOn then apply() end end } },
    }).root)

    box:add(feature.declare({
        id = "aesthetic.time", name = "Custom Time",
        description = "Locks the time of day (0-24). Set it with the cog slider -- handy for forcing daytime.",
        default = false, onToggle = function(v) st.timeOn = v; if not v then revertTime() end; apply(); ensureLoop() end,
        settings = { { type = "slider", name = "Time of day", key = "value", min = 0, max = 24, step = 1, default = 12,
            onChange = function(x) st.clock = x; if st.timeOn then apply() end end } },
    }).root)

    -- Saved shaders are GLOBAL so they follow the user across games.
    customPresets = persist.getGlobal("aesthetic.shaderPresets", {}) or {}
    customCount   = persist.getGlobal("aesthetic.shaderPresetCount", 0) or 0
    -- One-time migration: shaders used to be saved per-game. If the global store
    -- is empty but THIS game has old per-game saves, lift them into global so a
    -- shader made before this update isn't lost.
    if next(customPresets) == nil then
        local old = persist.get("aesthetic.shaderPresets", nil)
        if type(old) == "table" and next(old) ~= nil then
            customPresets = old
            customCount = persist.get("aesthetic.shaderPresetCount", 0) or 0
            persist.setGlobal("aesthetic.shaderPresets", customPresets)
            persist.setGlobal("aesthetic.shaderPresetCount", customCount)
        end
    end
    local presetOptions = { "Default" }
    for name in pairs(customPresets) do presetOptions[#presetOptions + 1] = name end

    box:add(feature.declare({
        id          = "aesthetic.preset",
        name        = "Preset Shaders",
        description = "Master RTX look + your saved shaders. Enabling applies the cinematic Lighting AND turns on Bloom, Depth of Field, Sun Rays, Color Grade and Motion Blur, and re-asserts every value each frame so the GAME can't override it. Pick a saved shader to load it; type a Name + 'Save' to store the current look (saved shaders are GLOBAL -- they show up in every game). Turn any effect off on its own; disabling Preset Shaders turns them all off AND resets to defaults. NOTE: client-side post-processing -- avoid on strict-AC games.",
        default     = false,
        onToggle    = function(v)
            enableLighting(v)
            if shaderBooting then return end
            if v then
                for _, id in ipairs(SHADER_CHILDREN) do feature.setEnabled(id, true) end
            else
                for _, id in ipairs(SHADER_CHILDREN) do feature.setEnabled(id, false) end
                resetAll()
            end
        end,
        settings = {
            { type = "dropdown", name = "Shader", key = "preset", options = presetOptions, default = "Default",
              onChange = function(v) applyPreset(v, not shaderBooting) end,
              onCreate = function(h) handles.preset = h end },
            { type = "textbox", name = "Name", key = "savename", placeholder = "name your shader",
              onCreate = function(h) handles.name = h end },
            { type = "button", name = "Save current as new preset", onClick = function() saveCurrentPreset() end },
            { type = "section", name = "Lighting" },
            { type = "slider", name = "Brightness",      key = "b",  min = 0,   max = 10, step = 0.01,  default = DEFAULTS.brightness,     onChange = function(v) sv.brightness = v;     applyLighting() end, onCreate = function(h) handles.brightness = h end },
            { type = "slider", name = "Exposure",        key = "e",  min = -3,  max = 3,  step = 0.01,  default = DEFAULTS.exposure,       onChange = function(v) sv.exposure = v;       applyLighting() end, onCreate = function(h) handles.exposure = h end },
            { type = "slider", name = "Shadow Softness", key = "ss", min = 0,   max = 1,  step = 0.01,  default = DEFAULTS.shadowSoftness, onChange = function(v) sv.shadowSoftness = v; applyLighting() end, onCreate = function(h) handles.shadowSoftness = h end },
            { type = "slider", name = "Env Diffuse",     key = "ed", min = 0,   max = 1,  step = 0.001, default = DEFAULTS.envDiffuse,     onChange = function(v) sv.envDiffuse = v;     applyLighting() end, onCreate = function(h) handles.envDiffuse = h end },
            { type = "slider", name = "Env Specular",    key = "es", min = 0,   max = 1,  step = 0.001, default = DEFAULTS.envSpecular,    onChange = function(v) sv.envSpecular = v;    applyLighting() end, onCreate = function(h) handles.envSpecular = h end },
            { type = "slider", name = "Geo Latitude",    key = "gl", min = -90, max = 90, step = 0.025, default = DEFAULTS.geoLat,         onChange = function(v) sv.geoLat = v;         applyLighting() end, onCreate = function(h) handles.geoLat = h end },
        },
    }).root)

    box:add(feature.declare({
        id = "aesthetic.bloom", name = "Bloom",
        description = "Soft glow on bright pixels. Client-side BloomEffect -- avoid on strict-AC games.",
        default = false, onToggle = function(v) if v then newFx("bloom", "BloomEffect"); applyBloom() else killFx("bloom") end end,
        settings = {
            { type = "slider", name = "Intensity", key = "i", min = 0, max = 4,    step = 0.01,  default = DEFAULTS.bloomIntensity, onChange = function(v) sv.bloomIntensity = v; applyBloom() end, onCreate = function(h) handles.bloomIntensity = h end },
            { type = "slider", name = "Size",      key = "s", min = 0, max = 2000, step = 10,    default = DEFAULTS.bloomSize,      onChange = function(v) sv.bloomSize = v;      applyBloom() end, onCreate = function(h) handles.bloomSize = h end },
            { type = "slider", name = "Threshold", key = "t", min = 0, max = 5,    step = 0.005, default = DEFAULTS.bloomThreshold, onChange = function(v) sv.bloomThreshold = v; applyBloom() end, onCreate = function(h) handles.bloomThreshold = h end },
        },
    }).root)

    box:add(feature.declare({
        id = "aesthetic.dof", name = "Depth of Field",
        description = "Blurs near/far, keeps a focus band sharp. Client-side DepthOfFieldEffect -- avoid on strict-AC games.",
        default = false, onToggle = function(v) if v then newFx("dof", "DepthOfFieldEffect"); applyDof() else killFx("dof") end end,
        settings = {
            { type = "slider", name = "Focus Distance",  key = "fd", min = 0, max = 200, step = 0.01,  default = DEFAULTS.dofFocus,  onChange = function(v) sv.dofFocus = v;  applyDof() end, onCreate = function(h) handles.dofFocus = h end },
            { type = "slider", name = "In-Focus Radius", key = "fr", min = 0, max = 200, step = 0.01,  default = DEFAULTS.dofRadius, onChange = function(v) sv.dofRadius = v; applyDof() end, onCreate = function(h) handles.dofRadius = h end },
            { type = "slider", name = "Near Intensity",  key = "ni", min = 0, max = 1,   step = 0.001, default = DEFAULTS.dofNear,   onChange = function(v) sv.dofNear = v;   applyDof() end, onCreate = function(h) handles.dofNear = h end },
            { type = "slider", name = "Far Intensity",   key = "fi", min = 0, max = 1,   step = 0.001, default = DEFAULTS.dofFar,    onChange = function(v) sv.dofFar = v;    applyDof() end, onCreate = function(h) handles.dofFar = h end },
        },
    }).root)

    box:add(feature.declare({
        id = "aesthetic.sunrays", name = "Sun Rays",
        description = "Volumetric light shafts from the sun. Client-side SunRaysEffect -- avoid on strict-AC games.",
        default = false, onToggle = function(v) if v then newFx("sun", "SunRaysEffect"); applySun() else killFx("sun") end end,
        settings = {
            { type = "slider", name = "Intensity", key = "i", min = 0, max = 1, step = 0.001, default = DEFAULTS.sunIntensity, onChange = function(v) sv.sunIntensity = v; applySun() end, onCreate = function(h) handles.sunIntensity = h end },
            { type = "slider", name = "Spread",    key = "s", min = 0, max = 1, step = 0.001, default = DEFAULTS.sunSpread,    onChange = function(v) sv.sunSpread = v;    applySun() end, onCreate = function(h) handles.sunSpread = h end },
        },
    }).root)

    box:add(feature.declare({
        id = "aesthetic.grade", name = "Color Grade",
        description = "Cinematic color grade (3 stacked passes). Client-side ColorCorrectionEffects -- avoid on strict-AC games.",
        default = false, onToggle = function(v)
            if v then newFx("cc1", "ColorCorrectionEffect"); newFx("cc2", "ColorCorrectionEffect"); newFx("cc3", "ColorCorrectionEffect"); applyGrade()
            else killFx("cc1"); killFx("cc2"); killFx("cc3") end
        end,
        settings = {
            { type = "slider", name = "Contrast",   key = "c", min = -1, max = 1, step = 0.01,  default = DEFAULTS.cc1C, onChange = function(v) sv.cc1C = v; applyGrade() end, onCreate = function(h) handles.cc1C = h end },
            { type = "slider", name = "Saturation", key = "s", min = -1, max = 1, step = 0.01,  default = DEFAULTS.cc1S, onChange = function(v) sv.cc1S = v; applyGrade() end, onCreate = function(h) handles.cc1S = h end },
            { type = "slider", name = "Brightness", key = "b", min = -1, max = 1, step = 0.001, default = DEFAULTS.cc1B, onChange = function(v) sv.cc1B = v; applyGrade() end, onCreate = function(h) handles.cc1B = h end },
        },
    }).root)

    box:add(feature.declare({
        id = "aesthetic.motionblur", name = "Motion Blur",
        description = "Camera blur scaled by how fast you turn. Client-side BlurEffect on the camera -- avoid on strict-AC games.",
        default = false, onToggle = function(v) enableBlur(v) end,
        settings = {
            { type = "slider", name = "Amount", key = "a", min = 0, max = 30, step = 1, default = DEFAULTS.blurAmount, onChange = function(v) sv.blurAmount = v end, onCreate = function(h) handles.blurAmount = h end },
        },
    }).root)

    shaderBooting = false
    log.info("Aesthetic module registered")
end

function Aesthetic.destroy()
    if enforceConn then enforceConn:Disconnect(); enforceConn = nil end
    revertFullbright(); revertFog(); revertTime(); revertFov()
    shaderTeardown()
end

return Aesthetic
end

_MODULES["modules.misc.autoobby"] = function()
-- Auto Obby: auto-completes an obstacle course toward a goal you place.
--
-- Engage with the feature keybind (or the toggle), then a PREVIEW reticle tracks
-- whatever your cursor points at -- click to drop a GOAL marker there. The bot
-- then heads to the goal on its own: it WALKS on continuous ground and only JUMPS
-- when it actually has to (a real gap, or a ledge taller than a normal step), and
-- it only ever attempts jumps the local character could physically make.
--
-- Caveats handled (this is meant to be robust):
--   * Non-collidable parts (invisible zone/trigger walls, decoration) are ignored
--     for BOTH footing and obstruction -- RaycastParams.RespectCanCollide + a
--     CanCollide re-check. They never count as ground or as a wall.
--   * Never noclips: walking is real physics; a jump is rejected if a collidable
--     wall sits in its straight-line path; the tween arc re-snaps onto real ground
--     on landing so it can't end up inside/through the floor.
--   * Only jumps when necessary (gap / tall ledge), never spam-jumps on flat ground.
--   * Rotates the BODY to face travel (rotation_lock's AlignOrientation) WITHOUT
--     moving the camera; AutoRotate is handed back when idle / off.
--   * Detects + avoids damage / kill blocks (name, lava material, strong-red).
--   * Steers around a wall when the straight line is blocked.
--   * Clears the goal + both markers + body constraint when you turn it off or die.
--
-- Modes: Legit = real Humanoid jump + air control over the gap. Tween = drives the
-- root along a gravity-accurate projectile arc (looks legit). Both are gated by the
-- same physics reachability, so Tween never travels farther/higher than a real jump.
-- Tween drives the root each frame -- a strict client AC can flag it; use Legit there.

local feature = require("ui.feature")
local notify  = require("ui.notify")
local log     = require("core.log")
local env     = require("core.env")

local Players          = game:GetService("Players")
local RunService       = game:GetService("RunService")
local UserInputService = game:GetService("UserInputService")
local Workspace        = workspace

local AutoObby = {}
local LP = Players.LocalPlayer

local s = {
    active      = false,
    mode        = "Legit",
    avoidDamage = true,
    reachPct    = 0.85,   -- fraction of physics-max reach we trust (safety margin)
    hopDelay    = 0.12,   -- pause after a jump before the next decision
    goal        = nil,    -- Vector3 goal (set by clicking)
    airTarget   = nil,    -- Vector3 we're air-controlling toward during a legit jump
    busy        = false,  -- mid tween arc
    lastJump    = 0,
    ctrlLoop    = nil,
    markConn    = nil,
    clickConn   = nil,
    mouse       = nil,
}

local STEP_HEIGHT = 2.5   -- ledges up to this we walk up (Roblox auto-steps); above -> jump
local LOOKAHEAD   = 4.5   -- studs ahead we probe for a body-height wall
local EDGE_LOOK   = 2.0   -- how close to a gap edge before we stop walking and jump
local GOAL_RADIUS = 5     -- within this (horizontal) of the goal = arrived
local JUMP_CD     = 0.25  -- min seconds between jump triggers

-- ---- damage heuristic --------------------------------------------------------
local DAMAGE_NAMES = {
    "kill", "lava", "damage", "spike", "death", "hazard", "trap",
    "acid", "poison", "laser", "saw", "void", "danger", "hurt", "deadly",
}
local DAMAGE_MATERIALS = { [Enum.Material.CrackedLava] = true }

local function isDamage(part)
    if not s.avoidDamage or not part then return false end
    local inst = part
    for _ = 1, 3 do
        if not inst or inst == Workspace then break end
        local n = inst.Name:lower()
        for _, pat in ipairs(DAMAGE_NAMES) do
            if n:find(pat, 1, true) then return true end
        end
        inst = inst.Parent
    end
    if part:IsA("BasePart") then
        if DAMAGE_MATERIALS[part.Material] then return true end
        local ok, c = pcall(function() return part.Color end)
        if ok and c and c.R > 0.62 and c.G < 0.32 and c.B < 0.32 then return true end
    end
    return false
end

-- ---- character + physics -----------------------------------------------------
local function rig()
    local c = LP.Character
    if not c then return nil end
    return c, c:FindFirstChild("HumanoidRootPart"), c:FindFirstChildOfClass("Humanoid")
end

local function jumpVelocity(hum)
    local g = Workspace.Gravity
    if hum.UseJumpPower then return hum.JumpPower end
    return math.sqrt(2 * g * math.max(hum.JumpHeight, 0))
end

local function reachable(hum, dx, dy)
    local g = Workspace.Gravity
    local v = jumpVelocity(hum)
    local peak = (v * v) / (2 * g)
    if dy > peak then return false end
    local disc = v * v - 2 * g * dy
    if disc < 0 then return false end
    local tLand = (v + math.sqrt(disc)) / g
    return dx <= hum.WalkSpeed * tLand * s.reachPct
end

-- one reusable params: ignore non-collidable parts (zone walls etc.) + water +
-- our own character. RespectCanCollide is pcall'd in case an old client lacks it;
-- callers also re-check CanCollide defensively.
local rp = RaycastParams.new()
rp.FilterType = Enum.RaycastFilterType.Exclude
rp.IgnoreWater = true
pcall(function() rp.RespectCanCollide = true end)
local rpIgnore = {}
local function params(extra)
    rpIgnore[1] = LP.Character
    rpIgnore[2] = extra
    rp.FilterDescendantsInstances = rpIgnore
    return rp
end

local function flat(v) return Vector3.new(v.X, 0, v.Z) end
local function rotateY(v, rad)
    local c, sn = math.cos(rad), math.sin(rad)
    return Vector3.new(v.X * c - v.Z * sn, 0, v.X * sn + v.Z * c)
end

-- ground (collidable) directly under pos
local function groundUnder(pos, depth)
    return Workspace:Raycast(pos + Vector3.new(0, 2.5, 0), Vector3.new(0, -(depth or 80), 0), params())
end
-- a hit counts as standable ground: collidable top surface that isn't a damage block
local function standable(rc)
    return rc and rc.Instance and rc.Instance.CanCollide ~= false
        and rc.Normal.Y > 0.6 and not isDamage(rc.Instance)
end

-- ---- body rotation (rotation_lock style: camera stays free) -------------------
local rot = { att = nil, align = nil, owned = false }
local function ensureAlign(hrp)
    if not (rot.att and rot.att.Parent) then
        rot.att = Instance.new("Attachment"); rot.att.Name = "PantheonObbyAtt"; rot.att.Parent = hrp
    end
    if not (rot.align and rot.align.Parent) then
        rot.align = Instance.new("AlignOrientation")
        rot.align.Name = "PantheonObbyAlign"
        rot.align.Mode = Enum.OrientationAlignmentMode.OneAttachment
        rot.align.Attachment0 = rot.att
        rot.align.RigidityEnabled = true
        rot.align.Responsiveness = 200
        rot.align.MaxTorque = math.huge
        rot.align.Parent = hrp
    end
end
local function faceDir(hrp, hum, dir)
    dir = flat(dir)
    if dir.Magnitude < 1e-3 then return end
    ensureAlign(hrp)
    rot.align.Enabled = true
    rot.align.CFrame = CFrame.lookAt(Vector3.zero, dir.Unit)
    if hum then hum.AutoRotate = false end
    rot.owned = true
end
local function releaseRot(hum)
    if rot.align then rot.align.Enabled = false end
    if rot.owned and hum then pcall(function() hum.AutoRotate = true end) end
    rot.owned = false
end
local function destroyRot()
    if rot.align then pcall(function() rot.align:Destroy() end); rot.align = nil end
    if rot.att   then pcall(function() rot.att:Destroy()   end); rot.att   = nil end
    rot.owned = false
end

-- ---- find a jump landing ------------------------------------------------------
-- Fans downward (collidable) rays ahead toward `heading`, keeping reachable, safe,
-- standable surfaces; scores by progress toward the goal (or raw forward distance).
-- Returns { hrpPos, inst, groundY } or nil.
local ANGLES = { 0, 15, -15, 30, -30, 45, -45 }
local function findLanding(fromPos, startGroundY, standOffset, heading, hum, goal)
    local g = Workspace.Gravity
    local v = jumpVelocity(hum)
    local peak     = (v * v) / (2 * g)
    local maxReach = hum.WalkSpeed * (2 * v / g)
    local fromFlat = flat(fromPos)
    local goalFlat = goal and flat(goal) or nil
    local goalDist = goalFlat and (goalFlat - fromFlat).Magnitude or nil

    local best, bestScore
    for _, deg in ipairs(ANGLES) do
        local dir = rotateY(heading, math.rad(deg)).Unit
        for i = 1, 7 do
            local dist = math.max(4, (i / 7) * maxReach)
            local col  = fromPos + dir * dist
            local top  = col + Vector3.new(0, peak + 6, 0)
            local rc   = Workspace:Raycast(top, Vector3.new(0, -(peak + 6 + 60), 0), params())
            if standable(rc) then
                local land = rc.Position
                local dx   = (flat(land) - fromFlat).Magnitude
                local dyP  = land.Y - startGroundY
                if dx >= 4 and reachable(hum, dx, dyP) then
                    local fwd = (flat(land) - fromFlat).Unit:Dot(heading)
                    if fwd > 0 then
                        local score = goalDist and (goalDist - (goalFlat - flat(land)).Magnitude)
                                       or (flat(land) - fromFlat):Dot(heading)
                        if score > 0.5 and (not bestScore or score > bestScore) then
                            best = { hrpPos = land + Vector3.new(0, standOffset, 0), inst = rc.Instance, groundY = land.Y }
                            bestScore = score
                        end
                    end
                end
            end
        end
    end
    return best
end

-- straight-line collidable obstruction between the root and a landing (so we never
-- jump THROUGH a wall). Excludes our character and the destination platform; stops
-- short of the landing so the platform itself doesn't read as a blocker.
local function pathClear(fromHrp, toHrp, destInst)
    local dir = toHrp - fromHrp
    local dist = dir.Magnitude
    if dist < 0.1 then return true end
    return Workspace:Raycast(fromHrp, dir * 0.9, params(destInst)) == nil
end

-- ---- movement decision -------------------------------------------------------
local GROUNDED = {
    [Enum.HumanoidStateType.Running]          = true,
    [Enum.HumanoidStateType.RunningNoPhysics] = true,
    [Enum.HumanoidStateType.Landed]           = true,
    [Enum.HumanoidStateType.GettingUp]        = true,
}

-- ground continuous + walkable-height for the next EDGE_LOOK studs, so we keep
-- walking right up to a gap edge, then jump (not several studs early).
local function walkClear(hrp, footY, dir)
    for i = 1, 2 do
        local p = hrp.Position + dir * (EDGE_LOOK * i / 2)
        local b = Workspace:Raycast(Vector3.new(p.X, footY + STEP_HEIGHT + 0.5, p.Z),
                                    Vector3.new(0, -(2 * STEP_HEIGHT + 0.5), 0), params())
        if not standable(b) then return false end   -- a gap / cliff / damage block in the path
    end
    return true
end

-- "walk" (continuous safe ground just ahead, no wall), "jump"+landing, "wall", or "stuck"
local function decideMove(hrp, hum, footY, heading)
    -- collidable wall at body height in the immediate path? (passes over small steps)
    local wall = Workspace:Raycast(hrp.Position, heading * LOOKAHEAD, params())
    if not wall and walkClear(hrp, footY, heading) then
        return "walk"
    end
    local land = findLanding(hrp.Position, footY, hrp.Position.Y - footY, heading, hum, s.goal)
    if land and pathClear(hrp.Position, land.hrpPos, land.inst) then
        return "jump", land
    end
    if wall or land then return "wall" end   -- blocked straight ahead -> try to steer
    return "stuck"
end

-- pick a sideways heading that's walkable, to round a wall / dead-end
local function steerAround(hrp, footY, heading)
    for _, deg in ipairs({ 25, -25, 50, -50, 80, -80 }) do
        local d = rotateY(heading, math.rad(deg)).Unit
        local wall = Workspace:Raycast(hrp.Position, d * (LOOKAHEAD + 1), params())
        local probe = hrp.Position + d * LOOKAHEAD
        local band  = Workspace:Raycast(Vector3.new(probe.X, footY + STEP_HEIGHT + 0.5, probe.Z),
                                        Vector3.new(0, -(2 * STEP_HEIGHT + 0.5), 0), params())
        if standable(band) and not wall then return d end
    end
    return Vector3.zero
end

-- ---- jump execution ----------------------------------------------------------
-- Tween: drive the root along the SAME projectile a real jump would trace, then
-- re-snap onto the real landing surface so it can never end up inside the floor.
local function tweenJump(hum, hrp, land, standOffset)
    s.busy = true
    local g = Workspace.Gravity
    local v = jumpVelocity(hum)
    local start = hrp.Position
    local target = land.hrpPos
    local dy = target.Y - start.Y
    local horiz = flat(target - start)
    local dx = horiz.Magnitude
    local dir = (dx > 0.01) and (horiz / dx) or flat(hrp.CFrame.LookVector).Unit
    local disc = v * v - 2 * g * dy
    if disc < 0 then s.busy = false; return end
    local T = (v + math.sqrt(disc)) / g
    if T <= 0 then s.busy = false; return end
    local hs = dx / T

    if rot.align then rot.align.Enabled = false end   -- the per-frame CFrame owns orientation now
    pcall(function() hum:ChangeState(Enum.HumanoidStateType.Jumping) end)
    local t = 0
    while t < T and s.active do
        if not (hrp and hrp.Parent) then s.busy = false; return end
        local dt = RunService.Heartbeat:Wait()
        t = math.min(t + dt, T)
        local y   = v * t - 0.5 * g * t * t
        local pos = start + dir * (hs * t) + Vector3.new(0, y, 0)
        hrp.CFrame = CFrame.lookAt(pos, pos + dir)
        hrp.AssemblyLinearVelocity = dir * hs + Vector3.new(0, v - g * t, 0)
    end
    -- land on the TRUE ground at the target column (re-raycast) so we never phase in
    if hrp and hrp.Parent then
        local snap = groundUnder(Vector3.new(target.X, target.Y + 2, target.Z), 12)
        local fy = (snap and standable(snap)) and (snap.Position.Y + standOffset) or target.Y
        local p = Vector3.new(target.X, fy, target.Z)
        hrp.CFrame = CFrame.lookAt(p, p + dir)
        hrp.AssemblyLinearVelocity = Vector3.zero
    end
    pcall(function() hum:ChangeState(Enum.HumanoidStateType.Landed) end)
    s.busy = false
    s.lastJump = os.clock()
end

-- ---- control loop ------------------------------------------------------------
-- returns true if it triggered a jump this tick (so the loop pauses briefly)
local function controlTick()
    local _, hrp, hum = rig()
    if not (hrp and hum) or hum.Health <= 0 then releaseRot(hum); s.airTarget = nil; return false end

    if not s.goal then                      -- idle: don't move, hand the body back
        hum:Move(Vector3.zero, false); releaseRot(hum); return false
    end
    if flat(s.goal - hrp.Position).Magnitude <= GOAL_RADIUS then
        s.goal = nil; s.airTarget = nil
        hum:Move(Vector3.zero, false); releaseRot(hum)
        notify.success("Auto Obby: reached the goal")
        return false
    end

    local goalDir = flat(s.goal - hrp.Position)
    if goalDir.Magnitude < 1e-3 then return false end
    goalDir = goalDir.Unit

    if not GROUNDED[hum:GetState()] then    -- airborne (legit jump): air-control toward the target
        local aim = s.airTarget or s.goal
        local d = flat(aim - hrp.Position)
        if d.Magnitude > 0.5 then hum:Move(d.Unit, false); faceDir(hrp, hum, d) end
        return false
    end
    s.airTarget = nil
    if s.busy then return false end

    local gr = groundUnder(hrp.Position, 14)
    if not gr then return false end          -- briefly off ground; wait
    local footY = gr.Position.Y
    local standOffset = hrp.Position.Y - footY
    faceDir(hrp, hum, goalDir)

    local action, land = decideMove(hrp, hum, footY, goalDir)
    if action == "walk" then
        hum:Move(goalDir, false)
        return false
    elseif action == "jump" then
        if os.clock() - s.lastJump < JUMP_CD then return false end
        if s.mode == "Tween" then
            tweenJump(hum, hrp, land, standOffset)
        else
            s.airTarget = land.hrpPos
            hum:Move(goalDir, false)
            hum.Jump = true
            s.lastJump = os.clock()
        end
        return true
    elseif action == "wall" then
        local d = steerAround(hrp, footY, goalDir)
        hum:Move(d, false)
        if d.Magnitude > 0 then faceDir(hrp, hum, d) end
        return false
    else
        hum:Move(Vector3.zero, false)
        return false
    end
end

local function startControl()
    if s.ctrlLoop then return end
    s.ctrlLoop = task.spawn(function()
        while s.active do
            local jumped
            local ok, err = pcall(function() jumped = controlTick() end)
            if not ok then log.warn("autoobby tick: " .. tostring(err)) end
            task.wait(jumped and s.hopDelay or 0.05)
        end
        s.ctrlLoop = nil
    end)
end

-- ---- markers (2D, projected; nothing in workspace) ---------------------------
local mk = { gui = nil, preview = nil, placed = nil, label = nil }
local function ensureMarkers()
    if mk.gui and mk.gui.Parent then return end
    local sg = Instance.new("ScreenGui")
    sg.Name = "_" .. tostring(math.random(100000, 999999))   -- randomized (anti-scan, Pantheon convention)
    sg.ResetOnSpawn = false
    sg.IgnoreGuiInset = false                                 -- matches WorldToViewportPoint space
    sg.DisplayOrder = 50
    sg.Parent = env.guiParent()
    env.protectGui(sg)

    -- preview reticle: hollow cyan ring + center dot (where a click WOULD set the goal)
    local pv = Instance.new("Frame")
    pv.Size = UDim2.fromOffset(26, 26)
    pv.AnchorPoint = Vector2.new(0.5, 0.5)
    pv.BackgroundTransparency = 1
    pv.Visible = false
    pv.Parent = sg
    local pvc = Instance.new("UICorner", pv); pvc.CornerRadius = UDim.new(1, 0)
    local pvs = Instance.new("UIStroke", pv); pvs.Color = Color3.fromRGB(120, 220, 255); pvs.Thickness = 2; pvs.Transparency = 0.1
    local dot = Instance.new("Frame", pv)
    dot.Size = UDim2.fromOffset(4, 4); dot.AnchorPoint = Vector2.new(0.5, 0.5); dot.Position = UDim2.fromScale(0.5, 0.5)
    dot.BackgroundColor3 = Color3.fromRGB(120, 220, 255); dot.BorderSizePixel = 0
    Instance.new("UICorner", dot).CornerRadius = UDim.new(1, 0)

    -- placed goal: solid green diamond + distance label (distinct from the preview)
    local pl = Instance.new("Frame")
    pl.Size = UDim2.fromOffset(18, 18)
    pl.AnchorPoint = Vector2.new(0.5, 0.5)
    pl.Rotation = 45
    pl.BackgroundColor3 = Color3.fromRGB(87, 242, 135)
    pl.BorderSizePixel = 0
    pl.Visible = false
    pl.Parent = sg
    local pls = Instance.new("UIStroke", pl); pls.Color = Color3.fromRGB(255, 255, 255); pls.Thickness = 1.5
    local lbl = Instance.new("TextLabel")
    lbl.Size = UDim2.fromOffset(120, 16)
    lbl.AnchorPoint = Vector2.new(0.5, 1)
    lbl.Position = UDim2.fromOffset(0, -16)
    lbl.BackgroundTransparency = 1
    lbl.Font = Enum.Font.GothamBold
    lbl.TextSize = 12
    lbl.TextColor3 = Color3.fromRGB(87, 242, 135)
    lbl.TextStrokeTransparency = 0.4
    lbl.Text = "GOAL"
    lbl.Rotation = -45                         -- counter the diamond's parent rotation
    lbl.Parent = pl

    mk.gui, mk.preview, mk.placed, mk.label = sg, pv, pl, lbl
end

local function cursorWorld()
    local m = s.mouse
    if m and m.Target and m.Target.Parent then return m.Hit.Position end
    return nil
end

local function updateMarkers()
    local cam = Workspace.CurrentCamera
    if not (cam and mk.gui) then return end
    -- preview at the cursor's world hit
    local cw = cursorWorld()
    if cw then
        local vp = cam:WorldToViewportPoint(cw)
        if vp.Z > 0 then mk.preview.Visible = true; mk.preview.Position = UDim2.fromOffset(vp.X, vp.Y)
        else mk.preview.Visible = false end
    else
        mk.preview.Visible = false
    end
    -- placed goal marker + live distance
    if s.goal then
        local vp = cam:WorldToViewportPoint(s.goal)
        if vp.Z > 0 then
            mk.placed.Visible = true
            mk.placed.Position = UDim2.fromOffset(vp.X, vp.Y)
            local _, hrp = rig()
            if hrp then mk.label.Text = ("GOAL  %d"):format(math.floor(flat(s.goal - hrp.Position).Magnitude)) end
        else
            mk.placed.Visible = false
        end
    else
        mk.placed.Visible = false
    end
end

local function hideMarkers()
    if mk.preview then mk.preview.Visible = false end
    if mk.placed  then mk.placed.Visible  = false end
end
local function destroyMarkers()
    if mk.gui then pcall(function() mk.gui:Destroy() end) end
    mk.gui, mk.preview, mk.placed, mk.label = nil, nil, nil, nil
end

-- ---- click to set goal -------------------------------------------------------
local function onInput(input, gpe)
    if gpe then return end   -- consumed by the Pantheon UI / any GUI
    if input.UserInputType ~= Enum.UserInputType.MouseButton1 then return end
    local cw = cursorWorld()
    if cw then
        s.goal = cw
        notify.info("Auto Obby: goal set")
    end
end

-- ---- lifecycle ---------------------------------------------------------------
local function setActive(v)
    v = v and true or false
    if s.active == v then return end
    s.active = v
    if v then
        s.mouse = s.mouse or LP:GetMouse()
        pcall(function() s.mouse.TargetFilter = LP.Character end)
        ensureMarkers()
        if not s.clickConn then s.clickConn = UserInputService.InputBegan:Connect(onInput) end
        if not s.markConn then s.markConn = RunService.RenderStepped:Connect(updateMarkers) end
        startControl()
        notify.success("Auto Obby ON -- click a spot to set a goal")
    else
        -- clear the goal + both markers + body constraint (full reset)
        s.goal, s.airTarget = nil, nil
        if s.clickConn then s.clickConn:Disconnect(); s.clickConn = nil end
        if s.markConn  then s.markConn:Disconnect();  s.markConn  = nil end
        hideMarkers()
        local _, hrp, hum = rig()
        releaseRot(hum)
        if hum then pcall(function() hum:Move(Vector3.zero, false) end) end
    end
end

function AutoObby.register(box)
    box:add(feature.declare({
        id          = "misc.autoobby",
        name        = "Auto Obby",
        description = "Auto-completes obstacle courses. Engage with the keybind, then a preview reticle follows your cursor -- click a spot to drop a GOAL marker and it heads there on its own. It WALKS on continuous ground and only JUMPS at real gaps / tall ledges, only attempting jumps your character can actually make, rotating the body to face travel (no camera movement). Ignores non-collidable parts (invisible zone walls), won't noclip through walls, and avoids damage / kill blocks it detects. Legit mode = real jump + air control; Tween mode = a gravity-accurate jump arc (looks legit, but drives your position -- a strict client anticheat may flag it). Turning it off clears the goal + markers.",
        default     = false,
        defaultKey  = Enum.KeyCode.G,
        onToggle    = setActive,
        settings    = {
            { type = "dropdown", name = "Mode", key = "mode", options = { "Legit", "Tween" }, default = "Legit",
              onChange = function(v) s.mode = v end },
            { type = "toggle", name = "Avoid damage blocks", key = "avoid", default = true,
              onChange = function(v) s.avoidDamage = v end },
            { type = "slider", name = "Reach safety %", key = "reach", min = 50, max = 100, step = 5, default = 85,
              onChange = function(v) s.reachPct = (v or 85) / 100 end },
            { type = "slider", name = "Jump pause (s)", key = "delay", min = 0, max = 0.6, step = 0.05, default = 0.12,
              onChange = function(v) s.hopDelay = v or 0.12 end },
        },
    }).root)
    log.info("Auto Obby feature registered")
end

function AutoObby.destroy()
    s.active = false
    if s.clickConn then pcall(function() s.clickConn:Disconnect() end); s.clickConn = nil end
    if s.markConn  then pcall(function() s.markConn:Disconnect()  end); s.markConn  = nil end
    local _, _, hum = rig()
    releaseRot(hum)
    destroyRot()
    destroyMarkers()
    s.goal, s.airTarget = nil, nil
end

-- pure helpers for the offline mock test (tools/mocktest_autoobby.py); no side effects
AutoObby._diag = { reachable = reachable, isDamage = isDamage, jumpVelocity = jumpVelocity,
                   findLanding = findLanding, decideMove = decideMove, pathClear = pathClear }

return AutoObby
end

_MODULES["modules.misc.init"] = function()
-- Miscellaneous: catch-all menu for standalone utility scripts that don't fit
-- the aim / aesthetic / tech buckets. Each script self-contains its own feature
-- declaration and lifecycle; this just owns the shared container and fans
-- register()/destroy() out to them. Add a new script: require it here, call its
-- .register(box) in Misc.register, and its .destroy() in Misc.destroy.

local container = require("ui.container")
local window    = require("ui.window")
local log       = require("core.log")

local autoobby  = require("modules.misc.autoobby")

local Misc = {}

local scripts = { autoobby }

function Misc.register()
    local box = container.new(window.parent(), "Miscellaneous")
    for _, m in ipairs(scripts) do
        local ok, err = pcall(function() m.register(box) end)
        if not ok then log.warn("misc script register failed: " .. tostring(err)) end
    end
    log.info("Miscellaneous module registered")
end

function Misc.destroy()
    for _, m in ipairs(scripts) do
        pcall(function() if m.destroy then m.destroy() end end)
    end
end

return Misc
end

_MODULES["games.jjs"] = function()
-- Jujutsu Shenanigans (PlaceId 17016840407) integration.
--
-- Registered into the game registry; its container only appears when you're
-- actually in JJS -- init.lua calls registry.current().register() gated on
-- game.PlaceId, so this never shows in other games.
--
-- Feature: Nanami "Perfect Special" -- auto-times Salaryman's R special, Ratio
-- Point (NanamiService.RE.RightActivated). Per the JJS wiki, Ratio Point marks a
-- target within 70 STUDS and runs a quick-time event whose timing speeds up as
-- the target's HP drops; this fires the confirm after an HP-scaled delay so it
-- lands on the ratio. Ported from the old lock-on script, which used a wrong
-- 27-stud range -- corrected to the wiki's 70.

local registry  = require("games.registry")
local window    = require("ui.window")
local container = require("ui.container")
local feature   = require("ui.feature")
local state     = require("modules.aim.state")
local targeting = require("modules.aim.targeting")
local shiftlock = require("modules.aim.shiftlock")
local log       = require("core.log")
local notify    = require("ui.notify")

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

-- JJS spans multiple places (17016840407 = "Lobby", 9391468976 = experience root)
-- under ONE GameId 3508322461 (grabbed in-game; matches the legacy script's id).
-- registry.current() checks game.GameId, so the GameId entry covers EVERY place /
-- VIP server in one go; the place ids are just extra redundancy.
local JJS_IDS = { 3508322461, 17016840407, 9391468976 }   -- GameId first, then known places

local JJS = {}

local CFG = {
    range    = 70,     -- studs -- wiki: Ratio Point marks a target within 70 studs
    delayHi  = 0.63,   -- s, target >= 80% HP (QTE slower early-fight)
    delayLo  = 0.55,   -- s, target <  80% HP (QTE faster as HP drops)
    hpThresh = 80,     -- % HP threshold between the two timings
}
local enabled = false

local function rootOf(c) return c and c:FindFirstChild("HumanoidRootPart") end

-- Prefer the Target Select / Lock-On target; fall back to the nearest valid
-- target so it still works if you haven't engaged Target Select first.
local function targetChar()
    local t = state.target
    if t then
        return (state.target_type == "npc") and t or t.Character
    end
    -- Fallback: nearest valid target when Target Select hasn't engaged. Mirror the
    -- (target, type) handling above -- with Bot Mode on, best may be an NPC Model,
    -- and reading `.Character` off a Model throws ("not a valid member").
    local best, ty = targeting.getBestTarget()
    if not best then return nil end
    return (ty == "npc") and best or best.Character
end

local function ratioPointPerfect()
    if not enabled then return end
    local tChar = targetChar()
    if not tChar then return end
    local myRoot, tRoot = rootOf(Players.LocalPlayer.Character), rootOf(tChar)
    if not (myRoot and tRoot) then return end
    if (myRoot.Position - tRoot.Position).Magnitude > CFG.range then return end
    local hum = tChar:FindFirstChildOfClass("Humanoid")
    if not hum then return end
    local hpPct = (hum.Health / math.max(hum.MaxHealth, 1)) * 100
    local delay = (hpPct < CFG.hpThresh) and CFG.delayLo or CFG.delayHi
    task.delay(delay, function()
        pcall(function()
            ReplicatedStorage.Knit.Knit.Services.NanamiService.RE.RightActivated:FireServer(tChar)
        end)
    end)
end

-- Per-game move scanner hook (called by modules.tech.scanner first; generic scan is
-- the fallback). JJS's hotbar: PlayerGui.Controls (SG) > Controls > Moveset > <MoveName>
-- > ItemName -- the inner "Controls" Frame matters (the SG and its Frame child share a
-- name). Each ItemName TextButton has the real MouseButton1Down handler on it directly
-- (no inner Base button like TSB). Slot frame's Name is the move name (e.g. "Projection
-- Breaker"); keys 1..N map to the slots LEFT-TO-RIGHT by AbsolutePosition.X. The scanner
-- annotates `move` (Knit service name) from these entries via the shared stem matcher.
local lastScanReport = -1
local function scanReport(stage, n, names)
    if n == lastScanReport then return end
    lastScanReport = n
    local msg = ("JJS scanMoves [%s]: %d move(s) %s"):format(stage, n, names and ("[" .. names .. "]") or "")
    log.info(msg)
    pcall(function() notify.info(msg, 6) end)
end

-- JJS hotbar lives at PlayerGui.Main.Controls.Moveset.<MoveName>.ItemName. There's
-- a SEPARATE ScreenGui named "Controls" in PlayerGui that's the Mobile UI (no
-- Moveset descendant) -- earlier versions of this hook targeted the wrong SG.
function JJS.scanMoves(pg)
    local main = pg:FindFirstChild("Main")
    if not main then scanReport("no Main SG", 0); return nil end
    local controls = main:FindFirstChild("Controls")
    local moveset  = controls and controls:FindFirstChild("Moveset")
    if not moveset then scanReport("no Main.Controls.Moveset", 0); return nil end

    local slots = {}
    for _, child in ipairs(moveset:GetChildren()) do
        local btn = child:FindFirstChild("ItemName")
        if btn and (btn:IsA("TextButton") or btn:IsA("ImageButton")) then
            -- Read the slot's actual keybind from the Key.Key TextLabel (per
            -- reference_jjs_autoblock: JJS stores "1".."4" there). Position-
            -- index fallback if the label is missing; the previous assume-
            -- positional-order code would send the wrong slot key whenever
            -- slots weren't packed left-to-right starting at "1".
            local keyFrame = child:FindFirstChild("Key")
            local keyTxt = keyFrame and keyFrame:FindFirstChild("Key")
            local label = keyTxt and keyTxt:IsA("TextLabel") and keyTxt.Text
            slots[#slots + 1] = {
                name = child.Name, button = btn,
                x = btn.AbsolutePosition.X,
                key = (label and label ~= "" and label) or nil,
            }
        end
    end
    if #slots == 0 then scanReport("Moveset empty", 0); return nil end
    table.sort(slots, function(a, b) return a.x < b.x end)

    -- Engine's Use Move path = fireButton (firesignal MouseButton1Down) on the
    -- ItemName TextButton. Confirmed live by a throwaway tester: PB casts when
    -- MB1Down is fired on PlayerGui.Main.Controls.Moveset["Projection Breaker"]
    -- .ItemName -- the earlier "ItemName is visual-only" guess was wrong, the
    -- button's MB1Down handler IS the move's fire-on-press. We still record
    -- `key` so JJS.useMove (RE-direct path) can use it if needed; useKey is
    -- omitted so engine takes the button-fire path by default.
    local out, names = {}, {}
    for i, s in ipairs(slots) do
        out[#out + 1] = {
            button = s.button, name = s.name, text = s.name,
            key = s.key or tostring(i),
        }
        names[#names + 1] = s.name
    end
    scanReport("ok", #out, table.concat(names, ", "))
    return out
end

-- Per-game useMove hook. We're now relying on the engine's button-fire path
-- (firesignal MouseButton1Down on the slot's ItemName button -- confirmed
-- working live for Projection Breaker), so this hook only fires when a move
-- is EXPLICITLY pinned to a Knit RE remote below. No substring/auto guesses
-- -- those risked firing the wrong move on a coincidental name match.
-- Add an entry here when (a) the button-fire path doesn't work for a move,
-- AND (b) we've verified the exact service + remote + arg shape.
local MOVE_REMOTE = {
    -- ["Move Name"] = { service = "FooService", remote = "Activated" },
}

local function findKnitRE(svcName, remoteName)
    local knit = ReplicatedStorage:FindFirstChild("Knit")
    if not knit then return nil end
    local inner = knit:FindFirstChild("Knit") or knit
    local svcs = inner:FindFirstChild("Services")
    local svc = svcs and svcs:FindFirstChild(svcName)
    local re = svc and svc:FindFirstChild("RE")
    return re and re:FindFirstChild(remoteName) or nil
end

-- Detect which JJS character we're playing as, for char-locked techs. The
-- HUD's Ultimate.Title text is the awakening name and is character-unique
-- (verified via reference_jjs_autoblock: "HUD swap signal = ultimate Title;
-- stable thru variant switches"). Returns the name or nil if not yet built.
function JJS.detectCharacter()
    local pg = Players.LocalPlayer:FindFirstChildOfClass("PlayerGui")
    if not pg then return nil end
    local main = pg:FindFirstChild("Main")
    local controls = main and main:FindFirstChild("Controls")
    local ult = controls and controls:FindFirstChild("Ultimate")
    local title = ult and ult:FindFirstChild("Title")
    if title and title:IsA("TextLabel") then
        local t = title.Text
        if t and t ~= "" then return t end
    end
    return nil
end

function JJS.useMove(name)
    local pin = MOVE_REMOTE[name]
    if not pin then return false end
    local re = findKnitRE(pin.service, pin.remote)
    if not re then
        log.warn(("[jjs] useMove: %s.RE.%s not found, falling through"):format(pin.service, pin.remote))
        return false
    end
    local ok, err = pcall(function() re:FireServer() end)
    if not ok then
        log.warn(("[jjs] useMove fire %s: %s"):format(pin.service, tostring(err)))
        return false
    end
    return true
end

function JJS.register()
    -- LOUD load-time toast so we can SEE whether this code path actually ran in
    -- the executor. If you see "Pantheon loaded" but NOT "JJS registered" then
    -- registry.current() didn't find us for this PlaceId/GameId.
    local buildTag = tostring(rawget(_G, "PANTHEON_BUILD") or "?")
    pcall(function() notify.success("JJS registered (build " .. buildTag .. ")", 8) end)
    log.info("JJS module REGISTER on PlaceId=" .. tostring(game.PlaceId) .. " GameId=" .. tostring(game.GameId))

    -- Eagerly run scanMoves once now so the diagnostic toast fires at load
    -- (instead of waiting for the user to open the picker).
    pcall(function()
        local Players = game:GetService("Players")
        local pg = Players.LocalPlayer:FindFirstChildOfClass("PlayerGui")
        if pg then JJS.scanMoves(pg) end
    end)

    -- JJS ships its own shiftlock, which overlapped Pantheon's. Auto-engage PAIR mode
    -- so Pantheon syncs its shiftlock to the game's and keeps rotating in lockstep
    -- (instead of running a second competing one or fighting it). Per-game patch:
    -- runs at load, BEFORE any shiftlock-enable, so the foreign sweep never kills
    -- the game's shiftlock we want to pair with.
    shiftlock.setShiftlockMirror(true)

    local box = container.new(window.parent(), "Jujutsu Shenanigans")
    box:add(feature.declare({
        id          = "jjs.nanami_special",
        name        = "Nanami Perfect Special",
        description = "Auto-times Salaryman's R special, Ratio Point, onto your target. With a target within 70 studs (wiki range), pressing the key fires Ratio Point after an HP-timed delay so the confirm lands on the ratio QTE (the QTE speeds up at lower HP). Uses your Target Select / Lock-On target, else the nearest player.",
        default     = false,
        defaultKey  = Enum.KeyCode.R,
        onToggle    = function(v) enabled = v and true or false end,
        onKey       = function() ratioPointPerfect() end,
    }).root)

    log.info("JJS module registered -- Nanami Perfect Special (Ratio Point, 70-stud range)")
end

-- Called by init.lua's shutdown (Auto Re-Execute / re-execute). register() runs
-- again on every boot, so anything it changed on shared modules must be undone
-- here or it compounds across teleports. The "Jujutsu Shenanigans" container,
-- the Nanami feature row, and its keybind are torn down by window.destroy /
-- keybinds.destroy; what's left is the module-level state below.
function JJS.destroy()
    enabled = false
    lastScanReport = -1
    -- register() force-enabled shiftlock PAIR (mirror) mode for JJS; undo it so a
    -- re-execute or a hop to a non-JJS place doesn't leave Pantheon mirroring a
    -- game shiftlock that isn't there.
    pcall(function() shiftlock.setShiftlockMirror(false) end)
end

registry.register(JJS_IDS, JJS)

return JJS
end

_MODULES["games.evilplate"] = function()
-- Evil Plate integration.
--
-- Evil Plate is a multi-mode Roblox game; one mode is hot potato: you're handed a
-- Tool named "HotPotatoBomb" and must touch another player to pass it before your
-- timer hits 0 (the holder at 0 dies). This module auto-returns the bomb to whoever
-- passed it to you.
--
-- Feature: Hot Potato Auto-Return -- on receiving the HotPotatoBomb Tool it picks
-- the giver (an explicit reference on the bomb if one exists, else the nearest
-- player at the instant of receipt = whoever just touched you), equips it, and
-- after a short delay (beats receive-immunity) fakes the Handle's Touched back at
-- the giver via firetouchinterest -- the same touch-faking trick IY's handlekill
-- uses. If the bomb DOESN'T move after "returned ...", the game's pass is a
-- RemoteEvent instead -- swap attemptReturn() for that remote (a remote logger
-- will surface it). Detection is name-scoped to "HotPotatoBomb", so the module
-- stays idle in Evil Plate's other modes (the Tool only exists during the hot-
-- potato round) -- no separate round gating needed.

local registry  = require("games.registry")
local window    = require("ui.window")
local container = require("ui.container")
local feature   = require("ui.feature")
local log       = require("core.log")
local notify    = require("ui.notify")

local Players    = game:GetService("Players")
local RunService = game:GetService("RunService")
local LP         = Players.LocalPlayer

-- GameId first (covers every place / VIP server), then the root PlaceId. Resolved
-- from the game URL roblox.com/games/100337093788565 (= PlaceId) -> universeId via
-- apis.roblox.com/universes/v1/places/<placeId>/universe.
local EVILPLATE_IDS = { 9324081218, 100337093788565 }   -- { GameId, PlaceId } -- Evil Plate

local EVILPLATE = {}

local CFG = {
    toolName    = "hotpotatobomb",  -- lowercased substring of the Tool name to match
    returnDelay = 0.7,              -- s before passing back (immunity buffer + not-instant)
}
local enabled = false
local pending = nil   -- { tool=, giver=, at= }
local conns   = {}    -- live connections; torn down in destroy()

local function track(c) conns[#conns + 1] = c; return c end
local function teardownConns()
    for _, c in ipairs(conns) do pcall(function() c:Disconnect() end) end
    conns = {}
end

-- ---- helpers (ported from the [Spec] standalone prototype) ----

local function rootOf(char)
    if not char then return nil end
    return char:FindFirstChild("HumanoidRootPart")
        or char:FindFirstChild("Torso")
        or char:FindFirstChild("UpperTorso")
        or char:FindFirstChildWhichIsA("BasePart")
end
local function myRoot() return rootOf(LP.Character) end

local function getHandle(tool)
    local h = tool:FindFirstChild("Handle")
    if h and h:IsA("BasePart") then return h end
    for _, d in ipairs(tool:GetDescendants()) do
        if d:IsA("BasePart") then return d end
    end
    return nil
end

local function nameMatches(name)
    return type(name) == "string" and name:lower():find(CFG.toolName, 1, true) ~= nil
end

-- nearest living other players (closest = most likely just touched us to pass it)
local function rankByDistance()
    local mr, list = myRoot(), {}
    if not mr then return list end
    for _, p in ipairs(Players:GetPlayers()) do
        if p ~= LP and p.Character then
            local r   = rootOf(p.Character)
            local hum = p.Character:FindFirstChildOfClass("Humanoid")
            if r and (not hum or hum.Health > 0) then
                list[#list + 1] = { player = p, dist = (r.Position - mr.Position).Magnitude }
            end
        end
    end
    table.sort(list, function(a, b) return a.dist < b.dist end)
    return list
end

-- explicit giver reference stored on the bomb (attribute or value object), if any
local GIVER_KEYS = { "last", "prev", "from", "giver", "owner", "holder", "thrower", "sender" }
local function keyHit(s)
    s = s:lower()
    for _, w in ipairs(GIVER_KEYS) do if s:find(w, 1, true) then return true end end
    return false
end
local function giverFromTool(tool)
    local ok, attrs = pcall(function() return tool:GetAttributes() end)
    if ok and attrs then
        for k, v in pairs(attrs) do
            if keyHit(tostring(k)) then
                log.info(("[evilplate] bomb @%s = %s (possible giver ref)"):format(tostring(k), tostring(v)))
                if type(v) == "string" then local p = Players:FindFirstChild(v); if p then return p end
                elseif type(v) == "number" then local p = Players:GetPlayerByUserId(v); if p then return p end end
            end
        end
    end
    for _, d in ipairs(tool:GetDescendants()) do
        if keyHit(d.Name) then
            if d:IsA("ObjectValue") and d.Value then
                local pl = (d.Value:IsA("Player") and d.Value) or Players:GetPlayerFromCharacter(d.Value)
                if pl then return pl end
            elseif d:IsA("StringValue") then
                local p = Players:FindFirstChild(d.Value); if p then return p end
            elseif d:IsA("IntValue") or d:IsA("NumberValue") then
                local p = Players:GetPlayerByUserId(d.Value); if p then return p end
            end
        end
    end
    return nil
end

-- one-time structure dump per receive -- console only, our live-verify aid
local function dumpTool(tool)
    log.info("[evilplate] ===== HotPotatoBomb dump =====")
    log.info(("[evilplate] Name=%s Class=%s Path=%s"):format(tool.Name, tool.ClassName, tool:GetFullName()))
    local ok, attrs = pcall(function() return tool:GetAttributes() end)
    if ok and attrs then for k, v in pairs(attrs) do log.info(("[evilplate]   @%s = %s"):format(tostring(k), tostring(v))) end end
    for _, d in ipairs(tool:GetChildren()) do log.info(("[evilplate]   child: %s (%s)"):format(d.Name, d.ClassName)) end
    local h = getHandle(tool)
    if h then
        local ti = h:FindFirstChild("TouchInterest")
        log.info(("[evilplate]   Handle=%s TouchInterest=%s CanTouch=%s"):format(
            h.Name, ti and "YES (firetouchinterest viable)" or "none (pass may be a RemoteEvent)", tostring(h.CanTouch)))
    else
        log.info("[evilplate]   NO Handle/BasePart (RequiresHandle=false? pass likely a RemoteEvent)")
    end
end

local function equip(tool)
    local char = LP.Character
    local hum  = char and char:FindFirstChildOfClass("Humanoid")
    if hum and tool.Parent ~= char then pcall(function() hum:EquipTool(tool) end) end
end

-- fake Touched: try handle->giver and ourRoot->giver (no-op where no TouchInterest)
local function attemptReturn(tool, giver)
    if type(firetouchinterest) ~= "function" then
        log.warn("[evilplate] firetouchinterest unavailable in this executor"); return false
    end
    local theirRoot = rootOf(giver.Character)
    if not theirRoot then return false end
    local sources, fired = {}, false
    local h = getHandle(tool); if h then sources[#sources + 1] = h end
    local mr = myRoot();        if mr then sources[#sources + 1] = mr end
    for _, s in ipairs(sources) do
        pcall(function()
            firetouchinterest(s, theirRoot, 0)  -- begin
            firetouchinterest(s, theirRoot, 1)  -- end
            fired = true
        end)
    end
    return fired
end

-- the instant a HotPotatoBomb appears on us
local function onReceive(tool)
    if not enabled then return end
    if pending and pending.tool == tool then return end
    dumpTool(tool)

    local giver = giverFromTool(tool)
    local ranking = rankByDistance()
    if not giver and ranking[1] then giver = ranking[1].player end

    -- mark pending BEFORE equipping: equip reparents the Tool (Backpack->Character),
    -- which fires Character.ChildAdded and re-enters onReceive; the pending guard at
    -- the top dedupes that re-entry so we don't process the same bomb twice.
    pending = { tool = tool, giver = giver, at = os.clock() }
    equip(tool)  -- Handle must be in workspace for the Touched to register
    notify.info(("HotPotatoBomb received -> returning to %s"):format(giver and giver.Name or "?"), 4)
end

local function scan(c)
    if not c then return end
    for _, d in ipairs(c:GetChildren()) do
        if d:IsA("Tool") and nameMatches(d.Name) then onReceive(d) end
    end
end

local function bindContainer(c)
    if not c then return end
    track(c.ChildAdded:Connect(function(d)
        if d:IsA("Tool") and nameMatches(d.Name) then onReceive(d) end
    end))
end

local function bindCharacter(char)
    if not char then return end
    bindContainer(char)
    task.defer(scan, char)
end

-- drain pending returns from Heartbeat -- NEVER task.wait inside the receive
-- signal callback on Wave (coroutine may not resume); queue + drain here instead.
local function onHeartbeat()
    if not pending then return end
    if (os.clock() - pending.at) < CFG.returnDelay then return end
    local job = pending; pending = nil
    if not enabled then return end

    local char = LP.Character
    local bp   = LP:FindFirstChildOfClass("Backpack")
    local have = job.tool and (job.tool.Parent == char or job.tool.Parent == bp)
    if not have then log.info("[evilplate] no longer holding bomb (already passed?)"); return end
    if not (job.giver and job.giver.Character) then log.info("[evilplate] giver gone, cannot return"); return end

    if attemptReturn(job.tool, job.giver) then
        notify.success(("Returned bomb to %s"):format(job.giver.Name), 4)
        log.info("[evilplate] returned to " .. job.giver.Name .. " (if it didn't move, pass = RemoteEvent)")
    else
        notify.warn("Bomb return failed (see console)")
        log.warn("[evilplate] return failed")
    end
end

function EVILPLATE.register()
    local buildTag = tostring(rawget(_G, "PANTHEON_BUILD") or "?")
    pcall(function() notify.success("Evil Plate registered (build " .. buildTag .. ")", 6) end)
    log.info("[evilplate] register on PlaceId=" .. tostring(game.PlaceId) .. " GameId=" .. tostring(game.GameId))

    -- detection: backpack + character (rebind on respawn / backpack rebuild). Wired
    -- once at register; onReceive/onHeartbeat gate on `enabled`. destroy() unwires.
    bindContainer(LP:FindFirstChildOfClass("Backpack"))
    track(LP.ChildAdded:Connect(function(c) if c:IsA("Backpack") then bindContainer(c) end end))
    bindCharacter(LP.Character)
    track(LP.CharacterAdded:Connect(bindCharacter))
    track(RunService.Heartbeat:Connect(onHeartbeat))

    local box = container.new(window.parent(), "Evil Plate")
    box:add(feature.declare({
        id          = "evilplate.hotpotato_return",
        name        = "Hot Potato Auto-Return",
        description = "When you're passed the HotPotatoBomb, automatically passes it back to whoever gave it to you. Picks the giver from a reference on the bomb if one exists, else the nearest player at the instant you received it (whoever touched you). Equips the bomb and fakes its Touched back at them after a short delay (to clear receive-immunity). If the bomb doesn't actually leave you, the game passes via a RemoteEvent instead -- say so and it gets switched.",
        default     = false,
        onToggle    = function(v)
            enabled = v and true or false
            -- enabling mid-hold: re-scan so a bomb you're already holding returns too
            if enabled then
                task.defer(function()
                    scan(LP.Character)
                    scan(LP:FindFirstChildOfClass("Backpack"))
                end)
            end
        end,
        settings    = {
            { type = "slider", name = "Return delay (s)", key = "delay",
              min = 0, max = 2, step = 0.05, default = CFG.returnDelay,
              onChange = function(v) CFG.returnDelay = v end },
        },
    }).root)

    log.info("[evilplate] module registered -- Hot Potato Auto-Return")
end

-- Called by init.lua shutdown (Auto Re-Execute / re-execute). register() reruns on
-- every boot, so every connection it made must be undone here or they stack across
-- teleports (see feedback_pantheon_reexec_leaks). The feature row + its keybind are
-- torn down by window/keybinds.destroy; the connections + module state are ours.
function EVILPLATE.destroy()
    enabled = false
    pending = nil
    teardownConns()
end

registry.register(EVILPLATE_IDS, EVILPLATE)

return EVILPLATE
end

_MODULES["init"] = function()
-- Pantheon entry point. Boots persist + keybinds + window, registers modules,
-- and stashes a shutdown handle on the executor's global env so a second
-- loadstring() of Pantheon tears down the previous instance before starting
-- fresh (no duplicate GUIs, stacked input listeners, or hook layering).

local log      = require("core.log")
local env      = require("core.env")
local persist  = require("core.persist")
local keybinds   = require("core.keybinds")
local window     = require("ui.window")
local container  = require("ui.container")
local notify     = require("ui.notify")
local components = require("ui.components")
local registry   = require("games.registry")

local genv = (env.getgenv and env.getgenv()) or _G

-- Tear down any previously-loaded Pantheon instance. Uses getgenv() (not _G)
-- because Wave/Synapse-style executors share getgenv across loadstring calls;
-- _G is the Roblox-sandbox-local table and would forget across reloads.
if genv.Pantheon and type(genv.Pantheon.shutdown) == "function" then
    log.info("replacing previously loaded Pantheon instance")
    local ok, err = pcall(genv.Pantheon.shutdown)
    if not ok then log.warn("previous shutdown errored: " .. tostring(err)) end
end
genv.Pantheon = {}

log.info("booting on executor: " .. tostring(env.executor))

persist.init()
keybinds.init()
window.init()

-- The single navigator menu: built first so it's the left-most panel and stays
-- visible. Every container created after this starts hidden and is opened/closed
-- from the navigator (Wurst-style) instead of all menus showing at once.
local nav = container.buildNavigator(window.parent(), "Menu")
container.startHidden = true

-- Universal modules
local aim = require("modules.aim.init")
aim.register()

local friendlies = require("modules.friendlies")
friendlies.register()

local tech = require("modules.tech.init")
tech.register()

local system = require("modules.system")
system.register()

local aesthetic = require("modules.aesthetic")
aesthetic.register()

local misc = require("modules.misc.init")
misc.register()

-- Per-game modules self-register on require; pull them in so registry.current()
-- can find one for this PlaceId. (Requiring in a non-matching game just adds to
-- the registry table; its .register() only runs if the PlaceId matches.)
require("games.jjs")
require("games.evilplate")

-- Per-game module (if registered for this PlaceId)
local gameMod = registry.current()
if gameMod and gameMod.register then
    log.info("game module found for PlaceId " .. tostring(game.PlaceId))
    local ok, err = pcall(gameMod.register)
    if not ok then log.err("game module register failed: " .. tostring(err)) end
else
    log.info("no game module for PlaceId " .. tostring(game.PlaceId))
end

-- Every module (and any per-game one) has now created its containers; fill the
-- navigator with a toggle row per menu. They start closed -- click a row to open.
nav.populate()

-- Expose the teardown so a future re-execute can call it.
-- Order matters: aim first (it stops render binds and unhooks the UIS
-- __newindex, so leftover input events from the about-to-die UI don't reach
-- already-torn-down state), then UI, then keybinds, then persist flush.
local function shutdown()
    -- Per-game module FIRST, while aim/shiftlock are still alive, so it can undo
    -- state it set on register (e.g. JJS force-enables shiftlock PAIR mode).
    -- Without this the game module's register() re-ran on every teleport (Auto
    -- Re-Execute) with no matching teardown.
    pcall(function() if gameMod and gameMod.destroy then gameMod.destroy() end end)
    pcall(function() if aim.destroy      then aim.destroy()      end end)
    pcall(function() if friendlies.destroy then friendlies.destroy() end end)
    pcall(function() if tech.destroy     then tech.destroy()     end end)
    pcall(function() if system.destroy   then system.destroy()   end end)
    pcall(function() if aesthetic.destroy then aesthetic.destroy() end end)
    pcall(function() if misc.destroy     then misc.destroy()     end end)
    pcall(function() if window.destroy     then window.destroy()     end end)
    pcall(function() if components.destroy then components.destroy() end end)
    pcall(function() if notify.destroy     then notify.destroy()     end end)
    pcall(function() if keybinds.destroy then keybinds.destroy() end end)
    pcall(function() if persist.flush    then persist.flush()    end end)
end
genv.Pantheon.shutdown = shutdown

-- Full removal ("Unload" / unexecute, from the Pantheon menu's cog). shutdown()
-- tears everything down but deliberately leaves the genv.Pantheon handle in place
-- so a later re-execute can find it and replace the instance. unload() is the
-- harder stop the user asked for: it runs the same teardown, then erases every
-- global handle so nothing -- not a stray reference, not the teleport latch --
-- can resurrect the hub. The game is left as if Pantheon never ran.
--
-- Caveat: an already-registered Auto Re-Execute teleport payload can't be
-- un-queued on most executors, so teleporting AFTER unload may still reload a
-- fresh Pantheon. Turn Auto Re-Execute off first if you want it gone across
-- teleports too.
genv.Pantheon.unload = function()
    pcall(shutdown)
    -- Native Roblox toast: independent of our just-destroyed GUI, so it's the one
    -- confirmation the user still sees after everything else is gone.
    pcall(function()
        game:GetService("StarterGui"):SetCore("SendNotification", {
            Title    = "Pantheon",
            Text     = "Unloaded. Re-run the loadstring to bring it back.",
            Duration = 4,
        })
    end)
    genv.Pantheon          = nil
    genv.PANTHEON_TP_QUEUED = nil
end

local buildTag = rawget(_G, "PANTHEON_BUILD") or "?"
notify.success("Pantheon loaded (" .. tostring(buildTag) .. "). Press RightCtrl to toggle UI.")

return true
end


_G.PANTHEON_BUILD = _BUILD
return require("init")
